-- Poems batch 376
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('da139b42-ee22-4d65-9b2d-554fde57f578','用前韻留别諸弟','李綱','宋','宋诗','song-poetry','','[]','久陪鴛鷺日朝天，却愛江湖作散仙。',64,'全唐诗/poet.song.89000.json','["久陪鴛鷺日朝天，却愛江湖作散仙。", "但有園林種松菊，便勝冠冕著貂蟬。", "棣華春早相輝映，鴈序風高自後先。", "暫此睽離休悵望，爲荒三徑徯予還。"]'),
('7a74fee1-0b8d-4660-9c74-09d7fc2786ae','同叔易季言遊虎丘寺邂逅何得之','李綱','宋','宋诗','song-poetry','','[]','理櫂適閩粤，虎丘聊艤航。',288,'全唐诗/poet.song.89000.json','["理櫂適閩粤，虎丘聊艤航。", "霜林正搖落，翠柏森成行。", "入門躡磴道，喬木間疏篁。", "秦帝試劍石，破瓜分路傍。", "生公雨花臺，說法今不亡。", "蒼蘚衣峭壁，枯荷響迴塘。", "遂遊劍池上，毛髮森以張。", "沈沈下無底，疑有虬龍藏。", "鐫削露天巧，胚胎勞混茫。", "清奇儼圖畫，祕怪叵測量。", "薜荔疊秀色，枇杷吐幽香。", "行行造梵宇，金碧相熒煌。", "危脊聳古殿，長腰曼脩廊。", "憑虛架雲閣，鑿險通禪房。", "開軒俯吳會，蜂窠繚池隍。", "風煙寄遠目，心逐征鴻翔。", "列岫靄遥碧，平湖湛孤光。", "追尋殊未倦，策杖登崇岡。", "幽獨詩句苦，闔廬丘塚荒。", "五聖瞻象設，羽泉酌甘芳。", "西庵何閑寂，修竹自蒼蒼。", "脫履足生繭，解衣汗如漿。", "却攜二三子，置酒白雲堂。", "念舊已悽惻，感時增慨慷。"]'),
('567d7a69-b7bd-49bc-a8b9-6d8082b9a60a','吳江五首  其一','李綱','宋','宋诗','song-poetry','','[]','重過松江憶舊遊，依然風景照行舟。',64,'全唐诗/poet.song.89000.json','["重過松江憶舊遊，依然風景照行舟。", "危橋跨水虹垂影，髙閣憑虚蜃吐樓。", "渺渺衝煙歸釣艇，輕輕點浪舞沙鷗。", "暮天横笛江村起，激烈能令逐客愁。"]'),
('dad9dc06-2ab6-4269-809d-e2d8f09bf726','吳江五首  其二','李綱','宋','宋诗','song-poetry','','[]','木落水寒天氣清，江湖合處一橋横。',64,'全唐诗/poet.song.89000.json','["木落水寒天氣清，江湖合處一橋横。", "波濤萬頃琉璃滑，欄檻千尋螮蝀明。", "茶竈筆牀隨陸子，蒓羮鱸鱠憶張生。", "他時若我歸來後，定向江頭事釣耕。"]'),
('a6e3875b-05f5-4336-80de-6ce05bc985f8','吳江五首  其三','李綱','宋','宋诗','song-poetry','','[]','返照澄波徹底明，江邊弭櫂若爲情。',64,'全唐诗/poet.song.89000.json','["返照澄波徹底明，江邊弭櫂若爲情。", "風煙漠漠無今古，舟檝紛紛盡利名。", "潮落片帆歸浦嶼，雲寒一鴈過江城。", "孤臣放逐三千里，此去龍津尚幾程。"]'),
('2c85d935-a841-43bb-a612-e919984470bf','吳江五首  其四','李綱','宋','宋诗','song-poetry','','[]','繫纜江頭日脚沈，鱸肥酒美只孤斟。',64,'全唐诗/poet.song.89000.json','["繫纜江頭日脚沈，鱸肥酒美只孤斟。", "長橋千步風濤穩，横笛一聲煙水深。", "契闊離親寧素願，迂愚報國祗丹心。", "遠遊自是男兒事，更把離騷細細尋。"]'),
('b51977ab-a55b-43f4-bf77-9ae46f346b5c','吳江五首  其五','李綱','宋','宋诗','song-poetry','','[]','鱸鄉宜曠望，煙靄起層陰。',48,'全唐诗/poet.song.89000.json','["鱸鄉宜曠望，煙靄起層陰。", "謳軋櫓聲急，蒼茫江色深。", "歸潮寒入浦，宿鳥暝投林。", "誰識登臨意，愁來遽不禁。"]'),
('538b3aa7-5f7f-4858-9a9e-ee86f15fd2c2','過吳江阻風遊寧境寺','李綱','宋','宋诗','song-poetry','','[]','扁舟渡松江，慘淡天色惡。',120,'全唐诗/poet.song.89000.json','["扁舟渡松江，慘淡天色惡。", "勝遊得禪房，曠望倚虚閣。", "軒楹俯巨浸，雲水互參錯。", "長風駕驚浪，飛雪相噴薄。", "未應神龍怒，端有蛟鼉作。", "片帆天際來，飄忽如隕籜。", "波濤浩無涯，撐突殊不愕。", "奈何操我舟，惴慄纜添索。", "蜚廉也世情，逐客正落寞。", "深夜始歸眠，蓬窗聽鳴鐸。"]'),
('4ae27692-95ae-48e8-b5a1-8b53e5e6d1f2','松江第四橋','李綱','宋','宋诗','song-poetry','','[]','松江第四橋，風雨不可過。',72,'全唐诗/poet.song.89000.json','["松江第四橋，風雨不可過。", "下有百尺蛟，蜿蜒枕橋臥。", "窟宅據要津，口腹長饑餓。", "毎憑波濤勢，能作舟檝禍。", "安得佽飛手，坐使神姦破。", "往來水無虞，時鼓清江柁。"]'),
('1c5444ed-b782-4fb0-8706-84c65e9b5b3c','操舟','李綱','宋','宋诗','song-poetry','','[]','吳兒便操舟，衣服皆楚製。',84,'全唐诗/poet.song.89000.json','["吳兒便操舟，衣服皆楚製。", "出沒波濤中，端如履平地。", "江湖渺千里，鼓柁等遊戲。", "臨深詎保身，涉險惟射利。", "天風難與期，飄驟出非意。", "傾覆瞬息間，永爲魚鼈餌。", "願言戒畏塗，巧手不可恃。"]'),
('5b9bb037-67b6-43da-9957-7060372c217d','雜興四首  其一','李綱','宋','宋诗','song-poetry','','[]','邑犬驚行客，林烏啼曉霜。',48,'全唐诗/poet.song.89000.json','["邑犬驚行客，林烏啼曉霜。", "山村雲冉冉，澤國水茫茫。", "移櫂輕舟穩，鈎簾野興長。", "誰知因謫宦，得到雲水鄉。"]'),
('2687988c-b2c3-4888-ab1f-6680c6e026ad','雜興四首  其二','李綱','宋','宋诗','song-poetry','','[]','肅肅歳華暮，霏霏烟靄深。',48,'全唐诗/poet.song.89000.json','["肅肅歳華暮，霏霏烟靄深。", "輕冰依淺渚，寒日映疏林。", "故邑懷親日，扁舟去國心。", "凝眸無限景，愁絕不成吟。"]'),
('57310aa2-1dc7-4af6-a36e-9ccc11a0c3ad','雜興四首  其三','李綱','宋','宋诗','song-poetry','','[]','片帆隨鳥翼，離恨滿江鄉。',48,'全唐诗/poet.song.89000.json','["片帆隨鳥翼，離恨滿江鄉。", "風細雲衣薄，日斜波影光。", "牧童寒哨笛，漁艇静鳴榔。", "景物正清絕，桑榆還夕陽。"]'),
('3caa2def-3b0d-471f-9171-765ad1ab0e2a','雜興四首  其四','李綱','宋','宋诗','song-poetry','','[]','暮天來遠色，行客尚貪行。',48,'全唐诗/poet.song.89000.json','["暮天來遠色，行客尚貪行。", "櫂急浪花碎，月髙雲縷輕。", "巢烏棲更起，漁火暗還明。", "獨寢不成夢，夜寒聞鴈聲。"]'),
('6d768bae-93c8-4017-aa4b-83f905375e80','韓賈','李綱','宋','宋诗','song-poetry','','[]','退之守潮陽，戚嗟見章表。',96,'全唐诗/poet.song.89000.json','["退之守潮陽，戚嗟見章表。", "賈生傅長沙，自廣託鵩鳥。", "拘達言雖殊，均爲未能了。", "今我謫龍津，管庫素所曉。", "粗令職事辦，便覺溪山好。", "燕坐一室間，妄念悉除掃。", "豈復計窮通，端亦忘壽夭。", "回觀古人心，頗歎二子小。"]'),
('2c485b9c-c15b-4f6a-bdd2-36cb1caea1e7','田家四首  其一','李綱','宋','宋诗','song-poetry','','[]','江村烟水遠，茅屋兩三家。',48,'全唐诗/poet.song.89000.json','["江村烟水遠，茅屋兩三家。", "斷岸垂衰柳，疏篁隱細沙。", "田疇賸秔稻，網罟足魚蝦。", "不識宦遊味，見人還歎嗟。"]'),
('cab612c1-9c4b-447c-a936-4f4ffca90ac1','田家四首  其二','李綱','宋','宋诗','song-poetry','','[]','場圃事方畢，稻粱成已勤。',48,'全唐诗/poet.song.89000.json','["場圃事方畢，稻粱成已勤。", "兒童自逐逐，雞犬亦欣欣。", "啼鳥霜林暮，臥牛烟草昏。", "田夫樂歳稔，斗酒共醺醺。"]'),
('3864cfaf-9319-4139-b013-03b8bf5e8b66','田家四首  其三','李綱','宋','宋诗','song-poetry','','[]','柴門臨小浦，竹徑遶幽荘。',48,'全唐诗/poet.song.89000.json','["柴門臨小浦，竹徑遶幽荘。", "雨剪葵韮滑，夜舂秔稻香。", "年豐飽妻子，日夕下牛羊。", "誰識田家樂，拂衣歸興長。"]'),
('24305167-1c04-4139-9459-3adafb9cfead','田家四首  其四','李綱','宋','宋诗','song-poetry','','[]','誰謂田家苦，田家樂甚真。',48,'全唐诗/poet.song.89000.json','["誰謂田家苦，田家樂甚真。", "鷄豚燕同社，簫鼓祭瘟神。", "髙廪方有歲，西疇行復春。", "但令租賦足，終老得相親。"]'),
('3f64f832-4069-4abc-8de5-71cba7bcb3a5','嘉禾道中遇夏侯子陽','李綱','宋','宋诗','song-poetry','','[]','京華契闊已再冬，扁舟野岸欣相逢。',112,'全唐诗/poet.song.89000.json','["京華契闊已再冬，扁舟野岸欣相逢。", "天寒水遠飛霜風，談笑坐覺迴春容。", "年踰七十兩頰紅，真氣上泝泥丸宫。", "剖符南海窺祝融，欲求丹砂訪葛洪。", "問予執筆侍九重，胡爲謫墮溪山中。", "迂愚久合親耕農，君恩未報徒忡忡。", "飄零孤跡隨斷蓬，他日相憶看雲鴻。"]'),
('47071633-0a28-4b51-bc1c-0a31b0849f97','初到臨平見山二首  其一','李綱','宋','宋诗','song-poetry','','[]','我見青山若故人，峰巒照眼自相親。',64,'全唐诗/poet.song.89000.json','["我見青山若故人，峰巒照眼自相親。", "只應今日愛山意，便是他時傲世因。", "點綴白雲春縹渺，縈迴綠水晚奫淪。", "君恩若許歸田里，定卜山間老此身。"]'),
('beff9f15-4dc0-499e-b5a8-98fba52d5c4b','初到臨平見山二首  其二','李綱','宋','宋诗','song-poetry','','[]','孤舟渺渺兩山間，終日鈎簾只看山。',64,'全唐诗/poet.song.89000.json','["孤舟渺渺兩山間，終日鈎簾只看山。", "落日半銜霞未散，疏林遠暝烏初還。", "悽凉離恨誰能寄，浩蕩詩愁自莫删。", "賴有青山可人意，與君相對且開顔。"]'),
('8eb104cc-6e5f-4d86-9d20-636c5ea19f80','小雨','李綱','宋','宋诗','song-poetry','','[]','小雨晚初急，暝雲深不收。',48,'全唐诗/poet.song.89000.json','["小雨晚初急，暝雲深不收。", "霏霏暗煙樹，索索響篷舟。", "山色增遠翠，漁蓑生暮愁。", "凄凉蘇季子，寒覓敝貂裘。"]'),
('0d44d64d-0af7-4836-84f3-d4d6643f37cc','將次錢塘','李綱','宋','宋诗','song-poetry','','[]','歲晚飄零日，舟行杳靄間。',48,'全唐诗/poet.song.89000.json','["歲晚飄零日，舟行杳靄間。", "江鄉多霧雨，風物近湖山。", "獨鶴徊翔久，飛雲自在閒。", "遠遊殊未已，蕭颯鬢毛斑。"]'),
('803af79e-2bed-4f54-a6b2-a06ec4af295a','靈隱宫','李綱','宋','宋诗','song-poetry','','[]','我昔曾遊飛來峰，白猿晝掛峰上松。',144,'全唐诗/poet.song.89000.json','["我昔曾遊飛來峰，白猿晝掛峰上松。", "曄然靈光如彩虹，鐘磬自響金仙宫。", "宦遊漂泊西復東，雖欲再到無由從。", "帝居鈞天陋瀛蓬，螭坳載筆侍重瞳。", "逆鱗聊試摩神龍，謫墮劍浦山重重。", "征鞍來此尋舊蹤，恍如夢落煙霞中。", "朱樓寶殿飛玲瓏，寒泉幽石欣相逢。", "門前池館虛含風，一洗塵慮清心胸。", "明朝南去隨征鴻，惆悵勝遊回首空。"]'),
('4825e0f7-cd2b-44f2-a55a-9b170927db54','望潮','李綱','宋','宋诗','song-poetry','','[]','樟亭一望浙江潮，震地凌空氣象驕。',64,'全唐诗/poet.song.89000.json','["樟亭一望浙江潮，震地凌空氣象驕。", "十萬軍聲來海嶠，三千銀界混煙霄。", "素車白馬縱横騖，翔鷺飛鷗散漫飄。", "好是波平風穩後，一帆千里不崇朝。"]'),
('d7b26440-864b-470a-b818-1a88989b1ca7','自哂','李綱','宋','宋诗','song-poetry','','[]','自哂何爲者，南遊亦偶然。',48,'全唐诗/poet.song.89000.json','["自哂何爲者，南遊亦偶然。", "未登離垢地，端有散花天。", "遇境聊爲戲，安心不離禪。", "幽懷誰與共，深炷一爐煙。"]'),
('ed2387b2-bf56-4a82-9848-2934209b8274','張南仲置酒心淵堂值雨','李綱','宋','宋诗','song-poetry','','["\u897f\u6e56"]','自别西湖日置懷，却因謫宦得重來。',64,'全唐诗/poet.song.89000.json','["自别西湖日置懷，却因謫宦得重來。", "雲深不見孤山寺，風急難乘搖碧齋。", "未放幽情窮水石，且將離恨泥樽罍。", "勝遊須徧山南北，何日晴天爲一開。"]'),
('cf6cd169-4d65-4bca-b7be-8a2052ff421f','北望','李綱','宋','宋诗','song-poetry','','[]','迢迢休北望，汨汨正南遷。',48,'全唐诗/poet.song.89000.json','["迢迢休北望，汨汨正南遷。", "出處豈無意，阨窮那問天。", "銷愁憑酒醆，遣興賴詩篇。", "詩酒吾家事，從今號謫仙。"]'),
('7ded52cb-eb8e-4a48-82ff-546b57a040cd','長至','李綱','宋','宋诗','song-poetry','','[]','黄鍾之宫萌一陽，萬彙滋發猶潛藏。',64,'全唐诗/poet.song.89000.json','["黄鍾之宫萌一陽，萬彙滋發猶潛藏。", "書雲詎復别祥異，揆景漸可知舒長。", "閉關不行著易象，客子倦遊悲故鄉。", "周南太史長太息，禋祀無因陪祼將。"]'),
('c52eb843-080e-4d34-99fc-5970490e9fc0','渡浙江','李綱','宋','宋诗','song-poetry','','[]','理櫂適桐江，隨潮過魚浦。',72,'全唐诗/poet.song.89000.json','["理櫂適桐江，隨潮過魚浦。", "山寒雪猶積，江迥月初吐。", "御氣凌煙霄，乘槎渡星渚。", "空濛老龍吟，髣髴翠蛟舞。", "境清人自愁，夜静氣尤古。", "獨坐不成眠，霜晴聽津鼓。"]'),
('a547cd31-06ac-4dde-b802-a88d73739e54','桐江行贈江致一少府','李綱','宋','宋诗','song-poetry','','[]','放浪江湖乃吾樂，羈束軒冕非所榮。',224,'全唐诗/poet.song.89000.json','["放浪江湖乃吾樂，羈束軒冕非所榮。", "謫官去爲劍浦吏，鼓柁遂作桐江行。", "艤舟浙岸候潮至，百越微茫煙水外。", "波横天際海倒流，噴雪驚雷聲震地。", "須臾風軟潮已平，片帆去逐飛鴻輕。", "櫂謳四起日西落，暮天杳杳惟參横。", "江山蒼蒼負殘雪，江水茫茫浸寒月。", "誰云逐客苦悽凉，今我斯遊最奇絕。", "清晨弭櫂桐君廬，溪光山色世所無。", "故人見我一笑粲，殺雞爲黍聊相娛。", "嗟予仕宦等遊戲，斷梗飄蓬本無蔕。", "但令景物供吟哦，出處窮通何足計。", "此行幽討殊未闌，滿目疊疊皆雲山。", "鷺飛魚躍石齒齒，今夜且宿嚴陵灘。"]'),
('4d13eab2-a1de-43cc-a0f6-e2bffc277c2f','覺度寺','李綱','宋','宋诗','song-poetry','','[]','夕發富春渚，朝次桐君廬。',84,'全唐诗/poet.song.89000.json','["夕發富春渚，朝次桐君廬。", "桐君採藥地，今作僧家居。", "石磴上窈窕，林芿下扶疏。", "山根二江合，清波見遊魚。", "霜晴響鐘磬，日落歸樵漁。", "客從何方來，弭櫂聊踟蹰。", "清景難久駐，悵然還問途。"]'),
('91f5f8ee-80cb-49b3-9aaa-0d031e262677','嚴陵灘下作二首  其一','李綱','宋','宋诗','song-poetry','','[]','世祖龍飛萬國朝，故人依舊隱蓬蒿。',64,'全唐诗/poet.song.89000.json','["世祖龍飛萬國朝，故人依舊隱蓬蒿。", "羊裘肯換貂冠貴，釣石終齊鳯闕髙。", "共宿客星親帝座，貽書直氣壓時豪。", "東京臣子多名節，皆自先生鑄此曹。"]'),
('3f69aae9-8d3d-4d11-9e00-bc4eab4f3ff7','嚴陵灘下作二首  其二','李綱','宋','宋诗','song-poetry','','[]','帝座髙懸漢客星，樵漁今亦想英聲。',32,'全唐诗/poet.song.89000.json','["帝座髙懸漢客星，樵漁今亦想英聲。", "釣臺直下三千尺，誰謂先生只釣名。"]'),
('efd143dc-0317-483d-a874-7049f5c9019a','蘭溪訪吳聖與不遇','李綱','宋','宋诗','song-poetry','','[]','夕次蘭溪縣，溪山照眼明。',48,'全唐诗/poet.song.89000.json','["夕次蘭溪縣，溪山照眼明。", "雲端雙塔聳，烟際一橋横。", "久旅易悽感，舊遊如隔生。", "故人尋不值，飄泊若爲情。"]'),
('22be9fbc-823c-48bc-9122-c6654974f907','陸行','李綱','宋','宋诗','song-poetry','','[]','水落石出溪難行，捨舟束装趨路程。',64,'全唐诗/poet.song.89000.json','["水落石出溪難行，捨舟束装趨路程。", "徒御諠呶烏雀噪，衣冠瓌偉兒童驚。", "天寒野迥怯霜露，日暮途遠傷蓬萍。", "我生胡爲浪自苦，濁酒且向燈前傾。"]'),
('e3ea8335-6c4a-440f-bb0a-220a8d54a404','水磑','李綱','宋','宋诗','song-poetry','','[]','鑿木爲機運不休，溪邊疊石駃溪流。',64,'全唐诗/poet.song.89000.json','["鑿木爲機運不休，溪邊疊石駃溪流。", "但知隨水能旋轉，肯道舂糧不自由。", "輪輻詎爲君子器，機關端與小人謀。", "方知抱甕漢陰老，混沌何須是假脩。"]'),
('c424e061-baae-461f-9e08-6342fbc04abb','戲爲吳語','李綱','宋','宋诗','song-poetry','','[]','莫問儂家作底愁，細思今古事悠悠。',64,'全唐诗/poet.song.89000.json','["莫問儂家作底愁，細思今古事悠悠。", "只因讀得數行字，便覺分爲一世憂。", "問舍求田須更以，濟時澤物且能休。", "梁谿幸有閒泉石，正好歸來作故侯。"]'),
('8f8c8668-f359-4215-b480-554cbc2b21d5','絕句','李綱','宋','宋诗','song-poetry','','[]','殷侯左降惟書字，陸相南遷不著書。',32,'全唐诗/poet.song.89000.json','["殷侯左降惟書字，陸相南遷不著書。", "今我新詩三百首，坐令二子覺區區。"]'),
('3af58ae3-7e1e-43ad-aba3-5956113876e6','次退之藍關韻','李綱','宋','宋诗','song-poetry','','[]','奏疏螭坳上九天，謫官劍浦路三千。',64,'全唐诗/poet.song.89000.json','["奏疏螭坳上九天，謫官劍浦路三千。", "披陳肝膽成微志，跋涉山川賴壯年。", "緬邈寄書黄犬後，凄凉陟岵白雲前。", "君恩欲報知無所，清夢時時到日邊。"]'),
('f6ca4532-744d-4d13-82cb-931d905328fb','三衢道中','李綱','宋','宋诗','song-poetry','','[]','行色虛無裏，人聲煙靄間。',120,'全唐诗/poet.song.89000.json','["行色虛無裏，人聲煙靄間。", "浪紋來縠水，地勢逼柯山。", "淺瀨通舟澀，飛橋跨石彎。", "風髙雲冉冉，灘急水潺潺。", "野迥松篁秀，境幽雞犬閒。", "輕装因路險，隱耳覺言蠻。", "村釀酤來薄，溪鱗買得慳。", "浦晴鳴鴈浴，林暝舞鴉還。", "寺僻殿閣古，堂虛苔蘚斑。", "僧房清夜宿，幽夢到鄉關。"]'),
('8d16b12d-2cbf-46c6-a525-dd816e5e0533','雜興三首  其一','李綱','宋','宋诗','song-poetry','','[]','日出霜晴鳥雀呼，束装還復戒征途。',64,'全唐诗/poet.song.89000.json','["日出霜晴鳥雀呼，束装還復戒征途。", "黄牛傍岸將孤犢，花鴨浮溪引衆雛。", "橋斷水寒尋野艇，路迷山曲問田夫。", "遠遊看盡溪山景，待向龍津書作圖。"]'),
('21c30327-122f-4bdb-bfca-66b393c110aa','雜興三首  其二','李綱','宋','宋诗','song-poetry','','[]','歲晚南遷殊未央，曉寒霜霰濕征裳。',64,'全唐诗/poet.song.89000.json','["歲晚南遷殊未央，曉寒霜霰濕征裳。", "煙籠山彩遠增翠，風皺溪瀾細漾光。", "嶺雪未銷宫頞粉，野梅初發御鑪香。", "誰憐飄泊螭坳史，曾向鈞天侍紫皇。"]'),
('0de9725a-64ea-4ba7-88d9-1a0f5d8cbe00','雜興三首  其三','李綱','宋','宋诗','song-poetry','','[]','盡日籃輿山水中，毎逢佳處慰飄蓬。',64,'全唐诗/poet.song.89000.json','["盡日籃輿山水中，毎逢佳處慰飄蓬。", "拂雲古木陰陰日，夾岸脩篁細細風。", "遠岫長溪千里碧，斷霞殘照半天紅。", "殊方景物隨時好，却恨登臨無與同。"]'),
('ac782f21-7e97-41f3-885c-7b110325d06e','戲成絕句三首  其一','李綱','宋','宋诗','song-poetry','','[]','山色黛眉遠，溪聲玉珮珊。',24,'全唐诗/poet.song.89000.json','["山色黛眉遠，溪聲玉珮珊。", "溪山憐逐客，故爲結清歡。"]'),
('c1ee470b-0d4b-4cc3-abb7-a9ce5882fd5f','戲成絕句三首  其二','李綱','宋','宋诗','song-poetry','','[]','粼粼溪底石，五色粲堅圓。',24,'全唐诗/poet.song.89000.json','["粼粼溪底石，五色粲堅圓。", "安得女媧手，錬之將補天。"]'),
('1bc05f45-309b-4b36-853d-1dcb25d1ea23','戲成絕句三首  其三','李綱','宋','宋诗','song-poetry','','[]','小艇渡行旅，往來終日操。',24,'全唐诗/poet.song.89000.json','["小艇渡行旅，往來終日操。", "但令人利涉，寧復計劬勞。"]'),
('83502a38-b3d7-4463-aaff-8bfcf51a2f25','偶題','李綱','宋','宋诗','song-poetry','','[]','日照溪光碧起鱗，溪頭鴈鶩自成羣。',32,'全唐诗/poet.song.89000.json','["日照溪光碧起鱗，溪頭鴈鶩自成羣。", "可憐獨鶴歸何處，萬里相隨一片雲。"]'),
('3bcb5cb7-a825-4ba7-b3b6-cd9ebbee2920','玉山道中五首  其一','李綱','宋','宋诗','song-poetry','','[]','悠悠征騎渡溪巖，跋涉艱難分所甘。',64,'全唐诗/poet.song.89000.json','["悠悠征騎渡溪巖，跋涉艱難分所甘。", "泉石幾時歸水北，風煙今夕過江南。", "日輪杳杳銜青嶂，天影茫茫浸碧潭。", "猿鳥不知遷客恨，雲間啼叫滿松柟。"]'),
('31571780-5afe-41a9-8806-08d154c8f147','玉山道中五首  其二','李綱','宋','宋诗','song-poetry','','[]','石路凝霜白，山村落月纖。',48,'全唐诗/poet.song.89000.json','["石路凝霜白，山村落月纖。", "溪頭一橋小，煙外數峰尖。", "髙畝層成級，寒沙軟勝鹽。", "江南風景好，無那旅愁添。"]'),
('e13d4e40-fbb6-4131-a528-4f1c8ca84e57','玉山道中五首  其三','李綱','宋','宋诗','song-poetry','','[]','乍入江南境，登臨慰所懷。',48,'全唐诗/poet.song.89000.json','["乍入江南境，登臨慰所懷。", "山林自平遠，水石巧縈迴。", "風暖鳥聲媚，日斜雲影開。", "故人千里别，欲寄一枝梅。"]'),
('d1cbcb05-5616-4620-be6d-1dc6dffa05ec','玉山道中五首  其四','李綱','宋','宋诗','song-poetry','','[]','石蘚紅依日，巖松翠耐霜。',48,'全唐诗/poet.song.89000.json','["石蘚紅依日，巖松翠耐霜。", "入溪看岫色，和月認梅香。", "歲暮旅情惡，夜寒燈影光。", "勞生真一夢，回首意茫茫。"]'),
('098420ed-3dba-4be6-8ab6-1b43109be61e','玉山道中五首  其五','李綱','宋','宋诗','song-poetry','','[]','行李遠瀫水，禪扉依玉山。',48,'全唐诗/poet.song.89000.json','["行李遠瀫水，禪扉依玉山。", "煙嵐數峰秀，雲水一溪彎。", "小市晚猶合，疏鐘寒自還。", "舊遊如昨日，屈指十年間。"]'),
('8c987272-25e0-4663-bc07-e7f669738295','望龜峰','李綱','宋','宋诗','song-poetry','','[]','何日清江使，來爲碧落趺。',48,'全唐诗/poet.song.89000.json','["何日清江使，來爲碧落趺。", "凝眸望霄漢，曳尾謝泥塗。", "霜曉疑曝甲，雲横如負圖。", "前知儻可仗，吾欲問玄夫。"]'),
('6d651b2d-6f05-48b1-af24-a93bc3dbf836','述懷','李綱','宋','宋诗','song-poetry','','[]','早遊文翰圃，誤齒縉紳塗。',288,'全唐诗/poet.song.89000.json','["早遊文翰圃，誤齒縉紳塗。", "蘭省爲郎久，霜臺奮舌孤。", "荷知誠特達，勵志敢躊躇。", "屢賜楓宸對，親蒙御筆除。", "月卿論鉅禮，柱史進寒儒。", "黼座當陽日，螭坳載筆初。", "明堂頒政事，路寢集簪裾。", "繡案横雕檻，天香夾御鑪。", "翠華來寶輦，清蹕警嵩呼。", "法駕臨真館，芳塵從屬車。", "重瞳瞻日月，粹色仰瓊瑜。", "侍立親龍衮，書言粲帝謨。", "視朝崇政罷，勸講邇英餘。", "麗日明金殿，輕風響珮琚。", "漏聲寒淅瀝，槐影綠扶疏。", "紫槖陪時彦，黄扉寓直廬。", "仙遊疑閬苑，清夢豈華胥。", "遇事肯懷祿，銜恩寧惜軀。", "惟慚涉道淺，豈恨與時迂。", "犬馬知愛主，龜蛇思報珠。", "未終青史志，一奏皂囊書。", "誰謂爰絲直，端同汲黯愚。", "謫官來劍浦，襆被出神都。", "感激心獨苦，飄零歲已徂。"]'),
('050bf605-2f3a-41f8-80a3-769845cf4c91','短歌','李綱','宋','宋诗','song-poetry','','[]','周家柱史本吾祖，唐室謫仙尤所許。',64,'全唐诗/poet.song.89000.json','["周家柱史本吾祖，唐室謫仙尤所許。", "垂世空餘道德經，傲時且以詩酒名。", "我今去作龍津客，學道吟詩真自適。", "也勝騎馬聽朝雞，晴壓塵埃雨壓泥。"]'),
('c6a26847-3610-4404-aa81-9c5a974298b2','遣興  其一','李綱','宋','宋诗','song-poetry','','[]','遊戲清都不記年，謫來猶作地行仙。',64,'全唐诗/poet.song.89000.json','["遊戲清都不記年，謫來猶作地行仙。", "龍墀叩額真率爾，石馬繫門非偶然。", "野寺山莊隨意宿，溪魚村釀不論錢。", "男兒本有四方志，出處安時休問天。"]'),
('1762c4dd-d30b-46f2-9a70-bd74a957dd79','遣興  其二','李綱','宋','宋诗','song-poetry','','[]','衝涉脩途僕已疲，今宵聊復宿沙溪。',64,'全唐诗/poet.song.89000.json','["衝涉脩途僕已疲，今宵聊復宿沙溪。", "心懷浙右家無耗，身在江南路欲迷。", "孤鶩斷霞晴杳杳，暝煙荒草晚悽悽。", "登臨誰會悠然意，寒日無言又向西。"]'),
('4058ad68-a766-4190-b8fa-8526d221e962','遣興  其三','李綱','宋','宋诗','song-poetry','','[]','風景正髙潔，歲律忽峥嶸。',48,'全唐诗/poet.song.89000.json','["風景正髙潔，歲律忽峥嶸。", "岸竹森如束，山田漫已耕。", "溪寒幽石出，岫遠暮雲横。", "試問螭頭吏，誰令向此行。"]'),
('c4e46f99-b6c1-4d33-ab4e-97fabd912a6b','江南六詠  其一','李綱','宋','宋诗','song-poetry','','[]','江南山，秀色晴光杳靄間。',28,'全唐诗/poet.song.89000.json','["江南山，秀色晴光杳靄間。", "一带平凝愁翠黛，數峰孤絕聳煙鬟。"]'),
('d8cdc7a6-4041-4de0-929e-ac225e454f1d','江南六詠  其二','李綱','宋','宋诗','song-poetry','','[]','江南雲，片片飛來湘水濱。',28,'全唐诗/poet.song.89000.json','["江南雲，片片飛來湘水濱。", "愁絕蒼梧鼓瑟女，悵望陽臺行雨神。"]'),
('bbd7a1a3-1b0f-4426-ade9-62c842822ca1','江南六詠  其三','李綱','宋','宋诗','song-poetry','','[]','江南月，依然照我傷離别。',28,'全唐诗/poet.song.89000.json','["江南月，依然照我傷離别。", "故人千里共清光，玉臂雲鬟香未歇。"]'),
('1a8493a1-c5a5-4b46-82f0-683f080d04fb','江南六詠  其四','李綱','宋','宋诗','song-poetry','','[]','江南竹，霜霰歲寒依舊綠。',28,'全唐诗/poet.song.89000.json','["江南竹，霜霰歲寒依舊綠。", "誰向溪邊飬籜龍，滴露搖風一林玉。"]'),
('370b08db-8cbb-433a-9290-6726419e0750','江南六詠  其五','李綱','宋','宋诗','song-poetry','','[]','江南梅，昨夜溪頭玉雪開。',28,'全唐诗/poet.song.89000.json','["江南梅，昨夜溪頭玉雪開。", "贈遠欲傳千里恨，和煙爲折一枝來。"]'),
('88658727-9ceb-42f7-a288-88593a6d9248','江南六詠  其六','李綱','宋','宋诗','song-poetry','','[]','江南客，鬢髮蒼浪不堪摘。',28,'全唐诗/poet.song.89000.json','["江南客，鬢髮蒼浪不堪摘。", "明時遷逐念前非，一夜愁吟霜月白。"]'),
('78651ea1-77c1-4f55-84f9-24d1ec6c2b7b','宿信州景德寺禪月堂','李綱','宋','宋诗','song-poetry','','[]','野寺虛堂倚翠微，雲山極目望中疑。',64,'全唐诗/poet.song.89000.json','["野寺虛堂倚翠微，雲山極目望中疑。", "溪寒連艦欄干直，日暮髙樓鼓角悲。", "倒景星河光破碎，亂螢燈火影參差。", "貫休髣髴英靈在，應笑登臨強賦詩。"]'),
('8ccd7a8c-bf8f-4bc5-a354-6d9cdc5cf55e','巖石村店有石泉梅橘幽雅可愛','李綱','宋','宋诗','song-poetry','','[]','巖下鳴泉淅瀝飛，誰知山店亦幽奇。',64,'全唐诗/poet.song.89000.json','["巖下鳴泉淅瀝飛，誰知山店亦幽奇。", "已過野橘分金日，未見寒梅噴雪時。", "旋洗雲秔炊白玉，自挑霜菔縷青絲。", "慇懃賦詠留巖石，他日重來覓舊詩。"]'),
('6a73474e-718d-49d9-aa60-696609e1aea5','上饒道中雜詠三首  其一','李綱','宋','宋诗','song-poetry','','[]','半世區區何所求，南來豈爲稻粱謀。',64,'全唐诗/poet.song.89000.json','["半世區區何所求，南來豈爲稻粱謀。", "烟嵐遠近濃還淡，石瀨縈迴咽更流。", "雲外鈎輈聽處好，溪頭略彴渡時幽。", "何須更論他年事，且把風光慰旅愁。"]'),
('aebb817f-7abd-4ad4-a753-d57bc4d927bd','上饒道中雜詠三首  其二','李綱','宋','宋诗','song-poetry','','[]','鬢毛蕭颯寸餘冠，蒙犯風霜却歲寒。',64,'全唐诗/poet.song.89000.json','["鬢毛蕭颯寸餘冠，蒙犯風霜却歲寒。", "但使孤忠能感激，豈辭遠謫備艱難。", "蒼蒼雲木留深景，渺渺深溪瀉暮湍。", "獨坐苦吟山寺冷，照人孤月正團欒。"]'),
('53eaf0de-da61-40fb-95bb-60efda27c3bb','上饒道中雜詠三首  其三','李綱','宋','宋诗','song-poetry','','[]','漠漠烟村一笛風，溪山都在夕陽中。',64,'全唐诗/poet.song.89000.json','["漠漠烟村一笛風，溪山都在夕陽中。", "遥看天色暮雲碧，漸見山頭野燒紅。", "閩嶺風煙知已近，浙江書問恨難通。", "暝投山寺憑虛閣，隱耳猶聽響暮鐘。"]'),
('49edadf7-f556-411d-a9d5-31a76e61e7f9','過鵝湖留贈昌長老二首  其一','李綱','宋','宋诗','song-poetry','','[]','雲山深處到鵝湖，萬木森森一徑紆。',64,'全唐诗/poet.song.89000.json','["雲山深處到鵝湖，萬木森森一徑紆。", "日落風髙鐘倍響，煙寒林暝鳥相呼。", "宗風振起人能繼，祖道流傳德不孤。", "須信山林真隱地，紛紛朝市更何如。"]'),
('a9c223f0-8568-47f4-8e2b-62b8bcfe4e8e','過鵝湖留贈昌長老二首  其二','李綱','宋','宋诗','song-poetry','','[]','謫宦去爲劍浦吏，稅駕且作鵝湖遊。',64,'全唐诗/poet.song.89000.json','["謫宦去爲劍浦吏，稅駕且作鵝湖遊。", "沈沈梵宇殿閣古，寂寂勝地林泉幽。", "祖師道場誰繼嗣，妙峰德雲真比丘。", "夜寒燈下接軟語，却恨行客難淹留。"]'),
('6445bb35-6cc2-475f-ac39-9786f504eb8c','昌老詢予來歷以詩答之','李綱','宋','宋诗','song-poetry','','[]','休問西來意，吾行日向南。',48,'全唐诗/poet.song.89000.json','["休問西來意，吾行日向南。", "悽悽達磨懴，歷歷善財參。", "舊事已不憶，新交寧易談。", "維摩本無語，非是學三緘。"]'),
('92b0a058-69ea-43a7-aa60-1f34982cb625','題石井慈濟泉二首  其一','李綱','宋','宋诗','song-poetry','','[]','誰將石洞當泉池，餘溜濺濺落水陂。',64,'全唐诗/poet.song.89000.json','["誰將石洞當泉池，餘溜濺濺落水陂。", "山骨鑿開蒼瑪瑙，雲腴凝貯碧琉璃。", "龜浮水面寒光動，竹舞巖端翠影垂。", "泉石幽奇天下少，祕藏休使北人知。"]'),
('cde8d693-d306-4f60-be32-cf49a005fdad','題石井慈濟泉二首  其二','李綱','宋','宋诗','song-poetry','','[]','巖石嵌空湛碧泉，酌甘鑑静意蕭然。',64,'全唐诗/poet.song.89000.json','["巖石嵌空湛碧泉，酌甘鑑静意蕭然。", "幽深端有神龍穴，虛迥疑藏古洞天。", "雲影漾波光璀璀，石渠飛溜響涓涓。", "會須掬取巖中水，洒作膏霖徧八埏。"]'),
('85b4c5a0-8ff9-4727-a554-c1716b46ab99','鉛山道中','李綱','宋','宋诗','song-poetry','','[]','行李踰江嶠，風煙接武夷。',48,'全唐诗/poet.song.89000.json','["行李踰江嶠，風煙接武夷。", "地靈嘉木秀，天闊暝雲垂。", "泉石日相樂，雪霜寒自遲。", "寄聲山下士，掃壁待題詩。"]'),
('a8fb93df-49c6-4c32-a0ff-5cfe88388dcd','小溪','李綱','宋','宋诗','song-poetry','','[]','脉脉寒溪徹底明，臨流聊復濯吾纓。',64,'全唐诗/poet.song.89000.json','["脉脉寒溪徹底明，臨流聊復濯吾纓。", "風微静愛琉璃色，竹密遥聞環珮聲。", "漾月下搖金瀲灧，涵虛不動鏡澄泓。", "自憐逐客難淹泊，不爲溪山景太清。"]'),
('83caea11-cb50-4fa5-b5c6-c48656f2dbb0','過紫溪值雪','李綱','宋','宋诗','song-poetry','','[]','明時報國敢懷安，遠謫方知行路難。',64,'全唐诗/poet.song.89000.json','["明時報國敢懷安，遠謫方知行路難。", "雲隔江鄉來鴈寂，雪飛閩嶺敝貂寒。", "韓詩解道藍關恨，賈賦聊憑鵩鳥寛。", "誰念紫皇香案吏，飄零已覺鬢毛乾。"]'),
('b8b7bc4a-24ec-4772-bd0a-e760ebb67f65','雪中過分水嶺六首  其一','李綱','宋','宋诗','song-poetry','','[]','寒雲漠漠雪霏霏，正是行人度嶺時。',64,'全唐诗/poet.song.89000.json','["寒雲漠漠雪霏霏，正是行人度嶺時。", "密洒峰巒開玉府，亂粧林木發瓊枝。", "步髙漸入烟霄路，望遠都迷澗壑姿。", "回首江鄉何處是，斷蓬飄梗不勝悲。"]'),
('e1348dc7-8939-4f7a-aba1-39a5eee869fc','雪中過分水嶺六首  其二','李綱','宋','宋诗','song-poetry','','[]','閩山髙處却無風，密雪飛雲墮曉空。',64,'全唐诗/poet.song.89000.json','["閩山髙處却無風，密雪飛雲墮曉空。", "去路似從銀色界，此身疑到廣寒宫。", "落梅飄絮來瓊樹，涌浪崩雲疊玉峰。", "景色幽奇無似雪，平生觀雪此爲雄。"]'),
('57a74344-cf73-4f8a-a240-3a7b5bc056c0','雪中過分水嶺六首  其三','李綱','宋','宋诗','song-poetry','','[]','藹藹層陰送雪來，亂山深處白皚皚。',64,'全唐诗/poet.song.89000.json','["藹藹層陰送雪來，亂山深處白皚皚。", "積巖錯認藍田玉，著樹全疑庾嶺梅。", "光射九霄來夜月，冷凝千嶂蟄春雷。", "武夷路近須晴霽，爲卷風雲一餉開。"]'),
('a2787005-f7d8-41b8-bf0e-2cd6b0c94816','雪中過分水嶺六首  其四','李綱','宋','宋诗','song-poetry','','[]','一夜同雲凝不開，曉寒整轡馬虺尵。',64,'全唐诗/poet.song.89000.json','["一夜同雲凝不開，曉寒整轡馬虺尵。", "千巖萬壑縈紆處，密雪迴風散漫來。", "愁裏溪聲琴的歷，望中山色玉崔嵬。", "溪山得雪尤奇絕，模寫無工恨不才。"]'),
('d66a2d40-70ab-4c55-beee-2178b5512ed4','雪中過分水嶺六首  其五','李綱','宋','宋诗','song-poetry','','[]','瑶妃遊戲水晶房，故剪冰花試曉粧。',64,'全唐诗/poet.song.89000.json','["瑶妃遊戲水晶房，故剪冰花試曉粧。", "坐見初平巖畔石，化爲元放隴頭羊。", "培堆積玉寒光瑩，頃刻開梅冷艶香。", "好是碧天雲散後，野蟾來助一輪光。"]'),
('460bef60-85ae-4d98-a8d4-d92a5a55cc8c','雪中過分水嶺六首  其六','李綱','宋','宋诗','song-poetry','','[]','玉龍耕種素芝田，誤入飛瓊小洞天。',64,'全唐诗/poet.song.89000.json','["玉龍耕種素芝田，誤入飛瓊小洞天。", "璧月珠星争璀璨，瑶環瑜珥鬬嬋娟。", "水晶宫闕雲腴滑，白玉樓臺霧彩鮮。", "骨冷魂清難久駐，恍然崑閬夢遊仙。"]'),
('7c1bf46b-e139-40d3-9cc3-fb971ca7a01b','次大安驛雪霽','李綱','宋','宋诗','song-poetry','','[]','雪霽烟村風滿林，暮天垂影碧沉沉。',64,'全唐诗/poet.song.89000.json','["雪霽烟村風滿林，暮天垂影碧沉沉。", "一輪明月光相射，千里白雲寒更深。", "寂寞樽盈陶令酒，飄零淚滿仲宣襟。", "燈殘夜永不成寐，莊舄悽然自越吟。"]'),
('70b03be6-4a2a-4c3e-9ee1-2d6a0324f7b5','山家','李綱','宋','宋诗','song-poetry','','[]','青山掩映野人家，翠竹蒼松一徑斜。',64,'全唐诗/poet.song.89000.json','["青山掩映野人家，翠竹蒼松一徑斜。", "夜對月鈎沉淺浦，曉看鳥篆印平沙。", "溪頭馴畜多宜鶩，園裏靈苗可種茶。", "占盡溪山幽勝處，自將風物向人誇。"]'),
('851a1296-7bcf-4421-8f2f-e9bc1f2dbf04','將次武夷','李綱','宋','宋诗','song-poetry','','[]','行行路近武夷山，秀氣蜿蜒百里間。',64,'全唐诗/poet.song.89000.json','["行行路近武夷山，秀氣蜿蜒百里間。", "蒼石插天雲縹緲，碧溪通壑水彎環。", "神仙恍惚誰能識，洞府深沉自不關。", "我向湖中如得路，便應脫屣謝塵寰。"]'),
('769b18a8-4415-4b98-877f-79182599518c','崇安宰見示武夷山圖記','李綱','宋','宋诗','song-poetry','','[]','征軒欲作武夷遊，先借圖經次第求。',64,'全唐诗/poet.song.89000.json','["征軒欲作武夷遊，先借圖經次第求。", "須信神仙真窟宅，故令峰岫巧雕鎪。", "四時花木千巖秀，一水波瀾九曲流。", "明日泛舟山下去，按圖細細問蹤由。"]'),
('e2fdc755-a3fd-4c51-abe5-5d88d0412965','自入閩境值雪默禱武夷君遊山日雪霽有感','李綱','宋','宋诗','song-poetry','','[]','鄙陋安能到古人，寸心潛格武夷君。',64,'全唐诗/poet.song.89000.json','["鄙陋安能到古人，寸心潛格武夷君。", "誓辭叱散蠻溪霧，詩句驅開衡嶽雲。", "忠讜自應慚吏部，精誠何敢並將軍。", "氛霾卷盡留殘雪，粧點峰巒意更勤。"]'),
('1127a91d-d65a-4b5a-afb2-c6c40b56483c','趨真亭','李綱','宋','宋诗','song-poetry','','[]','煙霞深處一亭閒，石磴縈紆紫翠間。',32,'全唐诗/poet.song.89000.json','["煙霞深處一亭閒，石磴縈紆紫翠間。", "但覺峰巒勞顧揖，不知身到武夷山。"]'),
('b892e3e3-f34a-4232-8960-596135d5efad','遊仙溪','李綱','宋','宋诗','song-poetry','','[]','一溪九曲貫羣峰，演漾輕舠淺碧中。',32,'全唐诗/poet.song.89000.json','["一溪九曲貫羣峰，演漾輕舠淺碧中。", "杳如誤入武陵去，落花流水山重重。"]'),
('ad880633-294b-4d21-895b-6f49e681a807','武夷山','李綱','宋','宋诗','song-poetry','','[]','百里雲山碧玉林，雕鎪融結見天心。',64,'全唐诗/poet.song.89000.json','["百里雲山碧玉林，雕鎪融結見天心。", "幔亭會散笙簫遠，天柱風髙煙霧深。", "畫鶴獨留青嶂表，林花常發紫巖陰。", "夢魂清切先曾到，故使飄零特特臨。"]'),
('4060cec1-09e6-4e78-84ab-e4e720cec76e','幔亭峰','李綱','宋','宋诗','song-poetry','','[]','燕罷虹橋絕世氛，曾孫誰見武夷君。',64,'全唐诗/poet.song.89000.json','["燕罷虹橋絕世氛，曾孫誰見武夷君。", "更無裀幕空中舉，時有笙竽静處聞。", "猿鳥夜啼千嶂月，松篁寒鎖一溪雲。", "洞天杳杳知何處，翠石蒼崖日欲曛。"]'),
('ea344f24-4448-49a4-a73f-3f51f048b084','天柱峰','李綱','宋','宋诗','song-poetry','','[]','巉巉千丈插烟空，始見天南一柱峰。',64,'全唐诗/poet.song.89000.json','["巉巉千丈插烟空，始見天南一柱峰。", "絕頂霧開擎日月，半巖雲暝噫雷風。", "俯臨萬壑林芿秀，髙壓羣山氣象雄。", "誰道共工曾觸折，斷鼇端是女媧功。"]'),
('71d23376-4d47-465a-937e-1ffa2c7777cd','洞天穴','李綱','宋','宋诗','song-poetry','','[]','沈沈幽穴閟雲煙，玉宇瓊樓鎖洞天。',64,'全唐诗/poet.song.89000.json','["沈沈幽穴閟雲煙，玉宇瓊樓鎖洞天。", "自向壺中飛日月，更於物外起山川。", "劉公隱後今誰繼，張湛仙來不記年。", "紫府若容幽客到，誅茅欲卜隱屏前。"]'),
('ede54b4d-86c7-413c-97b9-36453c12cca6','三姑石','李綱','宋','宋诗','song-poetry','','[]','風舞芳林鬢脚垂，朝雲行雨濕仙衣。',32,'全唐诗/poet.song.89000.json','["風舞芳林鬢脚垂，朝雲行雨濕仙衣。", "不知當日緣何事，化石山頭更不歸。"]'),
('12ae08ff-9c16-46ef-9f67-e1ac5f6f8ff1','換骨巖','李綱','宋','宋诗','song-poetry','','[]','玄化升真十六天，靈仙蟬脫翠巖前。',32,'全唐诗/poet.song.89000.json','["玄化升真十六天，靈仙蟬脫翠巖前。", "金堅玉潤留餘骨，密鎖烟霞幾百年。"]'),
('56ed9d1c-1bf3-4cec-bd06-3d98952f2219','龍潭','李綱','宋','宋诗','song-poetry','','[]','百丈清潭合兩溪，澄波瑩滑碧琉璃。',32,'全唐诗/poet.song.89000.json','["百丈清潭合兩溪，澄波瑩滑碧琉璃。", "神龍端向潭中睡，何事能容網罟垂。"]'),
('6693347f-3f63-48e9-8ec1-3223f5cb060b','獅子峰','李綱','宋','宋诗','song-poetry','','[]','奇石騰拏竹樹蒼，奮髯矯首據崇岡。',32,'全唐诗/poet.song.89000.json','["奇石騰拏竹樹蒼，奮髯矯首據崇岡。", "山深怪底無豺虎，端畏溪頭百獸王。"]'),
('3a10045c-9699-41b2-8fd9-10dc9e4d144e','觀音巖','李綱','宋','宋诗','song-poetry','','[]','銖衣珠珞寶花冠，宴坐翛然山水間。',32,'全唐诗/poet.song.89000.json','["銖衣珠珞寶花冠，宴坐翛然山水間。", "應爲武夷泉石好，不殊海岸補陀山。"]'),
('df9d9567-9f66-4b9c-b020-c083aee1a547','兜擔石','李綱','宋','宋诗','song-poetry','','[]','仙人戲睹翠蛾眉，空有花餘照夕暉。',32,'全唐诗/poet.song.89000.json','["仙人戲睹翠蛾眉，空有花餘照夕暉。", "雲月娟娟風嫋嫋，尚疑玉質在簾幃。"]'),
('d0ea6aa5-9977-49e3-b8f3-1eeefe098410','三女石','李綱','宋','宋诗','song-poetry','','[]','粲粲三英傍碧溪，玉肌雲鬢曉參差。',32,'全唐诗/poet.song.89000.json','["粲粲三英傍碧溪，玉肌雲鬢曉參差。", "想因巫峽行雲日，記得湘江解珮時。"]'),
('7fcd8055-bfae-4496-8340-415a4de0d131','學堂巖','李綱','宋','宋诗','song-poetry','','[]','仙官讀徹蕊珠篇，几案巖中自寂然。',32,'全唐诗/poet.song.89000.json','["仙官讀徹蕊珠篇，几案巖中自寂然。", "崑閬圖書藏策府，誰言孤陋解成仙。"]'),
('0bf4b5b0-f4a8-4623-bcf6-62e01eedcc2b','船場巖','李綱','宋','宋诗','song-poetry','','[]','仙艇何年插翠微，雲篷烟櫂尚依依。',32,'全唐诗/poet.song.89000.json','["仙艇何年插翠微，雲篷烟櫂尚依依。", "凌虛欲鼓天邊柁，喚取雙龍背負飛。"]'),
('2c111098-c2bc-4ac0-9013-6429a32b32ee','雞窠巖','李綱','宋','宋诗','song-poetry','','[]','磔磔天雞啼曉烟，仙家風景鎮芳妍。',32,'全唐诗/poet.song.89000.json','["磔磔天雞啼曉烟，仙家風景鎮芳妍。", "自從彩翼飛仙後，只有遺棲寄嶺巔。"]'),
('5ed7a901-2c74-4025-8015-1df234839a3d','大小藏巖','李綱','宋','宋诗','song-poetry','','[]','玉棺插徧兩巖傍，石罅開如小洞房。',32,'全唐诗/poet.song.89000.json','["玉棺插徧兩巖傍，石罅開如小洞房。", "鍊就陽魂歸紫府，空餘靈骨此中藏。"]'),
('93fddd09-dd45-45b6-a16e-507dfbd3e687','仙跡石','李綱','宋','宋诗','song-poetry','','[]','當年天姥戲溪邊，二石遺蹤膝宛然。',32,'全唐诗/poet.song.89000.json','["當年天姥戲溪邊，二石遺蹤膝宛然。", "却笑茂陵緱氏跡，只憑方士口中傳。"]'),
('abec7308-d7be-403b-ba8d-ea915020ff51','大小二廪石','李綱','宋','宋诗','song-poetry','','[]','仙家何事亦贏糧，廪石團團峙道傍。',32,'全唐诗/poet.song.89000.json','["仙家何事亦贏糧，廪石團團峙道傍。", "應駕斑龍耕紫石，深儲芝玉廪中藏。"]'),
('bffcbc22-529c-4bba-849d-02dda17d1b0e','鐘模石','李綱','宋','宋诗','song-poetry','','[]','誰鑄三鐘欒乳形，不須筍簴自能鳴。',32,'全唐诗/poet.song.89000.json','["誰鑄三鐘欒乳形，不須筍簴自能鳴。", "仙君欲奏賓雲曲，只感清霜便發聲。"]'),
('824af061-ceae-4eba-9eba-ae6d5f085263','鼓樓巖','李綱','宋','宋诗','song-poetry','','[]','洞天擊鼓集羣仙，石作髙樓鎖翠烟。',32,'全唐诗/poet.song.89000.json','["洞天擊鼓集羣仙，石作髙樓鎖翠烟。", "萬籟不鳴霜月曉，鼕鼕猶聽鼓聲傳。"]'),
('126c7223-8c21-4ba4-85c9-698d6386e874','丹竈','李綱','宋','宋诗','song-poetry','','[]','金鼎丹成透碧天，尚留丹竈在層巔。',32,'全唐诗/poet.song.89000.json','["金鼎丹成透碧天，尚留丹竈在層巔。", "一丸五色光騰夜，乞取從教作散仙。"]'),
('99ab151e-3145-473a-8fa2-fcb8fb053788','仙掌','李綱','宋','宋诗','song-poetry','','[]','玉指纖纖煙靄中，揮雲映日掌微紅。',32,'全唐诗/poet.song.89000.json','["玉指纖纖煙靄中，揮雲映日掌微紅。", "只疑華岳留蹤後，更向閩山映碧峰。"]'),
('8e46f9fd-3e4b-4e38-bf98-530da5168726','三層峰','李綱','宋','宋诗','song-poetry','','[]','三層靈峰氣象豪，噴雲洩雨不崇朝。',32,'全唐诗/poet.song.89000.json','["三層靈峰氣象豪，噴雲洩雨不崇朝。", "懸崖峭壁無人到，只恐峰頭是碧霄。"]'),
('5bcb5c6f-2141-4c79-817c-64f5180634dc','畫鶴','李綱','宋','宋诗','song-poetry','','[]','誰畫千年老令威，丹青今古照清輝。',32,'全唐诗/poet.song.89000.json','["誰畫千年老令威，丹青今古照清輝。", "玄裳朱頂蒼崖畔，豈憶冲天萬里飛。"]'),
('78bbf98d-2bd4-47b8-a038-da6c8be62a78','大隱屏','李綱','宋','宋诗','song-poetry','','[]','髙峰崛起翠微屏，何事呼爲大隱名。',32,'全唐诗/poet.song.89000.json','["髙峰崛起翠微屏，何事呼爲大隱名。", "自是市朝人不到，非關洞户鎖峥嶸。"]'),
('1b911888-0343-44f9-90c9-add9ca231f57','禪庵巖','李綱','宋','宋诗','song-poetry','','[]','虎嘯猿啼月滿天，山僧宴坐正安禪。',32,'全唐诗/poet.song.89000.json','["虎嘯猿啼月滿天，山僧宴坐正安禪。", "不知隻履歸何處，尚有庵巖名字傳。"]'),
('bad14ed3-72e9-4ff9-a625-2be540fb5970','仙機巖','李綱','宋','宋诗','song-poetry','','[]','雲去仙機杼軸空，報章何日已成功。',32,'全唐诗/poet.song.89000.json','["雲去仙機杼軸空，報章何日已成功。", "天孫織就烟霞錦，吹落溪山夕照中。"]'),
('ab74bc52-0965-4206-a93f-a3dd008bc380','魏王峰','李綱','宋','宋诗','song-poetry','','[]','危峰孤峭與天通，猶有當時羽化蹤。',32,'全唐诗/poet.song.89000.json','["危峰孤峭與天通，猶有當時羽化蹤。", "仙馭自隨鸞鶴遠，玉樓金鎖白雲封。"]'),
('dd6c02e7-0a33-4696-8c05-9c68c9d70b37','虎嘯巖','李綱','宋','宋诗','song-poetry','','[]','昔年雕虎嘯幽巖，千里清風皺碧潭。',32,'全唐诗/poet.song.89000.json','["昔年雕虎嘯幽巖，千里清風皺碧潭。", "虎去巖空風自遠，一林花雨落毿毿。"]'),
('70f08d7e-6686-4622-a112-870efe6cdbd3','釣臺石','李綱','宋','宋诗','song-poetry','','[]','釣石峨峨枕碧溪，仙人於此亦垂絲。',32,'全唐诗/poet.song.89000.json','["釣石峨峨枕碧溪，仙人於此亦垂絲。", "想當月白風清夜，正是寒魚食餌時。"]'),
('4738aa8f-5bb8-4960-ae0d-339da0445a25','試劍石','李綱','宋','宋诗','song-poetry','','[]','鍊氣爲金鑄劍成，且將頑石試青萍。',32,'全唐诗/poet.song.89000.json','["鍊氣爲金鑄劍成，且將頑石試青萍。", "光鋩鬱鬱冲牛斗，斬盡妖魔若發鉶。"]'),
('dd3bbf41-766c-4d65-8e20-b1848a0c1544','折筍巖','李綱','宋','宋诗','song-poetry','','[]','玉府鏘鏘玉筍林，誰將移種翠巖陰。',32,'全唐诗/poet.song.89000.json','["玉府鏘鏘玉筍林，誰將移種翠巖陰。", "斕斑猶带當時籜，照水籠烟幾百尋。"]'),
('f5d1df62-f7ba-4658-a9ba-097e3c20e72c','仙接石','李綱','宋','宋诗','song-poetry','','[]','天風吹折碧琅玕，神化茫茫接豈難。',32,'全唐诗/poet.song.89000.json','["天風吹折碧琅玕，神化茫茫接豈難。", "鳯髓鸞膠天上有，世人休作等閑看。"]'),
('b5d47b07-72fe-45c8-bc75-c65d55b46424','柴嶺','李綱','宋','宋诗','song-poetry','','[]','林花不逐歲寒凋，半嶺煙光媚遠霄。',32,'全唐诗/poet.song.89000.json','["林花不逐歲寒凋，半嶺煙光媚遠霄。", "須信仙家風景好，四時峰岫紫岧嶤。"]'),
('9ee4d197-2626-42a5-a7ab-d04b644095f4','車錢峰','李綱','宋','宋诗','song-poetry','','[]','塵緣洗盡便神仙，泉石幽奇即洞天。',32,'全唐诗/poet.song.89000.json','["塵緣洗盡便神仙，泉石幽奇即洞天。", "我欲雲崖結茅屋，侍從天姥借車錢。"]'),
('2876212c-0d06-4b24-b35c-077a5880ad55','毛竹洞','李綱','宋','宋诗','song-poetry','','[]','洞生毛竹綠猗猗，枝幹扶疏滿洞垂。',32,'全唐诗/poet.song.89000.json','["洞生毛竹綠猗猗，枝幹扶疏滿洞垂。", "傳是羣仙遊息地，蔽藏不許世人知。"]'),
('23ae4f0d-cded-49c4-b0ce-873d7d50425e','睎真館','李綱','宋','宋诗','song-poetry','','[]','小溪詰屈巧縈迴，行到睎真景更奇。',32,'全唐诗/poet.song.89000.json','["小溪詰屈巧縈迴，行到睎真景更奇。", "路轉山回疑不見，此中凝望却參差。"]'),
('07719400-141c-444b-bcd6-fa87f98e1af5','仙橘','李綱','宋','宋诗','song-poetry','','[]','巖畔陰森橘樹垂，青青亦有歳寒姿。',32,'全唐诗/poet.song.89000.json','["巖畔陰森橘樹垂，青青亦有歳寒姿。", "我來恨在秋風後，不見霜包結實時。"]'),
('8e1eb7aa-3c59-4183-a988-533ec67676ad','仙竹','李綱','宋','宋诗','song-poetry','','[]','陰崖翠竹自檀欒，痩節疏枝特地寒。',32,'全唐诗/poet.song.89000.json','["陰崖翠竹自檀欒，痩節疏枝特地寒。", "雖未化龍歸洞府，正宜和月掃天壇。"]'),
('58ea554a-f3cf-4c55-ab64-4cfe0378ff04','泛舟至睎真館遇雪  其一','李綱','宋','宋诗','song-poetry','','[]','雲散天開一餉中，依前飛雪落層空。',64,'全唐诗/poet.song.89000.json','["雲散天開一餉中，依前飛雪落層空。", "瓊花巧綴巖端樹，玉屑飄隨洞裏風。", "溪淺且遊仙掌石，雲深不見幔亭峰。", "斯遊清絕平生少，圖畫方知未是工。"]'),
('e8e9a5dc-850d-4a4a-be35-15c1435216f1','泛舟至睎真館遇雪  其二','李綱','宋','宋诗','song-poetry','','[]','行到清溪六曲頭，森然峰岫照人幽。',64,'全唐诗/poet.song.89000.json','["行到清溪六曲頭，森然峰岫照人幽。", "雪花拂水輕輕舞，石瀨依巖淺淺流。", "不盡清光常在目，未窮幽興且回舟。", "追尋欲徧神仙窟，須向他時卜再遊。"]'),
('f7e983cb-64f9-4ba6-b575-d96412595f3e','訪李道士  其一','李綱','宋','宋诗','song-poetry','','[]','青山中有一道士，獨臥烟霞晝掩扉。',32,'全唐诗/poet.song.89000.json','["青山中有一道士，獨臥烟霞晝掩扉。", "踏雪叩關知意重，擁爐相與話真機。"]'),
('326cd744-4a7c-44d6-81ad-b9262d9afb8e','訪李道士  其二','李綱','宋','宋诗','song-poetry','','[]','誅茅獨占溪一曲，時有白雲來伴宿。',32,'全唐诗/poet.song.89000.json','["誅茅獨占溪一曲，時有白雲來伴宿。", "自言身在此山中，暮暮朝朝看不足。"]'),
('77172c63-0673-49a4-bd38-4a2f9d1c9a34','紀舊夢','李綱','宋','宋诗','song-poetry','','[]','清夢先曾到武夷，玉峰積雪倍幽奇。',32,'全唐诗/poet.song.89000.json','["清夢先曾到武夷，玉峰積雪倍幽奇。", "小舟遊罷尋歸路，恰似翛然夢覺時。"]'),
('169ac185-3961-4730-b48b-d07948f22832','宿棲真館夜雪大作詰旦遂行','李綱','宋','宋诗','song-poetry','','[]','一夜武夷三尺雪，巖壑無聲聞竹折。',64,'全唐诗/poet.song.89000.json','["一夜武夷三尺雪，巖壑無聲聞竹折。", "雲峰烟岫望都迷，玉樹瑶林寒更發。", "山中道士毛骨奇，勸我留宿山前齋。", "輕裝冒雪非得已，仙賞更待他年來。"]'),
('5df15e8f-2bdc-4989-af2a-715ca963b08c','題棲真館三十六韻','李綱','宋','宋诗','song-poetry','','[]','武夷古洞天，奇峰三十六。',288,'全唐诗/poet.song.89000.json','["武夷古洞天，奇峰三十六。", "一溪貫羣山，清淺縈九曲。", "溪邊列巖岫，倒影浸寒綠。", "翩如鸞鳯翔，矯若虬龍蹙。", "樓觀聳岧嶤，屏幃互重複。", "蛻仙骨遺金，遊女肌削玉。", "鷄棲層巖巔，船插斷崖腹。", "學館存几案，仙機餘杼軸。", "藍光瑩澄潭，虹影掛飛瀑。", "翠竹蔭天池，蒼苔封石屋。", "繪禽頂長丹，遺跡指如掬。", "峨峨天柱峰，幔亭連翠麓。", "傳聞武夷君，嘗此會仙俗。", "飛橋幾千丈，絕頂亘山足。", "障以翠雲屏，藉以紫霞褥。", "瑶樽傾沆瀣，玉豆脯麟鹿。", "仙妃奏賓雲，金鼓間絲竹。", "酒酣歌夕暉，歎息光景促。", "曾孫誰復在，往事空遺躅。", "至今風月夜，笙簫響虛谷。", "地靈饒泉石，山潤秀草木。", "坐使七閩人，蔭此仙靈福。", "嗟予真散材，性愛山水酷。", "仙經與地志，名字久已熟。"]'),
('d57de673-22fd-4a10-ae8c-4409bdc69b3b','贈舅氏吳子和','李綱','宋','宋诗','song-poetry','','[]','契闊從來歎歳陰，幸因謫宦款清襟。',64,'全唐诗/poet.song.89000.json','["契闊從來歎歳陰，幸因謫宦款清襟。", "犯顔逆耳事已往，問舍求田意轉深。", "豈有聲名驚海宇，且忻山水共登臨。", "渭陽情重知何贈，玉佩瓊琚稱我心。"]'),
('9ac29bcd-1a30-4535-af9f-37ab6ee90d85','自建陽泛舟至建安','李綱','宋','宋诗','song-poetry','','[]','一葉輕舠漾碧流，却憐舟子解操舟。',64,'全唐诗/poet.song.89000.json','["一葉輕舠漾碧流，却憐舟子解操舟。", "急灘亂石疑難渡，短檝輕橈反自由。", "去國飄零同泛梗，凌波超忽逐飛鷗。", "建溪百里纔終日，過盡千巖萬壑幽。"]'),
('23fef0c1-006d-49cb-a734-61e0083cacdb','建溪再得雪鄉人以爲宜茶','李綱','宋','宋诗','song-poetry','','[]','閩嶺今冬雪再華，清寒芳潤最宜茶。',64,'全唐诗/poet.song.89000.json','["閩嶺今冬雪再華，清寒芳潤最宜茶。", "泛甌欲鬭千金價，著樹先開六出花。", "圭璧自須呈瑞質，旗槍未肯放靈芽。", "傳聞龍餅先春貢，已到鈞天玉帝家。"]'),
('c0f2e4f6-f658-433d-86e5-57b9644dbc60','天寧老齊珏錄慶餘師開堂疏見示','李綱','宋','宋诗','song-poetry','','[]','一别閩山三十年，重來相見兩依然。',32,'全唐诗/poet.song.89000.json','["一别閩山三十年，重來相見兩依然。", "煩師錄示當時語，猶喜曹溪一派傳。"]'),
('a0675859-42c7-4612-9271-6a491d1845a0','梅花二首  其一','李綱','宋','宋诗','song-poetry','','[]','寒梅昨夜洩春光，標格依然壓衆芳。',64,'全唐诗/poet.song.89000.json','["寒梅昨夜洩春光，標格依然壓衆芳。", "褭褭露枝團玉白，輕輕烟蕊簇金黄。", "瑶妃謫墮溪村寂，雪片飄殘月徑香。", "却笑漢宫争寵女，競將嬌額學新粧。"]'),
('3fcba0da-fbd7-4e30-b6cb-22b84be6b8c6','梅花二首  其二','李綱','宋','宋诗','song-poetry','','[]','數枝玉雪小溪濱，先得陽和一點春。',64,'全唐诗/poet.song.89000.json','["數枝玉雪小溪濱，先得陽和一點春。", "冷艷幽姿難與並，暗香疏影孰爲鄰。", "廣平不害心如鐵，和靖須知句有神。", "亦對寒芳動詩興，却嫌標格太凊真。"]'),
('333cf65c-2d33-4d5e-b74a-436ced1e0c4c','劍浦道中二首  其一','李綱','宋','宋诗','song-poetry','','[]','宿霧霏霏隱翠嵐，傍溪幽石自巉巖。',64,'全唐诗/poet.song.89000.json','["宿霧霏霏隱翠嵐，傍溪幽石自巉巖。", "樵歌遞響來危徑，漁網連舟集小潭。", "野渡無人閒寂寂，林花著雨落毿毿。", "誰知逐客凄凉意，歳宴南遷劍浦南。"]'),
('dfd4baa5-2c93-4685-8f60-ee2ed8d8bf73','劍浦道中二首  其二','李綱','宋','宋诗','song-poetry','','[]','此去平津路匪遥，嶺雲溪雨自蕭蕭。',64,'全唐诗/poet.song.89000.json','["此去平津路匪遥，嶺雲溪雨自蕭蕭。", "山深瀉澗泉長響，地暖凌寒草不凋。", "放逐却教窮水石，登臨因得狎漁樵。", "誰憐澤畔人憔悴，更把騷辭賦大招。"]'),
('f1c37fb4-2b4a-44d8-b667-f31b4bb6a9a6','自建安陸行至劍浦','李綱','宋','宋诗','song-poetry','','[]','聞道延平黯淡灘，舟行至此慘愁顔。',64,'全唐诗/poet.song.89000.json','["聞道延平黯淡灘，舟行至此慘愁顔。", "千金素佩垂堂戒，九折寧辭去路艱。", "涉險雖知憑信義，藏幽須信足神姦。", "勞生自取那惆恨，只羨飛雲自在閒。"]'),
('f65acf44-30ef-41cf-9594-e815fe687499','劍潭','李綱','宋','宋诗','song-poetry','','[]','當時神劍埋豐城，鬱鬱光氣衝斗星。',160,'全唐诗/poet.song.89000.json','["當時神劍埋豐城，鬱鬱光氣衝斗星。", "千年古獄斸幽扃，下得至寶雙青萍。", "雌雄不知誰與名，拭以異土聊發鉶。", "龍文星彩愈晶熒，正晝無影魑魅驚。", "雄飛霄漢隨雷霆，雌躍淵水歸延平。", "没人下瞰風濤生，天矯化作虯龍形。", "茂先博識非無憑，神物終合信有徵。", "沈沈潭影含虛明，寶氣久秘必復呈。", "會當探取搜元精，佩服坐能驅百靈。", "姦諛膏血紛羶腥，與爾相攜遊太清。"]'),
('95694c78-5355-42d4-8663-28695b7b682a','雙溪閣','李綱','宋','宋诗','song-poetry','','[]','凌虛髙閣枕雙溪，四出飛簷鳥翼齊。',64,'全唐诗/poet.song.89000.json','["凌虛髙閣枕雙溪，四出飛簷鳥翼齊。", "山鎖煙光青合匝，水分丁字碧凄迷。", "蟠虬舊化張公劍，翥鳯今留魯國題。", "放逐因能窮勝賞，登臨那惜醉如泥。"]'),
('7b406929-7447-4be5-b519-225bdbfdef3f','沙陽','李綱','宋','宋诗','song-poetry','','[]','沙陽雖僻左，風土冠閩城。',120,'全唐诗/poet.song.89000.json','["沙陽雖僻左，風土冠閩城。", "誰知亂山裏，有此膏壤平。", "邑屋號華麗，谿山倍澄明。", "七峰轉月色，十里無灘聲。", "民俗素康阜，士夫多俊英。", "食饒魚稻美，蔭有松竹清。", "筦庫職易辦，塵勞念尤輕。", "蕭然飄泊迹，忘此羈旅情。", "忽忽歳改律，欣欣木向榮。", "何當脫拘縳，春畝得躬耕。"]'),
('2180d12f-e0e4-4fe7-976a-8a87c29505c9','平津晚望','李綱','宋','宋诗','song-poetry','','[]','春入沙陽花滿林，七峰倒影碧沈沈。',64,'全唐诗/poet.song.89000.json','["春入沙陽花滿林，七峰倒影碧沈沈。", "饑鳶掠水盤旋久，戲鴨浮溪演漾深。", "風景只添流落恨，烟光遥鎖别離心。", "浙西三月無消息，始信家書抵萬金。"]'),
('e191e0c9-e4ee-4ebf-ba28-3a82ba631b4a','余扺沙陽之夕民居延火幾爇官局因念以論水得罪復以火驚殊可笑歎戲成此詩','李綱','宋','宋诗','song-poetry','','[]','囊封論水謫天涯，纔到沙陽火復隨。',64,'全唐诗/poet.song.89000.json','["囊封論水謫天涯，纔到沙陽火復隨。", "本爲玄冥遭放逐，却因回禄更驚疑。", "生辰端是窮申未，學易何曾悟坎離。", "爛額焦頭那足惜，只愁蓬跡久飄移。"]'),
('4eb99050-8d98-42f3-8ceb-459bfcb28a2c','除夜','李綱','宋','宋诗','song-poetry','','[]','年來三百六十日，忽忽過盡唯今宵。',64,'全唐诗/poet.song.89000.json','["年來三百六十日，忽忽過盡唯今宵。", "天涯遠謫罪未解，家問久缺心無聊。", "强傾濁酒慰愁獨，坐對寒燈尤寂寥。", "鐘鳴漏盡不成寐，世事又屬明年朝。"]'),
('2eb61a52-7723-43b9-a127-9c0de38d6322','元日','李綱','宋','宋诗','song-poetry','','[]','去年元日朝明堂，對立玉皇香案傍。',64,'全唐诗/poet.song.89000.json','["去年元日朝明堂，對立玉皇香案傍。", "今年元日謫沙陽，獨在天涯家一方。", "君恩未報已飄泊，親老欲養徒徬徨。", "東風回首帝鄉遠，白雲望斷吳天長。"]'),
('8fc1853b-594b-44b8-bb94-5e5926b2ec4d','立春日','李綱','宋','宋诗','song-poetry','','[]','春風吹到海南邊，氣候渾如二月天。',64,'全唐诗/poet.song.89000.json','["春風吹到海南邊，氣候渾如二月天。", "幡勝戴來聊應節，鼓簫鳴處已祈田。", "花梢柳眼争明媚，溪色山光愈翠鮮。", "生菜春盤誰與送，玉人纖手自嬋娟。"]'),
('944990ff-5ebb-44c3-a1dc-cc493ccfbaa3','春詞二十首  其一','李綱','宋','宋诗','song-poetry','','[]','一樹梨花傍小軒，結根幽寂更芳妍。',32,'全唐诗/poet.song.89000.json','["一樹梨花傍小軒，結根幽寂更芳妍。", "東君有意憐流落，故遣瑶姿堕目前。"]'),
('6a7c2c20-655d-49fb-a717-915a8f92ece3','春詞二十首  其二','李綱','宋','宋诗','song-poetry','','[]','晚來急雨作輕寒，只恐梨花落點殘。',32,'全唐诗/poet.song.89000.json','["晚來急雨作輕寒，只恐梨花落點殘。", "喚起小童窗外看，玉妃何事淚欄干。"]'),
('c0a88af6-648e-4edd-bfda-f04ce6462339','春詞二十首  其三','李綱','宋','宋诗','song-poetry','','[]','花開好鳥曉關關，驚覺幽窗小夢殘。',32,'全唐诗/poet.song.89000.json','["花開好鳥曉關關，驚覺幽窗小夢殘。", "宿酒未醒慵起早，透簾紅日上三竿。"]'),
('c7d4d156-b667-4a1b-9976-6976e88e9e41','春詞二十首  其四','李綱','宋','宋诗','song-poetry','','[]','蕭蕭檻外翠琅玕，瘦節疏枝特地寒。',32,'全唐诗/poet.song.89000.json','["蕭蕭檻外翠琅玕，瘦節疏枝特地寒。", "誰謂幽居太寥閑，此君長此結清歡。"]'),
('8510a8f7-3d43-4829-9bbd-237381c8bb8e','春詞二十首  其五','李綱','宋','宋诗','song-poetry','','[]','春光淡蕩一番新，花氣氛氲惱殺人。',32,'全唐诗/poet.song.89000.json','["春光淡蕩一番新，花氣氛氲惱殺人。", "只恐花飛春又老，須將酩酊對芳辰。"]'),
('3cafb5c5-d09a-4bb0-95c7-578f9f9b693b','春詞二十首  其六','李綱','宋','宋诗','song-poetry','','[]','清晨開卷坐幽窗，深注爐煙一縷香。',32,'全唐诗/poet.song.89000.json','["清晨開卷坐幽窗，深注爐煙一縷香。", "汲水養花顔色好，向人端似炫新粧。"]'),
('1ea96aaa-74f1-4969-9e9f-4846eed4bd19','春詞二十首  其七','李綱','宋','宋诗','song-poetry','','[]','春日遲遲午睡濃，夢魂飛過浙江東。',32,'全唐诗/poet.song.89000.json','["春日遲遲午睡濃，夢魂飛過浙江東。", "無端花底間關舌，喚起搔頭兩鬢蓬。"]'),
('735e19f0-e090-4682-b94a-76e72c7812df','春詞二十首  其八','李綱','宋','宋诗','song-poetry','','[]','寂寂春林杜宇啼，勸人只道不如歸。',32,'全唐诗/poet.song.89000.json','["寂寂春林杜宇啼，勸人只道不如歸。", "我今歸思何須勸，借爾翩翻兩翅飛。"]'),
('30b27a78-14fd-471e-affd-b44f7b4bb49e','春詞二十首  其九','李綱','宋','宋诗','song-poetry','','[]','春色困人渾似酒，花枝照眼恰如人。',32,'全唐诗/poet.song.89000.json','["春色困人渾似酒，花枝照眼恰如人。", "東君若解憐愁客，莫使花飛减却春。"]'),
('c51e5c6b-4e16-4b3c-931f-475c903406c2','春詞二十首  其一○','李綱','宋','宋诗','song-poetry','','[]','漠漠輕煙度短牆，春寒料峭怯羅裳。',32,'全唐诗/poet.song.89000.json','["漠漠輕煙度短牆，春寒料峭怯羅裳。", "惜春只怕多風雨，雲影披離漏日光。"]'),
('acf9c46d-26c8-44b9-8a51-60090835ff17','春詞二十首  其一一','李綱','宋','宋诗','song-poetry','','[]','幽禽百囀舌如簧，院宇深深花木香。',32,'全唐诗/poet.song.89000.json','["幽禽百囀舌如簧，院宇深深花木香。", "飄泊傷春惟泥酒，不知林外已斜陽。"]'),
('94eb0249-d30d-4623-b08c-5e379426fc48','春詞二十首  其一二','李綱','宋','宋诗','song-poetry','','[]','誰使鳴禽自在啼，感春端似惜芳時。',32,'全唐诗/poet.song.89000.json','["誰使鳴禽自在啼，感春端似惜芳時。", "一枝暫寄休饒舌，静處須防挾彈兒。"]'),
('18db1276-6864-492c-a1ba-ef40df38b39c','春詞二十首  其一三','李綱','宋','宋诗','song-poetry','','[]','春來南國藹韶光，百卉嫣然競早芳。',32,'全唐诗/poet.song.89000.json','["春來南國藹韶光，百卉嫣然競早芳。", "語燕啼鶯將婉孌，遊蜂舞蝶已顛狂。"]'),
('9994bfe8-8269-4d38-9dcc-8118bb15317a','春詞二十首  其一四','李綱','宋','宋诗','song-poetry','','[]','青鳥飛來動檻花，翠衿紺趾哢交加。',32,'全唐诗/poet.song.89000.json','["青鳥飛來動檻花，翠衿紺趾哢交加。", "向人自解傳消息，疑是來從阿母家。"]'),
('971a2ccb-9455-47a4-bcb8-229296a227c2','春詞二十首  其一五','李綱','宋','宋诗','song-poetry','','[]','微月籠雲黯淡明，忽聞索索雨來聲。',32,'全唐诗/poet.song.89000.json','["微月籠雲黯淡明，忽聞索索雨來聲。", "可憐窗外梨花老，一夜飄殘雪片輕。"]'),
('3d2484ae-bdf0-4595-a941-9a8b10507485','春詞二十首  其一六','李綱','宋','宋诗','song-poetry','','[]','聒聒鳴鳩喚雨來，蕭蕭寒響滴空階。',32,'全唐诗/poet.song.89000.json','["聒聒鳴鳩喚雨來，蕭蕭寒響滴空階。", "不知逐客傷春恨，多少殘英點翠苔。"]'),
('2cb77cab-3aaf-49e6-9949-bd9acd679f10','春詞二十首  其一七','李綱','宋','宋诗','song-poetry','','[]','飄風驟雨餉時間，墮蕊飛花滿地殷。',32,'全唐诗/poet.song.89000.json','["飄風驟雨餉時間，墮蕊飛花滿地殷。", "自是羣芳將結實，非關風雨故摧殘。"]'),
('7fbef398-5eef-46fe-bd55-4681f25a56b1','春詞二十首  其一八','李綱','宋','宋诗','song-poetry','','[]','桃花零落逐風飛，地上紅多枝上稀。',32,'全唐诗/poet.song.89000.json','["桃花零落逐風飛，地上紅多枝上稀。", "春色陡然歸艷杏，梢頭還欲衒芳菲。"]'),
('4dcf353b-1fba-493f-ae7c-6fec9394ae28','春詞二十首  其一九','李綱','宋','宋诗','song-poetry','','[]','南方春早花亦早，爛熳開盡枝頭紅。',32,'全唐诗/poet.song.89000.json','["南方春早花亦早，爛熳開盡枝頭紅。", "記得上林當此際，遊人殊未探芳叢。"]'),
('b0a0a362-4765-4f26-af03-3ce540c5ede1','春詞二十首  其二○','李綱','宋','宋诗','song-poetry','','[]','一年春事遽如許，千里旅愁何似生。',32,'全唐诗/poet.song.89000.json','["一年春事遽如許，千里旅愁何似生。", "濁酒飲餘惟五合，殘書讀盡忽三更。"]'),
('a1273a1f-c537-4c95-8153-564e20983803','用韻賦梅花三首  其一','李綱','宋','宋诗','song-poetry','','[]','寒梅幾樹開前村，靚粧綽約歸仙魂。',128,'全唐诗/poet.song.89000.json','["寒梅幾樹開前村，靚粧綽約歸仙魂。", "横斜影落石溪淺，皓潔色洗煙嵐昏。", "幽香暗動松竹徑，清格自羞桃李園。", "窮冬萬里霜雪積，獨得一點陽和温。", "冰姿最宜夜月白，玉彩更炫朝霞暾。", "明妃失意去朔漠，阿嬌無寵扃長門。", "芳容寂寂誰復顧，雅意耿耿今何言。", "天涯相對且相樂，爲爾吸盡黄金樽。"]'),
('a6606972-bc04-4e8c-8197-772885ae0504','用韻賦梅花三首  其二','李綱','宋','宋诗','song-poetry','','[]','草木凍死山中村，惟有梅花能返魂。',128,'全唐诗/poet.song.89000.json','["草木凍死山中村，惟有梅花能返魂。", "孤根不怕雪霜苦，冷艷似笑風雲昏。", "披芳獨占歳寒地，擢秀肯待春風園。", "溪邊寒影自的的，月裏皓色還温温。", "飄零疏雨夕煙瞑，厭浥清露晨光暾。", "玉妃遊戲隘崑閬，縞衣飛出瑶臺門。", "幽姿耿介不可狎，欲問所以難爲言。", "嗅花嚼蕊更奇絕，侑我一醉玻璃罇。"]'),
('f31f0da0-cea6-4219-93e8-1af5a5c2b1ed','用韻賦梅花三首  其三','李綱','宋','宋诗','song-poetry','','[]','雲山縹緲煙水村，嫣然顧我驚離魂。',128,'全唐诗/poet.song.89000.json','["雲山縹緲煙水村，嫣然顧我驚離魂。", "凝情不語自脉脉，旅愁易感方昏昏。", "我家梁谿富泉石，雪裏數株開北園。", "天涯相見一笑粲，玉色不减當時温。", "爲君清夜不成寐，月落已見東方暾。", "會栽千樹徧綠野，豈羨五柳垂衡門。", "臨風三嗅長太息，欲辯此意還忘言。", "何當歸去老三徑，攜幼入室酒盈樽。"]'),
('6e0e854f-336a-46d9-b639-def0fd744aec','再賦一首','李綱','宋','宋诗','song-poetry','','[]','十年不踏江南村，想像梅花勞夢魂。',128,'全唐诗/poet.song.89000.json','["十年不踏江南村，想像梅花勞夢魂。", "豈惟捧心笑西子，只恐舉步迷東昏。", "繁英恍訝羣玉府，墮蕊悄愁金谷園。", "冰肌自飲晨露白，粉質不浴驪湯温。", "我行閩嶺喜入眼，皓彩照耀咸池暾。", "煙凝雲慘更愁絕，積雪欲堆袁安門。", "天香國艷世無匹，何用苦死教能言。", "吹殘樓角真可惜，莫厭秉燭臨芳樽。"]'),
('1dbb13ed-848b-4323-a2a9-c000415e2547','吳慎微鄧志宏同遊陳氏園','李綱','宋','宋诗','song-poetry','','[]','我本惜春人，常恐春色老。',192,'全唐诗/poet.song.89000.json','["我本惜春人，常恐春色老。", "沙陽渺天南，春到一何早。", "羣芳忽爛漫，自覺被春惱。", "招邀適名園，景物得幽討。", "燦燦桃李妍，娟娟松竹好。", "虛室自含風，迴塘已生草。", "酌酒對芳菲，論文慰懷抱。", "瓌奇窺李杜，寒色笑郊島。", "軟語既温温，髙談方浩浩。", "二子若驊騮，輕車駕長道。", "而我正飄蓬，摧殘已枯槁。", "家在天一涯，情若風中翿。", "幸然得相從，豁我憂心擣。", "青春能幾時，落花看又掃。", "寧辭金罍空，坐使玉山倒。", "世事可兩忘，悠悠信蒼昊。"]'),
('85a44c86-ec24-4a36-b8df-78f33d3f3f25','鄧純彦家蘭盛開見借一本  其一','李綱','宋','宋诗','song-poetry','','[]','誰道幽蘭是國香，山林僻處更芬芳。',32,'全唐诗/poet.song.89000.json','["誰道幽蘭是國香，山林僻處更芬芳。", "從今借得佳人佩，伴我春堂晝夢長。"]'),
('5e421753-68e7-4d4e-9437-eab7e9c5806a','鄧純彦家蘭盛開見借一本  其二','李綱','宋','宋诗','song-poetry','','[]','特地聞時却不香，暗中芬馥度微芳。',32,'全唐诗/poet.song.89000.json','["特地聞時却不香，暗中芬馥度微芳。", "寂然鼻觀圓通處，深院無人春晝長。"]'),
('70f0a7fb-5ced-4de2-8c8d-efdc8ee20fd5','鄧純彦家蘭盛開見借一本  其三','李綱','宋','宋诗','song-poetry','','[]','噴了清香開了花，却歸盆檻付公家。',32,'全唐诗/poet.song.89000.json','["噴了清香開了花，却歸盆檻付公家。", "來春花發香尤好，預借幽根茁露芽。"]'),
('f7780837-438a-4809-b5e5-bdad94c1a10b','鄧純彦家蘭盛開見借一本  其四','李綱','宋','宋诗','song-poetry','','[]','纖纖碧葉淺黄花，暗淡香飄物外家。',32,'全唐诗/poet.song.89000.json','["纖纖碧葉淺黄花，暗淡香飄物外家。", "培壅莫教摧露下，春風歲歲長靈芽。"]'),
('fda8434b-7d06-4257-8f6e-9081f1504cbc','次韻陳介然幽蘭翠柏之作 幽蘭 其一','李綱','宋','宋诗','song-poetry','','[]','幽蘭出深林，得上君子堂。',96,'全唐诗/poet.song.89000.json','["幽蘭出深林，得上君子堂。", "置之顧盼地，藹藹振餘光。", "春風茁其芽，暗淡飄天香。", "刈防豈無用，授夢方薦祥。", "紉佩美屈子，披風快襄王。", "秋髙白露下，摧折增感傷。", "願與菊同瘁，羞隨蕕並長。", "收根歸舊林，肯改無人芳。"]'),
('70cd9581-cdb9-430a-87f3-e8a7ca1d7db7','次韻陳介然幽蘭翠柏之作 幽蘭 其二','李綱','宋','宋诗','song-poetry','','[]','温風茁幽蘭，採掇置中堂。',96,'全唐诗/poet.song.89000.json','["温風茁幽蘭，採掇置中堂。", "孤根亦何有，借此軒墀光。", "耿耿不自惜，凄微泛餘香。", "蕭然山林姿，詎是邦家祥。", "譬猶美芹子，乃以薦君王。", "棄置固其宜，零落誰復傷。", "賦詩慰寂寞，念子故意長。", "願言同心人，去去揚清芳。"]'),
('1e208bd9-109c-48d9-8c84-3378a9479bdf','次韻陳介然幽蘭翠柏之作 翠柏 其一','李綱','宋','宋诗','song-poetry','','[]','翠柏方歲寒，獨立羣木外。',84,'全唐诗/poet.song.89000.json','["翠柏方歲寒，獨立羣木外。", "不爲衆所知，此理實難會。", "惜哉結根淺，未使極髙大。", "天風動虬枝，蕭瑟起清籟。", "儻無斤斧殘，會拂千丈黛。", "空餘霄漢志，不逐雪霜改。", "委棄老空山，浩蕩付玄宰。"]'),
('bb9de54b-6326-4eb9-886b-93d0d81a6a1c','次韻陳介然幽蘭翠柏之作 翠柏 其二','李綱','宋','宋诗','song-poetry','','[]','崇岡有翠柏，擢榦煙靄外。',84,'全唐诗/poet.song.89000.json','["崇岡有翠柏，擢榦煙靄外。", "託非不得地，據此羣山會。", "青青歳寒姿，自許百圍大。", "舞月散清影，號風振虚籟。", "誰云根如石，已見色參黛。", "幽人挺髙懷，顧我顔不改。", "知音自昔難，多財爲爾宰。"]'),
('405407c8-dbc0-4f70-8416-b135898ff7f3','次韻鄧志宏梅花','李綱','宋','宋诗','song-poetry','','[]','空山極望皆黄葦，欲挽天河聊一洗。',128,'全唐诗/poet.song.89000.json','["空山極望皆黄葦，欲挽天河聊一洗。", "溪邊的皪見梅花，冷蘂疏枝澹煙水。", "安得健步移我堂，清夜桂魄來孤光。", "人寰塵土飛不到，鼻觀寂寂聞天香。", "吾衰文思久不起，見子新詩端可喜。", "落英坐使笑天桃，結實定知非苦李。", "年來蹤跡墮空濛，與子追隨邈未窮。", "琢磨妙句覷天巧，爲我一振詩家風。"]'),
('464a2637-0d24-4709-bcd7-114f48d6a9e7','上元日二首  其一','李綱','宋','宋诗','song-poetry','','[]','去年玉輦侍端門，燈滿鼇山訝曉暾。',32,'全唐诗/poet.song.89000.json','["去年玉輦侍端門，燈滿鼇山訝曉暾。", "寂寞沙陽山水裏，也將膏火照黄昏。"]'),
('43caac63-6589-4399-98be-b272679768ca','上元日二首  其二','李綱','宋','宋诗','song-poetry','','[]','應爲飄零有故侯，競將燈火簇谿樓。',32,'全唐诗/poet.song.89000.json','["應爲飄零有故侯，競將燈火簇谿樓。", "田夫野婦盈衢巷，怪我還能與共遊。"]'),
('50262446-99e9-44b7-8b22-2b0a8d3a9627','墨戲六首 拳蠧','李綱','宋','宋诗','song-poetry','','[]','屈折金石瘦，偃蹙虬龍怒。',24,'全唐诗/poet.song.89000.json','["屈折金石瘦，偃蹙虬龍怒。", "蕭然少生意，端爲根中蠧。"]'),
('21db796a-9ffd-4c6e-8172-1a2ee2133b8f','墨戲六首 枯折','李綱','宋','宋诗','song-poetry','','[]','歳晚風號寒，琅玕半吹折。',24,'全唐诗/poet.song.89000.json','["歳晚風號寒，琅玕半吹折。", "雖殘栖鳯枝，終抱凌霄節。"]'),
('e393555a-e7b5-46c5-82f4-38d62d60fd86','墨戲六首 宿枝','李綱','宋','宋诗','song-poetry','','[]','疏筠輕带粉，老葉飽經霜。',24,'全唐诗/poet.song.89000.json','["疏筠輕带粉，老葉飽經霜。", "試問枝頭實，何年集鳯凰。"]'),
('cc1e014b-0ef1-4c6c-be0e-fa47334c8506','墨戲六首 新葉','李綱','宋','宋诗','song-poetry','','[]','解籜能幾日，成陰不待春。',24,'全唐诗/poet.song.89000.json','["解籜能幾日，成陰不待春。", "天然爲誰笑，風露一枝新。"]'),
('bf144671-d4e0-4e85-984e-c7c06cc3594c','墨戲六首 引根','李綱','宋','宋诗','song-poetry','','[]','土潤引新萌，虬鞭獨處行。',24,'全唐诗/poet.song.89000.json','["土潤引新萌，虬鞭獨處行。", "此君人不厭，何惜滿林生。"]'),
('ebafcdef-c6bf-4c88-8a09-27a256f0bdd7','墨戲六首 迸筍','李綱','宋','宋诗','song-poetry','','[]','養就籜龍兒，斕斑角未齊。',24,'全唐诗/poet.song.89000.json','["養就籜龍兒，斕斑角未齊。", "斧斤休縱手，會看拂雲霓。"]'),
('e07647ad-5eac-4d85-8736-9c22592e911c','六竹外尚有偃風頂雨二本留故家志宏欲之而未得戲作絕句附卷末庶幾異日悉歸志宏也','李綱','宋','宋诗','song-poetry','','[]','六様根莖妙入神，兩枝風雨更清新。',32,'全唐诗/poet.song.89000.json','["六様根莖妙入神，兩枝風雨更清新。", "此君族類須收拾，莫使飄零歎失身。"]'),
('39fd302b-f6f6-4ba0-a3e2-4295bbde25c0','再用陳園韻示鄧志宏','李綱','宋','宋诗','song-poetry','','[]','青松更雪霜，始見枝幹老。',192,'全唐诗/poet.song.89000.json','["青松更雪霜，始見枝幹老。", "挺然節操士，安用致身早。", "吾衰習禪觀，頗覺得無惱。", "每於文字間，未免尚窮討。", "遇物空吟哦，愧乏句語好。", "有時肆狂言，自哂太草草。", "儒生捨翰墨，無與寄幽抱。", "富貴非所願，神仙渺雲島。", "寧知萬卷中，養此一氣浩。", "子若汗血駒，振轡千里道。", "我如鎩翮鴻，毛羽半摧槁。", "適然相值遇，豈異宛丘翿。", "新詩迭唱酬，險韻類虛擣。", "文章雖末技，塵語貴除掃。", "勉哉扛鼎力，迴此狂瀾倒。", "此外復何爲，窮通付旻昊。"]'),
('cd3ee59b-336b-4647-a663-43551c378c3b','惜花','李綱','宋','宋诗','song-poetry','','[]','瓶水養花花已老，零落春風寒不掃。',32,'全唐诗/poet.song.89000.json','["瓶水養花花已老，零落春風寒不掃。", "從教几案積殘紅，尚有餘香慰衰槁。"]'),
('70e47c41-3e83-4dac-a570-d321534f3c5f','乘興遊鄧季明園池邀志宏同會再賦陳園韻','李綱','宋','宋诗','song-poetry','','[]','幽人築小圃，自樂不知老。',192,'全唐诗/poet.song.89000.json','["幽人築小圃，自樂不知老。", "聞名雖已熟，相見苦不早。", "忘懷傾盖間，什我羈旅惱。", "春風入芳林，乘興聊一討。", "嘉葩寒未開，美木晴更好。", "飄零桃與杏，殘紅委煙草。", "急令招小阮，談笑款清抱。", "披襟步方池，散策窮遠島。", "翛然適我情，忘此歸志浩。", "人生暫寄身，寵辱何足道。", "舐痔得車多，未可驕黄槁。", "一杯且相属，起舞不須翿。", "文楸響玉子，更試兵家擣。", "羸形乍泉漲，猛勢驚電掃。", "應憐客素癡，屢勸罰觥倒。", "歸待月華生，清光滿春昊。"]'),
('256a396f-9cdc-465e-aa1f-507ecefac26c','招陳幾叟小飲','李綱','宋','宋诗','song-poetry','','[]','開樽欲約玉川子，致鯉先遣長鬚奴。',64,'全唐诗/poet.song.89000.json','["開樽欲約玉川子，致鯉先遣長鬚奴。", "春時海燕光涎涎，風暖城烏尾畢逋。", "幸有異書并古字，可無白飯與青芻。", "虛堂隱几共談笑，應信今吾非故吾。"]'),
('68d20c33-babc-426a-a803-85f3598750b8','志宏以墨戲見遺并貺古風次韻答之且歸其畫','李綱','宋','宋诗','song-poetry','','[]','老坡墨戲吾最許，雨葉風枝無點上。',128,'全唐诗/poet.song.89000.json','["老坡墨戲吾最許，雨葉風枝無點上。", "幽懷寄此管城穎，妙質森然會稽楮。", "要須胸次竹先成，故使落筆前無古。", "披圖但愛凌雲姿，作贊愧乏驚人語。", "嗟予迂闊與世疏，酷嗜栽培如老圃。", "築園會與種千竿，開國便勝封萬户。", "遺予此畫意已勤，奪人之好道所禦。", "封題依舊送書房，得畫何如得竹愈。"]'),
('ef3b4111-322a-45cc-aba8-99d25f7a15f4','再用奴字韻呈幾叟','李綱','宋','宋诗','song-poetry','','[]','平生志尚在丘壑，肯學衛霍追匈奴。',64,'全唐诗/poet.song.89000.json','["平生志尚在丘壑，肯學衛霍追匈奴。", "綿上之田方欲隱，草堂之靈休謝逋。", "富貴於人何翅夢，理義悦我真如芻。", "晚交夫子談道妙，應笑連叔驚肩吾。"]'),
('902398be-4082-4af2-8507-e20e91f06075','以墨戲歸志宏復有詩來次韻答之','李綱','宋','宋诗','song-poetry','','[]','玉局老仙人共許，秀骨于今已黄土。',128,'全唐诗/poet.song.89000.json','["玉局老仙人共許，秀骨于今已黄土。", "人間無復見文章，空餘戲墨歸囊楮。", "子能藏蓄真好事，便可祕惜傳千古。", "試將短句贊幽姿，却對此君難下語。", "年來懶惰百事廢，欲把鋤犂逐農圃。", "會栽脩竹滿園池，爲引清風到庭户。", "子詩往復句益奇，發我狂吟那可禦。", "超然對竹更吟詩，此病未知誰得愈。"]'),
('13426959-fee3-4451-ae50-364ec20590ac','再次韻','李綱','宋','宋诗','song-poetry','','[]','落筆蕭森遽如許，墨爲根莖紙爲土。',128,'全唐诗/poet.song.89000.json','["落筆蕭森遽如許，墨爲根莖紙爲土。", "眉山作此共言好，譬猶字法稱虞褚。", "世人畫竹不畫意，謾捨丹青欲侔古。", "胸中幹葉本天成，心手應時那可語。", "此君於我定有緣，每念移根栽小圃。", "開圖忽見數株新，却怪龍孫入吾户。", "年來幾欲斷吟哦，照眼還成自難禦。", "發緘又復讀佳篇，詩癖遥知猶未愈。"]'),
('1213e670-9a67-405e-abcc-98ada747c6f7','志宏復有詩來再賦兩篇爲報念其往復之無已也故寓意卒章以止之  其一','李綱','宋','宋诗','song-poetry','','[]','平生愛竹端自許，欲種千竿滿吾土。',128,'全唐诗/poet.song.89000.json','["平生愛竹端自許，欲種千竿滿吾土。", "豈知好物不須多，只費東坡數番楮。", "酒酣弄筆寫寒姿，一洗丹青空萬古。", "我今觀畫已蕭然，矧對吟風如共語。", "淵明荒徑便抛官，仲子辭官歸灌圃。", "終年端坐飽太倉，更欲此君長傍户。", "亦知兩者固難兼，無那幽懷終不禦。", "縱教富貴欲何爲，不若歸來栽竹愈。"]'),
('3636cebd-dfc0-41ee-9a78-fe35007e84a0','志宏復有詩來再賦兩篇爲報念其往復之無已也故寓意卒章以止之  其二','李綱','宋','宋诗','song-poetry','','[]','數君妙質來何許，生氣森森如得土。',128,'全唐诗/poet.song.89000.json','["數君妙質來何許，生氣森森如得土。", "依然對此未忘情，亦欲懷之恨無楮。", "宿枝新葉自清妍，蠧拳枯折尤奇古。", "已將金玉照雙眸，更得珠璣編好語。", "男兒學古貴根源，餘力遊兹文翰圃。", "沈思六藝見同歸，縱覽百家知異户。", "浩然養氣塞天淵，沛若江河知孰禦。", "却憐彫斵愁肺肝，但莫苦吟當自愈。"]'),
('23a3f8d2-3339-44cd-8a0f-10b2bacbc883','讀李白集用奴字韻','李綱','宋','宋诗','song-poetry','','[]','謫仙英豪盖一世，醉使力士如使奴。',64,'全唐诗/poet.song.89000.json','["謫仙英豪盖一世，醉使力士如使奴。", "當時左右悉諛佞，驚怪恇怯應逃逋。", "我生端在千載後，祭公只用一束芻。", "遺編凛凛有生氣，玩味無斁誰如吾。"]'),
('04cc5469-1934-4b7f-b570-65867fa4a7a3','春雨','李綱','宋','宋诗','song-poetry','','[]','春晚雨聲碎，天深雲影低。',48,'全唐诗/poet.song.89000.json','["春晚雨聲碎，天深雲影低。", "蕭蕭度遠岫，脉脉漲前溪。", "芳潤歸花蕾，清寒作燕泥。", "池塘夢生草，碧色已凄迷。"]'),
('71bd79ef-e4ad-4b4f-bec3-e7afcadac86d','春意','李綱','宋','宋诗','song-poetry','','[]','春鳥窺綠窗，踏落庭前花。',48,'全唐诗/poet.song.89000.json','["春鳥窺綠窗，踏落庭前花。", "美人爲之笑，鬢脚風中斜。", "不惜花踏殘，只愁鳥驚去。", "姹婭背人飛，林深無覓處。"]'),
('15a32d27-18b1-42e0-9979-c6b4c9d20dee','平津閤晚雨','李綱','宋','宋诗','song-poetry','','[]','暮雨带風急，春雲亂眼低。',48,'全唐诗/poet.song.89000.json','["暮雨带風急，春雲亂眼低。", "凄凉倚虛閤，湍激瞰回溪。", "煙遠桃花浪，山寒錦障泥。", "江鄉何處是，天闊望中迷。"]'),
('aa9df9d1-2867-4b69-929e-1c4003a5df86','春晝書懷','李綱','宋','宋诗','song-poetry','','[]','春院沈沈晝掩關，坐看雲起面前山。',64,'全唐诗/poet.song.89000.json','["春院沈沈晝掩關，坐看雲起面前山。", "静中圖史尤多味，身外功名已厚顔。", "匣硯細磨鴝鵒眼，茶甌深泛鷓鴣斑。", "簿書粗了無餘事，更有何人似我閒。"]'),
('05a25558-92e0-4435-9684-89a3c7b1fd7f','春雪  其一','李綱','宋','宋诗','song-poetry','','[]','怪底春來煖太深，忽驚雪片墮層陰。',64,'全唐诗/poet.song.89000.json','["怪底春來煖太深，忽驚雪片墮層陰。", "廉纖带雨初猶薄，散漫隨風遽不禁。", "光炫峰巒皆玉色，寒侵花木欲灰心。", "沙陽逐客家何在，擁鼻凄凉但越吟。"]'),
('88eb9051-de89-4880-8c35-89a8239a0baf','春雪  其二','李綱','宋','宋诗','song-poetry','','[]','東君也解惜芳容，故把冰花密密封。',64,'全唐诗/poet.song.89000.json','["東君也解惜芳容，故把冰花密密封。", "索索響寒窗外竹，亭亭戴白嶺頭松。", "只驚滿眼飄風絮，不覺瀕谿臥玉龍。", "身在天涯歸未得，澆愁直欲倒千鍾。"]'),
('a66516b5-73dd-4a1d-bda3-8fb99f1b51d2','食筍蕨','李綱','宋','宋诗','song-poetry','','[]','太官飽食厭羶腥，却喜沙陽有竹萌。',32,'全唐诗/poet.song.89000.json','["太官飽食厭羶腥，却喜沙陽有竹萌。", "山蕨邇來尤脆美，一杯聊試煮坡羮。"]'),
('7e361a85-2217-45fe-8acf-2800d40c60cd','學草書','李綱','宋','宋诗','song-poetry','','[]','平生行事見真書，草聖空慚點畫疏。',32,'全唐诗/poet.song.89000.json','["平生行事見真書，草聖空慚點畫疏。", "今日試臨寒食帖，却疑羲獻不難如。"]'),
('63fa82ef-8684-4578-b235-1402ca1bad4d','次韻志宏見示春雪長句','李綱','宋','宋诗','song-poetry','','[]','百花爛漫如冶容，頗訝陡然春色濃。',160,'全唐诗/poet.song.89000.json','["百花爛漫如冶容，頗訝陡然春色濃。", "那知忽作三尺雪，草木洗盡羣芳空。", "六英飄舞片片好，誰與刻削嗟神工。", "谿山恍在玉壺裏，樓觀飛出瑶臺中。", "却憐極目皆皓素，不復零落傷殘紅。", "幽人栩栩應夢蝶，落絮漠漠方黏蜂。", "虚堂兀坐清入骨，欲期汗漫遊鴻濛。", "剡谿訪戴久寂寞，安得一御泠然風。", "年來端恐詩道窮，幸予佳句時争鋒。", "客愁已劇更賦雪，半夜吟苦天地白。"]'),
('0b1a0875-1114-496a-a35a-22e051181d44','雪霽','李綱','宋','宋诗','song-poetry','','[]','夢殘鐘鼓報新晴，虛幌遥看曉日昇。',64,'全唐诗/poet.song.89000.json','["夢殘鐘鼓報新晴，虛幌遥看曉日昇。", "雲外崔嵬猶負雪，石間清淺欲銷冰。", "春歸花草蜂尋侣，巢寄簷楹燕語朋。", "貂敝不禁寒料峭，客愁惟藉酒憑陵。"]'),
('a80407d3-9c0b-4a44-9049-5115eaeaed86','次韻陸敦禮留題皇華驛二首  其一','李綱','宋','宋诗','song-poetry','','[]','貂裘端恐敝緇塵，勇向明時乞得身。',64,'全唐诗/poet.song.89000.json','["貂裘端恐敝緇塵，勇向明時乞得身。", "却擁紫荷來握節，遥知白鹿已隨輪。", "棣華輝映蕃宣地，篇什流傳放逐人。", "只恐晋江難久駐，爲將直道福生民。"]'),
('b806a3d1-263e-449d-9e9f-f187d097f9fe','次韻陸敦禮留題皇華驛二首  其二','李綱','宋','宋诗','song-poetry','','[]','宫漏初殘唱曉鷄，周廬同守禁城扉。',64,'全唐诗/poet.song.89000.json','["宫漏初殘唱曉鷄，周廬同守禁城扉。", "龍墀密簉鵷鸞羽，玉殿先瞻日月衣。", "青瑣笑談情已厚，皂囊章奏意何稀。", "擁旄晝繡方如意，也念飄零未得歸。"]'),
('0e0ab12a-b386-45ba-93ef-37b388d3899a','溪漲  其一','李綱','宋','宋诗','song-poetry','','[]','中宵驟雨駕驚雷，逗曉盤渦轂浪來。',32,'全唐诗/poet.song.89000.json','["中宵驟雨駕驚雷，逗曉盤渦轂浪來。", "端恐谿神似河伯，望洋向若始知咍。"]'),
('a8ab6e3b-b192-400b-b3e3-2ec1ab9670a8','溪漲  其二','李綱','宋','宋诗','song-poetry','','[]','雨過渾流漲曉溪，茫茫煙水拍春堤。',32,'全唐诗/poet.song.89000.json','["雨過渾流漲曉溪，茫茫煙水拍春堤。", "凄凉柱史憑虛閣，猶憶都城水自西。"]'),
('0ab4bb58-b2fd-4c03-93d7-4230019ead94','志宏以牡丹酴醿見遺戲呼牡丹爲道州長且許時餉酴醿作二詩以報之 牡丹','李綱','宋','宋诗','song-poetry','','[]','我昔驅車遊洛陽，正值名圃開花王。',272,'全唐诗/poet.song.89000.json','["我昔驅車遊洛陽，正值名圃開花王。", "嫣然萬本鬭妍媚，彫檻綽約羅紅粧。", "風枝似響湘浦珮，露苞如浴驪山湯。", "乍驚照眼國色好，更覺撲鼻春風香。", "鞓紅檀點玉版白，細葉次第舒幽房。", "玉奴纖指尚餘捻，鶴翎坐恐隨風翔。", "就中品格最奇特，共許魏紫并姚黄。", "千金不惜買一醉，少年渾欲花底狂。", "歸來試作牡丹譜，未服秉筆惟歐陽。", "自從遊宦多感傷，况此遠謫閩山傍。", "諦觀世味如嚼蠟，惜花未免猶膏肓。", "亦知春色到庭户，不見此花如未嘗。", "子於何處得一本，贈我意厚誠難忘。", "戲言劍浦此爲最，聊試呼作道州長。", "化工彫刻無厚薄，地氣培植非其鄉。", "雖云單葉不入品，無那富艷踰羣芳。", "願言愛惜勿嘲誚，且醉玉斝酬韶光。"]'),
('27671bda-aef8-4fa7-a434-6cfe28bee2a4','志宏以牡丹酴醿見遺戲呼牡丹爲道州長且許時餉酴醿作二詩以報之 酴醿','李綱','宋','宋诗','song-poetry','','[]','殘陰未許春光洩，噴作沙陽三尺雪。',128,'全唐诗/poet.song.89000.json','["殘陰未許春光洩，噴作沙陽三尺雪。", "摧傷花卉盡枯槎，惟有酴醿寒更茁。", "幽人早起傍園林，獨喜枝頭瓊蘂綴。", "應憐逐客正凄凉，折贈殷勤慰愁絕。", "清香馥郁坐中飄，汲水養之殊未歇。", "和煙带露愈芬芳，更許幽叢時爲擷。", "愁霖連日作輕寒，寂寂禪扉方晝閉。", "春風駘蕩好幽尋，安得連拳掛雌霓。"]'),
('3f26efa6-485a-4505-8cdc-330652cb2d16','志宏見和再次前韻 牡丹','李綱','宋','宋诗','song-poetry','','[]','半夜疏鐘來景陽，美人梳洗隨君王。',272,'全唐诗/poet.song.89000.json','["半夜疏鐘來景陽，美人梳洗隨君王。", "天然意態已傾國，何用苦死催嚴粧。", "朱顔半酡寧著酒，玉膚自滑非臨湯。", "鉛華固美豈真色，蘭麝雖馥非天香。", "我觀牡丹正如此，勾欄横檻爲雕房。", "乍驚神女峽中見，只恐弄玉雲間翔。", "檀心點點暈深紫，金蘂簇簇搖金黄。", "坐令雜花爲婢妾，解使蜂蝶成顛狂。", "臨風嫋嫋更妍好，渾如舞袖踏春陽。", "芳根最是洛中盛，安得千本栽砌傍。", "惜花惟怕春色老，此癖誰與鍼其肓。", "沙陽春晚始一見，如有異味争先嘗。", "蠟封剪處持送我，念子此意何時忘。", "禅關兀坐無與語，遲遲晝景方舒長。", "對花把酒不知醉，醒後還復悲殊鄉。", "佳篇酬和慰落寞，清麗欲與花争芳。", "吟哦愈苦詩愈好，去去惜此窗前光。"]'),
('03769bb2-1081-49e7-a9a9-2862408c7ad1','志宏見和再次前韻 酴醿','李綱','宋','宋诗','song-poetry','','[]','寒過春光還漏洩，酴醿架上花如雪。',128,'全唐诗/poet.song.89000.json','["寒過春光還漏洩，酴醿架上花如雪。", "輕盈皓色訝梅開，芬馥清香勝蘭茁。", "龍鬚初引翠蔓長，玉質全看素英綴。", "結成幽洞自深沈，蔭此芳醪更奇絕。", "銅瓶只浸兩三枝，香在根塵都不歇。", "幽人贈我意已勤，却愧終朝煩採擷。", "子美惟愁花欲飛，淵明自愛門常閉。", "尋芳須趁春未殘，更喜晴天垂彩霓。"]'),
('8039ccac-1418-4ab0-94f4-428508046c6b','次韻招志宏見過','李綱','宋','宋诗','song-poetry','','[]','旰起禪房只杜門，忽思嘉客共論文。',64,'全唐诗/poet.song.89000.json','["旰起禪房只杜門，忽思嘉客共論文。", "連山霧雨密難解，隱耳雷霆驚乍聞。", "我向圖書端作蠧，子今胸抱欲吞雲。", "春堂談笑能相就，爲把沈煙細細焚。"]'),
('48f4d343-c5b5-4717-bb30-bc67360b48b2','再賦酴醿贈志宏','李綱','宋','宋诗','song-poetry','','[]','春入酴醿如憤洩，翻空萬點枝頭雪。',128,'全唐诗/poet.song.89000.json','["春入酴醿如憤洩，翻空萬點枝頭雪。", "濃花嫩蘂滿柔柯，應笑蓬葭春亦茁。", "東君端的衒工夫，故把瓊酥巧粧綴。", "含風觸處便氛氲，带月看時更清絕。", "幽香移入小齋中，獨比餘花最難歇。", "子應憐我惜春光，刺手鈎衣幾番擷。", "却嗟草木本無情，亦解随時自開閉。", "對花一醉更繙書，醉裏猶能讀爲霓。"]'),
('ff2d5d20-d3d8-40fe-af48-fc38a209b783','題陳氏隱圃佚老堂二十韻','李綱','宋','宋诗','song-poetry','','[]','處世如大夢，悟者能有幾。',240,'全唐诗/poet.song.89000.json','["處世如大夢，悟者能有幾。", "鐘鳴漏已盡，躭著不知止。", "賢哉潁川公，纔老即謝事。", "懸車築園池，歸作隱君子。", "大塊方逸我，順之聊復爾。", "燕居二十年，坐進端爲此。", "委形雖物化，妙湛本無死。", "我來恨不及，猶喜識其嗣。", "鬢眉皓已霜，眸子炯如水。", "頭著白綸巾，蕭散真晋士。", "傳家有髙風，何必拾青紫。", "衡門久不開，荒徑爲我洗。", "相攜步方塘，春渌漲清泚。", "修篁間蒼松，新槐雜嘉卉。", "斷橋堆露籜，危架引煙蘂。", "蔭庭桂團團，疊澗石齒齒。", "蕭森無俗姿，曠遠含古意。", "慰我放逐情，翛然百憂弭。", "緬懷前人風，安得九原起。", "相過不厭頻，追隨從此始。"]'),
('ea15d384-a945-4cbf-be6b-325462c153d1','余賦佚老堂志宏見和復用前韻成一篇呈興宗','李綱','宋','宋诗','song-poetry','','[]','人生期百年，得老亦無幾。',240,'全唐诗/poet.song.89000.json','["人生期百年，得老亦無幾。", "超然髙世士，急流貴勇止。", "掛冠神武門，不與王侯事。", "驅車返田廬，出關隨父子。", "寧知千載後，夫子亦云爾。", "虛堂號佚老，遊息長在此。", "心閒齊物我，漏盡謝生死。", "遺德藹清芬，承家有賢嗣。", "行年踰六十，遇物如止水。", "豈惟詩家流，端是林下士。", "閉關園日涉，不種紅與紫。", "滿庭松桂香，月露浩如洗。", "風篁自蕭蕭，池溜方泚泚。", "知我却叩門，鋤榛出芳卉。", "杞菊初長苗，棠梨半含蘂。", "清談款襟抱，忘此德與齒。", "境幽人復佳，發我斐然意。", "作詩掛楹間，拙惡何時弭。", "鄧侯亦可人，佳句實予起。", "抱膝更長吟，蕪音慚四始。"]'),
('794b6fa4-50f3-4f72-96ed-cba5f3e40deb','寒食五首  其一','李綱','宋','宋诗','song-poetry','','[]','往歳遇寒食，親賓相與娛。',60,'全唐诗/poet.song.89000.json','["往歳遇寒食，親賓相與娛。", "飄零客異土，對之渾若無。", "豈不念佳節，寸心愁欲枯。", "花間有好烏，勸我提葫蘆。", "一醉聊自適，醉夢歸東吳。"]'),
('5d8a4470-7b6d-49e3-9d6c-db6ab5be8f00','寒食五首  其二','李綱','宋','宋诗','song-poetry','','[]','異縣遇寒食，悵然懷我家。',60,'全唐诗/poet.song.89000.json','["異縣遇寒食，悵然懷我家。", "千里遙相望，各在天一涯。", "佳節無與同，冉冉悲年華。", "鳴禽花底聒，舞燕風中斜。", "物情各自遂，羈束誠可嗟。"]'),
('1ea6345d-e9c6-4210-af37-e4350e971704','寒食五首  其三','李綱','宋','宋诗','song-poetry','','[]','天涯遇寒食，嘉節無與對。',60,'全唐诗/poet.song.89000.json','["天涯遇寒食，嘉節無與對。", "獨酌一盃酒，慷慨使心痗。", "來者或可追，既往那復悔。", "翛然畎畝心，敢忘犬馬愛。", "之推自欲隱，去去何所懟。"]'),
('9a8449d4-1e38-48dd-a8f3-9211eb1f80e4','寒食五首  其四','李綱','宋','宋诗','song-poetry','','[]','嘉節遇寒食，春陰猶作寒。',60,'全唐诗/poet.song.89000.json','["嘉節遇寒食，春陰猶作寒。", "閩人不知重，渾作等閒看。", "餳粥不復煮，青楓誰與鑚。", "開窗延霽景，脩竹正團欒。", "翠眉雙侍女，對此一樽殘。"]'),
('da1dcf88-3bc6-40ea-8ec5-7e60e6dc5280','寒食五首  其五','李綱','宋','宋诗','song-poetry','','[]','逐客已凄凉，矧復值寒食。',60,'全唐诗/poet.song.89000.json','["逐客已凄凉，矧復值寒食。", "花深日遲遲，院静春寂寂。", "雨餘山吐青，日落霞掃赤。", "浙江渺何在，三月無消息。", "棄置勿復陳，吾心乃如石。"]'),
('061d3b69-9337-4311-9a19-a68766cf512a','清明日','李綱','宋','宋诗','song-poetry','','[]','憶昔叨塵寓帝京，春光淡蕩值清明。',64,'全唐诗/poet.song.89000.json','["憶昔叨塵寓帝京，春光淡蕩值清明。", "賜來新火傳紅蠟，煮就香糜和白餳。", "遊女踏青尋苑草，戲童引線送風筝。", "沙陽寂寞都無此，臥看山雲聽水聲。"]'),
('322e1670-492c-40ca-a29b-2c357d6fd8b9','上巳日','李綱','宋','宋诗','song-poetry','','[]','暮春祓禊集簪裾，錫燕昆明詠樂胥。',64,'全唐诗/poet.song.89000.json','["暮春祓禊集簪裾，錫燕昆明詠樂胥。", "寶馬驍騰隨鼓吹，綵舟曼衍戲龍魚。", "閩山放逐家何在，帝里風光樂自如。", "嘉節只添遷客恨，寛恩何日賦歸歟。"]'),
('97a31d99-a327-45bd-a825-df6eaf01716f','晏起','李綱','宋','宋诗','song-poetry','','[]','清明已過初短宵，春氣困人如濁醪。',128,'全唐诗/poet.song.89000.json','["清明已過初短宵，春氣困人如濁醪。", "院深人静不知曉，虚堂一枕方陶陶。", "覺來紅日髙三丈，竹影扶疏風葉響。", "披衣散髮久逍遙，髣髴枕痕猶頰上。", "却思昔簉鵷鷺班，每聽朝雞長慘顔。", "戴星侵月未爲苦，衝風冒雨長艱難。", "何如謫墮溪山裏，鐘鼓不聞春睡美。", "先生夢覺本來齊，更與睡鄉重作紀。"]'),
('773d2f53-c78c-4dcc-9e37-5e1a88994c16','戒酒','李綱','宋','宋诗','song-poetry','','[]','吾初不解飲，涓滴莫下嚥。',204,'全唐诗/poet.song.89000.json','["吾初不解飲，涓滴莫下嚥。", "自從遊宦來，稍稍頗稱善。", "譬猶怯懦士，習慣亦能戰。", "作氣欲吞敵，賈勇乃求殿。", "迂愚攖重釁，飄泊旅異縣。", "懷家路迢迢，惜春花片片。", "澆愁欲千鍾，燕客卑九獻。", "浩如鯨吸川，無那壺浮箭。", "歡然偶過量，淺狹誠易見。", "噎嘔九藏翻，昏瞀兩目眩。", "宿酲味尤惡，累日不欲膳。", "吾生如浮漚，急景若奔電。", "學道貴清虛，爲文欲精錬。", "胡爲事杯杓，無乃廢筆硯。", "先生一石醉，待詔三升戀。", "枕麴與藉糟，自汙何足羨。", "從今梁谿翁，無復醉鄉願。"]'),
('044ce2e5-cda6-42e0-bb09-17b8d923b904','巖桂','李綱','宋','宋诗','song-poetry','','[]','閩山氣候真不常，浪蘂浮花渾欲狂。',96,'全唐诗/poet.song.89000.json','["閩山氣候真不常，浪蘂浮花渾欲狂。", "團團巖桂著春雨，擢秀不待秋風凉。", "微舒嫩葉玉剪碧，巧綴碎顆金排黄。", "木如犀理自堅緻，噴作十里旃檀香。", "沙陽滿眼皆此樹，安得白露零清商。", "芳根端可伴真隱，他日移植梁谿傍。"]'),
('75210acf-cc90-4521-a6c7-b38dad31f07d','志宏送巖桂并惠長篇求予賦詩次韻答之','李綱','宋','宋诗','song-poetry','','[]','我來閩嶺值春月，坐見園林花競茁。',160,'全唐诗/poet.song.89000.json','["我來閩嶺值春月，坐見園林花競茁。", "殷紅枝上破燕脂，嫩白稍頭開玉雪。", "平生苦吟緣愛奇，對花豈忍都無詩。", "愧將拙句寫天巧，但把濁酒酬春暉。", "適來巖桂花尤好，亂綴黄英向青昊。", "非時似欲鬭羣芳，草木無情亦相惱。", "栟櫚送花來覓句，端恐梁谿得歸去。", "謫官且作九年期，家在天涯那復顧。", "何時萬里吹秋風，清香伴此金芙蓉。", "臨風一醉百憂散，看子揮毫如彩虹。"]'),
('b0e331f9-ff92-44f6-9d0e-ce4263a0a78e','春暮平津晚望','李綱','宋','宋诗','song-poetry','','[]','風迴雨霽已春殘，景色蒼茫杳靄間。',64,'全唐诗/poet.song.89000.json','["風迴雨霽已春殘，景色蒼茫杳靄間。", "芳草渡頭看綠樹，白雲飛處見青山。", "鶯啼燕語愁腸斷，親老家遥淚點斑。", "却笑腐儒何所用，征商偷得半時閒。"]'),
('847c4b25-5df6-4fab-823f-ef41b280f0d7','寄諸弟','李綱','宋','宋诗','song-poetry','','[]','自取飄零不復云，索居終日念離羣。',64,'全唐诗/poet.song.89000.json','["自取飄零不復云，索居終日念離羣。", "送書未見來黄耳，陟岵惟知望白雲。", "素髮偏親烏鳥急，青春諸季棣華分。", "天涯只有思家切，須使音聲不輟聞。"]'),
('f9316129-cb9a-4e1e-901b-6924838b916f','寄內','李綱','宋','宋诗','song-poetry','','[]','南遷道遠不相攜，錦字還嗟雁到遲。',64,'全唐诗/poet.song.89000.json','["南遷道遠不相攜，錦字還嗟雁到遲。", "玉臂雲鬟同夜月，繡屏金鴨獨香帷。", "諸兒應解勤修習，稚女遙憐弄喔咿。", "何日得歸同隱志，孟光舉案定齊眉。"]'),
('0b07f886-509d-494d-96c2-51b2edc179de','夜坐三絕句  其一','李綱','宋','宋诗','song-poetry','','[]','春夜沈沈氣倍清，殘編讀徹忽三更。',32,'全唐诗/poet.song.89000.json','["春夜沈沈氣倍清，殘編讀徹忽三更。", "金釭挑盡空搔首，又聽簷間雨滴聲。"]'),
('86208bc7-8663-4228-9c04-9d7a32bc202f','夜坐三絕句  其二','李綱','宋','宋诗','song-poetry','','[]','平生最喜夜看書，人静心閒樂有餘。',32,'全唐诗/poet.song.89000.json','["平生最喜夜看書，人静心閒樂有餘。", "識盡古人興廢事，何如一枕夢華胥。"]'),
('6f3c646a-f9de-4743-8c07-4b932f017dea','夜坐三絕句  其三','李綱','宋','宋诗','song-poetry','','[]','中宵風雨透窗紗，獨坐無聊却念家。',32,'全唐诗/poet.song.89000.json','["中宵風雨透窗紗，獨坐無聊却念家。", "三月浙江無信息，寒燈何事結成花。"]'),
('2ae161f7-5b4f-45ea-82f6-8644429ac18d','夜坐觀斗','李綱','宋','宋诗','song-poetry','','[]','帝車運轉天沈沈，杓攜龍角魁枕参。',160,'全唐诗/poet.song.89000.json','["帝車運轉天沈沈，杓攜龍角魁枕参。", "斡旋造化豈終極，斟酌元氣分陽陰。", "物隨南北自生死，時繫俯仰成古今。", "攝提大角順所指，其餘萬象徒森森。", "舜觀璣衡齊七政，致治不獨薫風琴。", "後來方士誠幻怪，罡步禬禳難究尋。", "閩山春月多霧雨，夜霽天影髙而深。", "七星錯落掛北户，芒寒色正方照臨。", "我來瞻仰但再拜，頗見天地照回心。", "酒漿不挹西柄揭，詎敢更作詩人箴。"]'),
('aa5ad84e-2e46-4478-99e0-052ed4358eee','志宏送千葉鶯粟走筆代簡','李綱','宋','宋诗','song-poetry','','[]','世傳鶯粟如紙花，品目不爲人所嘉。',96,'全唐诗/poet.song.89000.json','["世傳鶯粟如紙花，品目不爲人所嘉。", "那知亦解吐繁艷，深紅淺白凌朝霞。", "一窠千葉類芍藥，傳種本自何人家。", "栟櫚乞得不敢惜，長須走送聲呀呀。", "杜門宴坐觀內典，方丈寂寂如毗耶。", "散花侍女一笑粲，居士默然惟啜茶。"]'),
('061d830b-1847-4135-9e1f-35f2142feefb','季明之子登第戲成小詩并紀巖桂之異','李綱','宋','宋诗','song-poetry','','[]','怪底春山桂開早，仙籍浮香遠相告。',64,'全唐诗/poet.song.89000.json','["怪底春山桂開早，仙籍浮香遠相告。", "固知鍾愛在賢郎，誰謂筆根無顯報。", "親賓來賀如雲奔，車馬煌煌于氏門。", "七杯燕客吾未與，應欲特開東閣樽。"]'),
('bf087060-bfd9-40e6-85d1-4cd4a33bbbf8','再賦志宏千葉鶯粟','李綱','宋','宋诗','song-poetry','','[]','春深百草争開花，天香國色世共嘉。',96,'全唐诗/poet.song.89000.json','["春深百草争開花，天香國色世共嘉。", "誰令鶯粟亦妍好，濯濯似舉風中霞。", "一畦同種偶千葉，巧思端屬東君家。", "年來居士已忘物，對花聊復一笑呀。", "色空本是不二法，何用自生分别耶。", "更思崖蜜煑牛乳，甘滑滿甌全勝茶。"]'),
('30c01c8a-4d56-47d2-b24b-f123b31555c3','羅疇老同遊栖雲院瞻禮新藏','李綱','宋','宋诗','song-poetry','','[]','寶峰古叢林，深寂雲所栖。',240,'全唐诗/poet.song.89000.json','["寶峰古叢林，深寂雲所栖。", "中有大寶藏，湧海蟠蛟螭。", "莊嚴極精麗，金碧光陸離。", "諸天渺宫殿，地軸森鐵圍。", "雷音出妙響，震破羣生疑。", "天人所瞻仰，神物應護持。", "吾聞金仙氏，變化難思惟。", "毫端見寶刹，芥子藏須彌。", "能於一塵裏，法輪常轉移。", "誰將創物智，設此妙圓機。", "佛語菩薩語，收拾靡有遺。", "八萬四千偈，轉一彈指時。", "功多用力少，權實相因依。", "偉哉象教力，天造非人爲。", "無量大居士，精進心不疲。", "夙植衆德本，爰得真依歸。", "咄嗟檀施開，成此一段奇。", "相攜結勝緣，洗我既往非。", "獲聞第一義，刮眼資金箆。", "超然脫塵垢，清凈真摩尼。"]'),
('a667ba7d-64bc-4ac7-b71d-1c94113e12c2','聞七弟叔易登科','李綱','宋','宋诗','song-poetry','','[]','吾家世儒業，教子惟一經。',192,'全唐诗/poet.song.89000.json','["吾家世儒業，教子惟一經。", "邇來四十載，父子三成名。", "憶昔塵忝初，非才廁羣英。", "臚傳被殊渥，姓氏落寰瀛。", "天子親識擢，屢對雲龍庭。", "玉音每褒諭，必及吾親寧。", "同朝大明宫，搢紳以爲榮。", "君恩太山重，欲報鴻毛輕。", "迂愚得放逐，不復嘆飄零。", "爾今又登第，相去纔九齡。", "勤勞酬素志，烜赫振家聲。", "箕裘端不墜，義方益芬馨。", "季弟亦鄉選，來年試春卿。", "雲鴻繼高舉，桂苑同飛鳴。", "子壯可起家，予衰欲歸耕。", "勉哉脩遠業，正值時休明。"]'),
('eb58887e-5905-49b7-9801-26cd19b02c3c','戲成短歌從志宏求芍藥','李綱','宋','宋诗','song-poetry','','[]','東風不隔沙陽僻，嫩蘂濃花自春色。',80,'全唐诗/poet.song.89000.json','["東風不隔沙陽僻，嫩蘂濃花自春色。", "栟櫚也是可憐人，每送梁谿慰愁寂。", "邇來芍藥已盛開，供花未到吾須覓。", "賦梅豈害廣平剛，乞醯更覺微生直。", "爲將爛熳數枝紅，伴我淋漓一丸墨。"]'),
('9247d0b3-4046-4e27-b4ee-30a314bf54d0','志宏供芍藥且以詩來再賦前韻','李綱','宋','宋诗','song-poetry','','[]','誰道心閑緣地僻，夢裏何嘗有空色。',80,'全唐诗/poet.song.89000.json','["誰道心閑緣地僻，夢裏何嘗有空色。", "小窗一枕覺來時，燕語鶯啼春寂寂。", "忽思春盡芍藥開，賦詩試與幽人覓。", "短篇纔去花已來，却愧詩詞太狂直。", "嫣然數朵玉樓春，何似江南穪落墨。"]'),
('20ea3f33-c5a3-4875-947b-3b7adff97d78','次韻羅丈留寶峰長老之作','李綱','宋','宋诗','song-poetry','','[]','至行孤高金不堅，犀顱鶴骨自巉然。',32,'全唐诗/poet.song.89000.json','["至行孤高金不堅，犀顱鶴骨自巉然。", "寶峰即是如如體，何用歸休更覓禪。"]'),
('187beb50-48e6-4de0-8470-5d92c5c1af6e','羅疇老所藏李伯時畫馬圖二首 蕃馬','李綱','宋','宋诗','song-poetry','','[]','邊人牧馬如牧羊，羣族散置初無傷。',160,'全唐诗/poet.song.89000.json','["邊人牧馬如牧羊，羣族散置初無傷。", "妙哉龍眠筆有眼，作此冀北才而臧。", "素紈盈尺十二匹，骨相毛物皆非常。", "青驄紫燕五色滿，騂騏騮駱駰驪黄。", "旁行側睨復迴顧，矯首奮鬛嘶風霜。", "背馳正立盡變態，意氣磊落如騰驤。", "想當盤礴初運思，工與造物爭毫芒。", "此中念慮詎可熟，至言發藥誠難忘。", "從此絕筆不畫馬，但寫妙相依圓光。", "斯人于今又黄土，斯畫可寶宜珍藏。"]'),
('9da5a3a1-034e-440a-9c06-03f824b57a2a','羅疇老所藏李伯時畫馬圖二首 御馬','李綱','宋','宋诗','song-poetry','','[]','房星之精下天駟，産此騏驎奉天子。',128,'全唐诗/poet.song.89000.json','["房星之精下天駟，産此騏驎奉天子。", "龍媒徠自大宛城，汗血生從渥洼水。", "那知妙手居合淝，筆端能出神俊姿。", "顧視清高氣深穏，志意俶儻精權奇。", "蘭筋秀骨連錢直，細毛蕭捎豐頰臆。", "金鞿絡首牽奚官，自中伏波銅馬式。", "一疋駐立一疋行，坐看千載風雲生。", "鸞旗在前屬車後，雖有絕足何由呈。"]'),
('b55f730b-1aaf-4b8b-99e8-87909658e3bf','從志宏求芭蕉','李綱','宋','宋诗','song-poetry','','[]','小圃初宜夏，靈蕉日日新。',48,'全唐诗/poet.song.89000.json','["小圃初宜夏，靈蕉日日新。", "輕風搖鳯尾，疏雨濕青巾。", "結蔭留嘉客，移根許散人。", "軒中拙居士，默對欲觀身。"]'),
('6f1ad62d-f298-462a-aa8a-81e2296c007e','松架','李綱','宋','宋诗','song-poetry','','[]','羈旅隨緣即道場，採松結架障斜陽。',64,'全唐诗/poet.song.89000.json','["羈旅隨緣即道場，採松結架障斜陽。", "摧殘自带青青色，森爽猶傳細細香。", "佛氏解將華作界，騷人愛把葯爲房。", "我遊法藏酬初志，宜得蒼官助蔭凉。"]'),
('91a2cccd-0dd0-4bbb-a2da-f27c7846ea00','再賦芭蕉','李綱','宋','宋诗','song-poetry','','[]','带雨移根潤，驚雷展卷新。',48,'全唐诗/poet.song.89000.json','["带雨移根潤，驚雷展卷新。", "清陰浸白氎，碧色照烏巾。", "戒酒盃翻葉，揮風扇傍人。", "幽姿隨處好，休問不堅身。"]'),
('300aa2a3-3e3e-423e-bdd2-63f64d1c88b5','次韻志宏贈丹霞師','李綱','宋','宋诗','song-poetry','','[]','傾蓋相逢亦有緣，那堪心契更同年。',64,'全唐诗/poet.song.89000.json','["傾蓋相逢亦有緣，那堪心契更同年。", "六根凈處三生現，一點通時萬法全。", "蓮社子能知舊侣，香山我亦學癯仙。", "丹霞妙悟思良覿，千偈瀾翻看湧泉。"]'),
('5cf37b40-ea56-48bb-b269-bc2893c0ace4','葺西軒已畢工奉呈志宏成彦','李綱','宋','宋诗','song-poetry','','[]','華藏千函得縱觀，莊嚴聊使道場安。',64,'全唐诗/poet.song.89000.json','["華藏千函得縱觀，莊嚴聊使道場安。", "巧遮斜日青松架，旋植新花紅藥欄。", "彈指寶樓開處速，遊心法界到時寛。", "含容萬象猶餘地，須作毘盧丈室看。"]'),
('fac5db70-c0e8-4074-8744-eb62a2d0eb56','次韻疇老贈丹霞三篇并寄丹霞以代簡書 送次丹霞歸瑞光巖韻 其一','李綱','宋','宋诗','song-poetry','','[]','太虚元湛寂，妙用起雲雷。',24,'全唐诗/poet.song.89000.json','["太虚元湛寂，妙用起雲雷。", "若解明如鏡，何須冷似灰。"]'),
('72fa6ff5-254d-4581-bb63-5302a29d8dd4','次韻疇老贈丹霞三篇并寄丹霞以代簡書 送次丹霞歸瑞光巖韻 其二','李綱','宋','宋诗','song-poetry','','[]','不能汲水機圓，自笑翻羮手捩。',28,'全唐诗/poet.song.89000.json','["不能汲水機圓，自笑翻羮手捩。", "願從明眼高人，爲看三生寶地。"]'),
('c7d71e23-cf60-4f32-9cab-cde4819d9ab4','次韻疇老贈丹霞三篇并寄丹霞以代簡書 次自警示丹霞韻','李綱','宋','宋诗','song-poetry','','[]','佛法如滄溟，深廣初無底。',120,'全唐诗/poet.song.89000.json','["佛法如滄溟，深廣初無底。", "欲以蠡測之，望洋顙已泚。", "我生乃虚幻，瀛渤一漚起。", "安得具眼人，爲發無生理。", "丹霞古禪伯，一派曹溪水。", "出岫或雲行，遇坎亦淵止。", "諦觀古文詩，相識佳句裏。", "聞風欲見之，踴躍不能已。", "豐巖距平津，飛錫片時耳。", "願將雪澡心，試聽風生齒。"]'),
('b7ed804e-6664-4be7-849d-caf8e5010930','移花','李綱','宋','宋诗','song-poetry','','[]','幽人憐我葺幽軒，爲植名花滿檻前。',32,'全唐诗/poet.song.89000.json','["幽人憐我葺幽軒，爲植名花滿檻前。", "須信人窮天未厭，炎暉變作養花天。"]'),
('ec9c8b17-793f-4426-8e45-442114d0a2d3','志宏送石菖蒲乃菖陽也作此詩以戲之','李綱','宋','宋诗','song-poetry','','[]','石上菖蒲何所擬，虬然連絡龍蛇尾。',96,'全唐诗/poet.song.89000.json','["石上菖蒲何所擬，虬然連絡龍蛇尾。", "寸餘九節痩根莖，能輔五臓堅髪齒。", "清泉白石養案間，璀璨芬芳誠可喜。", "子於何處得此本，葉大根粗恐非是。", "乞隣豈誤進菖陽，遺我還將比芹子。", "物雖非是意已勤，且置盆中浸寒水。"]'),
('51ed10e5-b19e-4f26-9447-da9850c8aca7','興宗許借盆荷以詩索之','李綱','宋','宋诗','song-poetry','','[]','隱圃清和夏景初，小盆荷芰已扶疏。',64,'全唐诗/poet.song.89000.json','["隱圃清和夏景初，小盆荷芰已扶疏。", "借公瓦沼開花種，伴我松軒晏坐餘。", "斷取當如妙喜國，莊嚴且作化人居。", "秋風幻出芙蕖後，來去須觀本一如。"]'),
('5868b43a-c3cc-4cdc-ac0c-1ca8d78f87c6','志宏見和西軒詩再賦前韻','李綱','宋','宋诗','song-poetry','','[]','休將內外别遊觀，一處安時在處安。',64,'全唐诗/poet.song.89000.json','["休將內外别遊觀，一處安時在處安。", "畫虎若成那類狗，牧羊已熟不須欄。", "芥瓶歷歷光明現，華藏重重境界寛。", "笑指庭前花樹子，爲言欲作麽生看。"]'),
('2c4021b9-7541-4bbc-b316-5041f230c249','次符讀書城南韻','李綱','宋','宋诗','song-poetry','','[]','騄驥有駿足，調御始服輿。',288,'全唐诗/poet.song.89000.json','["騄驥有駿足，調御始服輿。", "天資已髙邁，淬礪資羣書。", "敏學復好問，端由方寸虛。", "超然適正道，克慎在厥初。", "百家見異户，六藝知同閭。", "愽觀而妙柬，奥義將燦如。", "纖繳下雲鵠，沈鈎出淵魚。", "精思理難遯，篤志道匪疏。", "溉根食其實，浚源導成渠。", "反已類學射，求心猶放豬。", "精英謝糟粕，光景走蟾蜍。", "寸陰寶尺璧，旨味勝浮蛆。", "是中苟得趣，何適不可居。", "問言何以然，得之在學歟。", "譬猶大農家，豐年多蓄儲。", "人皆升斗窘，已獨倉箱餘。", "自飽以及衆，愽施誠樂且。", "文章乃餘事，筆墨爲耕鋤。", "當爲丹山鳯，勿作黔中驢。", "本末固有序，未菑那得畬。", "致身霄漢上，登降白玉除。", "朱雲既折檻，辛毘亦牽裾。", "愛君當以誠，危言豈邀譽。", "自古富貴者，磨滅同丘墟。"]'),
('8a729bbe-11af-4914-9328-8c8f12ce24ad','志宏供筍以詩報之','李綱','宋','宋诗','song-poetry','','[]','琅玕爲竹鐵爲鞭，長就新萌本類拳。',64,'全唐诗/poet.song.89000.json','["琅玕爲竹鐵爲鞭，長就新萌本類拳。", "味旨不須甜說蜜，膚腴更覺軟勝綿。", "錦䙀與脫重重縛，玉版來參的的禪。", "知子供予端有意，欲教蔬食學神仙。"]'),
('ebb1cadd-beb8-4dab-8adb-bab1edc34d43','早起','李綱','宋','宋诗','song-poetry','','[]','平時懶惰只隨緣，日照堂東尚栩然。',64,'全唐诗/poet.song.89000.json','["平時懶惰只隨緣，日照堂東尚栩然。", "華藏欲遊須勇猛，繐帷雖好莫留連。", "收將枕上黄粱夢，印取心中大覺仙。", "從此寓軒須早作，魔軍未破可安眠。"]'),
('4c014cc1-c930-459b-ac63-96120c92fa65','黄道夫惠紙','李綱','宋','宋诗','song-poetry','','[]','文房嘉楮製敲冰，遺我千番得未曾。',64,'全唐诗/poet.song.89000.json','["文房嘉楮製敲冰，遺我千番得未曾。", "敢比蠻牋修五鳯，願將綺語讚三乘。", "金花乍覺毫端滑，玉版尤宜墨點凝。", "只恐多言空費紙，更將文弔剡谿藤。"]'),
('8949d2bf-e842-47e6-9ed6-c7851ca4e520','吴親寄甆枕香罏頗佳以詩答之 甆枕','李綱','宋','宋诗','song-poetry','','[]','遠投瓦枕比瓊瑜，方暑清凉愜慢膚。',64,'全唐诗/poet.song.89000.json','["遠投瓦枕比瓊瑜，方暑清凉愜慢膚。", "瑩滑色侵蘄竹簟，玲瓏光照愽山罏。", "便便何必書爲笥，栩栩方將蝶夢吾。", "枕上片時聊適志，黄粱未熟到東吳。"]'),
('f261b38e-c1ba-43ab-a7e2-9eb1b17f8bfe','吴親寄甆枕香罏頗佳以詩答之 甆罏','李綱','宋','宋诗','song-poetry','','[]','華藏初遊願力堅，寶罏已現佛陀前。',64,'全唐诗/poet.song.89000.json','["華藏初遊願力堅，寶罏已現佛陀前。", "神通何似維摩詰，熏習聊同白樂天。", "沈水香焚煙縷細，卷雲花透月輪圓。", "愧煩遠示將何用，聊伴虚堂晏坐禪。"]'),
('0e28442e-774d-4ace-9989-46e5440c07fd','鄧成彦供茉莉以詩答之','李綱','宋','宋诗','song-poetry','','[]','芳花遺我比瓊瑰，慚愧幽人自壅培。',64,'全唐诗/poet.song.89000.json','["芳花遺我比瓊瑰，慚愧幽人自壅培。", "名字曾於佛書見，色香今入寓軒來。", "旋妝彫檻修清供，更促繁英使早開。", "須信莊嚴資衆力，道場化作雨華臺。"]'),
('9bf22faf-7db7-48f8-9f28-df5454174d67','平津閣望雨','李綱','宋','宋诗','song-poetry','','[]','平津景物晚依依，正是梅黄麥秀時。',64,'全唐诗/poet.song.89000.json','["平津景物晚依依，正是梅黄麥秀時。", "雲氣遮山來驟雨，水痕侵石漲湍谿。", "蒹葭带渚披離葉，松柏連山鼓舞枝。", "遷客不堪流落恨，憑髙北望意凄洏。"]'),
('363f742a-bcf2-4ffb-9198-188d9e3d9039','次韻題樂全庵贈鄧季明','李綱','宋','宋诗','song-poetry','','[]','寓形天壌間，自適乃其至。',216,'全唐诗/poet.song.89000.json','["寓形天壌間，自適乃其至。", "放懷得山林，肯逐市朝醉。", "舉世競紛華，誰識靜中意。", "澄清謝泥滓，淘汰見精粹。", "遊心無何鄉，養此浩然氣。", "猗歟樂全翁，於世寡所嗜。", "築菴以自居，方丈含大地。", "請問菴中人，其樂何由全。", "萬物備我身，不以人滅天。", "南畝豐可飽，北窗凉可眠。", "尚友古之人，聖賢存簡編。", "有時自種植，百卉爭芳妍。", "賓來聊一醉，醉中亦逃禪。", "鷄鶩自擾擾，獨鶴方雲騫。", "嗟予幸相見，一見即忘年。", "但愧聞道晚，敢懷著鞭先。", "何當歸梁谿，耒耜買一鄽。", "卜居學夫子，相望兩蕭然。"]'),
('8cd68a54-2fd5-421b-a8cb-6b0e409b926e','次韻題棣華堂','李綱','宋','宋诗','song-poetry','','[]','沙陽地僻有幽人，三樂高懷自壯辰。',64,'全唐诗/poet.song.89000.json','["沙陽地僻有幽人，三樂高懷自壯辰。", "雛鳯已聞棲郄桂，棣華更祝壽莊椿。", "家餘美醸時觴客，手植名花日賞春。", "借問市朝耽戀者，何如雲水自由身。"]'),
('f81f79b3-f481-4d07-b59d-91dd6c1ed672','陳興宗供茉莉','李綱','宋','宋诗','song-poetry','','[]','幽人蕭散省諸緣，也解栽花滿檻前。',64,'全唐诗/poet.song.89000.json','["幽人蕭散省諸緣，也解栽花滿檻前。", "羞把天姿爭媚景，故將清格占炎天。", "毗耶遣化來香積，隱圃移根入寓軒。", "多謝莊嚴修妙供，願熏芬馥散無邊。"]'),
('2340bcb1-a9cc-4052-8540-42dee90fc11a','季明惠含笑花其香滿室以詩報之','李綱','宋','宋诗','song-poetry','','[]','奇葩爲我摘芳條，一笑嫣然特地嬌。',64,'全唐诗/poet.song.89000.json','["奇葩爲我摘芳條，一笑嫣然特地嬌。", "花露玉顔誠巧倩，葉堆雲鬢愈妖嬈。", "韜藏妙質踰三月，噴洩清香在一朝。", "更把綵絲纒綠萼，肯教芳馥片時銷。"]'),
('6320f56f-54c1-49d1-a88c-f9eda895fbef','螢火','李綱','宋','宋诗','song-poetry','','[]','雨過禪房夜氣清，濕螢無數自宵行。',64,'全唐诗/poet.song.89000.json','["雨過禪房夜氣清，濕螢無數自宵行。", "光穿竹樹來還去，影照池塘滅復明。", "飛學流星疑有意，岀因腐草本無情。", "暫時熠燿休憑夜，敢傍長空曉日征。"]'),
('4de1a982-e37e-488f-a6a0-2bb7a7c1e4ca','泛碧齋詩','李綱','宋','宋诗','song-poetry','','["\u897f\u6e56"]','畫齋初泛碧谿潯，十里津平疊翠岑。',64,'全唐诗/poet.song.89000.json','["畫齋初泛碧谿潯，十里津平疊翠岑。", "拍岸煙波梅雨細，連天芳草嶺雲深。", "愧煩斷取西湖景，暫慰傾思北闕心。", "好是清霄山吐月，水光天影共沈沈。"]'),
('4daa1d61-6149-4179-bec7-d8d4759f9219','次韻志宏見贈拙軒','李綱','宋','宋诗','song-poetry','','[]','梁谿之拙天下絕，六年出入黄金闕。',288,'全唐诗/poet.song.89000.json','["梁谿之拙天下絕，六年出入黄金闕。", "太官珍膳厭羶肥，謫墮沙陽甘筍蕨。", "胸中空洞何所有，羞逐緇塵事奔走。", "鷦鷯本是棲一枝，鮒魚何用求升斗。", "翻羮觸諱拙誰如，悻悻還慚淺丈夫。", "小軒燕處聊自榜，方丈迥覺含空虚。", "簿書粗了多暇日，坐看日光搖霽隙。", "百年銷沒向此中，金玉滿堂何所益。", "不如便作逍遙人，富貴於我如浮雲。", "欲知內外孰輕重，何翅鴻毛與萬鈞。", "平生習氣未能已，更續春秋修舊史。", "馬遷忍恥託空文，欲洗前非徒費水。", "虞卿歸隱亦著書，筆墨自可爲歡娱。", "心閑意到時一掃，何用寸寸參釐銖。", "擴然無事還面壁，禪悅爲牀法爲食。", "月光照破客塵空，那有絲毫掛欣戚。", "栟櫚好學今所無，返從拙者來問途。", "拙翁已拙更何說，萬里清風一輪月。"]'),
('88a660b5-c30b-4efa-a8e6-fbfb2520a7a8','題吏隱軒','李綱','宋','宋诗','song-poetry','','[]','紛紛吏事何時已，隨掃隨生畏首尾。',128,'全唐诗/poet.song.89000.json','["紛紛吏事何時已，隨掃隨生畏首尾。", "那知動靜不相關，安用杜門并洗耳。", "曾侯作軒治丞事，鴈鶩成行亦衣紫。", "偷閒掃溉哦其間，壁記當須倩韓子。", "榜之吏隱名者誰，梁谿拙翁前柱史。", "蕭然一室自可人，况有明窗兼凈几。", "隱中涵養得佳趣，致遠自應從兄起。", "王良伯樂世豈無，騕褭驊騮日千里。"]'),
('cc23fd9a-d0ed-475b-82d4-ef3b32499569','寄陸敦禮二首','李綱','宋','宋诗','song-poetry','','[]','晉河太守况如何，日對溪山醉綺羅。',64,'全唐诗/poet.song.89000.json','["晉河太守况如何，日對溪山醉綺羅。", "肯念舊僚今逐客，强傾濁酒只悲歌。", "聞說長橋跨海涯，碧天影浸白虹垂。", "自嗟羈束無因到，乞取君謨大字碑。"]'),
('c93014e7-c811-4aaf-ac01-eefb63761cc4','聞仲輔弟自陳便親得南康軍逍遙觀','李綱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','宦遊方壯已抽身，始驗從來嬾是真。',64,'全唐诗/poet.song.89000.json','["宦遊方壯已抽身，始驗從來嬾是真。", "未看昂霄摩遠翮，且將戲綵慰偏親。", "我當放逐離羣日，爾作逍遙自在人。", "恩貸何時聽從便，廬山同作遠公賓。"]'),
('b96fc71e-e8ac-409f-a2e6-c570e600c2a1','重午','李綱','宋','宋诗','song-poetry','','[]','誰將佳節號天中，陽極陰生五自重。',64,'全唐诗/poet.song.89000.json','["誰將佳節號天中，陽極陰生五自重。", "角黍但能娱幼稚，綵絲那得制蛟龍。", "千年沉汨英靈在，萬里浮菖習俗同。", "逐客有家歸未得，滿懷離恨寄南風。"]'),
('e35ee9d4-e877-4ccd-bdf2-7bceb55c4ec1','志宏遺枯梅産芝','李綱','宋','宋诗','song-poetry','','[]','子家積慶芝自生，紫雲爲葉金爲莖。',64,'全唐诗/poet.song.89000.json','["子家積慶芝自生，紫雲爲葉金爲莖。", "世間美瑞子不有，分以遺我鴻毛輕。", "煌煌秀色照軒檻，猶带雨露凄芳馨。", "當留几案永爲好，他日煮食驅三彭。"]'),
('7d552b32-1cbd-4cfb-b7ad-743fcfe4812a','讀四家詩選四首 子美','李綱','宋','宋诗','song-poetry','','[]','杜陵老布衣，饑走半天下。',132,'全唐诗/poet.song.89000.json','["杜陵老布衣，饑走半天下。", "作詩千萬篇，一一干教化。", "是時唐室卑，四海事戎馬。", "愛君憂國心，憤發幾悲咤。", "孤忠無與施，但以佳句寫。", "風騷到屈宋，麗則凌鮑謝。", "筆端籠萬物，天地入陶冶。", "豈徒號詩史，誠足繼風雅。", "使居孔氏門，寧復稱賜也。", "殘膏與賸馥，霑足沽丐者。", "嗚呼詩人師，萬世誰爲亞。"]'),
('7bc6337a-9caf-47b4-ad6b-262b979a4d79','讀四家詩選四首 永叔','李綱','宋','宋诗','song-poetry','','[]','廬陵間世才，妙手歸大匠。',132,'全唐诗/poet.song.89000.json','["廬陵間世才，妙手歸大匠。", "文章振古風，獨立無與兩。", "詩篇尤藻麗，句法含萬象。", "平夷謝雕鐫，醇厚如醖醸。", "温温廊廟姿，不作窮愁相。", "平生蹈難危，利口困讒謗。", "終焉自光明，學者共師仰。", "每詩必言歸，耕釣箕潁上。", "但欲風波息，豈是事高尚。", "收身及未老，六一聊隱放。", "九原如可作，非公復誰嚮。"]'),
('bcdabad2-189a-4c45-b56d-8e0ffd9cc744','讀四家詩選四首 退之','李綱','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','昌黎文章伯，乃是聖人耦。',144,'全唐诗/poet.song.89000.json','["昌黎文章伯，乃是聖人耦。", "傳道自孟軻，淵源極師友。", "雄詞障百川，偉論掛衆口。", "餘事付詩篇，雅健古無有。", "尤工用險韻，妥貼等妍醜。", "毅然倔强姿，揮此摩天手。", "立朝著大節，去作潮陽守。", "驅掃雲霧開，約束鮫鰐走。", "位雖不稱德，妙譽垂不朽。", "譬猶觀泰山，羣嶺皆培塿。", "又如衆星中，錯落仰北斗。", "籍湜何足云，齊名豈其柳。"]'),
('71ba1e5a-ee21-4efb-8377-97abee24a12f','讀四家詩選四首 太白','李綱','宋','宋诗','song-poetry','','[]','謫仙乃天人，薄遊人間世。',132,'全唐诗/poet.song.89000.json','["謫仙乃天人，薄遊人間世。", "詞章號俊逸，邁往有英氣。", "明皇重其名，召見如綺季。", "萬乘尚僚友，公卿何介蔕。", "脫靴使將軍，故自非因醉。", "乞身歸舊隱，來去同一戲。", "沈吟紫芝歌，緬邈青霞志。", "笑著宫錦袍，江山聊傲睨。", "肯從永王璘，此事不須洗。", "垂天賦大鵬，端爲真隱子。", "神遊八極表，捉月初不死。"]'),
('ef7a0c82-e127-4269-9d8e-70b9261d4882','夜坐觀書','李綱','宋','宋诗','song-poetry','','[]','銅漏丁丁雜雨聲，夜凉兀坐已三更。',32,'全唐诗/poet.song.89000.json','["銅漏丁丁雜雨聲，夜凉兀坐已三更。", "十年奔走成何事，依舊韋編對短檠。"]'),
('171d03b8-52bb-4678-96ed-c8635dabd3e7','讀李長吉詩','李綱','宋','宋诗','song-poetry','','[]','長吉工樂府，字字皆雕鎪。',60,'全唐诗/poet.song.89000.json','["長吉工樂府，字字皆雕鎪。", "騎驢適野外，五藏應爲愁。", "得句乃足成，還有理致不。", "嘔心古錦囊，絕筆白玉樓。", "遺篇止如此，歎息空搔頭。"]'),
('8a28e24b-8516-4193-89ab-105e6075779c','讀孟郊詩','李綱','宋','宋诗','song-poetry','','[]','我讀東野詩，因知東野心。',156,'全唐诗/poet.song.89000.json','["我讀東野詩，因知東野心。", "窮愁不出門，戚戚較古今。", "腸饑復號寒，凍折西床琴。", "寒苦吟亦苦，天光爲沈陰。", "退之乃詩豪，法度嚴已森。", "雄健日千里，光鋩長萬尋。", "乃獨喜東野，譬猶冠待簪。", "韓豪如春風，百卉開芳林。", "郊窮如秋露，候蟲寒自吟。", "韓如鏘金石，中作韶濩音。", "郊如擊土鼓，淡薄意亦深。", "學韓如可樂，學郊愁日侵。", "因歌遂成謠，聊以爲詩箴。"]'),
('b886055f-b7c7-47cd-a416-4696a1efa8b4','足成夢中','李綱','宋','宋诗','song-poetry','','[]','本來佛法無多子，正覺菩提彈指超。',32,'全唐诗/poet.song.89000.json','["本來佛法無多子，正覺菩提彈指超。", "誰信曹谿一滴水，流歸法海作全潮。"]'),
('2e257d48-cb86-4752-86d9-d083b727cfd5','紙筆墨盡戲成','李綱','宋','宋诗','song-poetry','','[]','我生飄泊苦西東，四子相逐半世中。',64,'全唐诗/poet.song.89000.json','["我生飄泊苦西東，四子相逐半世中。", "越楮如雲隨散滅，絳玄終日困磨礲。", "禿憐毛穎頻遭斥，靜愛陶泓解困窮。", "一笑寓軒無所有，本來文字相皆空。"]'),
('4f3f1190-e303-4027-8df1-85f21bd7b510','梅雨','李綱','宋','宋诗','song-poetry','','[]','小麥青青梅正黄，連山霧雨濕溪鄉。',64,'全唐诗/poet.song.89000.json','["小麥青青梅正黄，連山霧雨濕溪鄉。", "輕絲嫋嫋搖空界，重滴涓涓響暮廊。", "結集鬱蒸來海嶠，驅排愁恨到禪房。", "寓軒居士心如鐵，默坐惟聞茉莉香。"]'),
('8f883ddf-b187-421b-ba3d-9135bf71645d','初見荷花','李綱','宋','宋诗','song-poetry','','[]','雨過芙蕖滿曲塘，端疑翠蓋擁新粧。',64,'全唐诗/poet.song.89000.json','["雨過芙蕖滿曲塘，端疑翠蓋擁新粧。", "風翻圓碧田田葉，露浥深紅苒苒香。", "根出淤泥成妙凈，氣侵虛閣愈清凉。", "開花不待秋風起，景物依然類浙鄉。"]'),
('3931ba4b-182e-4648-8d30-8223422a7102','志宏以家所生新芝遺予并以詩來次韻報之','李綱','宋','宋诗','song-poetry','','[]','紫芝多産白玉峰，服食益壽增明聰。',160,'全唐诗/poet.song.89000.json','["紫芝多産白玉峰，服食益壽增明聰。", "人間採茹未易得，悵望古曲來悲風。", "那知遠謫見奇物，子家端是慶所鍾。", "煌煌三秀豈難並，玉榦雲葉方成叢。", "嘉祥美瑞不自惜，掇以遺我誠由中。", "甘芳勝菌滑勝乳，能殺三尸驅九蟲。", "童顔瞭視駐可久，墮髪落齒生應重。", "嗟予迂疏與世闊，得食此物誰之功。", "商山儻可追四皓，淮南安用尋八公。", "驂鸞控鶴吾未暇，千里白雲聊與同。"]'),
('8bc9bdb5-c856-4095-b703-30eca6e50e14','疇老修撰所藏華嶽衡嶽圖 華嶽','李綱','宋','宋诗','song-poetry','','["\u534e\u5c71"]','往年跨馬觀羌戌，道歷太華西臨雍。',240,'全唐诗/poet.song.89000.json','["往年跨馬觀羌戌，道歷太華西臨雍。", "偉哉造化巧凝結，元氣孕此金芙蓉。", "平原陡起三萬仞，峻屏卻略羅秋空。", "巍然雄尊鎮西極，衆山班列如朝宗。", "天池瀲灩噴山頂，瀉作瀑布飛長虹。", "亭亭僊掌摩碧落，曉日照耀五指紅。", "巨靈贔屓運神力，導河擘華留其蹤。", "煙寒風遠張超谷，霞駮霧開毛女峰。", "希夷故隱今尚在，白雲依舊時東封。", "回頭一别二十載，不意見之圖畫中。", "生綃六幅掛清晝，隱耳颯颯聞松風。", "山中草木舊相識，恍如夢到雲臺宫。", "神遊絕巘窺玉井，欲取蓮藕根株通。", "好奇何必似韓子，懸崖側足悲途窮。", "從公傳此嶽真相，永結清好無時終。"]'),
('13b3814c-29c5-4d4e-b09e-877a0c54fad1','疇老修撰所藏華嶽衡嶽圖 衡嶽','李綱','宋','宋诗','song-poetry','','["\u534e\u5c71", "\u8861\u5c71"]','五嶽分奠如循環，作鎮南服惟衡山。',240,'全唐诗/poet.song.89000.json','["五嶽分奠如循環，作鎮南服惟衡山。", "炎方荒絕亘滄海，天付雄柄司神姦。", "祝融騰擲倚霄漢，羣峰邐迤猶堂壇。", "贊襄一氣洩雲雨，蟠據千里來荆蠻。", "屹然天地物最鉅，造化凝結良艱難。", "恭聞兹嶽魏夫人，羽駕白日遊山樊。", "翛翛雲氣變異色，笙竽聲雜環珮珊。", "神仙恍惚未易測，落花流水空潺潺。", "退之倔强古亦少，故取竄謫窺孱顔。", "精神默禱若有應，驅掃氛翳開煙鬟。", "乃知正直神所與，露奇呈巧初不慳。", "嗟予平生好山水，欲以兩足窮躋攀。", "恨兹覊束未能往，幽覿眇然圖畫間。", "何當身逐鴈同到，已覺心與雲俱閒。", "軒轅彌明儻未死，相與遊戲超塵寰。"]'),
('d7bfd6c4-d240-4e3d-bb4a-0b868683a8b3','與邑官會凝翠閣','李綱','宋','宋诗','song-poetry','','[]','屹然高閣虚且通，溪山增秀來薫風。',224,'全唐诗/poet.song.89000.json','["屹然高閣虚且通，溪山增秀來薫風。", "皆云閩境似此少，豈但爲最沙陽中。", "棟楹顯敞制度巧，飾以黝白非青紅。", "七峰倒景蘸層碧，十里平津流向東。", "連山松檜鬱葱蒨，一溪煙雨寒冥濛。", "沈沈月彩照清夜，漠漠雲影搖蒼穹。", "眼光到處色皆翠，凝結至今勞化工。", "幾年落寞顧眄地，拈出始知觀覧雄。", "開筵置酒共臨賞，正暑景物生秋容。", "畫船笳吹助清咽，津岸擊鼓聲逢逢。", "世間萬事非偶爾，成此一段傳無窮。", "我歸三子子歸我，畢竟假合誰之功。", "人生會合自可樂，且須吸盡玻瓈鍾。", "他時追憶如夢寐，一笑勝游回首空。"]'),
('6ac70b75-86b3-4ad0-bc65-fd0da35b1484','偶題二首  其一','李綱','宋','宋诗','song-poetry','','[]','金僊實語教觀空，老氏微言戒知足。',64,'全唐诗/poet.song.89000.json','["金僊實語教觀空，老氏微言戒知足。", "生前能著幾兩屐，安用胡椒八百斛。", "此身猶自是蘧廬，身外何須寶金玉。", "一衣一食便有餘，從此梁谿須窒欲。"]'),
('7ceba675-a3be-4328-961c-4f16b87509c4','偶題二首  其二','李綱','宋','宋诗','song-poetry','','[]','退之呵佛乃知佛，王莽崇儒豈信儒。',32,'全唐诗/poet.song.89000.json','["退之呵佛乃知佛，王莽崇儒豈信儒。", "救弊自須煩詆毁，即真安用假詩書。"]'),
('0ca523b9-66da-488d-a20b-cdedb777f262','寄吴元中給事','李綱','宋','宋诗','song-poetry','','[]','千里同風一念間，琳宫筦庫等爲閒。',64,'全唐诗/poet.song.89000.json','["千里同風一念間，琳宫筦庫等爲閒。", "高懷自遂全三樂，懵學于今見一斑。", "顧我望雲惟陟岵，羨公戲彩日承顔。", "何時恩許歸終飬，因得扁舟事往還。"]'),
('204c4c14-fb2e-4795-9847-24e799f8838d','寄顧子美提舉','李綱','宋','宋诗','song-poetry','','[]','聞說年來亦失官，高懷應作等閒看。',64,'全唐诗/poet.song.89000.json','["聞說年來亦失官，高懷應作等閒看。", "儻來本自非吾有，既往何須更返觀。", "問舍梁谿欣共里，寄聲閩嶺慰南冠。", "請公學取安心法，一點安時在處安。"]'),
('7ae2d51b-a9e4-4a9e-949b-b36e29176d5e','絕句','李綱','宋','宋诗','song-poetry','','[]','斷雲飛雨過溪來，簷溜蕭蕭瀉暮階。',32,'全唐诗/poet.song.89000.json','["斷雲飛雨過溪來，簷溜蕭蕭瀉暮階。", "一餉清凉驅熱惱，可憐襟抱向誰開。"]'),
('88dd6dd4-ef94-4004-999a-6b6e9053038e','次韻羅修撰古風','李綱','宋','宋诗','song-poetry','','[]','衡嶽臨清湘，欲往吾無航。',240,'全唐诗/poet.song.89000.json','["衡嶽臨清湘，欲往吾無航。", "側身長太息，心逐鴈南翔。", "洪河擘太華，欲往吾無馬。", "何當御風游，揮手與世謝。", "公家藏二圖，尤物伴閒暇。", "那知造化工，寓此粉墨假。", "一見慰我心，試使畫工寫。", "崢嶸峻極姿，慘澹生筆下。", "舊遊得窺尋，真賞寄持把。", "輕雲出層峰，飛瀑落高罅。", "川原藹林芿，山崦露臺榭。", "幽討窮雙眸，駐立勞兩骻。", "圖成掛虚堂，秋色忽改夏。", "清風掃凉朝，明月炚深夜。", "恍然疑斷取，無乃資幻化。", "作詩聊謝公，更辱報章灑。", "清新鄙元白，風流追屈賈。", "氣象嶽爭雄，諷玩手忘捨。", "觀圖更得詩，端如飽膾炙。", "什襲藏篋中，光鋩照林野。"]'),
('598746a4-b815-456a-bf8c-79aafbcab0ef','羅修撰寵示龍興老碑刻','李綱','宋','宋诗','song-poetry','','[]','龍興道與右文親，眼照沙陽肯許人。',64,'全唐诗/poet.song.89000.json','["龍興道與右文親，眼照沙陽肯許人。", "師唱宗風非鼓笛，公談實相託冠巾。", "已曾見了何須再，特地拈來卻未真。", "公案分明在碑刻，不煩師子更頻呻。"]'),
('fd7cb4af-e035-4e17-aac6-2f69e1e52083','五月三日夜坐達旦謾成','李綱','宋','宋诗','song-poetry','','[]','凉風振野星河翻，煌煌啓明夜將闌。',96,'全唐诗/poet.song.89000.json','["凉風振野星河翻，煌煌啓明夜將闌。", "孤燈照我不成寢，兀坐更將圖史繙。", "蠧穿編簡眼昏瞀，彫琢肺腎聲嘶酸。", "胡爲疲極浪自苦，中有至樂難爲言。", "窺尋古意偶有得，何翅九奏聞鈞天。", "撥書就枕還自笑，聊此遊戲終吾年。"]'),
('67549145-da34-428c-8dd7-efa9b7b51cd0','季明送南中花木','李綱','宋','宋诗','song-poetry','','[]','悟道方知色即空，樂全深得種花功。',64,'全唐诗/poet.song.89000.json','["悟道方知色即空，樂全深得種花功。", "願從真隱師爲圃，敢意芳根與樂叢。", "陶令欲歸三徑老，海神更借一帆風。", "梁谿異日憑欄處，把酒看花定憶公。"]'),
('100ec5d7-d5da-4834-a310-93dc295ec28e','苦熱行','李綱','宋','宋诗','song-poetry','','[]','南方苦暑殊中州，金遇火伏相拘囚。',208,'全唐诗/poet.song.89000.json','["南方苦暑殊中州，金遇火伏相拘囚。", "飛鳶跕跕草木愁，疑在鑪冶遭蒸烰。", "六龍中天停厥輈，火雲突兀燒高丘。", "炎風如焚汗翻油，祝融嘘呵不肯休。", "赤脚踏冰邈難求，返視絺綌猶狐裘。", "行人病暍喘車牛，雖處廣厦非所庥。", "我欲登彼白玉樓，側身西望心悠悠。", "何當萬里來清秋，其帝少昊神蓐收。", "颯然風露洗我憂，凉生暑退火西流。", "四時代謝如環周，及兹又作徂年謀。", "人生寒暑爲寇讎，何異瘧癘脂髓摉。", "有力負走藏壑舟，朱顔綠髪安可留。", "以靜勝躁聊優游，何必遠期汗漫遊。"]'),
('340d824b-f6cf-4af6-9150-7c07970e67a0','次韻志宏戲興宗耳疾之作','李綱','宋','宋诗','song-poetry','','[]','有病自當醫，無垢何須洗。',120,'全唐诗/poet.song.89000.json','["有病自當醫，無垢何須洗。", "六解一亦亡，動容皆中禮。", "諦觀新卷葉，成此清凈耳。", "悟道得圓通，教體真在此。", "虚含十方界，遐邇初無里。", "鏗然助發機，妙響非外宄。", "天人種種聲，和會歸一已。", "奈何物蔽之，問藥安可止。", "通以智慧刀，濯以功德水。", "是病速須除，慎勿聽鄧子。"]'),
('f76ac8c2-e025-4874-ac5e-f058b87f5d9e','夜坐聞笛','李綱','宋','宋诗','song-poetry','','[]','櫛櫛銀雲點太清，一天風露月華明。',32,'全唐诗/poet.song.89000.json','["櫛櫛銀雲點太清，一天風露月華明。", "數聲何處吹横笛，引起離家去國情。"]'),
('4fcbc066-201a-4422-a1fc-5a26c237d745','同羅疇老鄧季明燕凝翠閣泛碧齋','李綱','宋','宋诗','song-poetry','','[]','法界惟心在處安，勝遊須信得時難。',64,'全唐诗/poet.song.89000.json','["法界惟心在處安，勝遊須信得時難。", "雲峰遠並山峰碧，天影深搖溪影寒。", "去國不知流落恨，親仁且盡笑談歡。", "夜凉風露生舟楫，皓月遙升白玉盤。"]'),
('c11660aa-b18a-42c7-8cf1-d6aab18e6a77','六月十八日同陳興宗鄧成彦志宏早會凝翠閣晚遊泛碧齋','李綱','宋','宋诗','song-poetry','','[]','高閣凝虚翠，虛齋泛碧川。',192,'全唐诗/poet.song.89000.json','["高閣凝虚翠，虛齋泛碧川。", "七峰連秀色，萬户鎖晴煙。", "風物悲遊子，登臨集衆賢。", "伊蒲修淨供，香霧繚芳筵。", "嗜酒陶元亮，狂吟白樂天。", "嫩菱披紫角，新荔擘紅圓。", "文字真清飲，溪山結勝緣。", "畫橋横螮蝀，繡嶺臥蜿蜒。", "落日生氣靄，移舟信泝沿。", "星河光耿耿，風露氣涓涓。", "山吐三更月，人遊半夜船。", "亂螢行熠燿，宿鷺立聯拳。", "盡興忘歸櫂，銜盃約倒蓮。", "乘槎疑犯漢，御氣欲登僊。", "但有詩千首，何妨謫九年。", "深慚二三子，陪我亦蕭然。"]'),
('689ceb39-3c88-479e-98e8-dcf91aa7ae5f','十六日泛舟','李綱','宋','宋诗','song-poetry','','[]','小雨破殘暑，移舟佳致多。',48,'全唐诗/poet.song.89000.json','["小雨破殘暑，移舟佳致多。", "煙嵐遠增翠，雲水暮相和。", "散綺霞依日，搖金月委波。", "勝遊非易得，不飲欲如何。"]'),
('d82a14be-0c72-4ceb-a81e-4c17d77bbb10','七峰詩序 朝陽峰','李綱','宋','宋诗','song-poetry','','[]','先得朝陽一段紅，何年鳴鳯集梧桐。',32,'全唐诗/poet.song.89000.json','["先得朝陽一段紅，何年鳴鳯集梧桐。", "歸舟行到灣環處，知是沙溪第一峰。"]'),
('e82eb602-ea02-4a1e-a7c2-e59566938013','七峰詩序 碧雲峰','李綱','宋','宋诗','song-poetry','','[]','落日銜山隱半輪，桑榆殘照起遊氛。',32,'全唐诗/poet.song.89000.json','["落日銜山隱半輪，桑榆殘照起遊氛。", "佳人悵望何時見，萬里平凝合碧雲。"]'),
('875d66a8-4d8e-4953-8a8b-9739ea910e60','七峰詩序 妙高峰','李綱','宋','宋诗','song-poetry','','[]','疊嶪層巒枕碧流，七峰此地最奇幽。',32,'全唐诗/poet.song.89000.json','["疊嶪層巒枕碧流，七峰此地最奇幽。", "登臨若會妙高意，便識德雲真比丘。"]'),
('05b2ed4f-d706-4176-838b-71ee68617df0','七峰詩序 真隱峰','李綱','宋','宋诗','song-poetry','','[]','杳靄青松映白雲，地靈境寂好棲神。',32,'全唐诗/poet.song.89000.json','["杳靄青松映白雲，地靈境寂好棲神。", "結廬占盡溪山景，安得超然真隱人。"]'),
('4c757756-b8a1-4a80-be62-b54c02a2bbbf','七峰詩序 桂華峰','李綱','宋','宋诗','song-poetry','','[]','桂華歲歲吐秋風，香滿溪城十里中。',32,'全唐诗/poet.song.89000.json','["桂華歲歲吐秋風，香滿溪城十里中。", "怪底士夫多折得，移根初自廣寒宫。"]'),
('e9cf0b46-229a-4819-9194-af937ddf530b','七峰詩序 凝翠東峰','李綱','宋','宋诗','song-poetry','','[]','兩峰凝翠對飛簷，缺處青岑出遠尖。',32,'全唐诗/poet.song.89000.json','["兩峰凝翠對飛簷，缺處青岑出遠尖。", "暮雨朝雲時點綴，何須畫棟與珠簾。"]'),
('4fa64640-5b54-40a9-aec3-be40df85fcee','七峰詩序 凝翠西峰','李綱','宋','宋诗','song-poetry','','[]','翠峰高閣兩相宜，獨倚闌干注目時。',32,'全唐诗/poet.song.89000.json','["翠峰高閣兩相宜，獨倚闌干注目時。", "休問江山非故國，且將爽氣慰梁谿。"]'),
('851e257f-08b1-4fcb-910e-60226cdd877f','七峰詩序 太史溪','李綱','宋','宋诗','song-poetry','','[]','平溪淥靜見遊魚，十里無聲若畫圖。',32,'全唐诗/poet.song.89000.json','["平溪淥靜見遊魚，十里無聲若畫圖。", "但道曾經太史愛，不須汙染目爲愚。"]'),
('5e0a28b5-a4f8-4e71-9111-3ffc7787eeb5','次韻志宏泛碧齋會連飲三罸爵','李綱','宋','宋诗','song-poetry','','[]','占得溪山作散僊，更欣佳客許邀延。',64,'全唐诗/poet.song.89000.json','["占得溪山作散僊，更欣佳客許邀延。", "醉紅豈解勝文字，舉白還能樂聖賢。", "序飲我方追柳子，賦詩子已過劉顛。", "亂雲細細無情致，不放銀蟾上碧天。"]'),
('9be6bdff-939c-4711-b7b3-e898c83d9359','次韻志宏見示  其一','李綱','宋','宋诗','song-poetry','','[]','胡馬依風亦北嘶，雲鴻隨候且南飛。',64,'全唐诗/poet.song.89000.json','["胡馬依風亦北嘶，雲鴻隨候且南飛。", "奏刀久愛庖丁善，鼓瑟聊同曾點希。", "舉世渾如蟻穴夢，何人解契箭鋒機。", "我觀法界皆真宅，不必吾家始是歸。"]'),
('a2981798-c402-4070-892b-d6ce4740defe','次韻志宏見示  其二','李綱','宋','宋诗','song-poetry','','[]','謫從天上墮人寰，惟有清風夜款關。',64,'全唐诗/poet.song.89000.json','["謫從天上墮人寰，惟有清風夜款關。", "皓月一輪窺筆硯，白雲千里映溪山。", "我因拙誤無方治，子以才鳴有意攀。", "須信全齊千駟景，未如陋巷一瓢顔。"]'),
('6ff8dc2b-aaa6-48fd-9d8f-fc3d0d593d17','次韻湖陰曲','李綱','宋','宋诗','song-poetry','','[]','繡鞍玉勒黄金鞭，躍馬直入無玉錢。',128,'全唐诗/poet.song.89000.json','["繡鞍玉勒黄金鞭，躍馬直入無玉錢。", "繞營三匝人不識，天風翻動旌旗鮮。", "賊臣晝寢蒼黄起，夢裏陽烏光照水。", "追風鐵騎去非遲，真主那從賊中死。", "寶鞭傳玩日淒淒，行遠不聞天馬嘶。", "千金安用試虎口，將帥何如思鼓鞞。", "西南大星寒有鋩，畫衣繡衮垂平章。", "九重宫殿鎖春色，豈如萬里秦城長。"]'),
('1e9b9ccd-6c1a-4bab-a322-7fd0e5480ccb','次韻東坡四時詞四首  其一','李綱','宋','宋诗','song-poetry','','[]','玉欄花發惟愁落，風捲柳綿穿繡幕。',64,'全唐诗/poet.song.89000.json','["玉欄花發惟愁落，風捲柳綿穿繡幕。", "繞池煙草碧成茵，夾竹露桃紅破萼。", "美人半醉軟香肌，不語憑欄知恨誰。", "莫把春愁自銷損，且唱樽前金縷衣。"]'),
('edd752c6-9da0-4fd1-b30c-edd47e32a9f4','次韻東坡四時詞四首  其二','李綱','宋','宋诗','song-poetry','','[]','深院沉沉清晝永，畫屏玉枕冰肌冷。',64,'全唐诗/poet.song.89000.json','["深院沉沉清晝永，畫屏玉枕冰肌冷。", "轆轤驚起寶釵横，香篆浮煙簾幕靜。", "翠眉不爲捧心顰，鬢亂粧殘約略勻。", "情似楊花無定處，可憐金谷墮樓人。"]'),
('238e786f-e823-46dc-95a7-f932efc03adf','次韻東坡四時詞四首  其三','李綱','宋','宋诗','song-poetry','','[]','梧桐葉脫苔滋綠，綺窗寂寂風敲竹。',64,'全唐诗/poet.song.89000.json','["梧桐葉脫苔滋綠，綺窗寂寂風敲竹。", "笑將紅扇撲流螢，戲剪碧荷装寶屋。", "深沉玉宇夜長扃，風露凄凉可一庭。", "步月清霄攜手處，誰家笛作斷腸聲。"]'),
('3ccd646c-5e3e-447f-8431-ceefbf9be32c','次韻東坡四時詞四首  其四','李綱','宋','宋诗','song-poetry','','[]','參横葉落闌干角，夜氣侵人覺衣薄。',64,'全唐诗/poet.song.89000.json','["參横葉落闌干角，夜氣侵人覺衣薄。", "香醪只怕玉樽空，殘燈旋剔金釭落。", "夢回酒醒聽啼鵶，起看霜晴日襯霞。", "笑道紅梅夜來發，臨階自摘一枝花。"]'),
('cbec7176-a7e0-4413-9d61-2f0a39e9d665','將遊栟櫚二首  其一','李綱','宋','宋诗','song-poetry','','[]','栟櫚百里遠沙溪，水石稱爲小武夷。',64,'全唐诗/poet.song.89000.json','["栟櫚百里遠沙溪，水石稱爲小武夷。", "千古碧潭涵夜月，兩涯翠巘拂朝霓。", "猿猱飲澗聯修臂，椶木連雲擢老枝。", "天下幽奇多僻遠，只疑造物惡人知。"]'),
('159a9313-b00c-4e21-a791-ab613ed1d80b','將遊栟櫚二首  其二','李綱','宋','宋诗','song-poetry','','[]','栟櫚聞說自栟櫚，且往觀之盍問途。',64,'全唐诗/poet.song.89000.json','["栟櫚聞說自栟櫚，且往觀之盍問途。", "我向煙霞已成癖，子於水石更能娱。", "古來勝地因人重，他日清遊載酒俱。", "會把丹青傳畫取，歸來與對武夷圖。"]'),
('dad99453-3bbe-424c-846f-8ba7620262b7','荔枝詞集句','李綱','宋','宋诗','song-poetry','','[]','開元天子萬事足，惟惜當年光景促。',202,'全唐诗/poet.song.89000.json','["開元天子萬事足，惟惜當年光景促。", "昭陽殿裏第一人，十幅紅綃圍夜玉。", "夢中同躡鳯凰翎，歸作霓裳羽衣曲。", "沉香亭北倚闌干，緩歌慢舞凝絲竹。", "迴眸一笑百媚生，盡日君王看不足。", "崩騰獻荔枝，百馬死山谷。", "一騎紅塵妃子笑，婕妤傳詔才人索。", "綘紗嚢裏水精丸，不是人間香味色。", "漁陽鼙鼓動地來，血汙遊魂歸不得。", "明眸皓齒今何在，金盤玉筯無消息。", "漢主山河錦繡中，三十六宫土花碧。", "不見玉顔空死處，淚痕血點垂胸臆。", "片段荔枝筐，此心炯炯君應識。"]'),
('9bac90f1-bc63-4f85-84ea-01de361a2906','疇老見示荔枝絕句次韻','李綱','宋','宋诗','song-poetry','','[]','炎月南閩丹荔子，絳綃微皺裹明珠。',32,'全唐诗/poet.song.89000.json','["炎月南閩丹荔子，絳綃微皺裹明珠。", "金盤數顆已堪賞，何况莆陽十萬株。"]'),
('fbfa875b-a33b-409f-a8b8-b2137ca382e7','陳興宗和示耳聾詩頗佳再次其韻','李綱','宋','宋诗','song-poetry','','[]','天公有眸子，猶把明河洗。',120,'全唐诗/poet.song.89000.json','["天公有眸子，猶把明河洗。", "况我聰與明，聽樂而視禮。", "是心有天遊，神用寄雙耳。", "良哉觀世音，圓通端自此。", "世人竭耳力，所聽不踰里。", "聞性含虚空，物蔽乃爲宄。", "區區假藥醫，不若求諸己。", "虚室既生白，吉祥自止止。", "瀟灑隱圃翁，靈臺湛如水。", "須識本來人，莫認賊爲子。"]'),
('8cd19f52-c9ba-4c97-8f7f-c4fb0b0146db','嘗新橄欖二絕句  其一','李綱','宋','宋诗','song-poetry','','[]','豈無崖蜜十分甜，競愛清嚴解變甘。',32,'全唐诗/poet.song.89000.json','["豈無崖蜜十分甜，競愛清嚴解變甘。", "堪笑區區棄捐者，半途迴味始知慚。"]'),
('c51996cc-78bd-4c6b-b7fc-be4facfea493','嘗新橄欖二絕句  其二','李綱','宋','宋诗','song-poetry','','[]','蠲痾毒藥寧便舌，逆耳忠言却利行。',32,'全唐诗/poet.song.89000.json','["蠲痾毒藥寧便舌，逆耳忠言却利行。", "世上但能珍橄欖，那知言藥更甘清。"]'),
('c2bb495a-a15a-4144-80e4-d41817e11f44','種荔枝核有感','李綱','宋','宋诗','song-poetry','','[]','荔子欲傳種，他年養老饕。',48,'全唐诗/poet.song.89000.json','["荔子欲傳種，他年養老饕。", "試將千顆植，已喜寸萌高。", "豈耐雪霜苦，空慚澆灌勞。", "何殊茂陵客，藏核種蟠桃。"]'),
('67797de4-db4a-4cf9-a1c6-cca7e8bec5ee','松架敝以新枝易之','李綱','宋','宋诗','song-poetry','','[]','日曛雨濯半飄零，旋採虬枝蔭廣庭。',64,'全唐诗/poet.song.89000.json','["日曛雨濯半飄零，旋採虬枝蔭廣庭。", "風動細香還泛泛，露滋新葉更青青。", "雖慚剪伐勞斤斧，猶勝燒燃競爝螢。", "凉夜蒼龍尚吟嘯，坐看明月入重扃。"]'),
('6eecae7d-6cad-4b13-9704-6954c2a5c720','偶作','李綱','宋','宋诗','song-poetry','','[]','休問梁谿何所爲，應緣日用且隨時。',64,'全唐诗/poet.song.89000.json','["休問梁谿何所爲，應緣日用且隨時。", "朝看藏典聊遮眼，夜閱韋編未覺疲。", "獨酌飄零一杯酒，狂吟敏捷百篇詩。", "困來打睡饑來飯，遊戲神通誰得知。"]'),
('7a3ce689-e0ec-471c-b631-8a77f32bf037','晚虹','李綱','宋','宋诗','song-poetry','','[]','小雨初收杳靄中，日華照作美人虹。',64,'全唐诗/poet.song.89000.json','["小雨初收杳靄中，日華照作美人虹。", "五重絢彩縈層漢，數幅輕綃颺遠風。", "飲澗未應占美惡，干陽何必問雌雄。", "桑榆暮色蒼然至，隱隱猶拖半段紅。"]'),
('18f652fa-7aa7-42bb-b49b-9f11a86b948e','白鷺','李綱','宋','宋诗','song-poetry','','[]','白鷺孤飛映碧峰，皎如片雪落輕風。',32,'全唐诗/poet.song.89000.json','["白鷺孤飛映碧峰，皎如片雪落輕風。", "徊翔意態雖容與，心在清波寸鬛中。"]'),
('88ecd62a-9754-4db0-b636-41e4c0bc013c','以蜜漬荔枝寄遠','李綱','宋','宋诗','song-poetry','','[]','遠謫南閩食荔枝，始知圖記不予欺。',64,'全唐诗/poet.song.89000.json','["遠謫南閩食荔枝，始知圖記不予欺。", "欲將千顆封題去，無那三朝色味移。", "蜜漬僅能存典則，日乾愈更失珍奇。", "欲知妙質爲何似，甘露明珠絳縠皮。"]'),
('9aee99c4-c610-4de3-a94c-4182d2e76c82','石輪魚','李綱','宋','宋诗','song-poetry','','[]','廣寒宫闕夜不鎖，蟾蜍飛下清溪涯。',64,'全唐诗/poet.song.89000.json','["廣寒宫闕夜不鎖，蟾蜍飛下清溪涯。", "爬沙厥狀雖可怪，脆美一臠亦莫加。", "頗笑退之嘲蛤蚧，還同子厚甘蝦蟆。", "晚凉雨霽小池滿，兩部鼓吹空哇哇。"]'),
('d73fdb0e-535d-4351-9864-10bbfa7e4636','次韻丹霞宗本長老見寄古風','李綱','宋','宋诗','song-poetry','','[]','帝居鬱沉沉，梧桐植朝陽。',144,'全唐诗/poet.song.89000.json','["帝居鬱沉沉，梧桐植朝陽。", "愧將鷰雀翼，參彼鵷鸞行。", "含香待黼座，秉筆立明光。", "誰知汲黯戅，忽作朱雲狂。", "襆被出都門，濯纓走滄浪。", "飽聞瑞光巖，道席久振芳。", "識高行復苦，皎月照嚴霜。", "醍醐有妙味，薝蔔無餘香。", "願聞第一義，洗我浩刼茫。", "閉關不肯出，未許窺高墻。", "徒將非舌語，遠寄煩宣揚。", "秋風動樵水，何日思褰裳。"]'),
('ebfea54a-d903-4388-b72a-c2f9b63b26fd','次韻丹霞錄示羅疇老唱和詩四首 和古風','李綱','宋','宋诗','song-poetry','','[]','快哉善知識，能以種種喻。',288,'全唐诗/poet.song.89000.json','["快哉善知識，能以種種喻。", "我今亦樂說，漸修與頓悟。", "頓如草木芽，荄核已完具。", "又如大明鏡，色像悉陳露。", "漸如雞哺雛，羽翼勞覆護。", "又如苗成實，非一朝夕故。", "邈然孤峰頂，邂逅適相遇。", "歷歷親見之，非是夢而寤。", "却來共談說，妙契那復遻。", "精勤假修習，即得無生趣。", "清淨摩尼珠，初無塵垢汙。", "圓成一滴水，豈殊千里霔。", "妙藥須對治，能起膏肓痼。", "欲觀皎日輪，當去漫天霧。", "鐵輪頂上旋，不復有驚怖。", "劫火洞燃時，自有安身處。", "了兹一大事，餘外復何顧。", "庭前柏樹子，古廟香爐去。", "孤雲與獨鶴，何往不可寓。", "返觀生死海，便是湼槃路。", "普化示全身，達磨攜隻屨。", "證道坐菩提，降魔成露布。", "乃知費千談，不若行一步。", "丹霞真道人，願力極堅固。"]'),
('af6d1260-cb97-4d53-a25b-e48bc866b409','次韻丹霞錄示羅疇老唱和詩四首 和太華庵聞牡丹芍藥花香','李綱','宋','宋诗','song-poetry','','[]','嘉卉多生佛氏宫，一經鼻觀便圓通。',32,'全唐诗/poet.song.89000.json','["嘉卉多生佛氏宫，一經鼻觀便圓通。", "妙香來處非和合，豈在根塵吸染中。"]'),
('083fdf7d-ed49-48e9-bad8-a1de15a951ee','次韻丹霞錄示羅疇老唱和詩四首 和舫齋觀魚','李綱','宋','宋诗','song-poetry','','[]','鱗鬛從容戲碧漪，拈槌擊拂更無疑。',32,'全唐诗/poet.song.89000.json','["鱗鬛從容戲碧漪，拈槌擊拂更無疑。", "聞經聽法都休說，自是魚中有導師。"]'),
('a58a5e7f-31da-4574-8746-fa19164d2b8c','次韻丹霞錄示羅疇老唱和詩四首 和小菴晏坐','李綱','宋','宋诗','song-poetry','','[]','一縷銅鑪沉水煙，菴中晏坐孰爲禪。',32,'全唐诗/poet.song.89000.json','["一縷銅鑪沉水煙，菴中晏坐孰爲禪。", "靈山法會何曾散，蓮社高風尚宛然。"]'),
('ddf55e4b-dfbe-45c6-be56-47f75cb50589','題丹霞晏坐軒','李綱','宋','宋诗','song-poetry','','[]','白雲深處開虛室，晏坐非禪亦非律。',64,'全唐诗/poet.song.89000.json','["白雲深處開虛室，晏坐非禪亦非律。", "須觀任四威儀中，皆悉具六波羅密。", "超然處處坐道場，善哉步步能踏實。", "我今此義亦妄言，請師往問維摩詰。"]'),
('31c7c299-c1e9-4d11-b8ef-62f64c95735b','次韻江滋秀才見寄','李綱','宋','宋诗','song-poetry','','[]','拙直從知慕古風，吾衰不復夢周公。',64,'全唐诗/poet.song.89000.json','["拙直從知慕古風，吾衰不復夢周公。", "心如葵葉雖終日，身逐溪流且向東。", "華藏千函游佛界，黄粱一枕悟仙翁。", "何當放浪塵埃外，回首滄洲興未窮。"]'),
('bb714824-323a-424c-aefa-d4e563dbc366','羅疇老錄示和丹霞絕句五首次韻  其一','李綱','宋','宋诗','song-poetry','','[]','丹霞只在笑談中，明月清風萬里同。',32,'全唐诗/poet.song.89000.json','["丹霞只在笑談中，明月清風萬里同。", "欲識德雲真面目，却須行到妙高峰。"]'),
('c33cc0c2-139a-4524-9d95-5ebe2782031e','羅疇老錄示和丹霞絕句五首次韻  其二','李綱','宋','宋诗','song-poetry','','[]','非佛非心須在我，即心即佛亦從渠。',32,'全唐诗/poet.song.89000.json','["非佛非心須在我，即心即佛亦從渠。", "本來心佛都無有，幻化聊將示四衢。"]'),
('dbee4181-4055-4021-97dc-f3e69467f91a','羅疇老錄示和丹霞絕句五首次韻  其三','李綱','宋','宋诗','song-poetry','','[]','揚眉下喝亦皆空，此性初無瞽與聾。',32,'全唐诗/poet.song.89000.json','["揚眉下喝亦皆空，此性初無瞽與聾。", "若信見聞非耳目，瞽聾却解振宗風。"]'),
('1613ccfc-0429-487b-a286-983db2ff8f8b','羅疇老錄示和丹霞絕句五首次韻  其四','李綱','宋','宋诗','song-poetry','','[]','晃耀靈光真有體，從横妙用本無蹤。',32,'全唐诗/poet.song.89000.json','["晃耀靈光真有體，從横妙用本無蹤。", "須彌芥子非虚語，事理從來本自融。"]'),
('8ccecf80-d2aa-4d50-b8e7-b381d2a13996','羅疇老錄示和丹霞絕句五首次韻  其五','李綱','宋','宋诗','song-poetry','','[]','片雲出岫當何在，獨鶴摩空自識回。',32,'全唐诗/poet.song.89000.json','["片雲出岫當何在，獨鶴摩空自識回。", "若會去來無二相，丹霞應肯下巖來。"]'),
('19b63d20-fbe9-4407-a603-8e7d1ee3f173','次韻種果絕句','李綱','宋','宋诗','song-poetry','','[]','分枝擢幹倐花開，長養初從寸許栽。',32,'全唐诗/poet.song.89000.json','["分枝擢幹倐花開，長養初從寸許栽。", "欲識菩提能結果，靈根端自箇中來。"]'),
('7c337fb6-5213-4d3a-b88f-f50b09c20a11','寄題丹霞雨花軒','李綱','宋','宋诗','song-poetry','','[]','小軒幽邃敞巖巒，密雨飛來更可觀。',64,'全唐诗/poet.song.89000.json','["小軒幽邃敞巖巒，密雨飛來更可觀。", "瀑布千尋落峰頂，噴珠萬點散簷端。", "休言幻化成空果，且喜炎蒸作晝寒。", "軒內生公常說法，天花亂墜響珊珊。"]'),
('0396dd29-aef5-4452-8d91-e730f456a7b9','次韻志宏見示山居二首  其一','李綱','宋','宋诗','song-poetry','','[]','千仞青山一草堂，蕭然遠去利名場。',64,'全唐诗/poet.song.89000.json','["千仞青山一草堂，蕭然遠去利名場。", "夜凉愈覺風月好，雨過惟聞松桂香。", "野寺春朝喧鳥雀，田家日夕下牛羊。", "因公錄示山居作，使我歸休意轉忙。"]'),
('c57efad3-1c5f-4c73-99bf-7c0ccd5f7314','次韻志宏見示山居二首  其二','李綱','宋','宋诗','song-poetry','','[]','知章本是四明狂，珥筆聊依日月光。',64,'全唐诗/poet.song.89000.json','["知章本是四明狂，珥筆聊依日月光。", "謫宦未從南畝樂，傲時自愛北窗凉。", "溪山勝處陪詩社，文字空中見法王。", "何必更求難老術，得閒身世自舒長。"]'),
('51da2428-75e5-4b10-b901-09a53ee5829a','七夕  其一','李綱','宋','宋诗','song-poetry','','[]','銀河清淺界煙霄，欲渡何須烏鵲橋。',32,'全唐诗/poet.song.89000.json','["銀河清淺界煙霄，欲渡何須烏鵲橋。", "今我去家千里遠，却憐牛女會今宵。"]'),
('a8245ece-4a2a-4060-a64d-651c7b2b57e7','七夕  其二','李綱','宋','宋诗','song-poetry','','[]','雲潢斜界耿秋空，靈匹相過此夕中。',64,'全唐诗/poet.song.89000.json','["雲潢斜界耿秋空，靈匹相過此夕中。", "璀璨珠星連璧月，凄凉玉露墜金風。", "三秋景物隨時好，萬里瓜花習俗同。", "乞巧未能從柳子，送窮聊欲效韓公。"]'),
('566155d1-01bc-4800-b1e4-11fea9b8d354','十三夜有小偷迨曉而獲志宏戲以詩來次其韻','李綱','宋','宋诗','song-poetry','','[]','夜半偷兒亦可憐，乘虛欲負壑中船。',64,'全唐诗/poet.song.89000.json','["夜半偷兒亦可憐，乘虛欲負壑中船。", "銀盃羽化方搜篋，繡被風飄遽返氈。", "妄意室中真有道，奪從虎口豈徒然。", "貪夫一笑心爲咎，舉體空能發愛涎。"]'),
('6f38a90a-6a89-4ad0-bf00-76941dad4e85','垓下','李綱','宋','宋诗','song-poetry','','[]','鴻溝已畫天下分，漢王未肯空迴軍。',128,'全唐诗/poet.song.89000.json','["鴻溝已畫天下分，漢王未肯空迴軍。", "諸侯大會壁垓下，戈甲耀日如屯雲。", "夜聞四面楚歌起，天命人心知去已。", "拔山蓋世霸圖空，却嘆當時騅不逝。", "帳中美人身姓虞，悲歌起飲聊踟蹰。", "數行淚下竟别去，倉皇不得同馳驅。", "明眸皓齒爲黄土，草木含愁照今古。", "依然聽曲自低昂，豈憶平生離别苦。"]'),
('a272e3d7-095f-4ca2-af59-27a6e4769b94','秋日','李綱','宋','宋诗','song-poetry','','[]','人言一葉已知秋，萬葉凋零愈更愁。',64,'全唐诗/poet.song.89000.json','["人言一葉已知秋，萬葉凋零愈更愁。", "蟬噪風林朝嘒嘒，蟲吟露草夜啾啾。", "溪山信美非吾土，詩酒多情解客憂。", "極目江鄉何處是，月華依舊照西樓。"]'),
('320d62b9-eda8-492f-8c00-a964b03aa7d2','次韻和李太白感秋','李綱','宋','宋诗','song-poetry','','[]','秋風從西來，敲我庭下竹。',96,'全唐诗/poet.song.89000.json','["秋風從西來，敲我庭下竹。", "夜凉月窺樽，清光如可掬。", "風月豈故人，萬里慰愁獨。", "披衣從之遊，更欲邀共宿。", "泠然洗我心，耿耿安用卜。", "三十八年非，庶以不遠復。", "俯仰天地間，平生皆可覆。", "一醉夢還家，黄粱猶未熟。"]'),
('c81cc7e7-77d5-431d-9174-4a5fa97a1ba2','秋暑戲題','李綱','宋','宋诗','song-poetry','','[]','少昊行秋尚熾然，祝融何事苦侵權。',64,'全唐诗/poet.song.89000.json','["少昊行秋尚熾然，祝融何事苦侵權。", "欲呼屏翳來清道，却恨羲和懶著鞭。", "鹽米相仍無日了，圖書撥置且閒眠。", "箇中自有清凉地，不在中間及兩邊。"]'),
('ce968ec2-e432-43d3-931b-31e4ad77e291','七月二十四日泛舟','李綱','宋','宋诗','song-poetry','','[]','秋暑殊未已，泛舟成勝遊。',48,'全唐诗/poet.song.89000.json','["秋暑殊未已，泛舟成勝遊。", "日斜雲影亂，風逈水光浮。", "鷺起暮山碧，蟬吟髙木幽。", "銷愁圖一醉，醉眼更多愁。"]'),
('b1149994-d028-4c1d-b97c-8737bae32497','次韻志宏秋曉見示古風二首  其一','李綱','宋','宋诗','song-poetry','','[]','庭户曉蕭騷，寒聲起疏葦。',96,'全唐诗/poet.song.89000.json','["庭户曉蕭騷，寒聲起疏葦。", "凄然驚客夢，秋色浩如水。", "南方苦炎熱，羈旅困泥滓。", "及兹風露凉，又復悲宋子。", "散策東籬下，佳菊有新蘂。", "美人渺何在，明月共千里。", "緇塵敝紫貂，錦字寄黄耳。", "欲賦秋風辭，煙雲愁落紙。"]'),
('c891c744-f46f-46a0-9080-20ad5b2a9ec9','次韻志宏秋曉見示古風二首  其二','李綱','宋','宋诗','song-poetry','','[]','苦熱喜新凉，蕭蕭響黄葦。',96,'全唐诗/poet.song.89000.json','["苦熱喜新凉，蕭蕭響黄葦。", "雨餘山吐輝，沙沒溪漲水。", "天髙氣澄明，太清無穢滓。", "泠然欲御風，一訪赤城子。", "笑讀香霞篇，時餐金蛾蘂。", "逝將遊蓬瀛，弱水三萬里。", "咄嗟無羽翰，相望徒勞耳。", "不如且賦詩，虵蚓動盈紙。"]'),
('6b6be77d-6460-49f8-835a-97bae54ff2f7','秋雨','李綱','宋','宋诗','song-poetry','','[]','颯然風雨作新凉，臥聽簷聲氣韻長。',64,'全唐诗/poet.song.89000.json','["颯然風雨作新凉，臥聽簷聲氣韻長。", "驅掃炎蒸逐流火，招邀秋月到虚堂。", "日邊夢斷甘飄泊，澤國音稀墮渺茫。", "猶喜北窗燈可近，簡編爲釋九迴腸。"]'),
('631e4d72-2031-43da-b518-686f7bfd657d','讀韓偓詩并記有感  其一','李綱','宋','宋诗','song-poetry','','[]','唐室昔不競，天綱遂陵遲。',204,'全唐诗/poet.song.89000.json','["唐室昔不競，天綱遂陵遲。", "閹豎擅朝政，姦雄肆覦窺。", "天子遭迫脅，翠蓋蒙塵飛。", "矢石集黄屋，四郊皆鼓鼙。", "羣兇雖殄滅，國命亦已移。", "韓子司翰苑，實被昭宗知。", "忠言雖屢貢，顛厦誠難支。", "謫官旅南土，召復不敢歸。", "當時白馬驛，從横卿相尸。", "投之濁流中，至今耆舊悲。", "夫子乃幸免，禍福良難期。", "假道寓沙陽，空門知所依。", "雖踰二百載，猶傳贈僧詩。", "邑令真好事，作記刊豐碑。", "文辭雖淺陋，事實頗可追。", "讀之三嘆息，弔古情悽洏。", "寄聲藏去者，擅有將奚爲。"]'),
('e4ee73a1-e9d6-40ee-b623-e803b84a38d5','讀韓偓詩并記有感  其二','李綱','宋','宋诗','song-poetry','','[]','詞臣謫去墮天南，詩墨從來榜寺簷。',32,'全唐诗/poet.song.89000.json','["詞臣謫去墮天南，詩墨從來榜寺簷。", "好事不須收拾去，世間遺集有香匳。"]'),
('9e8028f3-72a0-4d0c-84ed-44372fa0218a','志宏復示秋意五篇次韻和之  其一','李綱','宋','宋诗','song-poetry','','[]','秋風到枕前，策策鳴窗葦。',96,'全唐诗/poet.song.89000.json','["秋風到枕前，策策鳴窗葦。", "起看山吐月，殘夜樓明水。", "皎月與我心，清淨兩無滓。", "玉露滴煙霄，飄然雜桂子。", "姮娥應笑人，仳離放紅蘂。", "乘風遊廣寒，三十億萬里。", "宫闕不勝寒，九奏感人耳。", "不如且世間，浩歌書著紙。"]'),
('71d7011d-237b-4de2-83fa-9bb89eac6307','志宏復示秋意五篇次韻和之  其二','李綱','宋','宋诗','song-poetry','','[]','秋色一夜改，白露漙蒼葦。',96,'全唐诗/poet.song.89000.json','["秋色一夜改，白露漙蒼葦。", "冠屨變淒清，如濯滄浪水。", "慢膚素多汗，執熱結成滓。", "振衣得新凉，儼若侍君子。", "起觀庭中花，露葉耿煙蘂。", "景物但可人，溪山即吾里。", "浮生駒過隙，百年一瞬耳。", "惟有古聖賢，髙名在毫紙。"]'),
('f0a77412-854d-495f-a1f7-5023fc7a5a81','志宏復示秋意五篇次韻和之  其三','李綱','宋','宋诗','song-poetry','','[]','秋風振迴溪，宿鷺起汀葦。',96,'全唐诗/poet.song.89000.json','["秋風振迴溪，宿鷺起汀葦。", "孤飛一片雪，寒影落煙水。", "羽毛可爲儀，皓潔絕埃滓。", "心跡兩翛然，邈若佳公子。", "却棲碧山岑，瑤樹發瓊蘂。", "豈知黄鵠心，一舉眇千里。", "翔集太液池，彼此皆戲耳。", "丹青雖善畫，爲我拂水紙。"]'),
('8f9595bd-beb2-4246-b698-0b85d7b9f236','志宏復示秋意五篇次韻和之  其四','李綱','宋','宋诗','song-poetry','','[]','秋風入虛堂，凄微带煙葦。',96,'全唐诗/poet.song.89000.json','["秋風入虛堂，凄微带煙葦。", "堂中拙居士，湛然如止水。", "默坐觀是心，自覺無纖滓。", "不知讀何經，但說舍利子。", "心清聞妙香，天花散芳蘂。", "含容河沙界，方寸知幾里。", "神光常在目，妙響不離耳。", "處處獲圓通，誰云鑽故紙。"]'),
('670b5b75-57ec-421e-a5a9-64e5863537dc','志宏復示秋意五篇次韻和之  其五','李綱','宋','宋诗','song-poetry','','[]','秋興殊未極，秋溪可杭葦。',96,'全唐诗/poet.song.89000.json','["秋興殊未極，秋溪可杭葦。", "順流欲東行，一觀滄溟水。", "洗我萬古愁，胸中瑩無滓。", "又欲歸梁谿，候門有稚子。", "攜幼酒盈樽，泛此東籬蘂。", "躬耕復著書，茗飲追甫里。", "聽子場屋聲，入我山林耳。", "文字驚世人，一日傳萬紙。"]'),
('e05354c3-b3d1-46a4-811a-1117341a2fc7','題寓軒','李綱','宋','宋诗','song-poetry','','[]','秋到寓軒殊不惡，滿庭爽氣有餘清。',64,'全唐诗/poet.song.89000.json','["秋到寓軒殊不惡，滿庭爽氣有餘清。", "架松著雨須髯奮，盆沼因風鱗甲生。", "葵向日光金盞側，荷翻露顆玉盤傾。", "焚香默坐無人會，自覺諸緣次第輕。"]'),
('7d55f8c3-eff4-475e-a18d-37cdb4adfd5c','江月五首  其一','李綱','宋','宋诗','song-poetry','','[]','一更山吐月，金篆繚輕瀾。',48,'全唐诗/poet.song.89000.json','["一更山吐月，金篆繚輕瀾。", "清光滿四海，獨向沙陽看。", "桂魄緣空逈，雲峰醮影寒。", "姮娥謾愁思，相對漏聲殘。"]'),
('a38e62fb-83f8-4262-b8bb-7e216e9c8c21','江月五首  其二','李綱','宋','宋诗','song-poetry','','[]','二更山吐月，風露靄清夜。',48,'全唐诗/poet.song.89000.json','["二更山吐月，風露靄清夜。", "待月泛蘭舟，停橈碧峰下。", "樽罍興未窮，枕簟涼可藉。", "言攜二三子，弔古相與話。"]'),
('a090090b-8853-4d58-ba45-635978f41b9f','江月五首  其三','李綱','宋','宋诗','song-poetry','','[]','三更山吐月，羈客方獨起。',48,'全唐诗/poet.song.89000.json','["三更山吐月，羈客方獨起。", "起游溪上閣，勝景乃如此。", "露滿七峰松，煙籠一川水。", "奔走塵埃間，顧未之知耳。"]'),
('7d5bd545-423f-49a6-a76b-2a887a8f007d','江月五首  其四','李綱','宋','宋诗','song-poetry','','[]','四更山吐月，夜靜月尤明。',48,'全唐诗/poet.song.89000.json','["四更山吐月，夜靜月尤明。", "玉梳掛碧落，銀漢自從横。", "寥泬羣動息，溪中有舟行。", "吾家渺何在，極目望江城。"]'),
('f096772f-632d-4c83-a4ba-d0e9d4780659','江月五首  其五','李綱','宋','宋诗','song-poetry','','[]','五更山吐月，禪室正清幽。',48,'全唐诗/poet.song.89000.json','["五更山吐月，禪室正清幽。", "星河光破碎，鐘鼓起髙樓。", "展轉不成夢，冷落還悲秋。", "五詠繼蘓子，誰爲商聲謳。"]'),
('900e1aa5-9bf9-420d-a48e-6e2da0af0dc4','玉局有眉子石硯歌予來沙陽獨攜一圓硯乃眉子石也戲次其韻','李綱','宋','宋诗','song-poetry','','[]','美人多恨顰雙眉，眼波秋水增清奇。',128,'全唐诗/poet.song.89000.json','["美人多恨顰雙眉，眼波秋水增清奇。", "天然此石巧相似，儒生作硯聲酸嘶。", "横雲慘淡遠山碧，猶带深閨畫時色。", "金堅玉潤月輪圓，笑殺世間銅雀渴。", "十年提挈隨拙翁，相攜謫墮溪山中。", "窗明几淨日相對，風露夜永燈光紅。", "毛穎陳玄用功處，髪禿肌銷留不住。", "與君長此結幽歡，我自多言子無語。"]'),
('8b7a31bd-d5f0-4f6f-a8ed-4cec1dd9096c','次韻虢國夫人夜遊圖','李綱','宋','宋诗','song-poetry','','[]','金鞍玉勒連錢驄，車如流水馬如龍。',112,'全唐诗/poet.song.89000.json','["金鞍玉勒連錢驄，車如流水馬如龍。", "遺簪墮珥碎珠翠，蜜炬夜入蓬萊宫。", "曲江宫殿春蒲柳，玉盤犀筯傳纖手。", "坐中綽約盡天人，錦茵雲幕清無塵。", "賜名大國動光彩，馬嵬回首空啼痕。", "我欲題詩弔千古，喪國亡家皆此路。", "嫣然一笑傾人城，皓齒明眸真女虎。"]'),
('9cb9caf3-fd41-49f7-a4f8-0cbf60ce6767','次韻俞祖仁寒翠亭翠字韻','李綱','宋','宋诗','song-poetry','','[]','愛奇走山林，蠟屐窮幽閟。',168,'全唐诗/poet.song.89000.json','["愛奇走山林，蠟屐窮幽閟。", "蕭然巖壑趣，乃在經行內。", "緬懷謫仙人，名湖自張謂。", "至今郎官湖，邈與峴山對。", "我遊古蘭若，殿閣煙霞外。", "眷兹道傍亭，勝境久翳昩。", "洗開松竹林，寒色靄蒼翠。", "戲題榜間名，筆墨聊自恣。", "時方春雨餘，澗水正横潰。", "泉聲落亭前，散作珠點碎。", "景物豈殊昔，因之不遐棄。", "佳哉二三子，詩酒作文會。", "留連不忍去，吟哦薄昏晦。", "我詠詩中言，端有亭上味。"]'),
('9164b738-6191-43d4-8a3d-e802e08182ce','次韻志宏見示寒翠亭之作','李綱','宋','宋诗','song-poetry','','[]','虚亭枕山麓，萬籟如笙簫。',96,'全唐诗/poet.song.89000.json','["虚亭枕山麓，萬籟如笙簫。", "佳哉松竹林，颯然風露秋。", "我題亭上名，過客爲少留。", "所嗟結搆小，未稱山光浮。", "緬懷瑯琊亭，醉翁昔曾遊。", "今我聊復爾，一洗胸中愁。", "數子真好事，佳句相與捜。", "會當同勝會，及此月如鈎。"]'),
('01744727-47f4-4dfe-9b23-a02206212ddc','題陳公叙舫齋','李綱','宋','宋诗','song-poetry','','[]','一心寓百骸，是身已虚舟。',96,'全唐诗/poet.song.89000.json','["一心寓百骸，是身已虚舟。", "寄形天壌間，大塊日夜浮。", "矧兹數椽屋，結搆谿山幽。", "假以舫爲名，諦觀有異不。", "行藏本一體，淵止同川流。", "蕭然齋中人，悟此復何求。", "但聞泉石美，景物方清秋。", "安得造其上，一與龜魚游。"]'),
('a63f92b4-9a0a-4cc8-8adf-6a0a65cb797c','鄧成彦以寒字韻長句來次韻答之','李綱','宋','宋诗','song-poetry','','[]','蓬萊東隔滄溟寛，我欲遊之恨無翰。',224,'全唐诗/poet.song.89000.json','["蓬萊東隔滄溟寛，我欲遊之恨無翰。", "崆峒西峙冰雪積，崛起萬仞良難攀。", "不如隨寓忻所愜，放逐愛此沙陽山。", "蒼松拂雲雨溜溜，古澗鑿石泉潺潺。", "遠峰三疊碧瑪瑙，脩竹个个青琅玕。", "煙霞縹緲巧粧綴，極目秀色如可餐。", "就中此亭更幽絕，泠然爽氣洗我肝。", "命名題字聊一戲，坐覺景物增清寒。", "子爲勝遊真得侣，纖月正掛青雲端。", "詩篇雕琢愁肺腎，筆力漸闊生波瀾。", "當觀佳致本來有，拈出便作一倍看。", "百壺何必事狂飲，一斗自足資幽歡。", "夜乘小艇鼓歸櫂，平溪十里初不關。", "更須風露稍凄冷，相約同自亭中還。"]'),
('9b0e1b5d-bc51-4b8b-b771-a2a8a6e50fa9','和志宏見示亭字韻','李綱','宋','宋诗','song-poetry','','[]','今日苦不樂，駕言適林坰。',120,'全唐诗/poet.song.89000.json','["今日苦不樂，駕言適林坰。", "散策尋遠寺，披襟坐虚亭。", "雲木上窈窕，澗泉泄清泠。", "千山自岑寂，一目皆葱青。", "嗟我得數子，不復嘆飄零。", "掃慮味禪悅，茹蔬謝葷腥。", "時爲亭上遊，散髪緩我形。", "騄驥行振足，倦鳥思歸翎。", "何當返梁谿，教子名添丁。", "林泉益自得，華髪從星星。"]'),
('02cb1884-c20f-4ec2-9136-5f2f838e6c5d','秋蟲','李綱','宋','宋诗','song-poetry','','[]','白霜降百草，候蟲寒自吟。',48,'全唐诗/poet.song.89000.json','["白霜降百草，候蟲寒自吟。", "不知抱何恨，唧唧無停音。", "歘爾驚客夢，悽然感離心。", "覉臣腸欲斷，豈事雍門琴。"]'),
('abbb96c6-9a98-4991-a9c3-603ac505e6ea','中秋望月次玉局翁韻二首  其一','李綱','宋','宋诗','song-poetry','','[]','明月如玉盤，飛上青霄東。',120,'全唐诗/poet.song.89000.json','["明月如玉盤，飛上青霄東。", "徘徊斗牛間，照我禪室中。", "爽氣靄亭户，清光透簾櫳。", "我雖不解飲，敢辭玉樽空。", "舉酒對明月，起舞聊相從。", "身世兩翛然，如遊廣寒宫。", "夜久風露冷，草根吟候蟲。", "咽咽不能已，豈自鳴其窮。", "天涯多霧雨，好景誠難逢。", "哦詩不成寢，頗類魚噞喁。"]'),
('ca5595ec-23d1-45c7-a939-99df9d252fdb','中秋望月次玉局翁韻二首  其二','李綱','宋','宋诗','song-poetry','','[]','皎皎月華白，寥寥秋氣清。',120,'全唐诗/poet.song.89000.json','["皎皎月華白，寥寥秋氣清。", "念我方遠客，步月亭中行。", "風露感我心，凄然入重扃。", "誰家弄横笛，巧作斷腸聲。", "獨酌一壺酒，對此千里明。", "人生但自適，何必四者并。", "醉眼視萬物，擾擾如浮萍。", "得喪何須道，譬猶陰與晴。", "節義太山重，富貴鴻毛輕。", "我心與明月，照見萬古情。"]'),
('28ed3a1b-61f4-4a3a-b8d9-4e933c8f1524','又次韻中秋長句','李綱','宋','宋诗','song-poetry','','[]','凉風吹空明月高，清光萬里見秋毫。',224,'全唐诗/poet.song.89000.json','["凉風吹空明月高，清光萬里見秋毫。", "銀雲櫛櫛方解駮，河漢掩映如波濤。", "須臾掃盡無多子，天影悠悠碧於水。", "冰輪正午久停鞭，羣動寂然聲不起。", "諦觀此月真跳丸，山河倒影猶蛇蟠。", "桂華耿耿巳澄潔，秋氣凛凛增清寒。", "前年望月都城汴，只恐中霄風雨變。", "一杯相屬有情親，側耳歌樓聞鼓板。", "今年望月沙陽山，照我心如鐵石堅。", "美人千里共明月，遙想閨中只獨看。", "空庭步月更幽好，白露漙漙濕煙草。", "開編况對古聖賢，發憤忘憂不知老。", "男兒本自甘賤貧，富貴名傳能幾人。", "題詩對月到日出，錦嚢何似龐眉客。"]'),
('2ac402a7-03b6-4973-ae2e-838cd4bfea0f','和陶淵明歸田園六首  其一','李綱','宋','宋诗','song-poetry','','[]','我家梁谿傍，門對九龍山。',120,'全唐诗/poet.song.89000.json','["我家梁谿傍，門對九龍山。", "山中有幽趣，遊息可忘年。", "陸子泉最甘，次之即龍淵。", "餘波作梁谿，可溉萬頃田。", "公垂讀書堂，古屋尚數間。", "我欲隱山下，誅茅占其前。", "疏泉鑿池沼，植竹來雲煙。", "縱目望震澤，策杖登山巔。", "神遊八極表，心跡兩超然。", "更結蓮社侣，遠追竹林賢。"]'),
('72f84c7d-fe0b-4f6b-87c7-52730157cfd8','和陶淵明歸田園六首  其二','李綱','宋','宋诗','song-poetry','','[]','秋風動梁谿，何日理歸鞅。',72,'全唐诗/poet.song.89000.json','["秋風動梁谿，何日理歸鞅。", "放逐正拘囚，寤寐勞夢想。", "新詩聊慰今，舊事那追往。", "緬懷故山居，杞菊苗應長。", "掛冠神武門，便欲學疏廣。", "躬耕南畝雲，實報無鹵莽。"]'),
('c4b305d3-5048-48a7-aeea-7ab1c0a3b0a4','和陶淵明歸田園六首  其三','李綱','宋','宋诗','song-poetry','','[]','落葉不可數，枝間綠將稀。',48,'全唐诗/poet.song.89000.json','["落葉不可數，枝間綠將稀。", "節物一如此，感歎何時歸。", "庭闈眇千里，篋藏老萊衣。", "從兹就閒曠，勿使吾心違。"]'),
('acd6079d-55d6-4d12-adf0-c2659cb4b2af','和陶淵明歸田園六首  其四','李綱','宋','宋诗','song-poetry','','[]','寂滅乃可樂，紛華何足娛。',96,'全唐诗/poet.song.89000.json','["寂滅乃可樂，紛華何足娛。", "百年會有盡，富貴同邱墟。", "不如早抽身，卜此山林居。", "手植松與桂，青青三萬株。", "幅巾坐其下，蕭散誰如吾。", "衣食粗飽暖，身在即有餘。", "歸依金仙氏，妙契端不虚。", "借問名利者，還有此樂無。"]'),
('2ad078f7-c061-4e91-b4ed-e36c9330454a','和陶淵明歸田園六首  其五','李綱','宋','宋诗','song-poetry','','[]','膝横五弦琴，試鼓南風曲。',48,'全唐诗/poet.song.89000.json','["膝横五弦琴，試鼓南風曲。", "寄傲北窗下，便覺此生足。", "開懷酒一壺，寓意棋一局。", "既使風掃門，還將月爲燭。"]'),
('b1a5d720-6493-4e46-82f6-74d0d7b969db','和陶淵明歸田園六首  其六','李綱','宋','宋诗','song-poetry','','[]','貧者無置錐，富者連阡陌。',84,'全唐诗/poet.song.89000.json','["貧者無置錐，富者連阡陌。", "嗟予亦何幸，伏臘粗能適。", "但使歲事豐，便足給朝夕。", "人生幾何時，倐如駒過隙。", "惟當適我心，安能供物役。", "著書聊寄懷，底之或可績。", "吾身雖不遇，吾言期有益。"]'),
('ce04709a-0637-4efc-8fcb-e03b793cb41f','次韻和淵明飲酒詩二十首  其一','李綱','宋','宋诗','song-poetry','','[]','是心本純白，利害俶擾之。',60,'全唐诗/poet.song.89000.json','["是心本純白，利害俶擾之。", "陶然到醉鄉，還此未擾時。", "古人重酒德，妙意端在兹。", "嗟予數杯量，徑醉不復疑。", "既得醉中趣，安用杯常持。"]'),
('aa175396-f856-4f5f-a371-41b7a737e763','次韻和淵明飲酒詩二十首  其二','李綱','宋','宋诗','song-poetry','','[]','醉中忘萬物，一視淵與山。',48,'全唐诗/poet.song.89000.json','["醉中忘萬物，一視淵與山。", "墜車神不驚，莊周非寓言。", "是鄉豈華胥，逸樂不記年。", "誰能造其域，勿爲薄俗傳。"]'),
('71ef3bc7-35f4-42db-b5cf-1c02fa397804','次韻和淵明飲酒詩二十首  其三','李綱','宋','宋诗','song-poetry','','[]','世俗愈澆薄，惟酒陶真情。',60,'全唐诗/poet.song.89000.json','["世俗愈澆薄，惟酒陶真情。", "如何遯世士，更以酒自名。", "嗟我方遠謫，慷慨念平生。", "酌此一壺酒，寵辱那復驚。", "醉中露天機，往往以詩鳴。"]'),
('17a93851-a1c0-4d94-8af0-bea497446917','次韻和淵明飲酒詩二十首  其四','李綱','宋','宋诗','song-poetry','','[]','駿足有遠步，逸翮無卑飛。',72,'全唐诗/poet.song.89000.json','["駿足有遠步，逸翮無卑飛。", "羈縶因羅網，慘澹終年悲。", "得酒且歡喜，醉鄉真所依。", "路稳良易到，時和可忘歸。", "不復夢周公，甚矣吾其衰。", "惟當飲醇酎，此志慎勿違。"]'),
('23171527-e93e-43a5-abb5-45febb6bf426','次韻和淵明飲酒詩二十首  其五','李綱','宋','宋诗','song-poetry','','[]','獨酌有真趣，何須歌管喧。',60,'全唐诗/poet.song.89000.json','["獨酌有真趣，何須歌管喧。", "既醉謝羈束，不知冠屨偏。", "扶挾煩侍女，頽然傾玉山。", "方遊無何鄉，命駕殊未還。", "醒來念前樂，欲辯誠難言。"]'),
('e26f7c76-2fcb-4826-a1c7-9d43cf727714','次韻和淵明飲酒詩二十首  其六','李綱','宋','宋诗','song-poetry','','[]','異論相矛盾，儒墨竟誰是。',48,'全唐诗/poet.song.89000.json','["異論相矛盾，儒墨竟誰是。", "仲尼雖大聖，寧免叔孫毁。", "得酒當痛飲，忘形相汝爾。", "採芝白雲中，願學園與綺。"]'),
('b74df666-7ac7-4968-8c46-cfd66fe4554f','次韻和淵明飲酒詩二十首  其七','李綱','宋','宋诗','song-poetry','','[]','風露颯秋色，東籬菊有英。',60,'全唐诗/poet.song.89000.json','["風露颯秋色，東籬菊有英。", "泛此忘憂物，寛我羈旅情。", "故人餉佳醖，樽空還自傾。", "雲外鴻雁度，堂中蟋蟀鳴。", "忽忽歲將暮，聊復樂此生。"]'),
('b9a24f89-656b-44fe-9de7-12d6345d6df3','次韻和淵明飲酒詩二十首  其八','李綱','宋','宋诗','song-poetry','','[]','我本田野人，蕭然巖壑姿。',60,'全唐诗/poet.song.89000.json','["我本田野人，蕭然巖壑姿。", "麋鹿喜豐草，鷦鷯安一枝。", "誤學霸王略，肯吐陳平奇。", "世故乃如此，拙謀何所爲。", "賓至且飲酒，吾身豈長羈。"]'),
('ebf2cfb4-a9d1-4216-b0cd-a738382a24c9','次韻和淵明飲酒詩二十首  其九','李綱','宋','宋诗','song-poetry','','[]','嘉葩含團香，氣至輒自開。',72,'全唐诗/poet.song.89000.json','["嘉葩含團香，氣至輒自開。", "置之白玉堂，可慰君子懷。", "少有高世心，壯年此志乖。", "君門植梧桐，參彼鸞鳯棲。", "謀身一何拙，墮此百尺泥。", "却笑東方生，取容事詼諧。"]'),
('c3a3769a-6dee-4776-83a1-8bd9d20e6306','次韻和淵明飲酒詩二十首  其一○','李綱','宋','宋诗','song-poetry','','[]','四方有定位，醉中初不迷。',84,'全唐诗/poet.song.89000.json','["四方有定位，醉中初不迷。", "立志既爾爾，豈復中道迴。", "珥筆螭殿坳，謫官鯨海隅。", "庭闈在千里，山川阻脩途。", "夢中欣得還，亦復勞馳驅。", "覺後謀一醉，三杯即有餘。", "何當聽從便，返我梁谿居。"]'),
('27dc3435-cce7-4b5b-9e0d-4f9f35a7b665','次韻和淵明飲酒詩二十首  其一一','李綱','宋','宋诗','song-poetry','','[]','三徑淵明居，一區子雲宅。',60,'全唐诗/poet.song.89000.json','["三徑淵明居，一區子雲宅。", "吾生誠易足，處靜期息跡。", "負郭千畝田，種秫當八百。", "釀爲甕盎春，悠然舉大白。", "於世復何求，安用長太息。"]'),
('7a5519fe-851c-40cb-aa30-445012440bfa','次韻和淵明飲酒詩二十首  其一二','李綱','宋','宋诗','song-poetry','','[]','飲酒資紅裠，其樂未爲至。',60,'全唐诗/poet.song.89000.json','["飲酒資紅裠，其樂未爲至。", "歡然文字飲，興逸不知醉。", "放懷谿山間，雅飲亦其次。", "裸裎豈是達，温克乃足貴。", "醉鄉誰不到，未必能知味。"]'),
('6de4ef6f-6484-4723-814b-61d32c750608','次韻和淵明飲酒詩二十首  其一三','李綱','宋','宋诗','song-poetry','','[]','樽俎爲舟車，遊此醉鄉境。',60,'全唐诗/poet.song.89000.json','["樽俎爲舟車，遊此醉鄉境。", "但願未死前，常醉不用醒。", "醒來寓翰墨，萬事勞總領。", "譬猶錐處囊，脫出終露穎。", "虎豹豈犬羊，文章自彪炳。"]'),
('d94f1fb0-1776-416e-a70c-7423b3db3850','次韻和淵明飲酒詩二十首  其一四','李綱','宋','宋诗','song-poetry','','[]','吾年行四十，意氣非少時。',72,'全唐诗/poet.song.89000.json','["吾年行四十，意氣非少時。", "世故茫不識，惟好古人詞。", "篇章自娛悅，適意良在兹。", "此外付之拙，直道不復疑。", "黄卷千萬言，聖賢豈吾欺。", "世事皆分定，飲酒姑安之。"]'),
('4162a265-87b5-42fe-926f-25aaec9c69b4','次韻和淵明飲酒詩二十首  其一五','李綱','宋','宋诗','song-poetry','','[]','萌心皆拙謀，遊世用直道。',72,'全唐诗/poet.song.89000.json','["萌心皆拙謀，遊世用直道。", "樂天吾何憂，發憤不知老。", "惟有杯中物，可以慰枯槁。", "三杯頰生紅，便覺顔色好。", "麴生端可友，金玉非吾寶。", "醉中亦慨然，志節還表表。"]'),
('87615de0-b593-4e50-8148-a56d7151ed2b','次韻和淵明飲酒詩二十首  其一六','李綱','宋','宋诗','song-poetry','','[]','少年學神仙，日誦瓊笈經。',72,'全唐诗/poet.song.89000.json','["少年學神仙，日誦瓊笈經。", "交梨與火棗，丹鼎期必成。", "呼吸存夜氣，宴坐至五更。", "豈知糟麴中，醉鄉即黄庭。", "玉池灩生肥，天鼓常自鳴。", "酩酊欲仙去，超然離世情。"]'),
('51b86c40-0970-401b-8170-7986581a1d7d','次韻和淵明飲酒詩二十首  其一七','李綱','宋','宋诗','song-poetry','','[]','霜林隕寒葉，淅淅隨西風。',48,'全唐诗/poet.song.89000.json','["霜林隕寒葉，淅淅隨西風。", "拙翁感節物，頹然坐軒中。", "獨酌一樽酒，不知窮與通。", "棲鳥忽驚去，子豈曾傷弓。"]'),
('5b410706-ea26-4b8e-b649-f59b0357397a','次韻和淵明飲酒詩二十首  其一八','李綱','宋','宋诗','song-poetry','','[]','人以謫而窮，我因謫而得。',60,'全唐诗/poet.song.89000.json','["人以謫而窮，我因謫而得。", "博考聖賢書，獨立愈不惑。", "世道迭污隆，時命有通塞。", "駕言遊醉鄉，疑是華胥國。", "漠然無是非，於此可以默。"]'),
('93a0360c-d9c8-4e5a-b357-7d58fa0be850','次韻和淵明飲酒詩二十首  其一九','李綱','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','結髪觀國光，壯年躋膴仕。',84,'全唐诗/poet.song.89000.json','["結髪觀國光，壯年躋膴仕。", "懷恩重泰山，欲報輕小己。", "幸立不諱朝，緘默誠可恥。", "晨趨玉陛前，暮謫閩山裏。", "飄零若萍梗，此志誰復紀。", "行藏豈異途，川流與淵止。", "不如飲美酒，世態何足恃。"]'),
('3dad6deb-fdfd-4aaa-817c-aa66110f10d3','次韻和淵明飲酒詩二十首  其二○','李綱','宋','宋诗','song-poetry','','[]','舉世人事僞，惟酒存天真。',120,'全唐诗/poet.song.89000.json','["舉世人事僞，惟酒存天真。", "飲多不如少，飲醨不如醇。", "借問何以然，每醉意每新。", "笑指黄金罍，是中可逃秦。", "糠粃鑄堯舜，萬世同埃塵。", "二豪侍坐側，議論徒慇懃。", "我讀古人書，獨與淵明親。", "北窗傲羲皇，桃源將問津。", "膝横無弦琴，頭著漉酒巾。", "我醉君且去，爲已非爲人。"]'),
('34d69165-570d-4f39-9610-a66986445f4a','桃源行','李綱','宋','宋诗','song-poetry','','[]','武陵溪水流潺潺，漁舟鼓枻迷泝沿。',224,'全唐诗/poet.song.89000.json','["武陵溪水流潺潺，漁舟鼓枻迷泝沿。", "谿窮路盡恍何處，桃花爛漫蒸川原。", "花間邑屋自連接，雲外雞犬聲相喧。", "衣裳不同俎豆古，見客驚怪爭來前。", "殺雞爲黍持勸客，借問世上今何年。", "自從秦亂避徭役，子孫居此因蟬聯。", "不知漢祖以劍起，况復魏晉稱戈鋋。", "慇懃留客不肯住，落花流水空依然。", "淵明作記真好事，世人粉飾言神仙。", "我觀閩境多如此，峻谿絕嶺難攀緣。", "其間往往有居者，自富水竹饒田園。", "耄倪不復識官府，豈憚黠吏催租錢。", "養生送死良自得，終歲飽食仍安眠。", "何須更論神仙事，只此便是桃花源。"]'),
('82faa82b-8e5e-452e-bb43-2212a92386c3','隱圃巖桂盛開興宗屢以爲供賦長篇以謝其意并簡志宏','李綱','宋','宋诗','song-poetry','','[]','沙陽巖桂雖云多，不若隱圃爲駢羅。',208,'全唐诗/poet.song.89000.json','["沙陽巖桂雖云多，不若隱圃爲駢羅。", "結根盤據極高大，蔭庭一畝纔數科。", "青葱翠蓋俯軒檻，夭矯蒼虬交枝柯。", "森森密葉碧如玉，撲撲細蘂黄於鵝。", "風傳賸馥尚酷烈，月散清影長婆娑。", "幽香豈止到十里，妙質端恐移金波。", "不隨春景鬭姸媚，直與秋色爭清和。", "芳鮮似欲伴佳菊，冷落更覺憐衰荷。", "幽人愛此自培植，林下不知雙鬢皤。", "爲予折贈誠有意，欲遣鼻觀通禪那。", "吾衰萬事付之懶，不飲奈此秋光何。", "徑須造詣謀一醉，莫待花落霑庭莎。", "妙香吸引入肺腑，吐作佳句同吟哦。"]'),
('2820987f-79a3-42b3-be6e-a2eb6bd24712','四花四首 芙蓉','李綱','宋','宋诗','song-poetry','','[]','浥露披風浩莫收，嫣然秀色照清秋。',32,'全唐诗/poet.song.89000.json','["浥露披風浩莫收，嫣然秀色照清秋。", "佳人日暮來何處，翠袖紅粧相對愁。"]'),
('ece75f7d-75dd-4a14-bf88-af7405d83f29','四花四首 金燈','李綱','宋','宋诗','song-poetry','','[]','葉卷須虬朵朵圓，化工如解刻雕然。',32,'全唐诗/poet.song.89000.json','["葉卷須虬朵朵圓，化工如解刻雕然。", "金燈玉柱歸天上，何事生來小檻前。"]'),
('8a10ffec-f3b1-4b6f-b61a-352ce2780c2d','四花四首 紅蕉','李綱','宋','宋诗','song-poetry','','[]','但見風來搖翠尾，那知露下濯紅英。',32,'全唐诗/poet.song.89000.json','["但見風來搖翠尾，那知露下濯紅英。", "色空須信元同體，誰把丹青與染成。"]'),
('aa478fb0-e183-4584-9cf4-6c62ef3ff6eb','四花四首 雞冠','李綱','宋','宋诗','song-poetry','','[]','花蘂成冠巧學雞，刻雕誰謂染胭脂。',32,'全唐诗/poet.song.89000.json','["花蘂成冠巧學雞，刻雕誰謂染胭脂。", "曉來得雨猶鮮好，却似昂然欲鬭時。"]'),
('73aae466-e771-4e2d-af4b-7266b5b5b398','從鄧季明求菊花','李綱','宋','宋诗','song-poetry','','[]','樂全治幽圃，種花如種田。',108,'全唐诗/poet.song.89000.json','["樂全治幽圃，種花如種田。", "秋來菊有花，亦復爭芳姸。", "璀璨碧玉蕾，散作黄金錢。", "風靜香自遠，露寒色爭鮮。", "乃知萬物性，皆欲全其天。", "九日忽已近，淵明思悠然。", "願移東籬下，植此西軒前。", "我有一壺酒，泛之可延年。", "不嫌盤筯薄，同作飲中仙。"]'),
('85e05a79-2fbc-4769-b7f7-ab16771b7605','燈花','李綱','宋','宋诗','song-poetry','','[]','禪室方清夜，寒燈自結花。',48,'全唐诗/poet.song.89000.json','["禪室方清夜，寒燈自結花。", "那知人有喜，且慰客思家。", "瑣碎星鋩密，紅圓玉粒斜。", "爲傳千里信，安穏到天涯。"]'),
('30188c13-a706-44d9-a487-496fd14881e0','秋日有感','李綱','宋','宋诗','song-poetry','','[]','秋水澹澄澈，秋山鬱嵳峨。',60,'全唐诗/poet.song.89000.json','["秋水澹澄澈，秋山鬱嵳峨。", "我遊谿山亭，山空水增波。", "感此物華暮，風林搖落多。", "惟有青青松，獨立不改柯。", "喬然傲霜霰，歲晏將如何。"]'),
('96a8e65e-2273-49f0-bf02-26fdb9f20b9e','秋思十首  其一','李綱','宋','宋诗','song-poetry','','[]','朝來秋色高，西山有爽氣。',48,'全唐诗/poet.song.89000.json','["朝來秋色高，西山有爽氣。", "開軒遠相望，自得靜中意。", "那知宋玉悲，肯灑楊朱淚。", "逍遙天地間，俯仰可無愧。"]'),
('e40ac43d-d095-4a66-b528-94800181c11b','秋思十首  其二','李綱','宋','宋诗','song-poetry','','[]','夜永秋氣凉，泠然入窗牖。',48,'全唐诗/poet.song.89000.json','["夜永秋氣凉，泠然入窗牖。", "照眼一編書，開懷一壺酒。", "念身幸無恨，齒髪猶未朽。", "富貴如浮雲，於我亦何有。"]'),
('79e50a0a-3afd-40d0-a56a-f1cbd93d334b','秋思十首  其三','李綱','宋','宋诗','song-poetry','','[]','南方秋節晚，九月始凄清。',48,'全唐诗/poet.song.89000.json','["南方秋節晚，九月始凄清。", "草木忽搖落，坐使客心驚。", "橐籥無暫息，機緘殊不停。", "未能超物外，慷慨念平生。"]'),
('9a491798-7282-4478-b639-57ccd932b802','秋思十首  其四','李綱','宋','宋诗','song-poetry','','[]','露下秋草衰，蒹葭亦蒼蒼。',48,'全唐诗/poet.song.89000.json','["露下秋草衰，蒹葭亦蒼蒼。", "森然巖中桂，十里飄天香。", "深林靜杳冥，無人自芬芳。", "採掇滿禪室，閑中氣味長。"]'),
('eb2b46ad-8710-4ad0-9653-0a487c04232b','秋思十首  其五','李綱','宋','宋诗','song-poetry','','[]','秋雲澹無依，皛皛映寒日。',48,'全唐诗/poet.song.89000.json','["秋雲澹無依，皛皛映寒日。", "卷舒誰使之，聚散在倐忽。", "出岫本無心，行空寧有質。", "功成歸何方，妙用藏於密。"]'),
('cca7e057-50a9-4825-8cc1-fb471e73570d','秋思十首  其六','李綱','宋','宋诗','song-poetry','','[]','秋風晚蕭索，凄然遂成林。',48,'全唐诗/poet.song.89000.json','["秋風晚蕭索，凄然遂成林。", "百穀欲成實，見此造物心。", "清凉入户牖，天光爲沈陰。", "禪房有羈客，抱膝正長吟。"]'),
('175b2afc-eb3b-412e-a4b9-26add0483e6e','秋思十首  其七','李綱','宋','宋诗','song-poetry','','[]','秋風動禾黍，泛泛凄芳馨。',48,'全唐诗/poet.song.89000.json','["秋風動禾黍，泛泛凄芳馨。", "散策步田野，欣此百穀成。", "林下父老醉，雲間雞犬聲。", "豐年誠可樂，安得遂吾生。"]'),
('356bc73b-dd08-4f4e-bd41-bb323d3ad1b4','秋思十首  其八','李綱','宋','宋诗','song-poetry','','[]','秋月照我心，清光奈愁何。',48,'全唐诗/poet.song.89000.json','["秋月照我心，清光奈愁何。", "回薄萬古恨，月愁應更多。", "獨飲不成醉，遡月空長歌。", "安得一丸藥，高奔伴姮娥。"]'),
('b79b5f44-2369-48c8-8b2c-944ba94df552','秋思十首  其九','李綱','宋','宋诗','song-poetry','','[]','古后有明訓，霜降休百工。',48,'全唐诗/poet.song.89000.json','["古后有明訓，霜降休百工。", "草木日搖落，蟋蟀鳴堂中。", "豈不感時節，念此歲復窮。", "勞生真一夢，飄泊隨西東。"]'),
('346cb009-6e7c-468c-b38a-c42456903db1','秋思十首  其一○','李綱','宋','宋诗','song-poetry','','[]','百卉秋具腓，先隕惟梧桐。',48,'全唐诗/poet.song.89000.json','["百卉秋具腓，先隕惟梧桐。", "豈無貞潔者，獨立青霜中。", "艷艷籬下菊，青青嶺頭松。", "與君爲德友，相好永無窮。"]'),
('258f6335-df4f-4fb5-8931-9190f9592450','鄧成彦病以詩來問所以治病者作詩答之','李綱','宋','宋诗','song-poetry','','[]','四大假合初不真，筋脈纒絡相依因。',128,'全唐诗/poet.song.89000.json','["四大假合初不真，筋脈纒絡相依因。", "□□□□類芭蕉，須叟變滅如浮雲。", "風寒暑濕起衆疾，痛楚展轉勞吟呻。", "醫工對治巧用藥，分别佐使甘酸辛。", "須知病者誰受病，其中必有不病人。", "於斯薦取自調伏，沈痾消散如埃塵。", "本來面目只一體，安用更分精與神。", "欲識其中不病者，即是毗盧清淨身。"]'),
('e6e304f2-fcbc-4247-9cf6-5e56749acb34','興宗志宏見和巖桂長篇再賦前韻奉呈','李綱','宋','宋诗','song-poetry','','[]','月中有桂光更多，扶疏一輪枝幹羅。',208,'全唐诗/poet.song.89000.json','["月中有桂光更多，扶疏一輪枝幹羅。", "天風飄下廣寒子，豈與凡種同其科。", "四時不改碧玉葉，滿庭自擢青銅柯。", "森然衆木共培植，無異野鶴羣雞鵝。", "秋來隱圃風露冷，噴花看蘂尤婆娑。", "圃中自有隱君子，心與世遠恬無波。", "對花度此九秋色，不以物外傷天和。", "西隣栟櫚更好古，妙年欲製芰與荷。", "連墻請謁不知倦，宜爾鬢髪忘其皤。", "天生逸才當有用，委棄寂寞理則那。", "吾衰尚有惜花意，零落奈此馨香何。", "却思梁谿有小圃，只恐松竹荒寒莎。", "未能歸去老三徑，且把詩句從公哦。"]'),
('4d2d14e7-c5d1-47eb-957c-6bb8daa11910','九日','李綱','宋','宋诗','song-poetry','','[]','常年九日必題詩，况此飄零海一涯。',64,'全唐诗/poet.song.89000.json','["常年九日必題詩，况此飄零海一涯。", "黄菊未開青蓓蕾，白醪聊吸碧玻瓈。", "登山但極孤雲目，整帽還羞短髪箆。", "弟妺奉親傾壽斝，茱萸徧插定吾思。"]'),
('fb36cae5-a6b9-408e-8516-2f16f7dad104','菊花開日即重陽二首  其一','李綱','宋','宋诗','song-poetry','','[]','南方氣候殊，佳月即中秋。',48,'全唐诗/poet.song.89000.json','["南方氣候殊，佳月即中秋。", "昨者月既望，蕭蕭風雨愁。", "安得一輪玉，清光滿溪樓。", "酌酒自起舞，與之相獻酬。"]'),
('d906fcd2-a09f-44f8-a45e-30a041cc31b5','菊花開日即重陽二首  其二','李綱','宋','宋诗','song-poetry','','[]','南方氣候殊，有菊即重陽。',48,'全唐诗/poet.song.89000.json','["南方氣候殊，有菊即重陽。", "九日今已近，青蘂未可嘗。", "安得黄金花，泛此白玉觴。", "會當爛漫開，爲插滿頭香。"]'),
('f6d3ff08-cab4-4c6a-8f4c-a1591ecb149f','次韻杜子美九日藍田崔氏莊','李綱','宋','宋诗','song-poetry','','[]','遠謫須知懷抱寛，節逢九日亦追歡。',64,'全唐诗/poet.song.89000.json','["遠謫須知懷抱寛，節逢九日亦追歡。", "手挼青蘂看浮醆，蠟剪黄花戲插冠。", "淅淅斜風飛敗葉，蕭蕭細雨作輕寒。", "天涯只是思親切，更把家書再四看。"]'),
('a0044bbb-c2ac-4d44-bb74-941f9c025274','和陶淵明採菊東籬下二首  其一','李綱','宋','宋诗','song-poetry','','[]','九日但孤坐，悄然無世喧。',60,'全唐诗/poet.song.89000.json','["九日但孤坐，悄然無世喧。", "菊花殊未開，始知氣候偏。", "開軒寓遠目，相對惟青山。", "昏鴉已接翅，獨鶴何時還。", "且盡杯中物，此外無足言。"]'),
('adee8127-78d4-40a3-92ab-af74ddfc1a9b','和陶淵明採菊東籬下二首  其二','李綱','宋','宋诗','song-poetry','','[]','小雨濕叢菊，何當噴金英。',60,'全唐诗/poet.song.89000.json','["小雨濕叢菊，何當噴金英。", "嚼蘂亦可人，蕭然慰我情。", "羈旅念家遠，濁酒還獨傾。", "雲表雁初過，草根蟲自鳴。", "歲晏將如何，一醉豁平生。"]'),
('4b647a84-280e-4110-97a7-612fd481c50f','寓軒用竹爲窗隔以禦西風戲成小詩紀其事示志宏','李綱','宋','宋诗','song-poetry','','[]','昔我自帝所，遠謫來沙陽。',156,'全唐诗/poet.song.89000.json','["昔我自帝所，遠謫來沙陽。", "由春以涉夏，及此秋氣凉。", "節物日凄緊，白露結爲霜。", "行當入室處，聊復葺我堂。", "伐竹製窗牖，樸素無青黄。", "西風屏寒色，短日來孤光。", "草木已零落，但聞菊蘂香。", "超然適燕處，便足傲羲皇。", "釋氏戒戀著，一宿寄枯桑。", "今我日必葺，於道無乃荒。", "彼以著故戒，無著何所妨。", "譬猶夢中境，離著可兩忘。", "儻能達此理，隨寓皆道場。"]'),
('7d8e95f4-7e8b-4fc7-a8e0-fa06944d87c0','傳畫美人戲成','李綱','宋','宋诗','song-poetry','','[]','美人顔色嬌如花，鬒髪光翳朝陽鵶。',96,'全唐诗/poet.song.89000.json','["美人顔色嬌如花，鬒髪光翳朝陽鵶。", "玉釵斜插翠眉蹙，豈亦有恨來天涯。", "畫工善畫無窮意，故把雙眸翦秋水。", "丹青幻出亦動人，况復嫣然能啓齒。", "年來居士心如灰，草户金鎚擊不開。", "縱教天女來相試，虛煩雲雨下陽臺。"]'),
('df863530-9891-4923-9f09-27c1fe067df8','傳畫忠義圖','李綱','宋','宋诗','song-poetry','','[]','君臣以道合，言出心莫逆。',120,'全唐诗/poet.song.89000.json','["君臣以道合，言出心莫逆。", "膏澤下於民，美化施無極。", "中世此道衰，言如水投石。", "義士以死爭，直諫或有益。", "折檻制留今，斷鞅事存昔。", "當車血污輪，伏蒲涕霑席。", "昭然貫日誠，屹爾迴天力。", "誰將丹青手，圖此忠義跡。", "傳之置坐隅，能使懦夫激。", "斯人不復見，壯哉古遺直。"]'),
('8e3f1c93-12fb-4fb9-a4e0-d23d70dfc672','四皓','李綱','宋','宋诗','song-poetry','','[]','皓髪龐眉四老翁，商山採盡紫芝叢。',32,'全唐诗/poet.song.89000.json','["皓髪龐眉四老翁，商山採盡紫芝叢。", "安劉畢竟成何事，空墮留侯巧計中。"]'),
('7dc87356-f7fb-4295-bec7-b76007623644','高祖','李綱','宋','宋诗','song-poetry','','[]','落魄劉郎仗衆謀，無心將將却成優。',32,'全唐诗/poet.song.89000.json','["落魄劉郎仗衆謀，無心將將却成優。", "誰言大度能容物，舊怨還封羮頡侯。"]'),
('4fb65f5d-e18f-42c5-897c-eb09155bb18d','得家信報淮南飛蝗渡江入浙歲事殊可憂感而賦詩','李綱','宋','宋诗','song-poetry','','[]','聞說飛蝗起自淮，勢如風雨渡江來。',32,'全唐诗/poet.song.89000.json','["聞說飛蝗起自淮，勢如風雨渡江來。", "我家歲事何須慮，只恐人言不是災。"]'),
('83d5560a-142a-4270-9384-823ddaaf36ba','九月十四夜月蝕','李綱','宋','宋诗','song-poetry','','[]','碧落遙升白玉盆，云何中夜黯然昏。',64,'全唐诗/poet.song.89000.json','["碧落遙升白玉盆，云何中夜黯然昏。", "初疑半被微雲掩，浸恐全無巨吻吞。", "慘淡乍看蟾魄出，扶疏更喜桂華存。", "妖蟆磔死猶餘罪，此外羣星盡可原。"]'),
('05f37320-bef7-45fd-9128-e0351e17d86c','讀劉向傳','李綱','宋','宋诗','song-poetry','','[]','晝觀書傳夜觀星，感憤陳辭出至誠。',32,'全唐诗/poet.song.89000.json','["晝觀書傳夜觀星，感憤陳辭出至誠。", "梓柱指明王氏切，優柔不斷豈能行。"]'),
('af1abe1c-47a0-4ed4-bf29-36be94e1e48a','題李伯時畫老子岀關圖','李綱','宋','宋诗','song-poetry','','[]','請說常無衆妙門，當時關尹意何勤。',64,'全唐诗/poet.song.89000.json','["請說常無衆妙門，當時關尹意何勤。", "青牛西去連沙漠，紫氣東來見瑞氛。", "妙法不離三十輻，至言都在五千文。", "世人不解宗慈儉，只欲長生躡白雲。"]'),
('50d30ea7-8401-4ddd-aa79-b4a25f2e59d7','題入定僧持法師畫像','李綱','宋','宋诗','song-poetry','','[]','形若龍蛇千歲蟄，神如日月四時新。',64,'全唐诗/poet.song.89000.json','["形若龍蛇千歲蟄，神如日月四時新。", "豈知雞足山中客，元屬蓮華社裏人。", "嶺上祖師提隻履，烟中普化露全身。", "拘拘守定乾皮袋，畢竟如何始是真。"]'),
('928e24b7-5d3f-4d8a-b923-a9c7f2c143ca','題富鄭公畫像','李綱','宋','宋诗','song-poetry','','[]','天驕自昔難羈縻，憑陵中夏侵北垂。',226,'全唐诗/poet.song.89000.json','["天驕自昔難羈縻，憑陵中夏侵北垂。", "秦城萬里塹山谷，漢女遠嫁爲閼氏。", "赫然武帝事征伐，天下騷動士馬疲。", "古來制禦無上策，本朝鎮撫誠得宜。", "祖宗守邊有良將，胡騎遠遯不敢窺。", "澶淵之役起倉卒，當時衆議何其危。", "萊公庭爭乃親討，貔虎百萬從六飛。", "弩機暗發虜酋殞，震怖屈膝祈完歸。", "歡盟從此到今日，生靈休息誠賴之。", "中間桀驁邀歲賜，懸河之辯亦莫支。", "篤生鄭公爲民社，一言剖决遂不疑。", "萊鄭之功實終始，配入太廟銘鼎彞。", "我生後公不及識，再拜圖像涕泗洟。", "安得如公之人在廊廟，坐使德澤漸烝黎。"]'),
('18ea6efa-3015-44a8-acc0-d60157c75675','明妃曲','李綱','宋','宋诗','song-poetry','','[]','昭君自恃顔如花，肯賂畫史丹青加。',112,'全唐诗/poet.song.89000.json','["昭君自恃顔如花，肯賂畫史丹青加。", "十年望幸不得見，一日遠嫁來天涯。", "辭宫脉脉灑紅淚，出塞漠漠驚黄沙。", "寧辭玉質配夷虜，但恨拙謀羞漢家。", "穹廬腥羶厭酥酪，曲調幽怨傳琵琶。", "漢宫美女不知數，骨委黄土紛如麻。", "當時失意雖可恨，猶得千古詩人誇。"]'),
('a0604a12-e79b-40c8-ba88-60f8fba466a4','九月十五日夜同陳興宗鄧志宏登凝翠閣觀月','李綱','宋','宋诗','song-poetry','','[]','溪閣臨虛面勢寛，涼天佳月共追歡。',64,'全唐诗/poet.song.89000.json','["溪閣臨虛面勢寛，涼天佳月共追歡。", "漁舟忽動水光碎，桂魄未髙山影寒。", "色染林巒烟漠漠，氣侵笑語露漫漫。", "須知此景人間少，更泛蘭槳遠處看。"]'),
('1e04e1e3-e554-4cbb-9ba4-9b701a6562e7','是夜復乘泛碧齋至北溪口觀新橋與興宗志宏分題予得泛字','李綱','宋','宋诗','song-poetry','','[]','秋髙氣倍清，夜靜舟初泛。',120,'全唐诗/poet.song.89000.json','["秋髙氣倍清，夜靜舟初泛。", "露華浩如洗，月色寒可鑒。", "林巒與邑屋，左右入軒檻。", "晶熒星影搖，崷崒山光蘸。", "風微煙羃羃，溪遠波湛湛。", "端疑客乘槎，坐使雲河犯。", "觀梁且停橈，戀月愁繫纜。", "景幽費摹寫，思妙造古淡。", "吾方久於此，勝賞豈云暫。", "願同二三子，險韻時得探。"]'),
('50de6d73-dcb6-4a59-b16a-5ad164681443','志宏得碧字以詩來次其韻','李綱','宋','宋诗','song-poetry','','[]','明月照清溪，影落千尋碧。',120,'全唐诗/poet.song.89000.json','["明月照清溪，影落千尋碧。", "輕風皺微瀾，蕩漾搖金色。", "相攜理桂檝，及此萬籟寂。", "天空露氣寒，棲鳥正縮瑟。", "何人起秋思，數弄月中笛。", "坐使遷客情，悽然感去國。", "清遊得英俊，勝賞飽泉石。", "豈殊在吾家，親戚欬於側。", "賦詩各言懷，險韻對勍敵。", "歸來氣未衰，開匣看三尺。"]'),
('7479cd72-968b-4b6d-9781-c5cbc7787bfa','興宗得齋字以詩來次其韻','李綱','宋','宋诗','song-poetry','','[]','佳月靄秋色，翛然感予懷。',120,'全唐诗/poet.song.89000.json','["佳月靄秋色，翛然感予懷。", "言攜二三友，泛此溪中齋。", "風露生萬里，屋木憑兩涯。", "淒微煙霧合，芬馥天香來。", "恍若度雲漢，奔月遊瑶臺。", "灝氣集肺腑，灑濯無纖埃。", "沉沉夜寥閴，迴舟興悠哉。", "澄波靜如練，何異浮江淮。", "但恨景物美，實難賦詠才。", "斯文當共勉，天意屬吾儕。"]'),
('e191cc47-a18e-438b-9158-9bc7fe586163','凝翠晚望五絕句  其一','李綱','宋','宋诗','song-poetry','','[]','白蘋紅蓼滿汀洲，淅淅西風古渡頭。',32,'全唐诗/poet.song.89000.json','["白蘋紅蓼滿汀洲，淅淅西風古渡頭。", "寒日無情又西下，清溪不語水東流。"]'),
('5ca412f9-bded-40ea-9665-768a86ef625c','凝翠晚望五絕句  其二','李綱','宋','宋诗','song-poetry','','[]','桂香泛泛滿秋風，十里沙溪一望中。',32,'全唐诗/poet.song.89000.json','["桂香泛泛滿秋風，十里沙溪一望中。", "景物隨時慰牢落，羈臣那解感飄蓬。"]'),
('f5702d6b-0b60-4673-a080-1d1c96381e03','凝翠晚望五絕句  其三','李綱','宋','宋诗','song-poetry','','[]','日輪隱隱落西山，尚有殘陽木杪間。',32,'全唐诗/poet.song.89000.json','["日輪隱隱落西山，尚有殘陽木杪間。", "暮暮朝朝成底事，可憐飛鳥自知還。"]'),
('08937093-7ea0-4559-ac09-17e6d4ad6a29','凝翠晚望五絕句  其四','李綱','宋','宋诗','song-poetry','','[]','林中輕素起寒煙，兩兩飛鷗傍釣船。',32,'全唐诗/poet.song.89000.json','["林中輕素起寒煙，兩兩飛鷗傍釣船。", "心在江湖歸未得，晚來幽獨更悽然。"]'),
('39d9fd82-d46b-49fb-b2ed-61556886e82e','凝翠晚望五絕句  其五','李綱','宋','宋诗','song-poetry','','[]','白雲點破亂山青，影落寒谿晚更明。',32,'全唐诗/poet.song.89000.json','["白雲點破亂山青，影落寒谿晚更明。", "誰謂天涯無鴈到，雝雝初聽兩三聲。"]'),
('d10ea6ae-62e7-435b-b01b-1705316a8bbd','秋意二首  其一','李綱','宋','宋诗','song-poetry','','[]','蕭蕭南浦白雲秋，楓葉蘆花相對愁。',32,'全唐诗/poet.song.89000.json','["蕭蕭南浦白雲秋，楓葉蘆花相對愁。", "何必更窮千里目，亂山凝碧滿溪樓。"]'),
('b36b8bf1-9167-422e-b33e-c756e3490730','秋意二首  其二','李綱','宋','宋诗','song-poetry','','[]','清霜夜落梧楸樹，脫葉驚風隕如雨。',32,'全唐诗/poet.song.89000.json','["清霜夜落梧楸樹，脫葉驚風隕如雨。", "一番掃盡一番新，策杖閑將黄葉數。"]'),
('94384786-eed4-4b64-a219-c78055d346cd','和唐人張爲秋醉歌','李綱','宋','宋诗','song-poetry','','[]','秋風愈淒緊，感此梁谿翁。',192,'全唐诗/poet.song.89000.json','["秋風愈淒緊，感此梁谿翁。", "煙水出砂石，風霜脫梧桐。", "歲晏無與歡，步屧攜蒼笻。", "俯視檻中菊，仰瞻峰頂松。", "有酒聊自適，旋滴真珠紅。", "長鯨吸百川，坐使玉樽空。", "念古壯氣激，懷家歸興濃。", "陶然不知醉，如墮烟霧中。", "醉魂眇安往，夢渡江水東。", "髣髴生六翮，飄忽騰雙龍。", "醒來無所見，溪冷山重重。", "紗窗透殘月，瓦枕來疏鐘。", "起視夜將闌，星河粲玲瓏。", "乘風欲輕舉，骨肉疑都融。", "却思向來醉，豈離方寸地。", "長醉不用醒，蕭然謝名利。"]'),
('5761a5e9-29df-4e29-bba6-28ad492dc178','讀陸龜蒙散人歌三復而悲之賦詩以卒其志','李綱','宋','宋诗','song-poetry','','[]','江湖散人氣節奇，布衣韋带霜鬢垂。',160,'全唐诗/poet.song.89000.json','["江湖散人氣節奇，布衣韋带霜鬢垂。", "有田甫里多水潦，闔門百指長號饑。", "躬耕粗足輸賦稅，時赴嘉客同襟期。", "西風笠澤起秋色，菰蒲初熟鱸鱖肥。", "扁舟乘興不知晚，筆牀茶竈常相隨。", "著書叢雜自編錄，巧怪不擇文與詩。", "那能枉道竊爵禄，但欲亂世全妻兒。", "胸中豈無佐時略，却笑諸郎殊不知。", "當年富貴盡磨滅，惟有夫子傳於斯。", "三髙名配范與李，散人雖散元非癡。"]'),
('62ddf41a-3ad5-4c5e-9da8-00dada3b370b','巖桂再開尤盛汲水飬之其香滿室墮蘂几案間燦然可愛嗅玩因爲賦小詩','李綱','宋','宋诗','song-poetry','','[]','桂華十里凌霜空，再開愈覺秋光濃。',64,'全唐诗/poet.song.89000.json','["桂華十里凌霜空，再開愈覺秋光濃。", "幽人贈我不知數，芬馥飄滿禪房中。", "蔌蔌風枝墮煙蘂，璀燦金英霑案几。", "不須掃去任飄零，從使清香在毫紙。"]'),
('667297ba-2080-4172-83c7-6675c5aed3b1','遊栖雲寺','李綱','宋','宋诗','song-poetry','','[]','清曉戒徒御，出郊爲勝遊。',144,'全唐诗/poet.song.89000.json','["清曉戒徒御，出郊爲勝遊。", "霜林半搖落，肅穆天地秋。", "散策陟峻嶺，憑髙瞰清流。", "禪居得蘭若，迥覺林泉優。", "露草淒更碧，風松鬱相繆。", "山空鐘磬響，地勝池臺幽。", "竹色森不改，桂香泱漭浮。", "經行豈蓮社，景物如虎丘。", "流水人寂寂，歸雲晚悠悠。", "惜哉光景促，妙賞難淹留。", "却步出山徑，猶迴戀山眸。", "登臨興未盡，更理溪中舟。"]'),
('1f73679f-d047-4770-a6cf-eac9c4cdd908','自西津乘泛碧齋歸邑小雨','李綱','宋','宋诗','song-poetry','','[]','亂山深處翠光浮，山寺歸來泛彩舟。',64,'全唐诗/poet.song.89000.json','["亂山深處翠光浮，山寺歸來泛彩舟。", "十里峰巒凝翠靄，一溪煙雨灑清秋。", "漁燈照水明還暗，野桂飄香散不收。", "只向畫中求好景，不知身在畫中遊。"]'),
('04643573-a6f7-4df6-ab7f-28ba512f37a2','是日聞報御筆許牽復有感','李綱','宋','宋诗','song-poetry','','[]','聞有佳音自日邊，羈臣感極却悽然。',64,'全唐诗/poet.song.89000.json','["聞有佳音自日邊，羈臣感極却悽然。", "矜愚本自加三宥，作賦休云謫九年。", "戲膝但能紆彩服，侍香那復望青氈。", "恩隆天地當何報，擊壤爲甿老一鄽。"]'),
('0c8f2907-c288-4134-9bd0-c32bbb4fa6fa','畫荔枝圖','李綱','宋','宋诗','song-poetry','','[]','南閩荔枝名四方，非因謫官那得嘗。',224,'全唐诗/poet.song.89000.json','["南閩荔枝名四方，非因謫官那得嘗。", "丁香爲核玉爲葉，絳綃爲殻冰爲瓤。", "烱如明珠出老蚌，燦如艷女披紅裳。", "膜凝雲母本來薄，液貯甘露初不漿。", "剖擎頗訝水晶滑，咀嚼但覺瓊瑶香。", "貢餘雖幸得一飽，無那品目多難詳。", "丹青巧爲拂絹素，數種磊落皆其良。", "牛心最大蚶殻褊，虎皮斑駮龍牙長。", "火山早依炎氣熟，中元晚待秋風凉。", "色奇更變江家綠，味旨尤稱十八娘。", "葡萄結實極繁盛，硫黄著子何芬芳。", "若將牡丹與比並，好把陳紫同姚黄。", "雖云香味不可畫，悅目自足垂虛堂。", "飫餐更得畫歸去，須信遠謫元非狂。"]'),
('d1e263bd-6087-4b3f-8c90-b67ad5856aa1','叢菊數日來頗有開意戲題','李綱','宋','宋诗','song-poetry','','[]','愛菊如淵明，憑欄惜花晏。',48,'全唐诗/poet.song.89000.json','["愛菊如淵明，憑欄惜花晏。", "朝來有開意，嫩蘂肥欲綻。", "願承玉露漙，一吐金英粲。", "臨風嗅馨香，爲爾發三歎。"]'),
('1bc9c3b9-9fdf-4126-b3c6-5e93f9264fe9','得了翁書并寄石芝云其味初淡中苦已而發甘鮮有此味者感而賦詩','李綱','宋','宋诗','song-poetry','','[]','海日氣射蒼崖根，石上生枝乾蘚文。',128,'全唐诗/poet.song.89000.json','["海日氣射蒼崖根，石上生枝乾蘚文。", "構梯採掇資好事，中有至味難爲言。", "豈惟食淡兼攻苦，嚼蠟茹荼多欲吐。", "清甘徐發齒頰間，潄以寒泉如飲乳。", "幽人贈我意已深，一掬可比千黄金。", "世間此味知者鮮，往往既吐還追尋。", "我欲持之獻君子，自古至言多逆耳。", "願於苦處辨忠良，若待迴甘真晚矣。"]'),
('7fe23fba-0d76-4afe-ad69-f6ce9f318666','次韻和歸去來集字十首  其一','李綱','宋','宋诗','song-poetry','','[]','少負丘壑志，誤嬰軒冕榮。',48,'全唐诗/poet.song.89000.json','["少負丘壑志，誤嬰軒冕榮。", "剛腸難隱忍，懶性倦將迎。", "學佛欣自得，謫官知物輕。", "悠悠勢利子，千古見交情。"]'),
('843853de-57ed-48b1-9d53-9a188074b11b','次韻和歸去來集字十首  其二','李綱','宋','宋诗','song-poetry','','[]','壯志已衰落，頺然成懦夫。',48,'全唐诗/poet.song.89000.json','["壯志已衰落，頺然成懦夫。", "編須休虎穴，曳尾且龜塗。", "松菊猶可理，田園將欲蕪。", "親朋悅情話，濁酒在觴壺。"]'),
('95b8af18-cbf5-4157-86b6-1d9c841609de','次韻和歸去來集字十首  其三','李綱','宋','宋诗','song-poetry','','[]','軒冕豈足戀，田園誠可歡。',48,'全唐诗/poet.song.89000.json','["軒冕豈足戀，田園誠可歡。", "村村自花柳，物物寄游觀。", "舊事不復憶，吾生良易安。", "南窗審容膝，歸去學鯢桓。"]'),
('6f0ffe83-0f7f-419f-b066-4184afcc0e65','次韻和歸去來集字十首  其四','李綱','宋','宋诗','song-poetry','','[]','聞說詔初下，預知歸有期。',48,'全唐诗/poet.song.89000.json','["聞說詔初下，預知歸有期。", "趣裝行去矣，俟命且安之。", "出處宛如夢，去來惟有詩。", "爲傳千里信，先報棣華知。"]'),
('620a8637-2dfc-4a33-9d42-b802c10ed52e','次韻和歸去來集字十首  其五','李綱','宋','宋诗','song-poetry','','[]','曠蕩推新澤，迂疏念昔非。',48,'全唐诗/poet.song.89000.json','["曠蕩推新澤，迂疏念昔非。", "休爲賈生賦，且治老萊衣。", "報國撫長劍，懷親歌式微。", "憑髙望吴越，千里白雲飛。"]'),
('cedfdfea-613a-40f7-91cd-b8c807688069','次韻和歸去來集字十首  其六','李綱','宋','宋诗','song-poetry','','[]','寤寐在親所，得歸欣載奔。',48,'全唐诗/poet.song.89000.json','["寤寐在親所，得歸欣載奔。", "綵衣猶在笥，素髪已垂門。", "遣興詩千首，忘憂酒一罇。", "歸歟理三徑，松菊故應存。"]'),
('ec98289b-ae1b-4bca-b920-f7252e305cf4','次韻和歸去來集字十首  其七','李綱','宋','宋诗','song-poetry','','[]','歸去復歸去，溪山滿眼前。',48,'全唐诗/poet.song.89000.json','["歸去復歸去，溪山滿眼前。", "公垂餘舊館，鴻漸有甘泉。", "結宇依青嶂，開池浸碧天。", "餘波到山下，更漑萬家田。"]'),
('18355b46-7c45-4bfb-814f-3e147d93b870','次韻和歸去來集字十首  其八','李綱','宋','宋诗','song-poetry','','[]','薄責思已厚，聽歸初不留。',48,'全唐诗/poet.song.89000.json','["薄責思已厚，聽歸初不留。", "昔來聊坎止，今去亦川流。", "圖史自可樂，親朋相與遊。", "罇中常有酒，此外復何求。"]'),
('90e96cd5-3661-4f91-849b-e16827e3e51e','次韻和歸去來集字十首  其九','李綱','宋','宋诗','song-poetry','','[]','舊隱北山北，結廬猶可尋。',48,'全唐诗/poet.song.89000.json','["舊隱北山北，結廬猶可尋。", "曾傳種松法，當遂採芝心。", "有酒且觴客，無絃何用琴。", "一生幾量屐，慎勿廢登臨。"]'),
('af9ad823-4073-4703-a6c0-928e10dac51a','次韻和歸去來集字十首  其一○','李綱','宋','宋诗','song-poetry','','[]','處世若大夢，吾生感行休。',48,'全唐诗/poet.song.89000.json','["處世若大夢，吾生感行休。", "何須縳軒冕，且復傲林丘。", "雲木千巖秀，煙波萬壑流。", "忘機齊物我，魚鳥與君遊。"]'),
('fdf91428-60ea-415d-a79f-6b39629a5eea','送羅惇詩赴舉','李綱','宋','宋诗','song-poetry','','[]','計偕西去不容遲，暫聚還分與願違。',64,'全唐诗/poet.song.89000.json','["計偕西去不容遲，暫聚還分與願違。", "丹桂一枝應俯拾，青雲萬里看横飛。", "我方謫宦陪鳩杖，子欲成名戲綵衣。", "努力爭先龍虎榜，發揮家學慰庭闈。"]'),
('cb3ea9e3-4c64-4347-9da2-62ac26b477ad','從人於柳木得芝一本面徑尺餘體圓而欹正類荷葉惜其生於僻遠不得與奏牘爲賦此詩','李綱','宋','宋诗','song-poetry','','[]','草木何爲亦發祥，靈芝三秀向沙陽。',64,'全唐诗/poet.song.89000.json','["草木何爲亦發祥，靈芝三秀向沙陽。", "成叢已茁枯梅上，盈尺還生臥柳傍。", "葉若圓荷方瀉露，色如紫椹更飄香。", "惜哉地去長安遠，不使公卿草賀章。"]'),
('7c0f5e88-3091-44fa-b39a-f3d3736b7aa2','將去沙陽留别鄧季明諸公','李綱','宋','宋诗','song-poetry','','[]','一載沙陽信有緣，寛恩許去却依然。',64,'全唐诗/poet.song.89000.json','["一載沙陽信有緣，寛恩許去却依然。", "碧齋翠閣已如夢，明月清風長自妍。", "溪上客舟横一葉，篋中詩卷賸千篇。", "諸公别後應思我，茗飲時時到寓軒。"]'),
('c0e794fd-20d4-4a96-8968-6a78d265aad2','疇老修撰見示七峰吟因成七言十韻律詩以叙别','李綱','宋','宋诗','song-poetry','','[]','謫墮閩山款棟閎，日親髙義慰平生。',160,'全唐诗/poet.song.89000.json','["謫墮閩山款棟閎，日親髙義慰平生。", "忘年許結看經社，乘興時參在野旌。", "三徑髙懷窮水石，七峰佳氣入軒楹。", "舫齋談笑龜魚慣，翠閣吟哦卷軸成。", "方幸遊從陪杖屨，敢將蹤跡歎蓬萍。", "寛恩宥罪千鈞重，小艇浮溪一葉輕。", "北闕未應容接武，東臯從此遂躬耕。", "寧親幸愜區區志，去德還深戀戀情。", "般若光中無聚散，毗盧海裏任從横。", "願公更展垂天翼，拭目鵬摶九萬程。"]'),
('bbcc81cc-2483-48fe-b15e-055d60d1ad13','自沙陽乘泛碧齋至洛陽口','李綱','宋','宋诗','song-poetry','','[]','罪大昔來謫，恩寛今許歸。',96,'全唐诗/poet.song.89000.json','["罪大昔來謫，恩寛今許歸。", "碧齋還泛泛，翠閣已依依。", "簫鼓轉山曲，旌旗搖夕暉。", "餘霞方散亂，倦鳥亦歸飛。", "頗悟邯鄲夢，還尋萊子衣。", "耄倪嗟得去，朋友惜相違。", "詎有甘棠愛，徒知蘧玉非。", "勞生成底事，歸老釣魚磯。"]'),
('8a280a13-5dd8-4ac5-8114-25b455dd66bc','留題雙溪閣書呈南劍守謝少卿','李綱','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','華構何年玉斧修，規摹宏麗屬賢侯。',160,'全唐诗/poet.song.89000.json','["華構何年玉斧修，規摹宏麗屬賢侯。", "治成不廢登臨樂，望遠宜窮水石幽。", "千里煙雲瞻北闕，四時風景冠南州。", "山如蟠踞成龍虎，劍有雌雄射斗牛。", "天倚筆峰排玉筍，仙留篆石浸銀鈎。", "二川俯瞰丁爲字，萬室傍連蜃結樓。", "罇俎幸容陪勝賞，笙歌更覺助清遊。", "朝雲暮雨滕王閣，明月清風白鷺洲。", "夢草惠連留句法，遊山安石繼風流。", "尚能執筆從公賦，却恨歸鞍不可留。"]'),
('1fce2351-c225-4940-b44b-40a59739e1f5','黄道夫約遊南山無名菴謁包法師','李綱','宋','宋诗','song-poetry','','[]','碧山盤屈白雲凝，竹徑通幽水石清。',32,'全唐诗/poet.song.89000.json','["碧山盤屈白雲凝，竹徑通幽水石清。", "門對演仙千古在，道人何事學無名。"]'),
('c6c97463-8bb8-4834-a382-4c7b13237267','奉酬陳之元教授見贈次韻','李綱','宋','宋诗','song-poetry','','[]','謫官因得窮林泉，陶寫聊復資詩篇。',176,'全唐诗/poet.song.89000.json','["謫官因得窮林泉，陶寫聊復資詩篇。", "青岑疊疊山滿眼，碧波湛湛溪涵天。", "南連海嶠饒霧雨，北望吴越淒風煙。", "感懷觸目還得句，但可娱戲那敢傳。", "譬猶候蟲與時鳥，自鳴自已真偶然。", "豈知飄落廣文耳，飾以妙語煩雕鐫。", "與公平生未相識，一見傾心誰與易。", "沙陽百里阻遊從，注目寒空暮雲碧。", "朅來邂逅慰所思，況得新詩飛霹靂。", "我今歸去隱梁谿，遠跡江湖飬愚直。", "看公白日上青霄，九萬扶搖不勞力。"]'),
('9a34414f-3cbb-4a70-be44-80eb5ea7cd4d','謝德夫約遊開平寺','李綱','宋','宋诗','song-poetry','','[]','出郭山村僻，尋真殿閣幽。',48,'全唐诗/poet.song.89000.json','["出郭山村僻，尋真殿閣幽。", "雙溪餘賞興，五馬故來遊。", "鐘梵含古思，林泉銷客愁。", "歸歟碧雲合，羅綺滿蘭舟。"]'),
('af898ecd-7589-47ff-ba4c-4468df7a8706','謝守送别至黯淡寺','李綱','宋','宋诗','song-poetry','','[]','送遠勞爲黯淡行，西風斜日嫋雙旌。',64,'全唐诗/poet.song.89000.json','["送遠勞爲黯淡行，西風斜日嫋雙旌。", "舟如一葉波濤舞，灘作半天風雨聲。", "修竹拂雲青蓊鬱，圓峰對閣翠崢嶸。", "如公髙義今人少，行客空餘戀德情。"]'),
('b17f6c4e-ff60-4293-95c2-796d51394338','長灘驛次韻陸惇禮留題二絕句  其一','李綱','宋','宋诗','song-poetry','','[]','文彩飄颻青瑣郎，朝班同望赭袍光。',32,'全唐诗/poet.song.89000.json','["文彩飄颻青瑣郎，朝班同望赭袍光。", "嶺雲深處觀題句，使我幡然念帝鄉。"]'),
('c129e0ac-143f-4c7e-b35f-9aea3a76884f','長灘驛次韻陸惇禮留題二絕句  其二','李綱','宋','宋诗','song-poetry','','[]','當年狂直叩龍墀，謫墮閩山省舊非。',32,'全唐诗/poet.song.89000.json','["當年狂直叩龍墀，謫墮閩山省舊非。", "須信寛恩若天地，纔周歲律已容歸。"]'),
('a6297b0a-5057-4cab-a947-b7b2443810e0','題黄亭驛','李綱','宋','宋诗','song-poetry','','[]','雲山一带碧崔嵬，迎我南遷又北迴。',32,'全唐诗/poet.song.89000.json','["雲山一带碧崔嵬，迎我南遷又北迴。", "歲籥纔周兩經歷，此行端爲武夷來。"]'),
('c0e2784c-f1be-4095-9ea9-ac67ec7841c7','武夷行','李綱','宋','宋诗','song-poetry','','[]','憶昨退朝門下省，槐影扶疏清晝永。',192,'全唐诗/poet.song.89000.json','["憶昨退朝門下省，槐影扶疏清晝永。", "瑣窗一枕夢仙山，覺來毛骨猶清冷。", "謫官道出武夷山，風景翛然似夢間。", "碧溪九曲山萬疊，況值密雪妝煙鬟。", "寛恩今日容歸去，笑指洞天尋舊路。", "霜晴日暖白雲深，遥望幔亭天一柱。", "羽人導我遊仙谿，翠壁蒼崖晚更奇。", "浩歌快飲縱迴櫂，星月耿耿風淒淒。", "曉來換骨巖中看，玉潤金堅餘片片。", "三姝駢立映彤霞，二水交流縈素練。", "征鞍欲去更從容，仙境靈跡豈易逢。", "他日追思不可到，夢魂還過七閩中。"]'),
('a8ebfec1-469c-4413-8be3-06853eb85b7f','泛遊仙溪','李綱','宋','宋诗','song-poetry','','[]','去年遊仙滿溪雪，今年遊仙一船月。',64,'全唐诗/poet.song.89000.json','["去年遊仙滿溪雪，今年遊仙一船月。", "武夷已擅天下奇，雪月相輝更幽絕。", "前生定在此山中，緣熟重遊六六峰。", "慚愧真仙借光景，恨無道骨與仙風。"]'),
('7a2ff78d-213c-42ae-89fe-8287f83a8d55','别武夷途中偶成寄觀妙法師','李綱','宋','宋诗','song-poetry','','[]','道妙觀來物物通，武夷仙境幸相逢。',64,'全唐诗/poet.song.89000.json','["道妙觀來物物通，武夷仙境幸相逢。", "溪流玉雪三三曲，山鎖雲霞六六峰。", "去路歸鞍方眷戀，淡煙疏雨正蒙茸。", "羡師日在神仙窟，迴首巖巒紫翠重。"]'),
('be60d7cf-b642-4c54-a6c0-108758a57fd2','寄題觀妙師閣皂山舊隱觀雲軒','李綱','宋','宋诗','song-poetry','','[]','獨搆幽軒福地陰，飛雲對面起青岑。',64,'全唐诗/poet.song.89000.json','["獨搆幽軒福地陰，飛雲對面起青岑。", "但知映日能成色，誰信崇朝解作霖。", "苒苒行雲寧有跡，霏霏出岫本無心。", "道人默坐觀舒卷，至理應符妙意深。"]'),
('987a251a-820d-4d17-945c-d5783348fcc3','崇安令朱邈公達送示武夷圖因成絕句','李綱','宋','宋诗','song-poetry','','[]','秀氣蜿蜒作武夷，巖巒窈窕白雲飛。',32,'全唐诗/poet.song.89000.json','["秀氣蜿蜒作武夷，巖巒窈窕白雲飛。", "再遊未盡平生興，六幅生綃畫得歸。"]'),
('ffe90414-d092-41d9-9faf-6bd19a2c57ba','自分水嶺過江南','李綱','宋','宋诗','song-poetry','','[]','行盡閩山萬屈盤，江南形勢陡然寛。',64,'全唐诗/poet.song.89000.json','["行盡閩山萬屈盤，江南形勢陡然寛。", "山平水遠望不盡，木落草枯霜始寒。", "醉裏謳吟聊自適，夢中往復本非難。", "誰言春信年年早，笑指江梅試折看。"]'),
('c39cae9d-de70-40ae-86c0-6c80e2602d8b','鉛山約髙無咎同遊石井','李綱','宋','宋诗','song-poetry','','[]','巖洞嵌空鑿翠崖，一泓雲液貯瓊瑰。',32,'全唐诗/poet.song.89000.json','["巖洞嵌空鑿翠崖，一泓雲液貯瓊瑰。", "幽人須信耽泉石，茗飲相招特特來。"]'),
('b4cf6a00-b6a3-407e-bb0d-696f12a06e14','自鉛山迂路至吴園','李綱','宋','宋诗','song-poetry','','[]','迂路入江南，寒煙鎖翠嵐。',48,'全唐诗/poet.song.89000.json','["迂路入江南，寒煙鎖翠嵐。", "清晨遊石井，薄暮宿了巖。", "月冷不成夢，雞號還整驂。", "吴園纔數舍，去去指龍潭。"]'),
('a94b729c-313d-4c52-923a-f16c5e36dff4','吴園','李綱','宋','宋诗','song-poetry','','[]','當時親迎到吴園，屈指重來十七年。',32,'全唐诗/poet.song.89000.json','["當時親迎到吴園，屈指重來十七年。", "身世恍然如一夢，從今歸去老林泉。"]'),
('97fa7909-a220-42b5-8d9d-80cf7f8ec9c6','留題月巖','李綱','宋','宋诗','song-poetry','','[]','廣寒宫殿寄幽巖，忌滿非緣玉斧戡。',64,'全唐诗/poet.song.89000.json','["廣寒宫殿寄幽巖，忌滿非緣玉斧戡。", "皓魄半輪横道左，清光千古照江南。", "陰精凝結元無質，神化肧胎豈易探。", "好是月華生碧落，扶疏桂影遠相參。"]'),
('03ecfcd4-e108-4cbf-8f7d-f99744dca505','宿黄藤驛','李綱','宋','宋诗','song-poetry','','[]','古驛號黄藤，休鞍夜已燈。',48,'全唐诗/poet.song.89000.json','["古驛號黄藤，休鞍夜已燈。", "溪寒水清淺，山瘦石稜層。", "豪客路方阻，歲寒陰始凝。", "開懷惟仗酒，獨酌醉瞢騰。"]'),
('2f04aa44-f331-408d-8e82-328a5b0f3b03','弋陽道中','李綱','宋','宋诗','song-poetry','','[]','南去北來皆歲暮，流年苒苒過光陰。',64,'全唐诗/poet.song.89000.json','["南去北來皆歲暮，流年苒苒過光陰。", "江南須信風煙好，浙右方虞寇盗深。", "雲外山深横筆格，月中灘響疊琴心。", "臥龍三顧今寥落，抱膝空爲梁甫吟。"]'),
('4c368193-018a-47fd-a140-d6e73eb3074a','望龜峰','李綱','宋','宋诗','song-poetry','','[]','饒陽景物猶武夷，巖石崛起多瓌奇。',176,'全唐诗/poet.song.89000.json','["饒陽景物猶武夷，巖石崛起多瓌奇。", "此峰厥狀更詭異，舉首曳尾如靈龜。", "穹隆曝甲正霜曉，蹣跚引氣當晴暉。", "故知造化巧凝結，欲問所以良難推。", "我疑龍伯釣溟渤，六鼇連引背負歸。", "中途遺一尚贔屓，直欲赴海冠峨巍。", "又疑清江使河伯，波濤相失留於斯。", "化爲巨石峙千古，雖欲鑽灼無由施。", "茫茫神怪不可詰，但使風景增清輝。", "我來閩嶺厭山水，見此還復伸雙眉。", "頗嗟行役不果到，側身西望生長悲。"]'),
('2538ec57-f4d7-4783-8e14-f3dc97797dcf','鳴山驛次韻蔡君謨續夢作','李綱','宋','宋诗','song-poetry','','[]','一夢神遊紫府天，覺來身寄驛亭眠。',32,'全唐诗/poet.song.89000.json','["一夢神遊紫府天，覺來身寄驛亭眠。", "何須悵望吹簫女，獨跨青鸞入翠煙。"]'),
('4cf6db60-61c8-4b43-bcbf-12a9b3978496','宿安仁雲錦堂','李綱','宋','宋诗','song-poetry','','[]','一宿溪邊雲錦堂，煙村浮動野梅香。',64,'全唐诗/poet.song.89000.json','["一宿溪邊雲錦堂，煙村浮動野梅香。", "沙平水澹近江浦，天闊山遥多夕陽。", "北陸寒凝風眇眇，東吴音斷意茫茫。", "片言無補空來往，贏得蕭條兩鬢霜。"]'),
('ec97fa37-0eb5-4942-ba36-d07b2b902402','餘干','李綱','宋','宋诗','song-poetry','','[]','歲寒迂路過江鄉，歎息飛蓬墮渺茫。',64,'全唐诗/poet.song.89000.json','["歲寒迂路過江鄉，歎息飛蓬墮渺茫。", "雲錦洞深煙水遠，琵琶洲轉暮灘長。", "田園歸去荒三徑，金鼓傳聞震一方。", "極目東吴何處是，斷霞輕靄落殘陽。"]'),
('7a759ff0-4468-43b7-84a8-dfb573814ab4','晚行','李綱','宋','宋诗','song-poetry','','[]','歲杪旅懷惡，驅車殘照中。',48,'全唐诗/poet.song.89000.json','["歲杪旅懷惡，驅車殘照中。", "暮雲千里碧，落日半輪紅。", "掠水起行鴈，隔林聞遠鐘。", "休鞍僧舍閑，皓月又生東。"]'),
('156c9655-029f-44a5-ac6c-d695fff4fb35','題安國寺翠玉亭呈平老','李綱','宋','宋诗','song-poetry','','[]','蘭若何年種碧瑜，凌霄髙節笑楸梧。',64,'全唐诗/poet.song.89000.json','["蘭若何年種碧瑜，凌霄髙節笑楸梧。", "渭川謾說三千畝，杜牧宜誇十萬夫。", "月舞清陰金影碎，風敲幽韻玉音敷。", "煩師長飬休斤斧，試問江南有此無。"]'),
('6f607c5e-eec7-4755-b363-0073514d3611','題仁義驛歲寒堂范文正公所植六松','李綱','宋','宋诗','song-poetry','','[]','江驛森森六本松，蜿蜒枝幹走虬龍。',64,'全唐诗/poet.song.89000.json','["江驛森森六本松，蜿蜒枝幹走虬龍。", "煙滋鱗甲蒼顔老，雲惹須髯美蔭濃。", "獨立雪霜君子操，曾因風雨大夫封。", "不栽桃李追時好，歎息前賢意可宗。"]'),
('bf0e7d83-dc6c-461e-b6a2-8be89ca2294e','聞浙東方寇大作道路不通迂路由江南以歸有感二首  其一','李綱','宋','宋诗','song-poetry','','[]','理裝適吴會，避寇由江濱。',144,'全唐诗/poet.song.89000.json','["理裝適吴會，避寇由江濱。", "寧知治安世，乃作途窮人。", "風濤豈不險，舟檝尚可因。", "失身入畏塗，難以理義陳。", "平生笑子美，逃亂走踆踆。", "如今翻自笑，亦須謀此身。", "此身何足惜，上有髙年親。", "骨肉幾百口，干戈已相鄰。", "以我此日心，知彼無辜倫。", "安得濟川舟，載之適通津。", "徙置安樂土，不知戰鬪塵。", "已矣可奈何，願爲太平民。"]'),
('d8153780-277f-40ee-8d5f-fc1618bf7460','聞浙東方寇大作道路不通迂路由江南以歸有感二首  其二','李綱','宋','宋诗','song-poetry','','[]','東南久無備，盗賊起不虞。',132,'全唐诗/poet.song.89000.json','["東南久無備，盗賊起不虞。", "掲竿與荷鋤，皆是耕田夫。", "誰爲捕逐者，得官緣苞苴。", "不讀一行字，況復知孫吴。", "厥初既輕敵，屢北輙睢旴。", "屯兵非不多，一掃不復餘。", "虎兕出於柙，是誰之過歟。", "凶焰陵郡縣，良民遭戮屠。", "坐令腹心地，化爲豺豕區。", "除惡當務早，滋蔓良難圖。", "王師何日出，努力觀廟謨。"]'),
('cf560e90-04a0-492c-b607-78785240ce32','童子驛見梅花  其一','李綱','宋','宋诗','song-poetry','','[]','天滑雲腴凝不流，歲寒迂騎過南洲。',32,'全唐诗/poet.song.89000.json','["天滑雲腴凝不流，歲寒迂騎過南洲。", "黄昏孤館沈吟處，賴有江梅慰客愁。"]'),
('1bd5ec8d-76d1-4582-90b9-8e687cdf56ab','童子驛見梅花  其二','李綱','宋','宋诗','song-poetry','','[]','江南爲客見江梅，似爲行人特特開。',32,'全唐诗/poet.song.89000.json','["江南爲客見江梅，似爲行人特特開。", "數點枝頭凝玉雪，隔窗和月送香來。"]'),
('33156cf6-fbe2-4583-9ef4-2a468c6850b9','偶題  其一','李綱','宋','宋诗','song-poetry','','[]','霜風響枯林，曠野慘寒色。',48,'全唐诗/poet.song.89000.json','["霜風響枯林，曠野慘寒色。", "川路阻且長，客子方遠適。", "東吴眇何在，仰羡歸飛翼。", "惟有溪邊梅，猶能慰愁寂。"]'),
('cd097517-08be-443b-9ca1-6db810b2b236','偶題  其二','李綱','宋','宋诗','song-poetry','','[]','水落潮乾人取途，西風索索響黄蘆。',32,'全唐诗/poet.song.89000.json','["水落潮乾人取途，西風索索響黄蘆。", "沙頭驚起數行鴈，恰似舊藏蘆鴈圖。"]'),
('6141c96d-1f74-4ff5-87d1-924042f32796','題建德縣開化寺','李綱','宋','宋诗','song-poetry','','[]','路遶江南煙水村，梅花的皪正銷魂。',64,'全唐诗/poet.song.89000.json','["路遶江南煙水村，梅花的皪正銷魂。", "峰巒影裏過山邑，鼙鼓聲中念故園。", "殘臘未曾看雪舞，勁風何事掃雲屯。", "拙翁自笑平生拙，欲叩天閽更一言。"]'),
('3e95467b-28bf-4320-8830-7e22457489ba','題紫巖驛','李綱','宋','宋诗','song-poetry','','[]','稚年曾向此途行，半世重來若泛萍。',64,'全唐诗/poet.song.89000.json','["稚年曾向此途行，半世重來若泛萍。", "山徑車聲欣路坦，江村市合厭魚腥。", "連天霜草蕭蕭白，蟠嶺雲松鬱鬱青。", "久旅懷家歸尚遠，暮煙殘照宿郵亭。"]'),
('b6f81d90-363a-4668-81a1-38e7c6a69908','贈池守張閎道','李綱','宋','宋诗','song-poetry','','[]','繡衣執法出霜臺，邂逅還如特特來。',64,'全唐诗/poet.song.89000.json','["繡衣執法出霜臺，邂逅還如特特來。", "華省舊曾陪笑語，清溪今復接罇罍。", "喜公筆有江山氣，顧我心如世味灰。", "天下蒼生待經濟，坐看蟠蟄起春雷。"]'),
('72648787-306c-42dc-a12f-e013f57dedfc','同天寧聰老遊齊山次杜牧之韻','李綱','宋','宋诗','song-poetry','','[]','東風初起白雲飛，禪客相邀步翠微。',64,'全唐诗/poet.song.89000.json','["東風初起白雲飛，禪客相邀步翠微。", "童稚舊遊如夢到，江山今幸假途歸。", "巖巒窈窕籠輕靄，鷗鷺翩翻舞夕暉。", "歸覲庭闈詢往事，篋中先整老萊衣。"]'),
('52c7376b-dc9c-460e-aa61-e55000b24ec0','題弄水亭','李綱','宋','宋诗','song-poetry','','[]','蕭條秋浦景如秋，誰信猿聲使客愁。',64,'全唐诗/poet.song.89000.json','["蕭條秋浦景如秋，誰信猿聲使客愁。", "煙樹森森連遠嶠，水田漠漠集飛鷗。", "髙樓吹角增離恨，古驛停驂憶舊遊。", "亦欲題詩江祖石，謫仙遺跡最風流。"]'),
('78e7a9cd-b2a4-4bb2-8f9e-9ea0bc722406','自池口登舟','李綱','宋','宋诗','song-poetry','','[]','水落溪乾不可舟，春潮理櫂淺沙頭。',64,'全唐诗/poet.song.89000.json','["水落溪乾不可舟，春潮理櫂淺沙頭。", "多風煙浪鱗鱗起，欲雪江雲苒苒浮。", "涉險物情終共畏，臨流歸興浩難收。", "波神借我風帆便，鼓柁清江汗漫遊。"]'),
('84f3e0d0-8b31-4947-b544-5ea59d8823b5','江行十首  其一','李綱','宋','宋诗','song-poetry','','[]','理櫂適江干，初欣眼界寛。',48,'全唐诗/poet.song.89000.json','["理櫂適江干，初欣眼界寛。", "日蒸江氣白，風約櫓聲寒。", "蔣詡謀新徑，鍾儀只舊冠。", "浮雲休蔽日，直北是長安。"]'),
('f3637c11-b47a-411f-9110-d9d26f116eda','江行十首  其二','李綱','宋','宋诗','song-poetry','','[]','春江徹底清，沙尾見潮生。',48,'全唐诗/poet.song.89000.json','["春江徹底清，沙尾見潮生。", "朝氣噓成霧，南風戰作晴。", "岸移看樹遠，船穩信波平。", "覽盡江山勝，還悲萬古情。"]'),
('10fab2a4-ec52-4230-9bf3-1d3683425999','江行十首  其三','李綱','宋','宋诗','song-poetry','','[]','渺渺春江穩，融融午睡腴。',48,'全唐诗/poet.song.89000.json','["渺渺春江穩，融融午睡腴。", "夢回雙櫓急，望極片帆孤。", "皺水風還逆，維舟日欲晡。", "雲中有行鴈，苒苒下平蕪。"]'),
('e2435666-a39f-4ecd-a290-91cdd12e9822','江行十首  其四','李綱','宋','宋诗','song-poetry','','[]','春光搖畫鷁，江影浸長天。',48,'全唐诗/poet.song.89000.json','["春光搖畫鷁，江影浸長天。", "浪勢隨潮急，渦痕逐櫓圓。", "避風依島嶼，防寇問人煙。", "深念還愁絕，髙歌且醉眠。"]'),
('8e11f42f-85db-466a-8207-16ce2eb589c6','江行十首  其五','李綱','宋','宋诗','song-poetry','','[]','江闊水雲暮，風髙舟檝停。',48,'全唐诗/poet.song.89000.json','["江闊水雲暮，風髙舟檝停。", "落帆歸别浦，宿鴈集迴汀。", "霜葦蕭蕭白，煙嵐朵朵青。", "夜來江色靜，寒浴一天星。"]'),
('262c2b5e-4392-48f6-aba1-bfb8609e2bcf','江行十首  其六','李綱','宋','宋诗','song-poetry','','[]','朝來問風信，五兩向南飛。',48,'全唐诗/poet.song.89000.json','["朝來問風信，五兩向南飛。", "旅泊添春恨，舟行與願違。", "瓶梅空的的，岸柳已依依。", "寂寞江南路，那知自此歸。"]'),
('f6cd6da4-cf8d-4c12-a26d-7daa9c01d581','江行十首  其七','李綱','宋','宋诗','song-poetry','','[]','春江望不極，慘淡起層陰。',48,'全唐诗/poet.song.89000.json','["春江望不極，慘淡起層陰。", "煙雨濛濛濕，雲濤渺渺深。", "懷家千里意，報國一生心。", "歎息知音少，空爲梁甫吟。"]'),
('cd1f2369-93bd-431a-be9d-1548df43c7b4','江行十首  其八','李綱','宋','宋诗','song-poetry','','[]','晚泊銅陵口，煙村八九家。',48,'全唐诗/poet.song.89000.json','["晚泊銅陵口，煙村八九家。", "岸沙崩浪響，江雨带風斜。", "泛泛浮波鴈，捎捎接翅鵶。", "無情東注水，對爾歎年華。"]'),
('47fd5b38-70b7-4b76-81bf-ca259b6b2349','江行十首  其九','李綱','宋','宋诗','song-poetry','','[]','杳杳楚天闊，悠悠江浦清。',48,'全唐诗/poet.song.89000.json','["杳杳楚天闊，悠悠江浦清。", "便風帆腹滿，順水櫓腰輕。", "煙澹山逾碧，雲髙雨易晴。", "無心問漁父，濁酒慰平生。"]'),
('5234a22b-fcaf-464b-b83a-81aea742dff3','江行十首  其一○','李綱','宋','宋诗','song-poetry','','[]','春到江波綠，潮來浦溆深。',48,'全唐诗/poet.song.89000.json','["春到江波綠，潮來浦溆深。", "曉風看五兩，家信抵千金。", "笑讀謫仙句，病爲莊舄吟。", "世途遊歷徧，歸去老山林。"]'),
('5274e869-3c75-4f73-aeae-77fc741c0297','遊五松山觀李太白祠堂','李綱','宋','宋诗','song-poetry','','[]','大江東南流，鼓柁江水上。',156,'全唐诗/poet.song.89000.json','["大江東南流，鼓柁江水上。", "薄遊五松山，獲見謫仙像。", "嗚呼天寶間，治亂如反掌。", "兵戈暗中原，豪傑多長往。", "謫仙當此時，逸氣隘天壤。", "脫身來江東，縹渺青霞賞。", "作詩幾千篇，醉筆籠萬象。", "迄今有遺祠，識者共瞻仰。", "嗟予豈後裔，愚拙誰復尚。", "珥筆玉殿螭，謫官閩嶺瘴。", "荷恩許生還，冒險理歸槳。", "於焉覿仙風，足以慰遐想。", "願言繼清芬，何由揖英爽。"]'),
('5312ede1-1423-42c9-8682-4a6e610b505e','舟中讀書有感','李綱','宋','宋诗','song-poetry','','[]','渺渺波濤淅淅風，此身忽在大江東。',64,'全唐诗/poet.song.89000.json','["渺渺波濤淅淅風，此身忽在大江東。", "浮家泛宅雲煙裏，思古傷今圖史中。", "盗賊從來能伺釁，治安自昔戒除戎。", "我今惟願兵戈息，歸作梁谿老釣翁。"]'),
('2aabde62-2153-4175-a4c7-1806ccd89da9','銅陵阻風','李綱','宋','宋诗','song-poetry','','[]','春色到江渚，梅花正斷魂。',48,'全唐诗/poet.song.89000.json','["春色到江渚，梅花正斷魂。", "風波留遠櫂，煙雨濕寒村。", "鴈過傳遺響，潮來没舊痕。", "淒凉一樽酒，愁絕與誰論。"]'),
('87475e5c-d470-4ae7-9cb5-3fc78efddcdf','題護法寺瑛老默堂','李綱','宋','宋诗','song-poetry','','[]','維摩丈室何年設，滿目江山自風月。',32,'全唐诗/poet.song.89000.json','["維摩丈室何年設，滿目江山自風月。", "道中試露默中機，千偈瀾翻本無說。"]'),
('221cf935-3636-4e7f-9c68-701079ee7356','次韻和瑛老頌','李綱','宋','宋诗','song-poetry','','[]','默堂前對五松山，敵面機鋒一瞬間。',32,'全唐诗/poet.song.89000.json','["默堂前對五松山，敵面機鋒一瞬間。", "禪客相逢休擬議，草鞋價直欲誰還。"]'),
('11203109-84e9-4e1e-8053-d895af020230','自銅陵行四十里風復作泊江北岸地名散潭屬淮南  其一','李綱','宋','宋诗','song-poetry','','[]','襟带江淮一望間，夕陽艤櫂散潭灣。',64,'全唐诗/poet.song.89000.json','["襟带江淮一望間，夕陽艤櫂散潭灣。", "波濤洶湧暮天闊，鷗鷺飄颻漁艇閒。", "風壯又還依北渚，雲深不復見南山。", "淛河千里何時到，過去飛鴻不可攀。"]'),
('dbd65b29-f357-401e-ab4c-f4ba639197e6','自銅陵行四十里風復作泊江北岸地名散潭屬淮南  其二','李綱','宋','宋诗','song-poetry','','[]','鏡中漸覺鬢絲多，半世勞生可奈何。',64,'全唐诗/poet.song.89000.json','["鏡中漸覺鬢絲多，半世勞生可奈何。", "極望不來青足鳥，滿江更起白頭波。", "揚帆賈客風前笛，撒網漁人月下歌。", "自斷此生甘寂寞，毗耶歸作老維摩。"]'),
('d49cb913-0111-4408-bcdf-8f210fe1feda','自銅陵行四十里風復作泊江北岸地名散潭屬淮南  其三','李綱','宋','宋诗','song-poetry','','[]','平生性酷愛江山，今日江山滿目前。',64,'全唐诗/poet.song.89000.json','["平生性酷愛江山，今日江山滿目前。", "明月清風人寂寂，淡煙輕靄露涓涓。", "波聲撼岸連淮壤，鴈陣驚寒入楚天。", "慨念往來成底事，一杯濁酒且安眠。"]'),
('0f6fb321-efa0-4539-b5a2-c504f269fb23','春睡  其一','李綱','宋','宋诗','song-poetry','','[]','半生遊宦鬢毛霜，依舊圖書對曉窗。',32,'全唐诗/poet.song.89000.json','["半生遊宦鬢毛霜，依舊圖書對曉窗。", "卯酒一杯春日暖，臥聽鳴櫓下清江。"]'),
('dc9f2a74-c508-42f3-9069-32b910542d66','春睡  其二','李綱','宋','宋诗','song-poetry','','[]','居士終朝只念歸，日行百里尚嫌遲。',32,'全唐诗/poet.song.89000.json','["居士終朝只念歸，日行百里尚嫌遲。", "小窗春夢分明到，歎息啼烏喚覺時。"]'),
('190962fd-a417-4f4b-81dc-efd162ecc8e7','夜泊繁昌','李綱','宋','宋诗','song-poetry','','[]','繫纜繁昌口，清江夜渺然。',48,'全唐诗/poet.song.89000.json','["繫纜繁昌口，清江夜渺然。", "寒星隨浪閃，孤月向人圓。", "漢渚乘槎客，雲川控鯉仙。", "何須論往事，且泛碧波船。"]'),
('995e5f9e-9b44-425b-992b-560f8009a584','試九華朱覲墨','李綱','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','九華山頂老松煙，名重初因玉局仙。',64,'全唐诗/poet.song.89000.json','["九華山頂老松煙，名重初因玉局仙。", "様古法精珪並製，膠清煤馥玉同堅。", "試將毛穎輕輕染，須遣陶泓細細研。", "居士年來無戀著，惟於三子欲逃禪。"]'),
('62beef55-2123-435b-bb82-a161c4086f4a','未至蕪湖四十里阻風','李綱','宋','宋诗','song-poetry','','[]','一夜寒雲凝不開，北風吹雨带潮來。',64,'全唐诗/poet.song.89000.json','["一夜寒雲凝不開，北風吹雨带潮來。", "濤翻天末銀山湧，浪打沙頭霹靂摧。", "心在浙西音斷絕，身留江左意徘徊。", "無聊獨酌開懷抱，賴有窗間數點梅。"]'),
('e643e896-a326-4fbd-8791-dcdd97c42e3b','草宰執書論方寇事戲成','李綱','宋','宋诗','song-poetry','','[]','江浙巨盗起，東南皆震驚。',96,'全唐诗/poet.song.89000.json','["江浙巨盗起，東南皆震驚。", "王師殊未出，赤子若爲情。", "試贈繞朝策，願飛燕將城。", "非因肉食鄙，只欲廟謨成。", "汲黯復妄發，終軍思請行。", "懷親寸心急，報國一身輕。", "曹劌亦問戰，申胥還乞兵。", "羣公佐天子，努力剪鯢鯨。"]'),
('dda28fac-98a1-4bfb-89e7-0416ca50a742','上元舟中有感','李綱','宋','宋诗','song-poetry','','[]','前年扈清蹕，玉輦臨端門。',120,'全唐诗/poet.song.89000.json','["前年扈清蹕，玉輦臨端門。", "鼇山綵構聳，露臺歌吹喧。", "去年謫沙陽，旅泊亦遊觀。", "士女隘衢巷，燈火滿溪山。", "今年過江南，艤舟煙水灣。", "風髙不可進，極目雲濤翻。", "蜜炬照獨酌，紅爐凌夜寒。", "感事心欲折，强歌聲無歡。", "坐看江邊月，飛上青雲端。", "清光不改舊，對我還團欒。"]'),
('35941185-457e-446f-ba33-9ee7b47fd0d6','夜坐  其一','李綱','宋','宋诗','song-poetry','','[]','春夜沈沈燈影明，卷書兀坐忽三更。',32,'全唐诗/poet.song.89000.json','["春夜沈沈燈影明，卷書兀坐忽三更。", "不知船外風多少，但聽滿江波浪聲。"]'),
('2a238840-10ee-4235-bb48-b9c428b11217','夜坐  其二','李綱','宋','宋诗','song-poetry','','[]','波濤漠漠雨紛紛，夜泊江南煙水村。',32,'全唐诗/poet.song.89000.json','["波濤漠漠雨紛紛，夜泊江南煙水村。", "慨念平生都不寢，可憐心事向誰論。"]'),
('ccfe9160-6f52-4042-b09c-48567402d470','至蕪湖聞賊陷錢塘復爲官軍所得有感  其一','李綱','宋','宋诗','song-poetry','','[]','督府繁華一掃空，須知狂寇計非庸。',32,'全唐诗/poet.song.89000.json','["督府繁華一掃空，須知狂寇計非庸。", "廟堂若爲蒼生計，早築高壇拜臥龍。"]'),
('be7c9391-d7b7-4edc-a090-109f982fd751','至蕪湖聞賊陷錢塘復爲官軍所得有感  其二','李綱','宋','宋诗','song-poetry','','[]','巨盗乘虛起浙東，猖狂如在笑談中。',32,'全唐诗/poet.song.89000.json','["巨盗乘虛起浙東，猖狂如在笑談中。", "錢塘猶喜官軍復，破賊須從此立功。"]'),
('c03a58a3-be4e-4740-a762-4e89551f4629','自蕪湖江行至采石  其一','李綱','宋','宋诗','song-poetry','','[]','萬頃春江徹底清，天風不動鏡泓澄。',32,'全唐诗/poet.song.89000.json','["萬頃春江徹底清，天風不動鏡泓澄。", "畫船安穩搖空翠，疑在琉璃地上行。"]'),
('81859af5-efa3-4da2-b376-c5cf54c22097','自蕪湖江行至采石  其二','李綱','宋','宋诗','song-poetry','','[]','江水春來綠似藍，臨流髙石翠巉巖。',32,'全唐诗/poet.song.89000.json','["江水春來綠似藍，臨流髙石翠巉巖。", "波恬舟穩已堪喜，況是清風借一帆。"]'),
('c13fd9ce-4e9c-4ccf-9020-e27cf189d0b4','阻風泊慈湖夾焚香默禱有長魚躍波而江豚出没舟人大驚抵暮風便因命解舟乘月泛禁江一夕至金陵蓋數百里作二絕以紀其事  其一','李綱','宋','宋诗','song-poetry','','[]','江豚出没白波中，十丈神魚躍晚空。',32,'全唐诗/poet.song.89000.json','["江豚出没白波中，十丈神魚躍晚空。", "知是陽侯憐我拙，故教來助一帆風。"]'),
('f9b48e9f-2755-4e58-b115-d60ffcf651d8','阻風泊慈湖夾焚香默禱有長魚躍波而江豚出没舟人大驚抵暮風便因命解舟乘月泛禁江一夕至金陵蓋數百里作二絕以紀其事  其二','李綱','宋','宋诗','song-poetry','','[]','露氣漫漫欲結霜，扁舟夜下秣陵江。',32,'全唐诗/poet.song.89000.json','["露氣漫漫欲結霜，扁舟夜下秣陵江。", "煙波如席月如晝，快意倒盡黄金缸。"]'),
('dd1d9cca-2021-40fc-8822-b3d45f18b47e','同李似之遊蔣山','李綱','宋','宋诗','song-poetry','','[]','北風阻行舟，駕言遊蔣山。',180,'全唐诗/poet.song.89000.json','["北風阻行舟，駕言遊蔣山。", "相攜得良友，談笑窮躋攀。", "松林靜杳冥，殿閣羅煙鬟。", "寶公骨已冷，白塔孤雲間。", "乘高望長空，極目波濤翻。", "東南正戎馬，戈甲照江干。", "與子適相遇，偷此半日閑。", "懷古六朝遠，道舊一笑歡。", "憶昨賜對初，接武玉殿班。", "螭坳珥史筆，毎慚追繼難。", "迂疏與世違，謫官墮甌蠻。", "寛恩幸脫去，假道來江關。", "邂逅兩萍梗，飄泊驚風旛。", "迴首顧淛河，不知涕泗澘。", "著鞭願努力，世路方多艱。"]'),
('9e34c708-987b-404d-8f95-0742284bb4cf','頌示勤老','李綱','宋','宋诗','song-poetry','','[]','平生聞說蔣山勤，今日相逢過所聞。',32,'全唐诗/poet.song.89000.json','["平生聞說蔣山勤，今日相逢過所聞。", "還似泉公喚居士，一聲吹散滿天雲。"]'),
('ca56b175-ea65-4322-8578-719ecd5bdbf5','次韻奉酬李似之見贈','李綱','宋','宋诗','song-poetry','','[]','吾宗才氣世無雙，用與時行舍亦藏。',64,'全唐诗/poet.song.89000.json','["吾宗才氣世無雙，用與時行舍亦藏。", "殿陛同瞻龍衮繡，螭坳繼染御爐香。", "紫荷持槖將清禁，貝葉繙經見寶坊。", "仄席正思經濟手，佇觀趣召侍顒昂。"]'),
('79a32205-3447-488d-8d5e-731b094d7005','金陵懷古四首  其一','李綱','宋','宋诗','song-poetry','','[]','六代兵戈王氣銷，山圍故國自周遭。',64,'全唐诗/poet.song.89000.json','["六代兵戈王氣銷，山圍故國自周遭。", "豪華散滅城池古，人物摧殘丘塚髙。", "阜轉蟠龍翔寶塔，洲分白鷺湧雲濤。", "悠悠世事都如夢，且對金樽把蟹螯。"]'),
('1b39dc33-b895-4862-8560-34f6d85d931f','金陵懷古四首  其二','李綱','宋','宋诗','song-poetry','','[]','六代繁華三百年，我來弔古一悽然。',64,'全唐诗/poet.song.89000.json','["六代繁華三百年，我來弔古一悽然。", "景陽鐘斷雞空唱，玉樹歌沈月自圓。", "潮没舊痕生晚浦，柳搖新色媚晴天。", "髙樓上盡窮雙目，千里江山遶檻前。"]'),
('0fda2825-b74e-433f-b8ee-696cac1d5310','金陵懷古四首  其三','李綱','宋','宋诗','song-poetry','','[]','六代興亡江上城，倦遊還向此中行。',64,'全唐诗/poet.song.89000.json','["六代興亡江上城，倦遊還向此中行。", "龍蟠虎踞空形勢，并廢臺荒爲戰爭。", "雲氣霏霏春雨急，煙波渺渺暮潮平。", "商人不識前朝恨，短笛還爲激烈聲。"]'),
('131b8b76-eac9-4e62-80e2-3a0be6ad0099','金陵懷古四首  其四','李綱','宋','宋诗','song-poetry','','[]','六代當年恨最長，兵戈陵滅故城荒。',64,'全唐诗/poet.song.89000.json','["六代當年恨最長，兵戈陵滅故城荒。", "非關霸氣多消歇，自是人謀未允臧。", "王謝風流今寂寞，江山形勝亦淒凉。", "我來正值興戎馬，慨念東南更慘傷。"]'),
('f849549e-7752-4c7e-9901-83ee8d675322','登鍾山謁寶公塔','李綱','宋','宋诗','song-poetry','','[]','寶公真至人，鳥爪金色身。',48,'全唐诗/poet.song.89000.json','["寶公真至人，鳥爪金色身。", "杖攜刀尺拂，語隱齊梁陳。", "我登鍾山頂，白塔髙嶙峋。", "再拜禮雙足，聊結香火因。"]'),
('f143c88c-13c3-46e0-9365-531b9e5cd659','題定林院','李綱','宋','宋诗','song-poetry','','[]','行過鍾山到定林，青松一徑白雲深。',32,'全唐诗/poet.song.89000.json','["行過鍾山到定林，青松一徑白雲深。", "三間古屋昭文館，那有沉迷富貴心。"]'),
('e73b612d-48a2-49fa-aecb-00d2e174fe6a','題八功德水','李綱','宋','宋诗','song-poetry','','[]','石作方池紫翠崖，湛然定水貯瓊瑰。',32,'全唐诗/poet.song.89000.json','["石作方池紫翠崖，湛然定水貯瓊瑰。", "何須功德標爲八，萬行圓成自此來。"]'),
('8fb65c77-e41d-4c31-9329-187e319f8a2a','題偃秀軒','李綱','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','青葱秀色一軒中，俯瞰梁朝萬本松。',64,'全唐诗/poet.song.89000.json','["青葱秀色一軒中，俯瞰梁朝萬本松。", "頂蹙風雲疑偃蓋，枝蟉雨露若蟠龍。", "四時鬱鬱寧彫葉，千載亭亭不改容。", "却笑宗人生岱嶽，佞秦先得大夫封。"]'),
('50f7e739-4f89-40f7-b3fd-a79ad0ecca65','得家信報避寇海陵','李綱','宋','宋诗','song-poetry','','[]','怪底燈花夜夜紅，朝來家問始相通。',64,'全唐诗/poet.song.89000.json','["怪底燈花夜夜紅，朝來家問始相通。", "田園已在危疑際，骨肉幸安飄泊中。", "子美無家尋弟妹，淵明有酒引兒童。", "我今已勝少陵老，稚子候門淮水東。"]'),
('a6767d6a-8037-413b-af4a-8f07169d6db3','自金陵江行未至長蘆阻風  其一','李綱','宋','宋诗','song-poetry','','[]','倐忽風雲接地陰，扁舟繫纜暮江潯。',32,'全唐诗/poet.song.89000.json','["倐忽風雲接地陰，扁舟繫纜暮江潯。", "波濤何必深爲阻，萬里歸來一寸心。"]'),
('2e742399-15bf-48a8-a9bc-6b6889e1e26c','自金陵江行未至長蘆阻風  其二','李綱','宋','宋诗','song-poetry','','[]','七日風不止，歸心何似生。',48,'全唐诗/poet.song.89000.json','["七日風不止，歸心何似生。", "煙添暮山色，風撼滿江聲。", "淮楚已非遠，波濤殊未平。", "坐看雲解駮，猶喜晚來晴。"]'),
('7567fee2-be8b-4146-a01a-91b163f18060','過長蘆','李綱','宋','宋诗','song-poetry','','[]','達磨當時一葦杭，棲棲暗度白沙江。',32,'全唐诗/poet.song.89000.json','["達磨當時一葦杭，棲棲暗度白沙江。", "不知雙履歸何處，吸盡西江屬老龐。"]'),
('4c756edd-f714-48e8-aa61-585f0dc17a9a','遊長蘆見衆僧已披剃','李綱','宋','宋诗','song-poetry','','[]','圓頂方袍復舊儀，欣欣便覺衆情熙。',32,'全唐诗/poet.song.89000.json','["圓頂方袍復舊儀，欣欣便覺衆情熙。", "可憐盡墮狙翁術，暮四朝三元不知。"]'),
('d3272c19-e624-45cf-ab9d-782a512312ac','次韻和淵明形影神三首 形贈影','李綱','宋','宋诗','song-poetry','','[]','大塊已載我，何如未生時。',96,'全唐诗/poet.song.89000.json','["大塊已載我，何如未生時。", "氣變芒芴間，七竅誰鑿之。", "百骸與九藏，假合以成兹。", "與子非故交，從我如相期。", "屈伸及動止，契合初不思。", "常恐隨物化，念此情淒洏。", "我生夢幻中，變滅不復疑。", "安得永相保，聽我悲來辭。"]'),
('24d88298-025a-4492-9abe-797fe3c9a291','次韻和淵明形影神三首 影答','李綱','宋','宋诗','song-poetry','','[]','紆餘非我妍，濩落非我拙。',96,'全唐诗/poet.song.89000.json','["紆餘非我妍，濩落非我拙。", "與子兩相依，生來無間絕。", "俯仰隨顧指，豈是事容悅。", "因光長周旋，處陰暫暌别。", "況復同物化，子壞我亦滅。", "冥冥長夜臺，念之五情熱。", "願子衞生經，無使精腦竭。", "千載永相從，彭殤孰優劣。"]'),
('29f705e3-9e3b-4315-905b-a7ac5d67c6b3','次韻和淵明形影神三首 神釋','李綱','宋','宋诗','song-poetry','','[]','人生若大夢，積微以成著。',144,'全唐诗/poet.song.89000.json','["人生若大夢，積微以成著。", "少壯得老死，一念即非故。", "二子異金石，松蘿暫依附。", "胡爲羡久生，切切兒女語。", "有形會當滅，是影無實處。", "惟我謝客塵，妙湛乃常住。", "不入造化機，豈墮陰陽數。", "迴光試反照，凡聖悉皆具。", "不減亦不增，誰毁復誰譽。", "超然外死生，卓爾無來去。", "周行萬物表，獨立初不懼。", "二子非吾徒，安用多憂慮。"]'),
('4abf21e0-61bb-4cd4-aafd-9b58b27fddcb','次韻李似之秋居雜詠十首  其一','李綱','宋','宋诗','song-poetry','','[]','達人有大觀，曲士多自束。',72,'全唐诗/poet.song.89000.json','["達人有大觀，曲士多自束。", "忘真供物役，終歲惟僕僕。", "所以梁谿翁，歸來蓺松菊。", "寒泉友龜魚，豐草侣麋鹿。", "清風爲掃門，明月相照燭。", "世故悉棄捐，吾方樂於獨。"]'),
('629903d5-6c1b-4c9a-8e8c-7c790e1c57bb','次韻李似之秋居雜詠十首  其二','李綱','宋','宋诗','song-poetry','','[]','亭亭南山松，下蔭千里道。',72,'全唐诗/poet.song.89000.json','["亭亭南山松，下蔭千里道。", "結根既得地，秀色亦何好。", "歲寒霜霰苦，獨立君子操。", "如何慷慨士，百慮繞中抱。", "寸心多感傷，搖搖若旌纛。", "逝將歸江湖，更拜散人號。"]'),
('f47040d7-2441-40e6-a4f6-d571171948c5','次韻李似之秋居雜詠十首  其三','李綱','宋','宋诗','song-poetry','','[]','烏鵲故巢心，鴻鴈稻梁謀。',72,'全唐诗/poet.song.89000.json','["烏鵲故巢心，鴻鴈稻梁謀。", "梁谿十畝園，歲晚營菟裘。", "自我去泉石，歲律纔一周。", "安知巨盜起，千里來蜂蟊。", "老稚適淮東，旅泊如寄郵。", "已矣復何言，吾生感行休。"]'),
('286007ab-f36a-431e-b61b-785800a644a4','次韻李似之秋居雜詠十首  其四','李綱','宋','宋诗','song-poetry','','[]','鼓鼙思將帥，戡亂屬豪傑。',72,'全唐诗/poet.song.89000.json','["鼓鼙思將帥，戡亂屬豪傑。", "吾儒貴全才，冠履仍佩玦。", "憬彼乘間盜，萌蘖傲霜雪。", "鋤惡當務本，使衆宜以悅。", "一掃巢穴空，毋俾蟻蝟結。", "安得李臨淮，念此五情熱。"]'),
('04030c78-e531-4b42-b0f0-688e7ecb8f73','次韻李似之秋居雜詠十首  其五','李綱','宋','宋诗','song-poetry','','[]','禪悅知道腴，寂樂忘世喧。',72,'全唐诗/poet.song.89000.json','["禪悅知道腴，寂樂忘世喧。", "自從遊宦來，常恐歲月捐。", "願從善知識，超然同晤言。", "心清聞妙香，不必爐中煙。", "竹實自鸞鳯，腐鼠從烏鳶。", "典籍亦可棄，魚兔非蹄筌。"]'),
('ef53399c-477c-4ab0-8b64-92042419e0b4','次韻李似之秋居雜詠十首  其六','李綱','宋','宋诗','song-poetry','','[]','取飯遣化人，散花有天女。',72,'全唐诗/poet.song.89000.json','["取飯遣化人，散花有天女。", "維摩一方丈，安用室百堵。", "況我麋鹿姿，本非冠冕伍。", "脫身歸梁谿，蓑笠釣煙雨。", "結交有風月，掃念無寒暑。", "巨盜儻削平，此志良自許。"]'),
('cead8cbf-5a88-4a6c-8617-8c9f7600b8d6','次韻李似之秋居雜詠十首  其七','李綱','宋','宋诗','song-poetry','','[]','兩曜真跳丸，百年如轉軸。',72,'全唐诗/poet.song.89000.json','["兩曜真跳丸，百年如轉軸。", "富貴能幾何，飄若雲過目。", "惟有金仙書，可以靜中讀。", "冷暖初自知，運用要當熟。", "仲尼貴毋我，老氏欲爲腹。", "悟真奚必多，半偈亦云足。"]'),
('8cee02f0-7966-4bfe-8d8a-6d110aaec866','次韻李似之秋居雜詠十首  其八','李綱','宋','宋诗','song-poetry','','[]','我行大江濱，舉頭見鍾山。',72,'全唐诗/poet.song.89000.json','["我行大江濱，舉頭見鍾山。", "清風自南來，長嘯宇宙寛。", "邂逅適相遇，取友平生端。", "戀戀故人意，憐此范叔寒。", "世路方多虞，期子慎所安。", "他時來訪我，陋巷一瓢顔。"]'),
('3ac1dd03-d1d8-4216-a64b-61da0b7b3507','次韻李似之秋居雜詠十首  其九','李綱','宋','宋诗','song-poetry','','[]','朝市不可留，山林有佳趣。',72,'全唐诗/poet.song.89000.json','["朝市不可留，山林有佳趣。", "結廬無人境，散策時遠步。", "手攜葛翁杖，足躡祖師屨。", "一笑浮世空，欻若草頭露。", "幻身粗飽煖，此外復何慮。", "休問東陵瓜，且種梁谿芋。"]'),
('8334243f-c867-4d3a-ab7f-7f6d1b4e0b76','次韻李似之秋居雜詠十首  其一○','李綱','宋','宋诗','song-poetry','','[]','浮雲不成雨，晶晶行晴晝。',72,'全唐诗/poet.song.89000.json','["浮雲不成雨，晶晶行晴晝。", "朝蔽扶桑暾，夜掩長河宿。", "迴颷一掃除，戢戢見遠岫。", "青天與白日，四顧喜瞻搆。", "願乘六氣辯，撫手磨宇宙。", "冷然御風行，平昔笑禦寇。"]'),
('7e92b346-105d-4a04-82d9-4a4fbf73d3f6','阻風舟中有感','李綱','宋','宋诗','song-poetry','','[]','扁舟泊枉渚，邈在大江南。',120,'全唐诗/poet.song.89000.json','["扁舟泊枉渚，邈在大江南。", "風雲鬭未息，波濤戰方酣。", "閉關坐明窗，開卷窮幽探。", "氣寒覺火冷，志苦思蘖甘。", "深炷一爐香，默默聊自參。", "半世徒擾擾，忙如未繭蠶。", "又若伏櫪馬，未脫轡與銜。", "逝將歸山林，瓶錫寄一巖。", "願從祖師六，不學黄庭三。", "得此無所得，超然離聖凡。"]'),
('e98339ef-60b3-42d9-9dfe-965c2565f86d','喜雨','李綱','宋','宋诗','song-poetry','','[]','北風吹雲雲不開，濛濛細雨和煙來。',96,'全唐诗/poet.song.89000.json','["北風吹雲雲不開，濛濛細雨和煙來。", "舟行雖阻亦可喜，潤澤及物誠佳哉。", "我辭閩嶺遵江渚，百日皆晴未嘗雨。", "江淮旱暵已踰年，牟麥焦枯但黄土。", "漕渠千里不復通，況復巨寇興兵戎。", "從兹一雨百事散，願化災疹爲康豐。"]'),
('07bfe008-e23c-4b82-874a-90d2090fa606','雙鳬','李綱','宋','宋诗','song-poetry','','[]','雲濤萬頃連天雨，波上雙鳬自容與。',32,'全唐诗/poet.song.89000.json','["雲濤萬頃連天雨，波上雙鳬自容與。", "風髙江闊煙水寒，日暮相將何處去。"]'),
('ef586be1-1e5f-4fd9-a598-28daf59d00a7','雪','李綱','宋','宋诗','song-poetry','','[]','小雨晚成雪，凍雲凝不開。',48,'全唐诗/poet.song.89000.json','["小雨晚成雪，凍雲凝不開。", "響窗初索索，積岸漸皚皚。", "色與濤頭並，寒資酒力排。", "平生看圖畫，今日畫中來。"]'),
('cc0348e1-8491-48cb-a4cf-e2803ca60951','江上值雪戲成短歌','李綱','宋','宋诗','song-poetry','','[]','我來自南今幾月，萬里不曾看點雪。',192,'全唐诗/poet.song.89000.json','["我來自南今幾月，萬里不曾看點雪。", "艤舟江南煙水灣，雪作春風更奇絕。", "凍雲漠漠愁鎖空，初聞冰霰響窗蓬。", "鮫人泣下玉盤碎，珠璣亂落層霄中。", "須臾雪片大如指，密灑江干浩無際。", "白帝從以萬玉妃，婀娜旂常墮雪水。", "迴風飄舞轉交加，坐看汀洲鋪玉沙。", "已驚綠柳早飛絮，更訝黄蘆還带花。", "沙頭鳬鴈自儔侣，天暝雲寒去何處。", "漁翁獨立釣清江，披得一蓑非好句。", "梁谿居士初歸來，對此超然慰所懷。", "家在淮東阻行色，晴天且爲片時開。"]'),
('b5ff2a55-52bc-4642-94b2-1e7f27278b11','舟次儀真','李綱','宋','宋诗','song-poetry','','[]','昔年試吏得江城，一紀重來若隔生。',32,'全唐诗/poet.song.89000.json','["昔年試吏得江城，一紀重來若隔生。", "惆悵舊遊誰可語，南園春色却多情。"]'),
('0854da6a-9a97-489e-a414-a062263c6be9','次韻王堯明遊北寺','李綱','宋','宋诗','song-poetry','','[]','小雨濕殘花，迴風振芳草。',144,'全唐诗/poet.song.89000.json','["小雨濕殘花，迴風振芳草。", "勝遊宜及時，嘉此春物好。", "蕭然二三子，散策窮杳眇。", "招提枕郊頭，殿閣出林表。", "中有王屋泉，一酌百慮澡。", "踟蹰古城隅，幽徑通翠篠。", "嗟予阻追陪，正坐塵事繞。", "衣冠方北渡，親故幸非少。", "客情終念歸，回首雲縹緲。", "遥憐松菊荒，仰羡鸛鶴矯。", "園田誠可樂，鼙鼓尚驚擾。", "何當終素心，永歎憂用老。"]'),
('24505d0e-3a06-44b3-b5bc-5aa98ed9dc4a','次韻王堯明三絕句  其一','李綱','宋','宋诗','song-poetry','','[]','春風初入牡丹枝，國色天香艷姣姬。',32,'全唐诗/poet.song.89000.json','["春風初入牡丹枝，國色天香艷姣姬。", "堪笑謫仙猶半醉，清泉沃面與題詩。"]'),
('f0e1c5a4-ce6e-455a-bd7e-ddf89e43680f','次韻王堯明三絕句  其二','李綱','宋','宋诗','song-poetry','','[]','康時致主接英遊，姚宋開元第一流。',32,'全唐诗/poet.song.89000.json','["康時致主接英遊，姚宋開元第一流。", "憔悴三閭空澤畔，離騷終日念靈脩。"]'),
('37479cc5-e332-4d4c-be36-60d3086d9ac8','次韻王堯明三絕句  其三','李綱','宋','宋诗','song-poetry','','[]','鄭衞曲終纔雅奏，詞人賦詠本多誇。',32,'全唐诗/poet.song.89000.json','["鄭衞曲終纔雅奏，詞人賦詠本多誇。", "未能句語全無纇，猶貴瓊瑜不掩瑕。"]'),
('159ca6ca-529a-496c-bd12-47473b1f0eb1','次韻茂載海陵寓居有感三首  其一','李綱','宋','宋诗','song-poetry','','[]','羣盜休憑險，天弧正指狼。',48,'全唐诗/poet.song.89000.json','["羣盜休憑險，天弧正指狼。", "犬羊徒跋扈，貔虎極精强。", "寓目江山異，傷心花草香。", "淛河那得此，回首一彷徨。"]'),
('1e0d05c5-b98b-4ea3-a95a-751c4cb8c502','次韻茂載海陵寓居有感三首  其二','李綱','宋','宋诗','song-poetry','','[]','江城飄泊久，幽徑綠寒莎。',48,'全唐诗/poet.song.89000.json','["江城飄泊久，幽徑綠寒莎。", "歎息青春暮，悲傷白髪多。", "蒼生端若此，狂寇竟如何。", "更起乘桴興，滄洲萬里波。"]'),
('b6636af1-a376-4c56-8586-96694dd36aed','次韻茂載海陵寓居有感三首  其三','李綱','宋','宋诗','song-poetry','','[]','不謂繁華地，還飛戰鬭塵。',48,'全唐诗/poet.song.89000.json','["不謂繁華地，還飛戰鬭塵。", "澆愁空泥酒，極目更傷春。", "懷古繙書帙，論情託友人。", "誰深醫國術，吾欲問甘辛。"]'),
('d5b7f9b4-3cd7-4119-9c27-035a3673d3b2','次韻王堯明喜雨古風','李綱','宋','宋诗','song-poetry','','[]','神化茫茫端莫測，不雨踰時忽盈尺。',256,'全唐诗/poet.song.89000.json','["神化茫茫端莫測，不雨踰時忽盈尺。", "誰云幽默志難通，一念周圓誠已格。", "井枯河竭欲飛塵，麥秀漸漸實半娠。", "翠虬潛伏杳無處，遺蝗出地方鱗鱗。", "觀音妙智悲慈主，爲灑楊枝作甘雨。", "應憐禱禬罄勤渠，致遣神人夢中語。", "雨暘之數雖有時，遲速亦可精神移。", "世間萬法盡心造，報若影響寧難期。", "不知今夕復何夕，千里風雲來陣墨。", "驅雷掣電雨建瓴，似赴前期初不忒。", "威神自在誰復如，噀酒投髗術已疏。", "有秋頗足慰民望，可喜更須煩史書。", "衣冠北渡連墻堵，旅食經時念終窶。", "已欣霖雨起蟠龍，更慶天兵擒猛虎。", "邇來世事不掛心，惟有憂國思猶深。", "安得年豐羣盗息，歸助擊壤堯民音。"]'),
('3ffba287-4a1f-44d8-bb74-227c175fbbea','送虞季然赴八寶丞','李綱','宋','宋诗','song-poetry','','[]','流落歸來旅海涯，相從幾集鳯凰池。',64,'全唐诗/poet.song.89000.json','["流落歸來旅海涯，相從幾集鳯凰池。", "暫欣捉麈共談笑，還惜整驂言别離。", "爲禄未能忘歛板，掃廳應不廢哦詩。", "如公豈是徒勞者，勉繼前修結主知。"]'),
('9e3b6afc-5bdd-4a3a-8313-fc77444e3e4f','次韻和曾徽言登北禪寺塔','李綱','宋','宋诗','song-poetry','','[]','佛教入中土，貝多凡幾翻。',192,'全唐诗/poet.song.89000.json','["佛教入中土，貝多凡幾翻。", "摩騰導其流，僧伽鼓其瀾。", "乃建窣堵波，髙標屹參天。", "劃如五彩虹，上與青霄干。", "兹塔更奇古，層簷俯通川。", "江山遞隱見，萬象森迴環。", "公子抱遠韻，登臨眇風煙。", "仰穿龍蛇穴，旁瞰日月懸。", "茫茫悉細碎，寓目疑無全。", "歸來吐妙句，字字勞精甄。", "嗟我方屏處，勝遊阻清緣。", "幸窺慈恩作，如見衆寶山。", "宗風久寂寞，紵絮何其寒。", "安得師子吼，震此龍象筵。", "關弓挾白羽，櫜鞬相周旋。", "當分寶塔坐，一瞬三萬年。"]'),
('301f0a61-3f3f-44d8-be00-f418b7236ab5','次韻徽言招飲絕句','李綱','宋','宋诗','song-poetry','','[]','壓架酴醿翠蔓柔，經春芬馥未全收。',32,'全唐诗/poet.song.89000.json','["壓架酴醿翠蔓柔，經春芬馥未全收。", "主人邀客醉花下，共喜王師破蔡州。"]'),
('d57e1e38-94c3-4d86-b50f-ebaec7ee316d','讀陳子直短歌三復而悲之次其韻','李綱','宋','宋诗','song-poetry','','[]','君不見韓昌黎，文章二百年。',202,'全唐诗/poet.song.89000.json','["君不見韓昌黎，文章二百年。", "又不見杜陵老，風月三千首。", "號寒啼饑四壁空，謾有篇章在人口。", "書生生事良易足，深林一枝河滿腹。", "但令藜莧可充膓，便把離騷靜中讀。", "儒冠誤身誠可憐，陳侯半世身猶邅。", "斗酒初乏青銅錢，忍饑哦詩空可傳。", "富兒菽粟泥沙擲，不必登朝家萬石。", "水陸畢陳方丈食，錦繡還將被墻壁。", "但資口腹爲身謀，問以詩書初不識。", "天公賦予真相百，彼富吾仁如黑白。", "鄉黨寧無急義人，誰哀王孫與進食。", "嘗思漂母飯淮陰，何用區區論報德。"]'),
('f6f32c30-ccb2-4bea-864b-53d1f6291d56','次韻王堯明四旱詩 河運','李綱','宋','宋诗','song-poetry','','[]','漕渠如坦途，泛此往來宅。',120,'全唐诗/poet.song.89000.json','["漕渠如坦途，泛此往來宅。", "疏川誰之功，乘木本諸益。", "常疑侔滄溟，巨釣可龍伯。", "那知旱暵甚，有此困涸阨。", "豈無車班班，莫勝倉箱積。", "譬猶一鶚飛，孰與鷙累百。", "汲江勞甕盎，禱雨費珪璧。", "端爲魚鼈憂，無乃雲雷斁。", "安得千里波，篙師發櫂歌。", "願借壯士手，爲乃挽天河。"]'),
('84759fb3-3ddf-4738-b754-ad9b9e8cb7d4','次韻王堯明四旱詩 井汲','李綱','宋','宋诗','song-poetry','','[]','我居梁谿傍，密邇陸子泉。',144,'全唐诗/poet.song.89000.json','["我居梁谿傍，密邇陸子泉。", "漂流旅海陵，又欲買一廛。", "願言酌甘芳，爲滌腥與羶。", "居然值歲旱，此志無由全。", "百井盡枯涸，簡編匪虛傳。", "夜汲費燭炬，曉趨駢足肩。", "一壺信千金，一飲或萬錢。", "逝將向井拜，飛泉爲濺濺。", "泓澄古鏡色，吸引星光圓。", "洋洋療衆渇，不竭如巨川。", "井收遂勿幕，瓶盆送迴旋。", "飲水自可樂，安用井底眠。"]'),
('d1c9faa9-dfd5-440d-9501-78274649d434','次韻王堯明四旱詩 酺祭','李綱','宋','宋诗','song-poetry','','[]','閔旱意不樂，駕言遊近坰。',192,'全唐诗/poet.song.89000.json','["閔旱意不樂，駕言遊近坰。", "田父紛在野，祭酺方乞靈。", "借問何以然，東臯産蝗螟。", "主張有神物，薄禮羞微馨。", "神歆庶災熄，敢愛酒滿瓴。", "導我試往觀，戢戢初插翎。", "剪穗齊若刀，抱稈牢如釘。", "異哉天壤間，孕此妖孽形。", "羣族既蕃衍，氣類屯臊腥。", "仲尼所不堪，紀異垂麟經。", "畀火見周雅，捕瘞聞唐庭。", "人力自足勝，何須詰冥冥。", "聰明實依人，正直神所聽。", "區區觴豆間，厥德安足銘。", "誰能起雲師，霈雨驅疾霆。", "一洗羽孽息，寥落如晨星。"]'),
('9f8ba078-f59f-456e-a7e0-9e67611fdc10','次韻王堯明四旱詩 雩禱','李綱','宋','宋诗','song-poetry','','[]','雩祭法已古，東方見蒼龍。',36,'全唐诗/poet.song.89000.json','["雩祭法已古，東方見蒼龍。", "厥後兹禮廢，但禱釋梵宫。", "淮堧值歲旱，川涸山欲童。"]'),
('29396495-fa5c-40e0-8796-fbf686449ad9','次韻和虞公明察院賦所藏李成山水','李綱','宋','宋诗','song-poetry','','[]','畫史古多有，李生獨寶傳。',264,'全唐诗/poet.song.89000.json','["畫史古多有，李生獨寶傳。", "譬猶古人書，墨妙稱誠懸。", "尤物世難蓄，變化登雲天。", "流落人間者，遺跡猶綿綿。", "此本更奇絕，髙深自山淵。", "想當槃礴時，舐筆應如椽。", "樓觀抱空曲，林芿靄層巔。", "屹然巖石姿，潤比金玉堅。", "倐忽變寒暑，霏微起雲煙。", "髙堂寓遠目，如墮嵩華前。", "迴觀舊所藏，一一可棄捐。", "乃知蓋代手，筆力能旋乾。", "衆工畫山水，意匠勞雕鐫。", "惟兹得簡易，大巧初天全。", "鑒裁有精識，丹青孰爭先。", "何須嫫姆醜，始辨西施妍。", "嗟我性迂拙，漂流方隱鄽。", "幸從長者遊，坐使伊鬱宣。", "嘯詠圖史間，髙臺謝牽攣。", "新詩與妙畫，更使窮鑽研。", "愧乏色絲句，爲續金聲篇。", "端思畫中趣，秪欲休林泉。"]'),
('a51decbc-57e8-4640-83ed-c0332630e16f','再次前韻','李綱','宋','宋诗','song-poetry','','[]','妙手不可遇，心匠良難傳。',264,'全唐诗/poet.song.89000.json','["妙手不可遇，心匠良難傳。", "於中營丘生，名若日月懸。", "胸次有衡霍，筆端合其天。", "坐令衆畫史，縮手嗟材綿。", "公於何處得，藏此圖書淵。", "晝賞不知厭，夜觀燭如椽。", "我昔遊七閩，足踏羣山巔。", "最愛演仙峰，石色潤且堅。", "樓臺與粧綴，輕素拖晴煙。", "朅來見兹畫，恍若復造前。", "爲技一至此，丹青誠可捐。", "譬猶繪神駿，不必錦連乾。", "陽嶺鬱葱蒨，陰崖極鎔鐫。", "人禽與屋木，種種法象全。", "往者邈難追，後來誰復先。", "新詩爲發揮，與畫爭清研。", "寶劍藏古嶽，賢士隱里鄽。", "一朝遇鑒賞，曄若五采宣。", "顧我涉道淺，遊世困縶攣。", "惟有古人心，刻意思精研。", "兹畫不可取，但誦瑶瓊篇。", "何須畫中看，吾方老雲泉。"]'),
('385377ed-7897-41e9-a548-a83fe313390e','次韻曾徽言桂漿','李綱','宋','宋诗','song-poetry','','[]','金椀擎來碧玉漿，端令袢暑吸飛霜。',64,'全唐诗/poet.song.89000.json','["金椀擎來碧玉漿，端令袢暑吸飛霜。", "何須社甕麴蘖法，自带廣寒風露香。", "清入肺肝殊有韻，甘餘齒頰固難忘。", "七甌已勝盧仝茗，似得仙人石髓嘗。"]'),
('24e549d5-f71c-4357-9ec4-14a9081703af','讀王堯明贈諸弟和陶詩次韻爲别','李綱','宋','宋诗','song-poetry','','[]','鷦巢安一枝，鵬運圖南溟。',120,'全唐诗/poet.song.89000.json','["鷦巢安一枝，鵬運圖南溟。", "巨細自有適，坐見萬物情。", "昔别東都門，我方墮蠻荆。", "豈知復會合，濁酒叙平生。", "念子抱器業，出值時清明。", "騫騰發素藴，當使王化平。", "而我志丘壑，肅肅正遐征。", "竊比淵明歸，逝同沮溺耕。", "脫屣謝軒冕，超然無所縈。", "出處良異趣，勉哉垂世名。"]'),
('72bf3561-d864-460b-a84e-102cbbe47ab9','虞公明出示序觀音詩事并頌次韻','李綱','宋','宋诗','song-poetry','','[]','聞思大士真奇絕，俱妙形神侔玉雪。',208,'全唐诗/poet.song.89000.json','["聞思大士真奇絕，俱妙形神侔玉雪。", "譬如水月自清凉，能與世間除惱熱。", "自從證悟今幾刼，定慧慈威初不滅。", "解脫曾因無盡宣，圓通更假文殊說。", "森然寶臂清淨目，八萬四千猶一吷。", "依怗羣生願力堅，宴坐諦觀塵世閲。", "先生往時墮憲網，澤雉在樊鷹在紲。", "默相虔誠賴覺慈，灼知情實蒙聖哲。", "踰年海上得歸來，冒險豈殊探虎穴。", "精剛何翅金百鍊，忠藎端同水萬折。", "觀音在處皆現前，不必圖繪勞携挈。", "此方教體在音聞，悟入此門良不拙。", "更將妙語贊悲心，功德須知莫如舌。"]'),
('9d495740-e64f-49c9-a393-1029896f7979','贈虞公明察院','李綱','宋','宋诗','song-poetry','','[]','岧嶤古城隅，下爲鳳凰池。',264,'全唐诗/poet.song.89000.json','["岧嶤古城隅，下爲鳳凰池。", "鳳去不復返，池水空漣漪。", "傍有幽人廬，松竹森四圍。", "結構極爽塏，借問居者誰。", "先生聞道久，昨自海上歸。", "食棗大如瓜，定曾見安期。", "不知修何術，能奪造化機。", "金鼎燦含葩，玉池灧生肥。", "顛倒出龍虎，騰降分坎離。", "行年五十餘，氣貎如嬰兒。", "餘暇付圖史，不廢酒與詩。", "髙堂會賓友，落筆風雨馳。", "戲事聊復爾，一笑初何爲。", "懸知廣成子，千歲形不衰。", "顧我抱迂拙，與世真相違。", "徒欲睎驥騄，曾未窺藩籬。", "寓居邇函丈，數造董公帷。", "願聞衆妙門，成此一段奇。", "胡爲久閉拒，客至輙圍棋。", "歸隱志已定，後會知何時。", "銘心誓相學，發藥幸教之。", "他年倘有得，同駕雲中螭。"]'),
('8a09fb28-399b-4200-bead-6b7e6a77b14f','讀錢申伯與仲弟唱和次韻見意','李綱','宋','宋诗','song-poetry','','[]','未忘世故似梅仙，謦欬那離狗馬間。',128,'全唐诗/poet.song.89000.json','["未忘世故似梅仙，謦欬那離狗馬間。", "肯信片言功若藥，坐使四海安如山。", "從來療疾應須艾，寧有艾丸如許大。", "扁鵲先知今豈無，和緩髙談良有在。", "錢郎志氣絕可人，不減風流温太真。", "新詩欲嗣汲黯直，陋巷更甘原憲貧。", "我有故園依北阜，松菊歸來知好否。", "著鞭願子勉爲先，我已摧頹瞠若後。"]'),
('309ded56-80d3-45dc-8e0b-c340d8803a7b','往復詩多用佛語再次前韻示仲輔','李綱','宋','宋诗','song-poetry','','[]','遠涉異域求金仙，豈知不離方寸間。',128,'全唐诗/poet.song.89000.json','["遠涉異域求金仙，豈知不離方寸間。", "此門悟入真捷徑，安用困苦棲窮山。", "憑君試灼一炷艾，能已千痾寧四大。", "病根若悟本來空，是則名爲觀自在。", "平生見盡學道人，舍妄求真不識真。", "指端明月休錯認，衣裏寶珠元不貧。", "巍巍蕩蕩如山阜，長與君俱君見否。", "仁者自生分别心，斷際何嘗有前後。"]'),
('dc48f883-0e5f-4d42-a90d-841d487feaf1','題李茂舉擁書堂','李綱','宋','宋诗','song-poetry','','[]','小堂深穩據西偏，插架牙籖燦屬聯。',64,'全唐诗/poet.song.89000.json','["小堂深穩據西偏，插架牙籖燦屬聯。", "萬卷新如手未觸，五經嘲解腹空便。", "子同蔣詡開三徑，我學揚雄老一廛。", "歸去梁谿謀築室，隔江相望兩翛然。"]'),
('3d3df23f-20c5-4b72-a17d-dcc3f2984c22','次韻徽言見贈','李綱','宋','宋诗','song-poetry','','[]','白首窮一經，此道何嘗東。',144,'全唐诗/poet.song.89000.json','["白首窮一經，此道何嘗東。", "陋質誤識擢，珥筆宸庭楓。", "胸中何所見，耿耿惟孤忠。", "謫官乃自取，寵辱久矣同。", "朅來旅江城，勝遊幸從公。", "款暱讌笑歡，顧忘身世窮。", "十年倦遊意，一笑回首空。", "尚餘愛君心，夢繞明光宫。", "夫子抱髙趣，才氣凛以雄。", "揮毫寫妙語，爗若五彩虹。", "寧淹江海上，行簉鵷鷺中。", "放懷且玉友，不用酟郫筒。"]'),
('650c3a4d-59a1-48cf-b91e-a9f0ee18b599','堯明以五詩賮行辭意激昂欽玩無已輙用第五首次韻爲報聊發一笑','李綱','宋','宋诗','song-poetry','','[]','吹臺一罇酒，平昔接英遊。',120,'全唐诗/poet.song.89000.json','["吹臺一罇酒，平昔接英遊。", "棘闈澹墨榜，曾見成名秋。", "焉知江海上，乃復同唱酬。", "子如清廟器，端俟識者收。", "又如御厨珍，可用三公羞。", "髙志凛冰雪，妙語鏘琳球。", "三年未飛鳴，一舉宜無儔。", "我已謝世網，逝將老一丘。", "願子勉自愛，食肉鄙虎頭。", "名節乃難立，富貴良易求。"]'),
('bab81619-54f1-467d-9e32-5ccd1e826dae','自海陵泛江歸梁谿作','李綱','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','清江湛湛波不興，澄江際天如鏡平。',240,'全唐诗/poet.song.89000.json','["清江湛湛波不興，澄江際天如鏡平。", "火雲突兀聳峰岫，倒影萬丈搖空明。", "扁舟歸逐落潮急，聒耳但聞雙櫓聲。", "乃知長江無六月，水氣自與風兼清。", "去年狂寇起歙睦，江浙慘澹妖氣凝。", "百年涵養極繁盛，一日蕩析屯臊腥。", "衣冠北渡旅淮甸，扶老攜幼紛從横。", "王師出討盛貔虎，兇渠授首封鯢鯨。", "迨兹浙右稍安定，鼓拖復作東南征。", "家山在望已可喜，僮僕候我應歡迎。", "平疇戢戢稻秧綠，峻嶺靄靄松林青。", "田園有趣良足樂，軒冕無味非所榮。", "蒼生倘有安堵望，笑傲自可終餘齡。", "只今餘孽尚充斥，努力廟筭宜哀矜。", "裹包兵革不復用，坐使四海還康寧。"]'),
('4232436f-ad29-485c-8fe7-fa3f9c5121e1','次韻上元宰胡俊明蔣山勤老唱和古風','李綱','宋','宋诗','song-poetry','','[]','竺教流傳入中土，以相求之無自可。',384,'全唐诗/poet.song.89000.json','["竺教流傳入中土，以相求之無自可。", "達磨西來直指心，擬議之間已蹉過。", "皮髓誰分深淺機，祖禰翻貽子孫禍。", "鍾山禪老真可人，髙唱宗風震江左。", "學流雲集欲何爲，佛祖要須自心作。", "宰官倥偬牒訟間，偷暇相從還作麽。", "也知襟抱素相親，更把篇章迭酬和。", "詞嚴義密讀難曉，字順文從識皆妥。", "應憐孤陋方杜門，亦欲追隨良未果。", "故將佳句寄幽人，此意勤渠滋愧荷。", "談空摩詰無一言，聽法文殊非兩箇。", "若將情解議真如，明眼人前應看破。", "世間萬法互低昂，正若旋輪與推磨。", "隨時俯仰乃善謀，就中拙者無過我。", "九折羊腸欲着鞭，萬里滄溟思縱柁。", "只今行年四十餘，已覺衰頹多坐臥。", "平生作具何所施，盡以付之一弄火。", "迴光返照默自參，妙湛本然無點涴。", "公方齒壯志氣豪，正可立功同魏顆。", "胡爲亦復味禪那，坐視軒裳如縶鎖。", "蓮社莊嚴清凈池，丈室含容髙廣座。", "他時共結香火緣，心期耿耿當非頗。", "爲余稽首問勤師，如師材德誠磊砢。", "釣龍羅鳳大江濱，法器誰爲語無墮。"]'),
('375731ec-d6d3-48ca-a736-92e8a0e63c8e','寄許振叔顯謨','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','我向江湖老此身，公猶拘縶作羈臣。',64,'全唐诗/poet.song.89000.json','["我向江湖老此身，公猶拘縶作羈臣。", "蘭宫笑語真一夢，澤國過從今幾人。", "霜落洞庭橙橘熟，泉斟桑苧茗芽新。", "相望百里如千里，早晚歸來共釣緡。"]'),
('c6e7c0eb-80bc-4886-8c17-bc52620c6044','次韻仲弟古意','李綱','宋','宋诗','song-poetry','','[]','棣萼相榮華，鴒原同急難。',156,'全唐诗/poet.song.89000.json','["棣萼相榮華，鴒原同急難。", "富貴何足羡，名節在所完。", "吾家諸弟昆，擢秀森琅玕。", "雖無金朱樂，顧有道義歡。", "故人豈不多，誰念范叔寒。", "卜築九峰下，庇此拙且頑。", "山光入户牖，溪水清不湍。", "我屋雖無華，容膝審易安。", "田疇半莨莠，念兹歲方艱。", "虛室味圖史，小圃蓻茝蘭。", "蕭然寂寞濱，庶保餘齡閒。", "哲弟富才業，壯志思昭姦。", "勉哉振此道，吾方閒處看。"]'),
('104f5494-fad3-4cc9-8b41-54538112340d','次韻李似表縣丞出示遊西湖古風二首  其一','李綱','宋','宋诗','song-poetry','','["\u897f\u6e56"]','迂愚與世違，深渺方自屏。',180,'全唐诗/poet.song.89000.json','["迂愚與世違，深渺方自屏。", "蕭然巖壑心，不與餘事並。", "澄湖武林西，風物非塵境。", "願爲境中人，此志久已定。", "卜居梁谿濱，日汲陸子井。", "幽夢繞湖山，妙趣神先領。", "浮家苕霅間，初不費馳騁。", "招攜得佳友，髙詠笑匡鼎。", "富貴如浮雲，功名真畫餅。", "且盡季鷹杯，更飽盧仝茗。", "李侯東南來，胸次涵萬頃。", "作詩紀幽尋，句法言可永。", "念子到山中，天地正悽冷。", "青鞋踏冰霜，共賞誰復肯。", "勝遊子先之，吾亦行買艇。"]'),
('c5e3d96c-2e89-4bef-bbe2-a5b2fc22c51f','次韻李似表縣丞出示遊西湖古風二首  其二','李綱','宋','宋诗','song-poetry','','["\u897f\u6e56"]','李侯嗜學古，餘事皆遠屏。',180,'全唐诗/poet.song.89000.json','["李侯嗜學古，餘事皆遠屏。", "昂昂鸞鵠姿，豈與凡禽並。", "捧檄來南州，初識浙江境。", "尋盟款吾廬，不待日中定。", "從容叩所得，響答如汲井。", "時方羅俊乂，寧久淹簿領。", "清秋鵰鶚飛，大道驊騮騁。", "詞章尤激昂，筆力可扛鼎。", "虛堂縱談笑，霜月掛金餅。", "夜闌言愈微，至味嚼佳茗。", "古來會合難，歲月積俄頃。", "願子謹所之，萬里路方永。", "吾衰老閒曠，軒冕志已冷。", "棲遲丘壑間，此興良自肯。", "他日來相遇，梁谿尋釣艇。"]'),
('c018a3c3-1daa-48f6-9dfb-eb2ce18a1141','似表復以詩來再次前韻并簡似矩待制似之舍人','李綱','宋','宋诗','song-poetry','','[]','吾宗抱逸韻，試吏得南屏。',180,'全唐诗/poet.song.89000.json','["吾宗抱逸韻，試吏得南屏。", "掃廳日哦詩，俗士駕敢並。", "雙谿與疊嶂，拄頰對佳境。", "諸昆奉板輿，晨夕嚴省定。", "仲氏近剖符，鍊養窺丹井。", "叔兮久燕閒，禪要心獨領。", "何人縶騏驥，逸足未髙騁。", "會當歸本朝，宗社重九鼎。", "衰疲老山林，耕釣供餌餅。", "叩門欣得朋，草草具醪茗。", "追思會金陵，三載如食頃。", "契闊懷晤言，川途阻修永。", "臨流送將歸，歲晏風霜冷。", "寄聲昆季間，卜隣誰定肯。", "天髙烟霧深，且縱江湖艇。"]'),
('4f80a3d7-b452-4ad7-a99c-4722ce53f49b','寄池陽黄季岑士曹  其一','李綱','宋','宋诗','song-poetry','','[]','昔年多士萃南宫，曾見雄文曄彩虹。',64,'全唐诗/poet.song.89000.json','["昔年多士萃南宫，曾見雄文曄彩虹。", "萬里相期霄漢上，一官猶在大江東。", "新詩寄遠句增麗，舊事追遊夢已空。", "努力要津張此志，吾方寒釣五湖中。"]'),
('6aff55e2-b3db-4057-bb39-f1dfaf6262c3','寄池陽黄季岑士曹  其二','李綱','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','稚年嬉戲曾遊地，往歲飄零假道還。',64,'全唐诗/poet.song.89000.json','["稚年嬉戲曾遊地，往歲飄零假道還。", "溪水寒生江祖石，洞雲深接九華山。", "錦苔綠字幾多在，石鷰白鷗相與閒。", "幕府詩人富家學，定留秀句滿巖間。"]'),
('a8aee7b5-39c8-4b8f-ae11-5838f14bdf30','冬日登小閣有感呈子美提舉奉議  其一','李綱','宋','宋诗','song-poetry','','[]','霜落風髙萬里枯，孤鴻窅窅下平湖。',64,'全唐诗/poet.song.89000.json','["霜落風髙萬里枯，孤鴻窅窅下平湖。", "行藏誰會倚欄意，嘯詠聊爲終老娱。", "寒日溪山相掩藹，暮雲樓閣半虛無。", "何人妙解丹青事，畫作輞川煙靄圖。"]'),
('357ecfee-951b-443a-bdb4-816f00b63f3b','冬日登小閣有感呈子美提舉奉議  其二','李綱','宋','宋诗','song-poetry','','[]','遶舍松林寒不枯，煙霞深處見澄湖。',64,'全唐诗/poet.song.89000.json','["遶舍松林寒不枯，煙霞深處見澄湖。", "縈青繚白知誰賞，把酒裁詩可自娱。", "剡曲幸非千里遠，同雲又復一冬無。", "會當半夜溪山白，乘興真爲訪戴圖。"]'),
('b113df90-248d-4b45-8aa4-6c4436834f3f','送鄧志宏赴試南省','李綱','宋','宋诗','song-poetry','','[]','杜門憂患餘，戚戚常鮮歡。',156,'全唐诗/poet.song.89000.json','["杜門憂患餘，戚戚常鮮歡。", "故人千里來，一笑解我顔。", "念昔寓沙陽，溪山鬱迴環。", "游從得良友，妙賞窮躋攀。", "别來幾何時，歲月驚飛翻。", "索居無與遊，衰病兩鬢斑。", "子充觀國賓，假道叩我關。", "草草具盤饌，把酒望西山。", "道舊訪陳跡，相對如夢間。", "顧子若鴻鵠，整翮正髙騫。", "軒然四海心，豈憚行路難。", "努力取殊第，自致青雲端。", "春風得意後，期子從兹還。"]'),
('a5107bf9-115f-43ba-94a3-724d0cda0a62','次韻仲弟獨遊惠山古風','李綱','宋','宋诗','song-poetry','','[]','我家九峰下，跬步臨勝境。',288,'全唐诗/poet.song.89000.json','["我家九峰下，跬步臨勝境。", "循除環珮聲，滿庭松桂影。", "宦遊阻幽尋，每若龜引頸。", "十年旅京華，萬里走閩嶺。", "歸懷寄清夢，投檄期子請。", "向來兵火作，此地偶無警。", "餘生集百憂，負郭耕二頃。", "新交浸已疏，舊學謀復整。", "功名一灰灺，毁譽兩鼃黽。", "抱拙與世違，退縮甘遠屏。", "杜關絕外遊，但欲俗緣省。", "兹山乃故人，雅契相與永。", "登臨富泉石，採掇足芹荇。", "下瓢酌甘芳，日汲謝瓶綆。", "胡爲久不到，有愧稚川井。", "仲弟絕俗姿，好勇先我騁。", "新詩紀清賞，得句頗彪炳。", "艱難見鴒原，歲月侵晚景。", "相期老丘壑，不復歎土梗。", "梁谿寒可漁，蓑笠同舴艋。", "寧如六一翁，終日思汝潁。", "方兹築吾廬，跧伏念前眚。", "面山開小閣，制度閴深靚。", "山氣日夕佳，爽致當共領。"]'),
('e71a0cc7-0bf6-4b44-90ea-26198f66f612','吴元中書言近不作詩以所著豳七月詩義見示因成三篇贈之  其一','李綱','宋','宋诗','song-poetry','','[]','旰起幽居尚閉關，忽傳尺素破愁顔。',64,'全唐诗/poet.song.89000.json','["旰起幽居尚閉關，忽傳尺素破愁顔。", "迂疏似我宜深隱，才術如公豈暫閑。", "雅意未曾忘北闕，勝遊今日且東山。", "十年迴首當時事，歎息人生似夢間。"]'),
('d8e10e60-2545-4099-a004-1e8bf6d1d7f6','吴元中書言近不作詩以所著豳七月詩義見示因成三篇贈之  其二','李綱','宋','宋诗','song-poetry','','[]','底事年來不作詩，應緣思苦少人知。',64,'全唐诗/poet.song.89000.json','["底事年來不作詩，應緣思苦少人知。", "凌雲健筆含毫日，照眼花枝得句時。", "陶冶性情端賴此，詠嘲風月漫多爲。", "驛筒若許陪酬唱，朱字青牋復寄誰。"]'),
('927fea3b-b1df-4b50-9c7c-6e14131bd653','吴元中書言近不作詩以所著豳七月詩義見示因成三篇贈之  其三','李綱','宋','宋诗','song-poetry','','[]','儒生樂事信同風，端抱前言當鼓鐘。',64,'全唐诗/poet.song.89000.json','["儒生樂事信同風，端抱前言當鼓鐘。", "公正說詩箋七月，我方學易緯羣龍。", "艱難盛事原衣食，憂患餘生問吉凶。", "去聖寥寥千載後，何時揮麈得從容。"]'),
('d6bf65ce-39e7-429f-b6c7-dc165d02f6dc','題伯時明皇蜀道圖','李綱','宋','宋诗','song-poetry','','[]','君不見開元天寶同一主，治亂相翻如手舉。',259,'全唐诗/poet.song.89000.json','["君不見開元天寶同一主，治亂相翻如手舉。", "掔盈欲惡雖一人，變易安危原近輔。", "姚宋已死九齡黜，誰使楊釗繼林甫。", "宫中太真專寵私，塞外番酋成跋扈。", "禍胎養就不自知，漫向華清遺匕筯。", "漁陽突騎破潼關，百二山河震金鼓。", "翠華杳杳幸西南，赤縣紛紛集夷虜。", "傷心坡下失紅顔，墮淚鈴中聞夜雨。", "山青江碧蜀道難，棧閣連空㒟相拄。", "旌旗慘淡雲物愁，林木陰森猿鳥侣。", "戎裝宫女亦善騎，皓齒明眸猶笑語。", "老髯奚官驅蹇驢，負橐齎糧豈供御。", "九重徼衞復誰勤，萬里艱危真自取。", "至尊狼狽尚如此，歎息蒼生困豺虎。", "千秋萬歲不勝悲，玉輦金輿盡黄土。", "空令畫手思入神，一寫丹青戒今古。"]'),
('158ef516-8e7b-4aa8-a1bd-832fea9aeb5d','送韓茂遵解元赴試南省','李綱','宋','宋诗','song-poetry','','[]','憂患餘生日杜關，幅巾青顧得開顔。',64,'全唐诗/poet.song.89000.json','["憂患餘生日杜關，幅巾青顧得開顔。", "虛堂把酒延佳月，小閣哦詩對遠山。", "子學鯤鵬將海運，我同猿鶴且雲閑。", "都城故舊還相問，爲道衰頽鬢已斑。"]'),
('df9d1420-cadd-4c36-aa24-145b7f574adc','題邵平種瓜圖','李綱','宋','宋诗','song-poetry','','[]','君不見伯成子髙讓侯爵，在野終年自耕穫。',326,'全唐诗/poet.song.89000.json','["君不見伯成子髙讓侯爵，在野終年自耕穫。", "下風趨問禮徒勤，俋俋田間事無落。", "又不見於陵仲子推相位，爲人灌園刈葵藿。", "抱甕區區同漢陰，不糝藜羮有餘樂。", "古來賢達有如此，志趣未可常情度。", "力辭富貴居賤貧，凛若風霜隕輕籜。", "邵平本自侯東陵，秦破國除休一壑。", "當時漢祖疑鄼侯，置衞增封意非薄。", "衆賓皆賀平獨弔，一言轉禍推先覺。", "以兹智略佐風雲，復取故封何所怍。", "歸來種瓜青門外，灌溉耡耘甘寂寞。", "長安之東壤尤美，翠蔓離離照城郭。", "秋陽正熾瓜正肥，解衣摘實如俛鶴。", "兒童隨立形骨清，挈笠攜筐助操作。", "遂令世美東陵瓜，身後髙名動寥廓。", "屠販曾聞封絳灌，奴僕從來興衞霍。", "髙鳥已盡良弓藏，更有韓彭辱囚縛。", "何如終老守瓜畦，自飽飽他真不惡。", "龍眠也是可憐人，畫此端令事如昨。", "世間如畫畫如夢，聊爲作歌資一噱。"]'),
('4667cc1e-e695-4c82-acf5-2cb85f705d19','寄題外氏松源紹祖亭  其一','李綱','宋','宋诗','song-poetry','','[]','束劍艱危際，結廬閒曠濱。',48,'全唐诗/poet.song.89000.json','["束劍艱危際，結廬閒曠濱。", "全家入青嶂，避地爲黄巾。", "族系歸圖譜，風流藹薦紳。", "雲仍藉餘澤，勿替德維新。"]'),
('40872ccc-61b3-41c2-9ab2-e875c9ebde41','寄題外氏松源紹祖亭  其二','李綱','宋','宋诗','song-poetry','','[]','外族雲峰畔，新亭烟水濱。',48,'全唐诗/poet.song.89000.json','["外族雲峰畔，新亭烟水濱。", "兒童舊遊地，感慨易霑巾。", "竹裏鏘鳴珮，山邊繚素紳。", "何當俯軒檻，一覽物華新。"]'),
('a028d884-1c57-42fe-a43c-659b6cab5963','近以詩寄許振叔承林德祖見和復次前韻寄之','李綱','宋','宋诗','song-poetry','','[]','甫里先生早乞身，最憐流落漢庭臣。',64,'全唐诗/poet.song.89000.json','["甫里先生早乞身，最憐流落漢庭臣。", "也知雅有綈袍意，故使同爲蓮社人。", "佳句傳來油素濕，靈文繙處貝多新。", "更煩爲指趨真路，舊國于今草木緡。"]'),
('c295716f-ca98-45e3-8607-ff8bb537613c','次韻顧子美見示題曲江畫像','李綱','宋','宋诗','song-poetry','','[]','天眷李唐能肖德，異人間出生其國。',384,'全唐诗/poet.song.89000.json','["天眷李唐能肖德，異人間出生其國。", "於中貞觀開元間，譬若豐年多黍稷。", "曲江擢秀自妙齡，國器早被燕公識。", "文詞贍蔚冠後來，大冊髙文振鴻筆。", "孤生徒步起荒陬，職秉鈞衡爵侯伯。", "一時推挽盡正人，讜議嘉謨咸可績。", "能於偏校識胡情，此理未可常情億。", "哥奴豈是郎官材，誰使巖廊久踐歷。", "眉宇津津挾兔鵰，醖藉居然困摧抑。", "正衙造膝訪相臣，豈止伶官論安叱。", "天意方將啓禄山，帝心那解疑仙客。", "房帷陰謀獨上陳，三子未寃繄巨力。", "偉哉相業繼姚宋，允矣威聲落夷貊。", "千秋金鑑奉君王，仁者之言古遺直。", "詠燕論心詎免猜，賦扇陳情竟何意。", "黄鍾毁棄瓦釜嗚，鳳去鴞鴟集槐棘。", "固知骨骾易嬰鱗，坐使姦諛得乘隙。", "一麾出守來荆蠻，直道忘懷謝欣戚。", "詩篇冥助得江山，文史終年自怡懌。", "漁陽鼙鼓震長安，禍亂寧從一朝積。", "翠華西幸蒙塵飛，蜀道艱難會相憶。", "至言逆耳棄不收，遣祭徒勞長歎息。", "古來忠讜盡如此，端欲濟時如穀帛。", "空令萬世滄海南，崒兀髙名配韶石。"]'),
('9481f1a8-9323-443f-9947-20bf5d69c61b','小閣晚望書懷一百韻示仲弟并簡顧子美','李綱','宋','宋诗','song-poetry','','[]','歲晏羣陰積，天髙霰雪晴。',288,'全唐诗/poet.song.89000.json','["歲晏羣陰積，天髙霰雪晴。", "西山來爽致，小閣湛虛明。", "曲檻馳孤照，微雲點太清。", "泛觀周宇宙，曠望出枝撐。", "九隴龍蛇伏，梁谿組練縈。", "翠烟浮近市，碧瓦麗髙甍。", "湖外千巖秀，林端一带平。", "松篁森薈蔚，樓觀鬱崢嶸。", "天末氛埃歛，坤倪物象呈。", "清風生户牖，秀色入軒楹。", "北極星辰拱，東臯雨露贏。", "寸懷舒遠目，萬感集孤情。", "憶昨陪螭殿，終年侍玉京。", "含毫青瑣闥，通籍鳳凰城。", "奬擢知恩重，臨危覺死輕。", "囊書朝入奏，襆被夕徂征。", "去歷谿山險，歸虞盜賊驚。", "西江足波浪，南國滿旃旌。", "迂路良非策，尋家不計程。", "天戈戡猰貐，廟略掃欃槍。", "蕪没田園在，歡呼僕隸迎。", "亂離才甫定，患禍忽相嬰。", "風木悲摧感，祥琴慘愴聲。", "誓終墳墓守，望絕縉紳榮。"]'),
('d2a4ea43-5710-4128-8948-8d2be2ed4e9d','唐植甫左司許出示所藏紅絲硯輙成短歌奉呈并簡顧子美','李綱','宋','宋诗','song-poetry','','[]','羲和整御升暘谷，赤雲夾日如飛鶩。',352,'全唐诗/poet.song.89000.json','["羲和整御升暘谷，赤雲夾日如飛鶩。", "晶光下射東方山，石卵含丹孕巖腹。", "誰令巧匠鑿山骨，截此頳堅一肪玉。", "琢爲巨硯形製奇，中有彤雲爛盈目。", "端溪美璞色馬肝，黟歙珍胚紋霧縠。", "豈知至寶出嵎夷，散綺浮花彩尤縟。", "鳳咮空聞名字佳，龍尾苦笑規模俗。", "謾誇眉子鬬嬋娟，休認明眸類鴝鵒。", "顧眄幸蒙君子知，拂拭自遠塵埃辱。", "火輪炫熀赤烏流，墨海奫淪玄兔浴。", "千金象管雕鏤精，百鍊松煤龍麝馥。", "怒猊渇驥縱奔拏，春蚓秋蛇相綰束。", "楮生便覺肌理妍，毛穎何嘗免冠秃。", "公家三世擅直聲，此硯提攜資簡牘。", "力侔天地掌中迴，膽落姦諛筆端戮。", "固宜祕玩不輕示，神物護持無輙黷。", "窗明几凈齋閣深，日暖風清靄松竹。", "試將墨妙寫新詩，落筆煙雲歎神速。", "矧公早年曾餌丹，龜鶴精神鬢毛綠。", "久臥商山茹紫芝，行度天門騎白鹿。", "猗蘭玉樹富階庭，黄卷青緗賸編軸。", "願言什襲遺雲仍，大筆髙文永相續。"]'),
('8d27ae92-dc54-4cfd-bcfb-bbcef79762d1','次韻顧子美提舉許雪中見過之作','李綱','宋','宋诗','song-poetry','','[]','殘臘苦寒情味惡，萬里風雲欣雪作。',240,'全唐诗/poet.song.89000.json','["殘臘苦寒情味惡，萬里風雲欣雪作。", "夜積端愁坤軸傾，曉望却驚天界擴。", "玉龍鱗甲臥羣山，水海波瀾凝巨壑。", "謝家兒女自多才，笑詠飛花度羅幕。", "金爐未覺獸炭温，錦帳猶訝貂裘薄。", "書生饑甚況復寒，坐聽朱絃折臨獄。", "松孤竹老念山林，甲冷戈寒憫沙漠。", "豈思龍尾賀千官，且疊琴心舞雙鶴。", "瑶林玉樹粲迴環，勿謂軒庭全冷落。", "擁門但作袁安臥，命駕誰思子猷樂。", "溪山如畫真自知，金玉滿堂端不博。", "煩公攜具款我門，注目遥空登晚閣。", "凍吟猶作號寒聲，此病欲醫那有藥。", "公家故自富香醪，我亦安能辭巨杓。", "醉看萬事雪銷凝，妙觀圓成不須學。"]'),
('6f09c8ab-29d1-4bff-afc0-13724a60e7b9','次韻邵子非見贈之作','李綱','宋','宋诗','song-poetry','','[]','持竿相與釣鯨魚，歎息平生術已疏。',64,'全唐诗/poet.song.89000.json','["持竿相與釣鯨魚，歎息平生術已疏。", "嬉戲尚能追舊事，窮愁聊復著新書。", "昂霄聳壑公行爾，拂石眠雲我自如。", "卜築相望纔一水，未應歲晚恨離居。"]'),
('1588cd81-222f-4192-82e6-3e8fd09e9f1d','次韻子美寄彦章同遊惠山之作','李綱','宋','宋诗','song-poetry','','[]','結廬寂無車馬喧，雀羅可設深扃門。',288,'全唐诗/poet.song.89000.json','["結廬寂無車馬喧，雀羅可設深扃門。", "北窗一枕半成夢，剝啄叩户驚心魂。", "故人見過適我願，相與攜手遊山樊。", "春風桃李已零落，孟夏草木行滋繁。", "下瓢共酌陸子井，策杖更步公垂園。", "山肴野蔌助清賞，此心非子將誰論。", "人生聚散如露電，訪舊歎息無多存。", "區區得失何足較，瑟僴但期終不諼。", "嗟予夙昔志四海，遠游欲學飛鴻軒。", "南征曾上帝子閣，暮雨朝雲相吐吞。", "西山積翠多爽氣，大江縈練方東奔。", "十年回首如夢到，舊事今復聞公言。", "邇來百念已灰冷，但願痛飲窮朝昏。", "新交漸鮮俗緣久，省要更覺情懷敦。", "山中蕙帳不落寞，無復怨鶴啼驚猿。", "平生有意師老氏，以退爲進卑爲尊。", "致君澤物付公等，我乃送老溪前村。", "置之此事勿復道，且須吸盡黄金罇。"]'),
('fed420fc-79f7-4906-ba48-aa6ff459a3c7','蔣山佛果師爲緣事來而此土方饑戲賦是詩以發一笑','李綱','宋','宋诗','song-poetry','','[]','鍾山禪老天骨奇，叢林晏座如孤羆。',192,'全唐诗/poet.song.89000.json','["鍾山禪老天骨奇，叢林晏座如孤羆。", "諸方宗仰第一義，說法舌作霹靂飛。", "年來爲衆建廣厦，胸中結構良峨巍。", "修梁巨棟資喜捨，瓶錫不憚東南馳。", "飛騰道俗走檀越，堆積金貝羅珠璣。", "此方旱潦異常歲，百里稚耋方流離。", "析薪鬻子給朝夕，闔境半作嬰兒啼。", "坐看緣事莫措手，却欲反著僧伽梨。", "未聞蘭若泣龍象，好把信施賙寒饑。", "向來收拾大寶聚，隨手散盡真慈悲。", "惟師具眼得空觀，稇載豈愁華槖歸。", "吾言可聽勿惆悵，無價寶珠元在衣。"]'),
('5154ff95-b2f6-463f-9686-1bc4823dc3e8','次韻葉少藴內翰丈霅川上買得弁山石林二首  其一','李綱','宋','宋诗','song-poetry','','[]','翰林風度世間無，炯若清冰置玉壺。',64,'全唐诗/poet.song.89000.json','["翰林風度世間無，炯若清冰置玉壺。", "暫向霅川謀小隱，未應魯國舍真儒。", "平泉草木何須記，杜曲桑麻幸可圖。", "我亦新霑散人號，浮家正欲老江湖。"]'),
('52c3f6fe-6200-422a-98a0-759506ba5304','次韻葉少藴內翰丈霅川上買得弁山石林二首  其二','李綱','宋','宋诗','song-poetry','','[]','視草金鑾不記年，却將心事付林泉。',64,'全唐诗/poet.song.89000.json','["視草金鑾不記年，却將心事付林泉。", "歸居盤谷真良策，買得愚溪定夙緣。", "隔竹聞聲鳴佩玉，揮毫落紙散雲煙。", "欲誇水石無窮趣，故把新詩得得傳。"]'),
('88924016-c155-4160-8325-0318f55d2e29','近約周仲居同遊陽羡以私故不果見寄笱蕨因成此詩','李綱','宋','宋诗','song-poetry','','[]','勝遊尚爾阻躋攀，自愧閒中亦未閒。',64,'全唐诗/poet.song.89000.json','["勝遊尚爾阻躋攀，自愧閒中亦未閒。", "多謝幽人分筍蕨，宛同春日到雲山。", "洞天上下煙霞裏，溪水迴環圖畫間。", "暫過豈能窮妙賞，結廬終欲老疏頑。"]'),
('41084c89-69aa-4d2f-a90d-dc69485b4300','次韻顧子美見示久雨三首  其一','李綱','宋','宋诗','song-poetry','','[]','一春常苦雨，入夏尚慳晴。',48,'全唐诗/poet.song.89000.json','["一春常苦雨，入夏尚慳晴。", "雲物頻舒卷，軒窗乍晦明。", "下田嗟漲溢，髙岸惜頽傾。", "蔓草無情思，芟除又發生。"]'),
('b5d17726-f668-4ca1-919d-929df840c12d','次韻顧子美見示久雨三首  其二','李綱','宋','宋诗','song-poetry','','[]','朝來疑欲霽，雲氣復如蒸。',48,'全唐诗/poet.song.89000.json','["朝來疑欲霽，雲氣復如蒸。", "泥潦疲馳驟，晨昏錯寢興。", "及時初可喜，失節反堪憎。", "安得西山出，層樓共一登。"]'),
('98362eca-a768-464c-8410-54e9d65a1657','次韻顧子美見示久雨三首  其三','李綱','宋','宋诗','song-poetry','','[]','中夏猶裌衣，澤國信殊候。',48,'全唐诗/poet.song.89000.json','["中夏猶裌衣，澤國信殊候。", "連陰不復開，似欲無晴晝。", "涓涓簷間滴，駃駃渠中溜。", "蒼生環堵完，遑恤吾廬漏。"]'),
('e938d014-7661-4a86-bec5-5edda63a1d26','寄毛達可內翰并錄送魏公别錄  其一','李綱','宋','宋诗','song-poetry','','[]','縠水柯山藴秀奇，精忠深結冕旒知。',64,'全唐诗/poet.song.89000.json','["縠水柯山藴秀奇，精忠深結冕旒知。", "玉堂視草久推重，金椀書名猶恨遲。", "廊廟未應忘澤物，江山且復助題詩。", "慇懃寄錄韓公事，好爲斯民更築基。"]'),
('d9f18df1-9d94-42c0-9335-59ba2fe671c6','寄毛達可內翰并錄送魏公别錄  其二','李綱','宋','宋诗','song-poetry','','[]','迂愚聊復隱清時，幽事相關只自知。',64,'全唐诗/poet.song.89000.json','["迂愚聊復隱清時，幽事相關只自知。", "滿地落花看鶴舞，一軒春雨對僧棋。", "閑中日月真銷得，物外煙霞漸可期。", "坐致時康賴公等，不須深遯採商芝。"]'),
('96a2a6b2-9f5c-4962-b58f-c94fc4858348','蓴菜','李綱','宋','宋诗','song-poetry','','[]','渺渺春湖水拍天，紫蓴千里正聮綿。',64,'全唐诗/poet.song.89000.json','["渺渺春湖水拍天，紫蓴千里正聮綿。", "初抽荷蘂半含露，旋摘龍須尚带涎。", "鹽豉欲調難並美，鱸魚兼憶詎非賢。", "自憐不是知機士，飽食空能上釣船。"]'),
('80ade052-1dcd-43d4-ae4e-2cc2fcc32deb','送李泰發吏部赴官陽朔  其一','李綱','宋','宋诗','song-poetry','','[]','意氣相期會面前，謫官邂逅兩蕭然。',64,'全唐诗/poet.song.89000.json','["意氣相期會面前，謫官邂逅兩蕭然。", "誰憐蘭省鵷鸞友，去作桂林山水仙。", "直道事人寧免黜，拙謀於我欲爭先。", "寛恩下逮宜非久，來買梁谿二頃田。"]'),
('5d785dde-ae11-4cc4-acaa-ffcf2f9d1c1c','送李泰發吏部赴官陽朔  其二','李綱','宋','宋诗','song-poetry','','[]','陽朔谿山冠百蠻，羡君遠宦得躋攀。',64,'全唐诗/poet.song.89000.json','["陽朔谿山冠百蠻，羡君遠宦得躋攀。", "聲名已落寰區內，忠信自行夷貊間。", "山作劍鋩攢峻拔，水如羅带巧迴環。", "此生又作南征計，好把輕綃寄一斑。"]'),
('3888490e-6a4d-4e2a-b2c5-fe42f356584d','寄李泰發吏部','李綱','宋','宋诗','song-poetry','','[]','我生稟賦愚且屯，昔遊帝所知何因。',256,'全唐诗/poet.song.89000.json','["我生稟賦愚且屯，昔遊帝所知何因。", "狂言妄發取譴廢，屏跡分甘麋鹿羣。", "公於何許知姓字，迂趾訪我梁谿濱。", "平生傾蓋意氣合，談笑便覺襟懷親。", "如公材識邁倫等，緩步自當居要津。", "胡爲亦復作此態，出語輙已驚臣鄰。", "扁舟歸探會稽穴，單騎去指蒼梧雲。", "嶺南風土不全惡，陽朔山水古所珍。", "郎官出宰乃故事，絕徼萬里皆吾民。", "布宣德澤被蠻邑，獷俗可使風還淳。", "古來節士志溝壑，笑視生死同埃塵。", "甘心刀鋸蹈鼎鑊，狥國詎免危其身。", "聖朝寛大幸無比，竄謫未久多蒙恩。", "轅駒仗馬戀芻豆，何用局促聲長吞。", "堂堂基業甚宏遠，豈使扶助無良臣。", "勉旃行矣佇旋旆，乘興且訪山陰人。"]'),
('2aaf78c3-6453-4007-82d8-aa5c96278af3','同翁士特小飲中隱堂','李綱','宋','宋诗','song-poetry','','[]','三伏炎蒸畫舸迴，蓬門聊復爲君開。',64,'全唐诗/poet.song.89000.json','["三伏炎蒸畫舸迴，蓬門聊復爲君開。", "松篁蔭翳罇中渌，杖履逍遥池上臺。", "小雨乍隨雲影散，好風還逐月光來。", "虛堂夜久羣囂息，枕簟相從亦快哉。"]'),
('dfa70043-c68f-4d9e-aaf8-3fc75d1e3c57','士特見和復次前韻','李綱','宋','宋诗','song-poetry','','[]','丘園命駕未應迴，三徑還同蔣詡開。',64,'全唐诗/poet.song.89000.json','["丘園命駕未應迴，三徑還同蔣詡開。", "盤谷初能容蕙帳，鈞天無復夢瑶臺。", "稚年尚憶嬉遊處，老境相從歸去來。", "幸有西山供醉眼，不妨吟望思悠哉。"]'),
('e77a1c46-1022-4688-a290-98cbfb977458','同士特遊惠山再次前韻','李綱','宋','宋诗','song-poetry','','[]','九峰秀色照溪迴，古寺崢嶸殿閣開。',64,'全唐诗/poet.song.89000.json','["九峰秀色照溪迴，古寺崢嶸殿閣開。", "潄玉泉聲鏘石洞，鬱藍天影抱瓊臺。", "親賓情話真難得，巖壑幽尋豈易來。", "且復淹留同一醉，未應遄櫂念歸哉。"]'),
('0b812602-2dd0-4b06-b95e-ae23ba240f10','題周孝侯廟','李綱','宋','宋诗','song-poetry','','[]','周侯高節冠千古，志氣剛明乃如許。',115,'全唐诗/poet.song.89000.json','["周侯高節冠千古，志氣剛明乃如許。", "劍斬長橋戟尾蛟，刺殺南山雪毛虎。", "歸來一聽閭里言，折節寧辭遠遊苦。", "學成名立世共驚，狥國忘身乃其所。", "至今血食荆溪濱，廟貎崇深日簫鼓。", "我來再拜仰遺像，思古傷今悵誰語。", "君不見淮陰跨下已亡奇，噲等何羞與爲伍。"]'),
('4409a07a-d11c-4010-8f3a-03be191563c3','余乙巳春赴奉常召如京師五月四日至京口同似表叔易遊北固甘露寺','李綱','宋','宋诗','song-poetry','','[]','招提殿閣鬱嵳峨，占得江山氣象多。',64,'全唐诗/poet.song.89000.json','["招提殿閣鬱嵳峨，占得江山氣象多。", "一水下臨縈素練，兩山對峙疊青螺。", "乍欣心目到空闊，坐看風雲相盪摩。", "景物自新人自老，舊遊追憶奈愁何。"]'),
('3c6663ae-585d-4ca3-98ed-33bfe5d33390','雨中渡楊子江書懷呈似表叔易','李綱','宋','宋诗','song-poetry','','[]','波光澹澹櫓聲圓，風軟潮平利涉川。',64,'全唐诗/poet.song.89000.json','["波光澹澹櫓聲圓，風軟潮平利涉川。", "浩渺雲濤連海嶠，空濛煙雨濕樓船。", "江山雄偉冠天下，景物瓌奇繞目前。", "遠蹟禹功須我輩，感時懷古一悽然。"]'),
('d8aa1b8e-3caf-41ee-916d-737307b7d657','同似表叔易置酒平山堂','李綱','宋','宋诗','song-poetry','','[]','暫停征櫂此從容，歎息前賢結構雄。',64,'全唐诗/poet.song.89000.json','["暫停征櫂此從容，歎息前賢結構雄。", "心眼乍隨天宇闊，笑談不覺酒罇空。", "江光隱見軒楹裏，山色虛無煙雨中。", "種柳仙翁何處去，年年疏翠自春風。"]'),
('793279c5-da53-4a73-b899-e40cc92f0f57','過召伯埭遊斗野亭次司諫孫公韻','李綱','宋','宋诗','song-poetry','','[]','星斗照淮楚，綠野如砥平。',120,'全唐诗/poet.song.89000.json','["星斗照淮楚，綠野如砥平。", "兹亭結構小，景物有餘清。", "我來值袢暑，霽霧褰高甍。", "登臨得佳友，坐使懷抱傾。", "方塘楊柳合，極望菰蒲生。", "仰德思謝傅，弔古傷蕪城。", "濁酒聊共酌，小鱗鮮可烹。", "抱拙臥江海，胡爲復此行。", "區區螢爝光，何補日月明。", "稽古得車馬，平生笑桓榮。"]'),
('328af5ef-8fd6-4416-bd91-4a061e80981d','途中書懷','李綱','宋','宋诗','song-poetry','','[]','去國飄零伴一星，誤恩還許謁承眀。',64,'全唐诗/poet.song.89000.json','["去國飄零伴一星，誤恩還許謁承眀。", "已甘松菊老三徑，豈有材猷廁九卿。", "晚景故慚題柱客，壯懷多謝棄繻生。", "片帆自逐南風起，遇坎乘流且麽行。"]'),
('59096af5-2598-4245-ad78-767ca7b5a347','新開河食鱖魚戲成','李綱','宋','宋诗','song-poetry','','[]','平湖渺漫煙蒼蒼，菰蒲擢秀新荷香。',160,'全唐诗/poet.song.89000.json','["平湖渺漫煙蒼蒼，菰蒲擢秀新荷香。", "漁舟演漾出深浦，舟中鮮鱖肥而臧。", "傳呼就買不論價，得錢留魚魚眼光。", "細鱗哆口傳鬐鬛，斕斑點黑微塗黄。", "巨盆汲水養餘息，撥剌奮尾猶洋洋。", "付庖薦酒擇困者，揮刀切玉芼桂薑。", "麯生風味已醖藉，得此更使不可忘。", "松江之鱸不足憶，銀色詎數綿州魴。", "惜哉行役難駐櫂，一飽未許杯盤常。", "雨蓑煙笠乃吾事，安得獨釣青茫茫。"]'),
('38e3f9be-c01e-4e00-a263-01bd76b0608c','泗上瞻禮僧伽塔','李綱','宋','宋诗','song-poetry','','[]','湯湯淮泗濱，實爲至人居。',144,'全唐诗/poet.song.89000.json','["湯湯淮泗濱，實爲至人居。", "至人骨已冷，靈響初不渝。", "巍然窣堵波，金碧耀雲衢。", "突兀三百尺，勢欲凌霄虛。", "乃知天人師，宜有神明扶。", "憶昔歲乙未，奉親由此途。", "開關瞻晬容，端相不可誣。", "清秋日當午，爲現摩尼珠。", "蟬聮寶鐸間，懸綴如流蘇。", "萬目共瞻睹，稚耋驩驚呼。", "重來念舊事，感歎涕澘如。", "再拜禮雙足，如師真丈夫。"]'),
('41f06cdc-415c-4c67-8432-466b8f789605','汴上有感','李綱','宋','宋诗','song-poetry','','[]','不踏隋池今幾日，重來空歎二毛侵。',64,'全唐诗/poet.song.89000.json','["不踏隋池今幾日，重來空歎二毛侵。", "黄流渾渾帆檣影，綠岸森森榆柳陰。", "雨霽鳩鳴呼婦急，曉涼蟬噪感人深。", "區區往返何爲者，誰識先賢用舍心。"]'),
('0758f932-9af2-4285-9806-bf296df39bad','寶劍聯句','李綱','宋','宋诗','song-poetry','','[]','造化鑪錘巧，山谿鑛鏷良。',288,'全唐诗/poet.song.89000.json','["造化鑪錘巧，山谿鑛鏷良。", "精金付歐冶，妙手鑄干將。", "淬礪呈鋒鍔，飛騰辨耿光。", "青黄司火候，爪髪助祈禳。", "桃氏幾時獻，龍文難久藏。", "鱗皴識松理，乙屈認魚腸。", "黯黯青蛇色，炎炎赤帝祥。", "提攜起三尺，駕馭牧羣狼。", "彈鋏悲馮子，誇鐔悟趙王。", "神功歸不試，利用運無旁。", "贈客千金直，方人百鍊鋼。", "還須玉具飾，何用蒯緱裝。", "詎使妖腰喜，當容節士狂。", "純盧非娬媚，巨闕太堅剛。", "鬱勃衝牛斗，蛇蜒接混茫。", "疇能寶於越，俱議刻艅艎。", "抆拭資神土，珍藏閟寶房。", "斬蛟誠壯勇，剸象見銛鋩。", "韓信歸髙祖，朱雲賜尚方。", "雄材元倚仗，佞膽已飛揚。", "渾脫公孫舞，縵胡庶士傷。", "吳鈎能曲折，蜀漢有文章。", "六賜恩何厚，三名怨未償。", "先知吼蛟兕，摩鈍凜冰霜。"]'),
('74934032-8b79-416f-9b06-aace3ee48f97','山藥','李綱','宋','宋诗','song-poetry','','[]','山家爲我斸青冥，養就仙芝指掌明。',64,'全唐诗/poet.song.89000.json','["山家爲我斸青冥，養就仙芝指掌明。", "風味自應殊紫芋，功名初不减黄精。", "藤盤欲薦冰霜質，石鼎先聞風雨聲。", "辟糓留侯正歸去，淡然悠久見交情。"]'),
('0285ba02-89a8-4bea-92d5-26352730a669','煨芋','李綱','宋','宋诗','song-poetry','','[]','今夕何夕夜未央，天寒擁爐更漏長。',169,'全唐诗/poet.song.89000.json','["今夕何夕夜未央，天寒擁爐更漏長。", "縮肩環坐有饑色，呼童取芋灰爲塘。", "蹲鴟得火良易熟，脫落皮毛如紫玉。", "迭煨迭進争相先，笑語頗喧知實腹。", "錦里先生亦不貧，家園收拾動千斤。", "凶年自可活妻子，美好不减岷江濱。", "鄴侯昔遊衡嶽左，懶瓚食餘貽半箇。", "我今歸去隱家山，豈復從人覓殘顆。", "臞儒奉養亦已微，一飽便吟煨芋詩。", "君不見齊公夜半意不嗛，易牙煎熬燔炙和調五味而進之。"]'),
('fc535b40-fab9-4c18-9670-c1ff6880a8ee','食蟹','李綱','宋','宋诗','song-poetry','','[]','秋風蕭蕭蘆葦蒼，野岸郭索紛成行。',160,'全唐诗/poet.song.89000.json','["秋風蕭蕭蘆葦蒼，野岸郭索紛成行。", "持矛被甲正雄健，意氣正欲行無旁。", "朝魁執穗似有禮，擁劍敵虎何其强。", "野人篝火夜採撥，束縛赴鼎如驅羊。", "樽前風味若無敵，芼以橙橘尤芬芳。", "流膏斫雪快一飽，咀嚼海錯皆尋常。", "丹楓夜落吳天霜，䆉稏欲熟千畦黄。", "梁谿白蟹正可釣，雛雞濁酒肥且香。", "先生歸去營口腹，老饕未許他人當。", "家山漸近意漸適，思歸豈獨鱸魚鄉。"]'),
('90b68262-68ea-4eef-9348-b554504fc4f7','九月五日對菊小飲簡申伯叔易','李綱','宋','宋诗','song-poetry','','[]','淵明愛此九日名，對菊無錢可留客。',128,'全唐诗/poet.song.89000.json','["淵明愛此九日名，對菊無錢可留客。", "杜陵爛醉作生涯，青蘂空嗟未堪摘。", "我今鼓柁適長淮，坐見幽叢爛熳開。", "自從多病久不飲，又爾一洗黄金罍。", "東南節物誠已早，翠葉金花爲誰好。", "三徑荒蕪爾尚存，未覺出山同小草。", "世間萬事皆可忘，且須泛此酬秋光。", "平生最愛老坡語，菊花開日即重陽。"]'),
('8709ae18-7c36-494a-ad88-04e1e22058b4','小飲即事呈申伯','李綱','宋','宋诗','song-poetry','','[]','夜凉同詠古人詩，新月娟娟照酒巵。',64,'全唐诗/poet.song.89000.json','["夜凉同詠古人詩，新月娟娟照酒巵。", "一醉且忻軍寇退，扁舟似與菊花期。", "銜杯樂聖真吾事，泛宅浮家漫爾爲。", "歸去雲山最深處，隔江千里幸相思。"]'),
('c486d092-1604-446d-984b-73f84d4dbc88','玉華宫用杜子美韻','李綱','宋','宋诗','song-poetry','','[]','阿房但遺基，銅爵亦飄瓦。',96,'全唐诗/poet.song.89000.json','["阿房但遺基，銅爵亦飄瓦。", "兹宫製何朝，棟宇妙天下。", "溪山最清絕，畫手不可寫。", "于今黍離離，客過淚如灑。", "廼知營宫殿，徒以業力假。", "起滅猶浮漚，聚散齊一馬。", "如何世間士，天運欲持把。", "此理貫古今，宜有知之者。"]'),
('774ae320-0a16-4cb2-b5c1-a1d508e127f7','九月八日渡淮','李綱','宋','宋诗','song-poetry','','[]','長淮渺渺煙蒼蒼，扁舟初脫隋渠黄。',160,'全唐诗/poet.song.89000.json','["長淮渺渺煙蒼蒼，扁舟初脫隋渠黄。", "平生見此爲開眼，况復乞身還故鄉。", "嗟余涉世誠已拙，徑步不虞機穽設。", "空餘方寸炳如丹，北望此時心欲折。", "楚天清曉作輕寒，黄蘆着霜聲正乾。", "川迴金碧隱窣堵，風遠鍾磬聞龜山。", "櫓聲嘔軋歸何處，笑指江臯尋舊路。", "松菊荒蕪欲自鉏，盗賊顛翻非所懼。", "蟹螯菊蘂風味遒，且須爲盡黄金舟。", "世間種種如夢電，此物能消萬古愁。"]'),
('54023bcb-c406-4365-9426-8d1a881a9e42','九日與申伯叔易小飲','李綱','宋','宋诗','song-poetry','','[]','上客相從稱玉觴，楚天杳杳湛清光。',64,'全唐诗/poet.song.89000.json','["上客相從稱玉觴，楚天杳杳湛清光。", "紫茱黄菊有佳色，白蟹頳鱗聊共嘗。", "自哂三朝爲逐客，常於九日旅殊方。", "十年往返成何事，贏得蕭蕭滿鬢霜。"]'),
('9a4e63d1-49e5-41ff-8eb4-0d76c33d2710','章華宫用張籍韻','李綱','宋','宋诗','song-poetry','','[]','楚王初建章華時，脩梁巨棟如雲垂。',144,'全唐诗/poet.song.89000.json','["楚王初建章華時，脩梁巨棟如雲垂。", "諸侯共落相長鬛，示汰往往逃而歸。", "當年左史箴王闕，祈招之詩爲之發。", "固宜便嬖意相當，肯使俊乂居周行。", "宫中門户如蓮房，錦茵繡幕春風香。", "娥媌曼睩肌雪霜，侍燕承娛夜未央。", "金石間作侑玉觴，兕觥不復稱公堂。", "志窺九鼎輕天王，翠被豹舄垂瓊璫。", "乾谿之辱豈其壽，峻宇雕牆湎于酒。"]'),
('e888f598-9b70-454e-ac77-9337fd68419d','次韻季弟善權阻雪古風','李綱','宋','宋诗','song-poetry','','[]','歲晏江南三尺雪，奕奕瀌瀌遂連月。',304,'全唐诗/poet.song.89000.json','["歲晏江南三尺雪，奕奕瀌瀌遂連月。", "意濃豈是天綱疏，勢重便疑坤軸折。", "溪行小艇碎瓊瑤，自勝縞带隨車轍。", "暝投蘭若寄僧房，更覺千巖鳥飛絕。", "憶昔宣和全盛年，嘉瑞應期來自天。", "千官朝賀未央裏，仰視龍尾垂蜿蜒。", "珠樹瑩煌青瑣闥，玉花浮動蒼龍闕。", "但將歌舞賞清妍，肯信山河會分裂。", "自從國步多艱難，胡騎長驅窺漢關。", "陰風慘淡隨殺氣，見雪翻使摧心顔。", "古來治理初無别，中國浸强胡浸滅。", "坐令和氣變陽春，肉食于今未宜忽。", "迂愚放逐恩已寛，敢憚道遠貂裘寒。", "空餘炯炯寸心赤，中夜不寐憂千端。", "素髪飄蕭頭已滿，百年光景行將半。", "未知夢幻此生中，幾回看雪光凌亂。", "會當掃動豺狼穴，國恥乘時須一雪。", "酒酣拔劍斫地歌，心膽開張五情熱。", "中興之運我期皇，江漢更灑纍臣血。"]'),
('7e5c8b9e-337b-4a37-9b3f-3b6f930ed33b','善權即事十首  其一','李綱','宋','宋诗','song-poetry','','[]','荆溪移櫂雪漫漫，皓色連空眼界寛。',64,'全唐诗/poet.song.89000.json','["荆溪移櫂雪漫漫，皓色連空眼界寛。", "練带縈迴迷罨畫，玉屏崷崒失銅官。", "風飄珠蘂來玄圃，槎泛銀潢到廣寒。", "安得丹青似摩詰，生綃寫作圖畫看。"]'),
('2e4e7ca1-ffcf-40dc-9ed3-ea8968f4369d','善權即事十首  其二','李綱','宋','宋诗','song-poetry','','[]','十日荆溪雪未晴，敲冰聊作善權行。',64,'全唐诗/poet.song.89000.json','["十日荆溪雪未晴，敲冰聊作善權行。", "最憐擊碎瓊瑤片，欲愛長聞環珮聲。", "百仞巖端仙梵過，千株松下老僧迎。", "斯遊自覺平生少，頗怪淹留景太清。"]'),
('4eda55a5-150b-45d3-b81d-0a685e1154a8','善權即事十首  其三','李綱','宋','宋诗','song-poetry','','[]','雪著谿山澹復濃，行舟疑在玉壺中。',64,'全唐诗/poet.song.89000.json','["雪著谿山澹復濃，行舟疑在玉壺中。", "雲藏半嶺深難見，冰塞長川邈未通。", "賴有僧房容假榻，未應塵跡歎飄蓬。", "勞生夢幻成何事，萬古閑愁一笑空。"]'),
('88df76c7-0af3-4a93-ac50-930b5e5f5abf','善權即事十首  其四','李綱','宋','宋诗','song-poetry','','[]','山崦溪灣三四家，竹籬茅舍暮烟斜。',64,'全唐诗/poet.song.89000.json','["山崦溪灣三四家，竹籬茅舍暮烟斜。", "仙村自種田田玉，梅徑疑開處處花。", "近渚冰銷迷浴鷺，遠村煙暝數栖鴉。", "年年值雪長爲客，對此悽然感歲華。"]'),
('44c888f3-a5ef-47e6-8aea-64bcbd4bbbbb','善權即事十首  其五','李綱','宋','宋诗','song-poetry','','[]','小童又報雪花飛，深炷鑪煙欲起時。',64,'全唐诗/poet.song.89000.json','["小童又報雪花飛，深炷鑪煙欲起時。", "淅瀝乍聞經竹葉，飄蕭初看著松枝。", "南人共訝何曾見，北顧深顰有所思。", "牢落無言自搔首，却驚華髪頓成絲。"]'),
('3d4d23eb-ea8d-4c6d-93b7-a5970fd2053b','善權即事十首  其六','李綱','宋','宋诗','song-poetry','','[]','一夜凝寒雪意濃，禪房睡美不聞鍾。',64,'全唐诗/poet.song.89000.json','["一夜凝寒雪意濃，禪房睡美不聞鍾。", "起看銀色三千界，更憶瑤臺十二重。", "戴白蒼官尤覺好，折腰青士若爲容。", "暮晴透出寒蟾色，爲照溪頭羣玉峰。"]'),
('e7f4f8a0-520e-4d0f-bff2-7127c9e66530','善權即事十首  其七','李綱','宋','宋诗','song-poetry','','[]','連日風雲匝地陰，玉花飛舞滿煙岑。',64,'全唐诗/poet.song.89000.json','["連日風雲匝地陰，玉花飛舞滿煙岑。", "竹窗夜色碁方適，書幌朝寒酒倍斟。", "幸有髙人同勝賞，不妨佳處得幽尋。", "庭前暗積知多少，自策笻枝探淺深。"]'),
('4e933f29-fecd-4c98-b76b-e7de76660fb1','善權即事十首  其八','李綱','宋','宋诗','song-poetry','','[]','山空鳥雀傍簷楹，景邃惟聞鐘鼓聲。',64,'全唐诗/poet.song.89000.json','["山空鳥雀傍簷楹，景邃惟聞鐘鼓聲。", "懶瓚但知煨紫芋，少陵何處斸黄精。", "江南寇盗休無賴，塞北煙塵迄未平。", "太息浮生端值此，不如無念契無生。"]'),
('ef82976b-de08-433a-bf89-27a7156e0a58','善權即事十首  其九','李綱','宋','宋诗','song-poetry','','[]','霽色初開雪未融，坐來風撼落長松。',64,'全唐诗/poet.song.89000.json','["霽色初開雪未融，坐來風撼落長松。", "林芿趫捷緣饑鼠，洞壑深沉蟄老龍。", "致遠未須金騕褭，憑髙且看玉芙蓉。", "豐年最有田家樂，雪屋何妨入夜舂。"]'),
('62e610df-3b8c-44c1-b1a4-71878fac00ac','善權即事十首  其一○','李綱','宋','宋诗','song-poetry','','[]','朝來鳥雀報新晴，乍喜窗間日影明。',64,'全唐诗/poet.song.89000.json','["朝來鳥雀報新晴，乍喜窗間日影明。", "糝徑楊花渾寂寞，倚簷冰柱漫峥嶸。", "早梅向暖垂垂發，好鳥知時得得鳴。", "從此陽光漸舒暢，放回春色滿江城。"]'),
('46bf3189-ffd7-41c7-8c56-73d202df7f3d','投金瀨有感','李綱','宋','宋诗','song-poetry','','[]','楚王聽讒誅五卿，招呼二子同就烹。',176,'全唐诗/poet.song.89000.json','["楚王聽讒誅五卿，招呼二子同就烹。", "子胥彎弓見使者，義不戴天非惜生。", "操瓢乞食困江表，曷嘗一日忘郢城。", "溧水之陽遇真識，壺漿簞食欣相迎。", "當時追捕尚爾急，殺身滅口意豈輕。", "霸吳何止服句踐，破楚遂以鞭荆平。", "倒行逆施道雖遠，復仇攄憤聖所稱。", "却來訪舊欲報德，歎息玉質隨流萍。", "投金淺瀨亦何有，聊以寓意通精誠。", "哀窮進食類漂母，解劍掛墓同延陵。", "古人已矣不可見，空有史筆垂聲名。"]'),
('4a3f1067-4ef7-4ae4-83e8-616d7fde02d7','題成士瑴所藏輞川雪圖','李綱','宋','宋诗','song-poetry','','[]','朔風飛雪何漫漫，羣山大半埋雲端。',176,'全唐诗/poet.song.89000.json','["朔風飛雪何漫漫，羣山大半埋雲端。", "藍田丘壑不易得，更把雲雪粧林巒。", "茅齋竹屋架巖巘，軒楹面勢隨所安。", "素華淅瀝灑空翠，逼耳似聞聲正乾。", "層崖凍沍石欲裂，飛瀑不礙雙流湍。", "長松落落有生意，連臂下飲惟玄猿。", "椒園柳浪眇安在，髣髴猶認芙蓉沜。", "乘危跨蹇者誰子，竦肩縮袖何其寒。", "祇應詩句獨有得，不减灞橋風雪間。", "幽人一去久寂寞，寒藤滋蔓誰能刪。", "生綃數幅寫絕景，空有圖畫今人看。"]'),
('f6d4e13a-1452-47c2-b95a-56f4e0524ba4','次季弟韻賦梅花三首  其一','李綱','宋','宋诗','song-poetry','','[]','冷蘂疏枝煙水濱，江南此地又逢春。',64,'全唐诗/poet.song.89000.json','["冷蘂疏枝煙水濱，江南此地又逢春。", "年年行路常爲客，的的寒花解笑人。", "雪裏暗香來鼻觀，風前髙格見天真。", "誰言對爾銷愁得，一段清愁特地新。"]'),
('96891f6c-5243-4514-9869-ad23250ea4cc','次季弟韻賦梅花三首  其二','李綱','宋','宋诗','song-poetry','','[]','年年青女久橫陳，賴有江梅漏洩春。',64,'全唐诗/poet.song.89000.json','["年年青女久橫陳，賴有江梅漏洩春。", "孤潔如親隱君子，風流似對謫仙人。", "雅期蘭蕙香非遠，解笑松華色未真。", "開罷枝頭著青實，故教桃李一番新。"]'),
('6da099b5-5fb6-46a1-be27-2089b385b340','次季弟韻賦梅花三首  其三','李綱','宋','宋诗','song-poetry','','[]','羣芳凍死未招魂，誰使梅花獨占春。',64,'全唐诗/poet.song.89000.json','["羣芳凍死未招魂，誰使梅花獨占春。", "願折繁華憑驛使，爲傳幽思惱詩人。", "心馳魏闕慚商鼎，路入章江憶子真。", "莫道廣平心似鐵，賦辭得得與清新。"]'),
('351d3863-b530-4479-a8f6-98cc83c7f133','宿黄柏村館','李綱','宋','宋诗','song-poetry','','[]','客館可人意，敢懷行路勞。',48,'全唐诗/poet.song.89000.json','["客館可人意，敢懷行路勞。", "軒窗面蒼翠，棋酒助嬉遨。", "雨過竹聲碎，風搖雲影髙。", "人生隨處適，何必賦離騷。"]'),
('65695bf8-98ed-4a6a-ae11-b8200337ac4e','寓寧國縣圃中桃李雜花盛開感而賦詩  其一','李綱','宋','宋诗','song-poetry','','[]','春光不爲干戈薄，花縣縱觀桃李開。',64,'全唐诗/poet.song.89000.json','["春光不爲干戈薄，花縣縱觀桃李開。", "可惜繁華勞剪刻，莫教風雨便殘摧。", "溪山有意相輝映，蜂蝶多情自往來。", "應笑逐臣心似鐵，客中扶病亦登臺。"]'),
('2d449272-474d-4305-980c-c5783fc68d44','寓寧國縣圃中桃李雜花盛開感而賦詩  其二','李綱','宋','宋诗','song-poetry','','[]','乍雨乍晴三月節，半開半合百花枝。',64,'全唐诗/poet.song.89000.json','["乍雨乍晴三月節，半開半合百花枝。", "傷心春望不堪遠，感事淚痕長欲垂。", "塞北但知隨水草，江南何事插旌麾。", "上林無限鶯花老，應怪來遊鳳輦遲。"]'),
('770c84e6-b742-460e-9ce6-a3ec357e3666','詠草','李綱','宋','宋诗','song-poetry','','[]','夢覺池塘碧草萋，風搖煙濕已菲菲。',64,'全唐诗/poet.song.89000.json','["夢覺池塘碧草萋，風搖煙濕已菲菲。", "綿聯山色不知遠，惆悵王孫何日歸。", "微質亦知煩雨露，寸心終欲報春暉。", "芳根縱腐猶能化，舞蝶流鶯到處飛。"]'),
('d478c2d0-6d93-4cc7-81f1-f33e66d0776c','休寧縣驛舍初見楊花','李綱','宋','宋诗','song-poetry','','[]','山館風光隨分好，方塘碧長萋萋草。',32,'全唐诗/poet.song.89000.json','["山館風光隨分好，方塘碧長萋萋草。", "楊花搖蕩入疏簾，又是一年春色老。"]'),
('80aef76b-8fc5-4ff6-9778-cdc82293e068','黟歙道中士人獻牡丹千葉面有盈尺者爲賦此詩','李綱','宋','宋诗','song-poetry','','[]','平生愛花被花惱，每見牡丹常絕倒。',160,'全唐诗/poet.song.89000.json','["平生愛花被花惱，每見牡丹常絕倒。", "自從喪亂减風情，兩年不識花枝好。", "邇來謫墮烟雨中，行色日與春光濃。", "今夕何夕見粲者，頗類壽安千葉紅。", "豈知黟歙深山裏，乃有此花端若此。", "不論玉板與鶴鴒，可亞姚黄并魏紫。", "嫣然見我如感傷，似訴處此非其鄉。", "吾衰多病不解飲，對爾歎息空持觴。", "人言老境花如夢，獻此慇懃情已重。", "蠟封瓶貯可多時，惆悵洛陽今不貢。"]'),
('b1ed9542-5f86-4787-ad2c-a7c1729b25a0','自鄱陽泛江至星子','李綱','宋','宋诗','song-poetry','','[]','我行黟歙間，山隴如黏蠔。',204,'全唐诗/poet.song.89000.json','["我行黟歙間，山隴如黏蠔。", "澗水互縈繞，路石何墝嶅。", "深谷四無景，峻嶺干雲霄。", "朝行嵐氣合，暮宿怪禽號。", "吾雖一險夷，無乃徒御勞。", "及兹夏潦漲，弭節俯江臯。", "試命具舟檝，聊以釋煩囂。", "巨浸與天永，東流日滔滔。", "來檣與去櫂，倐忽馳千艘。", "進舟枕席間，舟子巧所操。", "江山遞隱見，景物資遊遨。", "頗同謫仙人，醉著宫錦袍。", "長嘯倚柁樓，軒然詠離騷。", "心隨八極遠，身逐秋鴻髙。", "風帆擘巨浪，大櫓駕雲濤。", "百里須臾間，千里不崇朝。", "快哉可以賀，把酒持蟹螯。"]'),
('98f5af21-4739-4463-89e6-728a39990cb6','彭蠡','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','神禹治水江爲最，邐迤逶蛇鍾作滙。',192,'全唐诗/poet.song.89000.json','["神禹治水江爲最，邐迤逶蛇鍾作滙。", "泓澄不獨陽鳥居，浩蕩端使羣川會。", "羣川已會江不湍，朝宗到海東南安。", "烟收雲歛望不盡，眼界始知天宇寛。", "世傳揚瀾并左蠡，無風白浪如山起。", "我今謫官此中行，何事恬然風浪止。", "陽侯也自可憐生，不學世人皆世情。", "好風已借一帆便，霽色更增雙眼明。", "晚來畫舸鳴六櫓，超忽千山如脫兔。", "波心突兀見星宫，雲際峥嶸望廬阜。", "世間此景良不多，洞庭三峽真么麽。", "共浮大白期一醉，對此不飲當如何。"]'),
('f63ef9e4-021a-4a8d-9d8e-7e24b875e218','遊落星寺','李綱','宋','宋诗','song-poetry','','[]','一氣升沉誰所肇，隕星爲石古不少。',160,'全唐诗/poet.song.89000.json','["一氣升沉誰所肇，隕星爲石古不少。", "羣川會處渺無涯，墜此精堅鎮江表。", "坐令釋子開梵宫，棟宇規摹浮玉小。", "窈窕樓臺四面通，洶湧波濤千柱㒟。", "我來端是好幽奇，一葉飄然陵漭渺。", "初疑牛女在銀潢，更訝靈槎經畢昴。", "星房月殿夜沉沉，水色天容秋杳杳。", "恍如清夢到天門，欲駕颷輪憇蓬島。", "塵世喧囂那易得，幻境去來何日了。", "心閒境寂付幽人，衲被蒙頭任昏曉。"]'),
('8fcd5d0c-027e-4a27-998a-5e49e38254f3','望廬山','李綱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','多年不省廬山面，江上初從望中見。',128,'全唐诗/poet.song.89000.json','["多年不省廬山面，江上初從望中見。", "秀骨蒼顔五老人，顧我欣然如素善。", "香爐峰頂紫烟浮，瀑布遥看銀漢流。", "雲舒霞卷互明滅，倐忽變態無停留。", "却疑清夢尋丘壑，風物何爲宛如昨。", "縱令真是夢中看，夢未覺時良不惡。", "平生所願今乃償，寛著日月遊山房。", "青鞋布襪久已辦，百錢掛杖聊徜徉。"]'),
('3cd72f5d-9e0a-4958-85bc-aeb06807d90b','韓德全以小舟相迓於落星寺下','李綱','宋','宋诗','song-poetry','','[]','故人一别兩寒暑，鴈斷魚沉杳何所。',64,'全唐诗/poet.song.89000.json','["故人一别兩寒暑，鴈斷魚沉杳何所。", "那知迎我落星傍，一葉凌波聽掀舞。", "胸中耿耿初自若，身世悠悠乃如許。", "且須酌酒澆肺肝，慎勿開口論今古。"]'),
('ff64610d-8ea1-47b6-9562-d00c9bec51d8','晚出南康遊廬山','李綱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','捨舟星子渚，遂作廬山遊。',144,'全唐诗/poet.song.89000.json','["捨舟星子渚，遂作廬山遊。", "空濛杳靄間，十里松桂秋。", "草木吐香潤，泉石交横流。", "乃知山中物，一一皆其尤。", "嵐逼空翠濕，峰髙紫烟浮。", "心閑雲出嶺，眼浄龍還湫。", "月壑夜窈窕，風林晚颼飀。", "稍聞鐘磬聲，迥覺梵宇幽。", "平昔念清賞，孰云今乃酬。", "似非人間境，須向物外求。", "顧揖雖不暇，吟哦浩難收。", "聊將詩紀行，一洗他年愁。"]'),
('dd9a8de3-1ffb-40a0-a776-c5ef56329b9b','過玉澗道人草堂','李綱','宋','宋诗','song-poetry','','[]','道人妙彈琴，能作醉翁操。',72,'全唐诗/poet.song.89000.json','["道人妙彈琴，能作醉翁操。", "人亡琴亦亡，頗爲識者悼。", "草堂玉澗邊，蕪沒已秋草。", "繐帳鶴驚空，藥杵香餘搗。", "竹光浄如洗，桂子寒不掃。", "松風肅泠泠，猶想琴聲好。"]'),
('3ac2624a-33d3-4d45-a932-9a5b1b6636c0','五老峰','李綱','宋','宋诗','song-poetry','','[]','五峰秀出如五老，鬚髪蒼然長美好。',128,'全唐诗/poet.song.89000.json','["五峰秀出如五老，鬚髪蒼然長美好。", "問之不肯道姓字，儼若子房從四皓。", "商山採芝亦已久，漢庭辟穀何其早。", "優游相與定儲皇，攜手江湖共幽討。", "化爲峰石寄山巔，下視塵寰真電掃。", "衣冠想像猶偉然，容貌至今初不槁。", "祗應明月見當時，間有白雲來問道。", "逝將築室近峰前，歲晚相依得相保。"]'),
('e3d9049f-b2ff-4d90-a126-d297729e8585','羅漢寺','李綱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','梵宫臺殿古，松桂碧參天。',48,'全唐诗/poet.song.89000.json','["梵宫臺殿古，松桂碧參天。", "玉澗碎寒石，金池開小蓮。", "循渠窮水脉，策杖到巖巔。", "漸入廬山境，從參五味禪。"]'),
('1b175410-9c31-44ef-9494-cccd66f05856','自羅漢院欲遊尋真觀雨作不果遂次栖賢聞尋真景物尤美留爲異日不窮之賞賦詩紀之','李綱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','羽人之宫鄰五老，杖屨欣然事幽討。',160,'全唐诗/poet.song.89000.json','["羽人之宫鄰五老，杖屨欣然事幽討。", "那知一夜雨翻盆，山路難行愁滑倒。", "世間違意常八九，萬事皆然寧自保。", "山靈豈是祕幽奇，欲結清歡故相惱。", "傳聞景物冠廬山，小殿飛樓更精巧。", "古潭搖蕩明月光，綠蘿青松覆煙草。", "屏風九疊雲錦張，古來詩句謫仙好。", "山中道士不出門，玉杵金丹手親搗。", "我方放浪謝冠裳，未覺山林跡如掃。", "真遊儻有不盡緣，容我他年來訪道。"]'),
('0572d274-f009-4b9e-878e-c5396c8a30fe','栖雲庵','李綱','宋','宋诗','song-poetry','','[]','禪老幽棲地，雲峰尺五天。',48,'全唐诗/poet.song.89000.json','["禪老幽棲地，雲峰尺五天。", "江湖縈縞带，世界廓青蓮。", "說法三乘外，藏身萬象巔。", "潛虬蟠不去，應聽祖師禪。"]'),
('5abc000b-59b4-424d-aef0-b8665e9e9d58','三峽橋','李綱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我昔曾作雲安行，道逢除書還玉京。',224,'全唐诗/poet.song.89000.json','["我昔曾作雲安行，道逢除書還玉京。", "至今遺恨不一到，與聽三峽流泉聲。", "此來又謫武昌去，廬山當道欣所經。", "栖賢寺前小三峽，拭目便覺增雙明。", "黄牛明月坐中見，瞿塘艷澦森相迎。", "山寒草木鬱葱蒨，逼耳似聞猿狖鳴。", "懸崖亂石互迴轉，震吼正坐不得平。", "珠跳雲沸巧潨射，晴晝雨雹驅雷霆。", "壯哉造化融結此，故使水石相喧轟。", "妙音流出無盡藏，乃與衲子門庭争。", "飛橋贔屓跨虚碧，面對五老峰峥嶸。", "我來雲物爲開霽，當暑萬壑松風生。", "提攜更得二三子，杖履不辜丘壑情。", "垂瓶得水不敢潄，老坡舊約今尋盟。"]'),
('b3b0edd0-1612-4a77-9e98-fc24fa22156a','萬杉寺散珠亭','李綱','宋','宋诗','song-poetry','','[]','一派飛泉落坐隅，跳波沸石散成珠。',32,'全唐诗/poet.song.89000.json','["一派飛泉落坐隅，跳波沸石散成珠。", "道人諦看空濛際，顆顆圓明定有無。"]'),
('33f5348a-2b3b-4d95-b145-fd10e4929b82','諸刹皆以石渠道水有至十餘里者感之賦詩','李綱','宋','宋诗','song-poetry','','[]','廬阜秀江南，凝結盡雲母。',156,'全唐诗/poet.song.89000.json','["廬阜秀江南，凝結盡雲母。", "泉源乃雲腴，甘冽固其所。", "懸爲瀑布垂，蹙作龍鸞舞。", "交流澗谷中，厥味皆鍾乳。", "僧坊有能事，致遠勞汲取。", "鑿石爲通渠，計里不計步。", "回環繞山麓，髙下映簷廡。", "蜿蜿虹腰轉，溜溜螭頭吐。", "沛然飲濯餘，灌溉及園圃。", "誰將創物智，作此濟衆祖。", "暫勞逸則永，心一力乃舉。", "豈惟小物然，萬事盡如許。", "吾道何其衰，寤寐慨思古。"]'),
('54f16353-52a9-4c07-8a92-77f99cb512da','谷簾泉','李綱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','甘泉多自名山出，世品谷簾爲第一。',240,'全唐诗/poet.song.89000.json','["甘泉多自名山出，世品谷簾爲第一。", "淄澠之水不易辨，臆說詎敢評得失。", "廬山深處爲谷簾，度嶺穿雲費時日。", "道人裹飯時一到，敲火烹茶資野逸。", "坐令僕隸致瓶甖，是非誠否良難詰。", "世間知味定何人，食蔗多謂甜於蜜。", "居然真僞相混殽，往往循名因去實。", "何似家山陸子泉，石縫迸出蒼龍淵。", "山中空洞乳滿腹，一派下作梁谿源。", "清甘著舌久不散，持以瀹茗增芳妍。", "華堂石甃與覆護，好事汲取肩相駢。", "有時置酒飲其上，醉滌肺腑塵煩蠲。", "緘題寄遠無僞者，貴賤均飲初不偏。", "彼如幽人在空谷，此若佳客臨風前。", "未須細較味優劣，且問所處誰爲賢。"]'),
('c8716331-9d1c-45d9-b7ae-35779c3fe002','余幼嘗一到廬山再遊已三十年矣感懷二首  其一','李綱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','夢想廬山三十秋，却因謫宦得重遊。',64,'全唐诗/poet.song.89000.json','["夢想廬山三十秋，却因謫宦得重遊。", "禪林處處逢清賞，山路人人識故侯。", "絕嶺半將雲幕覆，飛泉長作玉虹流。", "平生丘壑真吾志，一洗胸中萬斛愁。"]'),
('1dfd364f-6874-476f-9b02-a9c08410ee13','余幼嘗一到廬山再遊已三十年矣感懷二首  其二','李綱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','香爐峰頂紫煙凝，三峽橋邊雪浪驚。',64,'全唐诗/poet.song.89000.json','["香爐峰頂紫煙凝，三峽橋邊雪浪驚。", "不爲迂疏成遠謫，豈能蕭散箇中行。", "雲霞映带松蘿色，殿閣深嚴鍾磬聲。", "回首世緣真夢幻，故應長此寄浮生。"]'),
('f2a9c0dd-54fc-4b20-96ef-a6da521716c5','開先寺漱玉亭','李綱','宋','宋诗','song-poetry','','[]','未遊潄玉亭，先誦東坡詩。',136,'全唐诗/poet.song.89000.json','["未遊潄玉亭，先誦東坡詩。", "手持芙蕖跳下清泠中，疑非謫仙不能爲此詞。", "後翁三十年，我亦遊於斯。", "飛橋已堙沒，故跡多推移。", "空餘髙巖與深谷，落日慘淡松風吹。", "白龍依舊出青峽，散沫下作清漣漪。", "古來陵谷會遷變，况乃景物資人爲。", "雲間灩灩吐寒月，清光不減翁當時。", "相望一世發孤笑，坐使萬古生長悲。"]'),
('9229ded4-efc9-43bd-a1d2-07c74653b376','瀑布','李綱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我昔遊太華，矯首望仙掌。',132,'全唐诗/poet.song.89000.json','["我昔遊太華，矯首望仙掌。", "瀑布如懸河，斗落五千丈。", "空濛雨雹飛，澒洞巖壑響。", "及觀廬山瀑，未覺快清賞。", "飛泉出山腰，半派隱層嶂。", "沈吟謫仙詞，其或過所奬。", "傳聞山之巔，峰岫列屏障。", "銀河落九天，噴薄殊異狀。", "倒掛三石梁，無乃在此上。", "逝將隨羽人，裹足一同往。", "懷哉不可得，空積青霞想。"]'),
('fe80519a-89e1-43b4-a102-6813a8b785fd','簡寂觀','李綱','宋','宋诗','song-poetry','','[]','髙士不可見，雲鄉空舊居。',48,'全唐诗/poet.song.89000.json','["髙士不可見，雲鄉空舊居。", "煙嵐飛瀑外，露石禮星餘。", "松老未歸鶴，沼深清見魚。", "何人得丹訣，應有枕中書。"]'),
('7bc5402c-b125-434a-a426-e3e8a8363cec','歸宗寺四詠  其一','李綱','宋','宋诗','song-poetry','','[]','孤峰秀拔翠嶤岧，峰頂虚無是紫霄。',32,'全唐诗/poet.song.89000.json','["孤峰秀拔翠嶤岧，峰頂虚無是紫霄。", "從此上賓朝帝所，直須穏跨玉龍腰。"]'),
('ffbe5c06-2c83-4313-92c1-9e0e164226a1','歸宗寺四詠  其二','李綱','宋','宋诗','song-poetry','','[]','溪流宛轉若翔鸞，翠色涵虛特地寒。',32,'全唐诗/poet.song.89000.json','["溪流宛轉若翔鸞，翠色涵虛特地寒。", "底事舞餘窺碧沼，袛應誤作鏡中看。"]'),
('83c813a4-c1d2-474f-ba39-235aa3b5779b','歸宗寺四詠  其三','李綱','宋','宋诗','song-poetry','','[]','右軍真是墨中仙，到處成池豈盡然。',32,'全唐诗/poet.song.89000.json','["右軍真是墨中仙，到處成池豈盡然。", "祗有此間疑可信，白雲書法至今傳。"]'),
('d147925b-9b5f-4aaf-b054-bfceff4a023d','歸宗寺四詠  其四','李綱','宋','宋诗','song-poetry','','[]','光射蒼巖石鏡屏，我來一現豈無情。',32,'全唐诗/poet.song.89000.json','["光射蒼巖石鏡屏，我來一現豈無情。", "誰云顯晦知時節，長伴空山寒月明。"]'),
('34c244e3-35b3-47c7-87af-912a63ecc8a9','偶成','李綱','宋','宋诗','song-poetry','','[]','洞霄吏上紫霄峰，潄玉亭遊玉局翁。',64,'全唐诗/poet.song.89000.json','["洞霄吏上紫霄峰，潄玉亭遊玉局翁。", "人物風流何可並，山林趣舍略相同。", "是非論定千年後，身世塵勞一夢中。", "我是騎鯨謫仙裔，赤鯶相逐御清風。"]'),
('387c42e7-78cd-41d1-b4f4-ac1241f50b90','靈湯','李綱','宋','宋诗','song-poetry','','[]','石甃靈湯列道周，玉池金屋未相侔。',32,'全唐诗/poet.song.89000.json','["石甃靈湯列道周，玉池金屋未相侔。", "滌塵時有幽人到，不與驪山共一流。"]'),
('8c92c55d-7894-4e34-9d17-b21c04042b3a','客言廬山往年之盛今不逮遠矣戲成此詩','李綱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','福地禪林海內無，盛衰亦與世緣俱。',64,'全唐诗/poet.song.89000.json','["福地禪林海內無，盛衰亦與世緣俱。", "祗應泉石不知老，長伴煙雲得自娛。", "種杏仙家今寂寞，獻花衲子亦乾枯。", "我生頗恨來遊晚，也勝不來空看圖。"]'),
('52b6b580-4c23-4318-b6b3-ed0998e10cc9','圓通寺與覺老步月','李綱','宋','宋诗','song-poetry','','[]','石耳峰前松檜香，月華天影夜茫茫。',32,'全唐诗/poet.song.89000.json','["石耳峰前松檜香，月華天影夜茫茫。", "道人試道依溪水，何似曹溪一派長。"]'),
('6162ee81-927a-49c8-a12b-886edf8922f1','諸刹以水激磑磨殊可觀爲賦此詩','李綱','宋','宋诗','song-poetry','','[]','疊石壅寒派，湍流瀉逥溪。',96,'全唐诗/poet.song.89000.json','["疊石壅寒派，湍流瀉逥溪。", "誰將方便智，成此妙圓機。", "輪輻互髙下，波濤鬱翻飛。", "磨牙遞旋斡，磑杵紛昂低。", "玉粒已粲粲，瓊花亦霏霏。", "雖存機械巧，利澤成慱施。", "試語漢陰老，使知渾沌非。", "惟當善用心，功與天地齊。"]'),
('740eda78-c19c-4b68-80cd-0dccd25c2ad7','子弟輩遊天池余以病不果往','李綱','宋','宋诗','song-poetry','','[]','雲山積翠倚穹蒼，仙聖靈蹤寫上方。',64,'全唐诗/poet.song.89000.json','["雲山積翠倚穹蒼，仙聖靈蹤寫上方。", "瑞像世傳藏錦繡，神光人說似清涼。", "心安是處皆歡喜，眼正無時非吉祥。", "我病未能尋勝境，慇懃爲爇一爐香。"]'),
('84d7b630-0a2e-4672-8514-fadd0637071b','戲贈東林珪老','李綱','宋','宋诗','song-poetry','','[]','我遊廬阜南山北，師住二林東院西。',64,'全唐诗/poet.song.89000.json','["我遊廬阜南山北，師住二林東院西。", "試問遠公求作佛，何如陶令醉如泥。", "苦邀名山同蓮社，笑送幽人過虎溪。", "千載風流久寥落，更煩拈出與提撕。"]'),
('51da2f76-787a-423b-bdeb-6d88ada6fa26','西林寺','李綱','宋','宋诗','song-poetry','','[]','東林大禪苑，殿閣傑以雄。',96,'全唐诗/poet.song.89000.json','["東林大禪苑，殿閣傑以雄。", "西林乃律居，僧房小玲瓏。", "泉流庭廡間，宛轉如鸞龍。", "花竹深窈窕，松蘿鬱青葱。", "縱觀魯公書，遠揖峭直風。", "餘碑雖崢嶸，一掃凡馬空。", "安得數椽地，介居二林中。", "當有遠公流，策杖時相從。"]'),
('01cf0ef4-1f65-4096-a208-759e84cf649b','道出廬阜偶值崧老右丞同遊東西二林蒙示佳篇輒次來韻','李綱','宋','宋诗','song-poetry','','[]','迂疏又復謫南州，假道江山得勝遊。',64,'全唐诗/poet.song.89000.json','["迂疏又復謫南州，假道江山得勝遊。", "杖履欣逢長者轍，笑談同訪遠公流。", "風搖杉檜驚寒夢，煙鎖峰嵐繞翠樓。", "回首中原意蕭瑟，此生飄泊任雲浮。"]'),
('44b646ff-f1a1-4d9b-8bc3-999164da3a32','太平觀道士植瑞香於簷廡間可愛頗恨不及其花時爲賦小詩','李綱','宋','宋诗','song-poetry','','[]','道人心境閑，種花白雲鄉。',120,'全唐诗/poet.song.89000.json','["道人心境閑，種花白雲鄉。", "交柯碧珊瑚，薿薿衆葉光。", "弱質資灌溉，孤根怯清霜。", "治畦簷廡間，晏温借朝陽。", "我來恨太晚，不見花吐房。", "想像正開時，淡紫兼微黄。", "濯濯炫秀色，霏霏㒟天香。", "空餘風露枝，璀璨繞逥廊。", "地靈草木潤，長與蘭蕙芳。", "明年花更好，矯首遥相望。"]'),
('3fea1044-9c02-49e0-a794-71e2b6937248','白公草堂','李綱','宋','宋诗','song-poetry','','[]','樂天平生不可及，謫官乃作廬中集。',64,'全唐诗/poet.song.89000.json','["樂天平生不可及，謫官乃作廬中集。", "香爐峰下結草堂，石屏紙帳隨時給。", "維摩丈室亦何有，天女散花空結習。", "何須江上聽琵琶，泫然淚滴青衫濕。"]'),
('d2b871c1-d17f-4177-b87b-7594948ec388','琵琶亭','李綱','宋','宋诗','song-poetry','','[]','去年假道潯陽城，扁舟夜泊琵琶亭。',128,'全唐诗/poet.song.89000.json','["去年假道潯陽城，扁舟夜泊琵琶亭。", "却憶當時醉司馬，送客江頭秋月明。", "今年謫官又重到，掃地乃緣蜂寇經。", "軒楹回首已不見，况欲更聞絃索鳴。", "西風蕭蕭蘆葦響，月色下照江波清。", "秪應風月長不老，坐閲塵世猶流萍。", "我生多病苦憂患，未能忘世那忘情。", "移船相近夜悄悄，側聽疑有檀槽聲。"]'),
('61729be3-e55b-41cf-bdc6-892ba19e7c7e','過淵明故居','李綱','宋','宋诗','song-poetry','','[]','捨櫂湓浦城，稅駕柴桑里。',132,'全唐诗/poet.song.89000.json','["捨櫂湓浦城，稅駕柴桑里。", "緬懷靖節翁，衡宇兹避世。", "乞食雖甚貧，折腰肯爲米。", "陶然傲羲皇，獨得醉中意。", "三徑不願餘，五斗聊自誄。", "優游晉宋間，俯仰無可愧。", "若人骨已朽，凛凛有生氣。", "斜川尚環流，層城亦秀峙。", "如何髙世士，廟貌乃頽圮。", "誰將一觴酒，薦此菊與杞。", "朗詠歸來辭，感嘆成坐起。"]'),
('8c026029-8f26-42e8-b15d-bda93b95f264','德安食枇杷','李綱','宋','宋诗','song-poetry','','[]','故人餉盧橘，煙雨江上村。',48,'全唐诗/poet.song.89000.json','["故人餉盧橘，煙雨江上村。", "芳津流齒頰，核細肌豐温。", "誰爲黄金彈，偏宜白玉樽。", "返源旋味處，寂寞自無言。"]'),
('b5ada413-5f2e-425b-9fa7-866e25423939','雲居勤老以書見邀不果往戲作此頌寄之','李綱','宋','宋诗','song-poetry','','[]','吾師脱浮玉，振錫來雲居。',80,'全唐诗/poet.song.89000.json','["吾師脱浮玉，振錫來雲居。", "江邊波浪已遠去，山頂風雷應晏如。", "我來問津師草草，咫尺雲岑悵難到。", "師既拗折柱杖不出山，我亦把定韁繩不下道。", "試將此意示叢林，撫掌呵呵同絕倒。"]'),
('38fbb9d5-1c05-4dfd-b8d0-aad27fe037d1','午暑憩潭田精舍老僧求詢其曾遊方否云以少嘗一到分甯感而賦此','李綱','宋','宋诗','song-poetry','','[]','修江深寂處，蘭若寄高邱。',48,'全唐诗/poet.song.89000.json','["修江深寂處，蘭若寄高邱。", "松竹有古意，雲山無世愁。", "老僧頭已白，鄰邑幼曾遊。", "自哂何爲者，半生踰百州。"]'),
('b8bc7336-28f3-4c3b-ab2d-db1ac816668a','聞子規','李綱','宋','宋诗','song-poetry','','[]','江南四月五月時，空山月夜啼子規。',64,'全唐诗/poet.song.89000.json','["江南四月五月時，空山月夜啼子規。", "勸我不如歸去好，我方遠謫何時歸。", "中原杳杳暗鋒鏑，縱使得歸何所益。", "不如且住碧山中，爲憑青鳥通消息。"]'),
('148a4c7c-3850-4635-b602-8a39bf771cd7','戲賦墨畫梅花','李綱','宋','宋诗','song-poetry','','[]','道人畫手真三昩，力挽春風與遊戲。',160,'全唐诗/poet.song.89000.json','["道人畫手真三昩，力挽春風與遊戲。", "露枝煙蘂忽嫣然，自得工夫畦徑外。", "由來黑白無定姿，濃淡間錯相參差。", "炯如落月耿寒影，翳若宿霧含疏枝。", "羣芳種種徒繁縟，脫略丹青尤拔俗。", "妙質聊資陳氏煤，幽姿好伴文生竹。", "世呼墨竹爲墨君，此花宜稱墨夫人。", "鉛華不御有餘態，世間顔色皆非真。", "年來妙觀齊空色，天花時露真消息。", "試煩幻出數千枝，不費梁谿一丸墨。"]'),
('1e3f6983-451c-4aab-9fa1-c64b3c162436','兜率寺','李綱','宋','宋诗','song-poetry','','[]','隨意寓禪房，小軒風露凉。',48,'全唐诗/poet.song.89000.json','["隨意寓禪房，小軒風露凉。", "山幽雲傍户，林迥月窺牀。", "竹色曉增翠，桂花秋欲香。", "無人知此意，天影碧茫茫。"]'),
('a6179289-0ec9-4b96-9ae8-be774e95e374','玉溪寺','李綱','宋','宋诗','song-poetry','','[]','玉溪何日寺，古佛亦塵埃。',48,'全唐诗/poet.song.89000.json','["玉溪何日寺，古佛亦塵埃。", "髙閣雲初卷，小池蓮半開。", "竹風清枕簟，松露滴莓苔。", "寂寞溪邊路，幽人自往來。"]'),
('d2c18401-715f-4262-b457-770eecbfbe86','過苦竹嶺二首  其一','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','絕嶺横鳥道，江湖從此分。',48,'全唐诗/poet.song.89000.json','["絕嶺横鳥道，江湖從此分。", "沈吟洞庭野，悵望具區雲。", "去住本非我，别離空念羣。", "子歸啼苦竹，腸斷不堪聞。"]'),
('97a71547-b2ed-4c8c-bfe8-379c805d4fe2','過苦竹嶺二首  其二','李綱','宋','宋诗','song-poetry','','[]','今日江湖境，雙眸嶺上明。',48,'全唐诗/poet.song.89000.json','["今日江湖境，雙眸嶺上明。", "山光隨地好，秋氣逼人清。", "隴水初分處，雲鴻欲别情。", "離羣古來有，嘆息未休兵。"]'),
('6e42accf-4a47-4024-bc14-b8383bd4c070','次通城送季言弟還錫山二首  其一','李綱','宋','宋诗','song-poetry','','[]','半載相從作遠遊，物華苒苒又新秋。',64,'全唐诗/poet.song.89000.json','["半載相從作遠遊，物華苒苒又新秋。", "江南山水共清賞，湖外風煙成獨留。", "家遠爲傳安稳信，時艱增重别離憂。", "渚宫此去無他地，悵望自登黄鶴樓。"]'),
('b0db7eab-6efe-4870-b3df-74c53c202d94','次通城送季言弟還錫山二首  其二','李綱','宋','宋诗','song-poetry','','[]','陸離長佩切雲冠，澤畔行吟且紉蘭。',64,'全唐诗/poet.song.89000.json','["陸離長佩切雲冠，澤畔行吟且紉蘭。", "我已安心爲逐客，子今何事亦抛官。", "江湖鴻鴈初寥落，風雪鶺鴒相急難。", "歸去家山見諸季，爲言努力且加餐。"]'),
('121585a3-f5e8-498d-9a26-7fd429510551','季言送余至湖外欲往無爲挈其姊旅櫬歸錫山憫其勤贈此一絕','李綱','宋','宋诗','song-poetry','','[]','送我謫官遷姊殯，人生如汝亦勞哉。',32,'全唐诗/poet.song.89000.json','["送我謫官遷姊殯，人生如汝亦勞哉。", "他時寄骨西江上，煩汝還須得得來。"]'),
('8b51b95b-433c-4107-8b7f-247333639413','寄王周士絕句二首  其一','李綱','宋','宋诗','song-poetry','','[]','偶然一病便休官，萬石巖中處已安。',32,'全唐诗/poet.song.89000.json','["偶然一病便休官，萬石巖中處已安。", "底事書來猶剩語，也知習氣掃除難。"]'),
('47418c06-fac3-477e-9060-33a3d6a4ce0d','寄王周士絕句二首  其二','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','年來百念冷於灰，夢到江湖又一回。',32,'全唐诗/poet.song.89000.json','["年來百念冷於灰，夢到江湖又一回。", "從此故人音問近，洞庭秋色鴈初來。"]'),
('1f2cf973-9259-4ca5-93a5-9b12cfb6c380','寓居通城僧舍東軒池蓮盛開竹庵珪老有意見過戲贈此篇','李綱','宋','宋诗','song-poetry','','[]','道人庵外萬竿竹，何似小池千葉蓮。',64,'全唐诗/poet.song.89000.json','["道人庵外萬竿竹，何似小池千葉蓮。", "月白風清誰共此，心閑境寂兩翛然。", "好抛筠粉娟娟凈，來看荷珠的的圓。", "飛錫儻能真過我，直須趁取晚霜前。"]'),
('4c145a5d-f8a6-49ff-a4a6-89a2486231f6','張子公以圓鑑見寄作詩報之','李綱','宋','宋诗','song-poetry','','[]','我觀大圓鑑，瑩澈靡瑕垢。',288,'全唐诗/poet.song.89000.json','["我觀大圓鑑，瑩澈靡瑕垢。", "清光溢寒蟾，碧井窺古甃。", "冰池絕埃塵，玉璧無肉好。", "不知何年鑄，款識雜篆籕。", "冷然照肝膽，况燭須眉秀。", "英英張公子，輟贈意獨厚。", "使我正衣冠，更以别妍陋。", "嗟予罹百憂，半世困馳驟。", "蒼浪齒髪衰，已覺成老醜。", "幸兹置寛閑，閉户念往咎。", "冠欹與珮落，顛倒散襟袖。", "平生遭謗讒，白黑坐分剖。", "逝將杜德機，漸可塞智竇。", "豈徒齊美惡，端欲一昏晝。", "鑑焉何所施，無乃虚授受。", "聊持戲鳳匣，藏此蟠螭紐。", "精光祕不露，猶使魑魅走。", "詎逃鸚鵡形，時作蛟龍吼。", "君看方寸間，此物誰蔽覆。", "靈臺湛虚明，廣博含宇宙。", "纖毫莫凝結，萬象悉籠囿。", "寧隨古今移，不逐面目皺。", "人人各具足，一一謝雕鏤。", "無塵安用拂，表裏自通透。"]'),
('aec85b7c-f1d1-44d8-9715-5e09b876d53b','早起','李綱','宋','宋诗','song-poetry','','[]','秋曉凄然枕簟凉，小窗殘月尚臨牀。',64,'全唐诗/poet.song.89000.json','["秋曉凄然枕簟凉，小窗殘月尚臨牀。", "追尋夢境烟雲散，起傍荷花風露香。", "慨念關河心黯黯，諦觀身世意茫茫。", "樽中有酒聊須醉，造物於人自叵量。"]'),
('2cd85558-4b17-4dcc-9a59-69781da4ad3e','有感','李綱','宋','宋诗','song-poetry','','[]','三年再謫墮江湖，何啻經行萬里餘。',64,'全唐诗/poet.song.89000.json','["三年再謫墮江湖，何啻經行萬里餘。", "環繞真同循磨蟻，羈窮更類局轅駒。", "自憐許國心猶壯，却笑謀身術巳疏。", "二聖未還民未靖，尚思痛哭奏囊書。"]'),
('51706341-2ebd-4ada-b244-75f9f8bd6f57','小塘','李綱','宋','宋诗','song-poetry','','[]','誰使精廬鑿小塘，坐令天女試新粧。',64,'全唐诗/poet.song.89000.json','["誰使精廬鑿小塘，坐令天女試新粧。", "風搖翠蓋珊珊響，露裛紅衣冉冉香。", "棋罷雨聲來絕巘，夢回月影上脩廊。", "我生本自無根蔕，觸處爲家殊未央。"]'),
('aba00c91-8531-49a5-927c-35bfe6a8090e','飛雲','李綱','宋','宋诗','song-poetry','','[]','飛雲遊碧虚，夭矯龍蛇勢。',48,'全唐诗/poet.song.89000.json','["飛雲遊碧虚，夭矯龍蛇勢。", "因風態無窮，抱日色增麗。", "飄然欲安歸，出岫非本意。", "爲霖竟何成，跂望增歎喟。"]'),
('da9e2b27-adba-4089-ae65-6f90d6096d06','讀留侯傳有感','李綱','宋','宋诗','song-poetry','','[]','秦人失鹿解其紐，羣雄競逐死誰手。',114,'全唐诗/poet.song.89000.json','["秦人失鹿解其紐，羣雄競逐死誰手。", "天方注意隆準公，故使留侯作賓友。", "圯上老人親授書，言從志合真其偶。", "捕取項籍如嬰兒，指麾諸將猶獵狗。", "運籌决勝帷幄中，楚漢存亡良已久。", "誰言劉季田舍翁，秪聽人言本無有。", "但能信用子房謀，何妨抱持戚姫日飲酒。"]'),
('d3eb7fe6-f332-4033-839e-2426c64b4d80','東軒夜坐','李綱','宋','宋诗','song-poetry','','[]','苒苒流年催白頭，此生那向此淹留。',64,'全唐诗/poet.song.89000.json','["苒苒流年催白頭，此生那向此淹留。", "天髙露下物華肅，月澹風清僧宇幽。", "河底光芒螢照水，草間悲怨蚓吟秋。", "夜凉人閑家千里，别是羈臣一段愁。"]'),
('265da8f7-d8ce-4be1-8df1-88af1665343d','浴罷追和東坡韻','李綱','宋','宋诗','song-poetry','','[]','華髪短且稀，無事蘭湯沐。',168,'全唐诗/poet.song.89000.json','["華髪短且稀，無事蘭湯沐。", "及兹秋暑闌，頭垢資一浴。", "平生冠裳汗，往咎不可復。", "聊將清泠泉，濯此空洞腹。", "荒山薪易採，巨斛水良足。", "融融氣通膚，爛爛光溢目。", "枵然勺用瓢，何必池甃玉。", "呼童爲爬背，自勝飛燕沃。", "振衣絺綌涼，晞汗風前竹。", "却來就繩牀，一枕睡初熟。", "忘世安用愁，抛書且休讀。", "夢中期汗漫，萬里歸一矚。", "吾生真寄耳，來者亦何卜。", "沛然乘天遊，無心且緣督。"]'),
('4c4208c1-c1ab-4165-ba9f-036f511ce443','次韻謫居三適 旦起理髪','李綱','宋','宋诗','song-poetry','','[]','未能運河車，上泝泥丸宫。',120,'全唐诗/poet.song.89000.json','["未能運河車，上泝泥丸宫。", "鬢髪忽已華，颯若冒雪松。", "清晨起自理，濯此萬里風。", "蕭蕭櫛齒快，淅淅氣脉通。", "呼兒助千徧，緩手無怱怱。", "我生本疏懶，誤墮軒冕中。", "野馬就羈靮，何如霧生鬃。", "握髪諒未能，散髪聊與同。", "金丹變鬒色，緣合亦易逢。", "逝將弄雲海，一訪安期公。"]'),
('e28d7710-6937-4a4f-a9ac-150d0711cf88','次韻謫居三適 午窗坐睡','李綱','宋','宋诗','song-poetry','','[]','涉世幾滅頂，欲爲多掣肘。',120,'全唐诗/poet.song.89000.json','["涉世幾滅頂，欲爲多掣肘。", "功名如浮雲，於我亦何有。", "惟兹華胥國，風土諳已久。", "坐中可斷取，聊試維摩手。", "昏昏一卷書，兀兀三杯酒。", "飄然到其鄉，自覺樂而壽。", "嗟我蒲柳姿，未老先已朽。", "何嘗慕管蕭，但欲師廣受。", "未能脫羈束，洗濯愈瑕垢。", "已矣姑兩忘，蘧蘧學莊叟。"]'),
('5b673243-7450-4cb4-a07a-615b35533c94','次韻謫居三適 夜臥濯足','李綱','宋','宋诗','song-poetry','','[]','養生貴養足，不假衾與裯。',96,'全唐诗/poet.song.89000.json','["養生貴養足，不假衾與裯。", "温温斗水間，可以解我憂。", "月露夜寂寂，風雨寒颼颼。", "呼童具盆湯，足若雙蜺投。", "老來嗜坐臥，突兀鷹在韝。", "有時起游行，恍訝煙雲浮。", "自從飽滌濯，此病良已瘳。", "虚堂日千轉，輕捷如沐猴。"]'),
('019de108-7a70-448b-bd4a-b1807df0136c','懷季言弟并簡仲輔叔易','李綱','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','我昔謫沙溪，爾送至虎丘。',288,'全唐诗/poet.song.89000.json','["我昔謫沙溪，爾送至虎丘。", "相攜觀劍池，共坐蒼崖陬。", "霜寒草木衰，肅肅天地秋。", "慷慨論世故，豈復知離愁。", "中間謫雲安，爾病家山留。", "獨與仲及叔，分攜浙江頭。", "潮聲來海門，風雨助颼颼。", "銀濤蹙天起，泛此一葉舟。", "及玆謫武昌，爾復從我遊。", "回環溪壑間，渺若雙沙鷗。", "長江快清曠，廬阜探奇幽。", "行盡江南山，始次湖外州。", "傳聞浙郡兵，盗用官庫矛。", "夜深赤白丸，殺吏起相讎。", "懷家動歸心，觸熱遽還輈。", "作别今幾時，此情浩難收。", "塊處誰共語，把酒無與酬。", "憑髙欲望遠，獨上黄鶴樓。", "吳越天杳杳，風煙晚悠悠。", "顧嗟禰處士，坐困鸚鵡洲。", "胡虜氣方横，盗賊起如蟊。", "中原腤鋒鏑，江漢屯貔貅。", "爾歸議遷徙，已有定論不。", "黄屋尚飄泊，吾敢懷燕休。"]'),
('36763292-a8c8-4200-93f7-d27dc5cd5a12','次韻張子公見寄二首  其一','李綱','宋','宋诗','song-poetry','','[]','處世何殊夢裏人，大千沙界幾迴巡。',64,'全唐诗/poet.song.89000.json','["處世何殊夢裏人，大千沙界幾迴巡。", "萬緣盡處方爲我，一念生時已是塵。", "幻境是誰從出沒，舌根何物辨甘辛。", "安心須到無心地，始契如來清浄身。"]'),
('ce635353-2d9d-46d6-87d8-126a596fbbbf','次韻張子公見寄二首  其二','李綱','宋','宋诗','song-poetry','','[]','功名身外兩悠悠，有意功名已可羞。',64,'全唐诗/poet.song.89000.json','["功名身外兩悠悠，有意功名已可羞。", "與世浮沉非我意，觀時進退豈人謀。", "不能爲國闢百里，祗欲歸耕老一疇。", "禍福死生皆默定，初非捨去亦非求。"]'),
('1d56cd93-1da0-4c1c-abad-b71f262aba8f','余久不飲酒雨過晚凉悠然獨酌戲成此篇','李綱','宋','宋诗','song-poetry','','[]','崎嶔歷落真可笑，飄泊流離初不羞。',64,'全唐诗/poet.song.89000.json','["崎嶔歷落真可笑，飄泊流離初不羞。", "蒼髯華髮老張鎬，火色鳶肩窮馬周。", "身長九尺安所用，命酒一斗聊銷憂。", "醉中起舞頗自得，慷慨不知風雨秋。"]'),
('25cac1d1-a742-495c-8831-45b8cdb54d29','葉落','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','鏗然一葉已驚秋，况復紛紛巧見投。',64,'全唐诗/poet.song.89000.json','["鏗然一葉已驚秋，况復紛紛巧見投。", "振槁不禁風淅淅，催寒長共雨颼颼。", "洞庭波起初微脱，雲夢霜髙浩不收。", "舞砌穿帷不須掃，蕭騷從伴逐臣愁。"]'),
('389b4f7a-8ae2-4b39-b5eb-de5382cbaad9','去歲寓長沙遊道林嶽麓真天下絕景也今相去不遠無因再遊賦詩見意','李綱','宋','宋诗','song-poetry','','["\u8861\u5c71", "\u6d1e\u5ead\u6e56"]','衡山之陬湘水濱，道林嶽麓天下少。',224,'全唐诗/poet.song.89000.json','["衡山之陬湘水濱，道林嶽麓天下少。", "蟠岡複嶺相掩重，石磴松門遞縈繞。", "經行多在煙靄間，臺殿半開雲木杪。", "衲僧宴坐禪寂餘，朝磬暮鐘清杳杳。", "憑髙曠望楚天闊，志氣已逐飛鴻矯。", "橘洲楓浦指顧中，俯視更覺長沙小。", "風檣浪舶千艘屯，丹樓粉堞百雉繚。", "蒼茫曉色散平川，點綴殘霞映疏蓼。", "從來篇翰誰最優，沈宋杜韓争表表。", "古今塵跡散煙雲，獨有斯文傳不了。", "隔年清賞回首空，斯欲再遊真漭渺。", "蒼梧九疑雲漠漠，青草洞庭風嫋嫋。", "有時幽夢一到之，覺來枕席清秋曉。", "人間萬事不由人，安得忘情逐猿鳥。"]'),
('675d7c55-c11a-4d24-8d85-fe8d0bcb2ec5','五哀詩 楚三閭大夫屈原','李綱','宋','宋诗','song-poetry','','[]','楚懷聽秦誑，身作咸陽鬼。',216,'全唐诗/poet.song.89000.json','["楚懷聽秦誑，身作咸陽鬼。", "當時屈原争，坐困椒蘭毁。", "襄王復不悟，遠作江南徙。", "行吟沅湘間，形槁顔色悴。", "著書稱離騷，風雅齊厥理。", "鴟鴞况小人，鸞鳳喻君子。", "眷眷不忘君，一篇三致意。", "紉蘭採杜若，冠佩空自偉。", "舉世混濁中，誰與同樂此。", "忠臣會遇難，千古共一軌。", "人情疏骾亮，物能使軟美。", "存亡反覆間，悔及良晚矣。", "嗟嗟屈子心，芳潔疇與比。", "日月可争光，塵垢安能滓。", "聊從太史卜，肯逐漁父醉。", "甘葬魚腹中，懷沙汨羅水。", "千秋身後名，芬馥同茝芷。", "夫豈椒蘭徒，據勢長不死。"]'),
('a4b490df-0ce8-4754-9c21-e1d6393d1247','五哀詩 漢梁王太傅賈誼','李綱','宋','宋诗','song-poetry','','[]','賈生公輔器，弱冠遊漢廷。',264,'全唐诗/poet.song.89000.json','["賈生公輔器，弱冠遊漢廷。", "髙論帝王略，妙極理亂情。", "出意對詔令，驚倒諸老生。", "從容畫籌策，籍籍飛英聲。", "是時漢初定，頗雜秦覇稱。", "力還治古制，物物與正名。", "改朔易服色，庶幾禮樂興。", "儀章悉草具，輿議當公卿。", "豈知絳灌徒，譖毁如建瓴。", "天子疏不用，謫去長沙城。", "翩然渡湘水，投書弔屈平。", "棄鼎寶康瓠，鉛刀鈍青萍。", "微言豈悼屈，聊復以自評。", "長沙地卑濕，安得壽且寧。", "及觀鵩鳥賦，頗覺生死輕。", "晚奉宣室對，夜半前席聽。", "文帝豈易遇，所言略施行。", "雖不位卿相，儒者良已榮。", "梁王墜馬死，泣涕亦傷生。", "受任乃如此，孤忠本精誠。", "奈何君臣義，澆薄返不明。", "緬懷古人心，使我氣拂膺。"]'),
('cac45f44-22eb-4655-b561-696ff7ab6880','五哀詩 漢處士禰衡','李綱','宋','宋诗','song-poetry','','[]','禰生抱逸韻，乃是古之狂。',267,'全唐诗/poet.song.89000.json','["禰生抱逸韻，乃是古之狂。", "負才頗傲物，齒少氣方剛。", "懷刺遊許下，漫滅竟摧藏。", "肯從屠沽兒，借面與弔喪。", "偉哉孔文舉，國寶借路傍。", "上書薦一鶚，欲使觀翺翔。", "振翼雲漢間，永垂虹蜺光。", "飛兔與腰褭，滅沒不可望。", "觀其慰辭薦，器識豈易量。", "平生輕魏祖，縱口成否臧。", "召令爲鼓吏，閱試當改装。", "蹀{⻊習}初散步，摻撾作漁陽。", "聲節既悲壯，容態隨低昂。", "岑牟與單絞，裸袒易故裳。", "卻來坐軍門，畫地聲琅琅。", "曹瞞黠如鬼，嗜殺猶虎狼。", "縮手不敢動，送與劉及黄。", "娛賓賦鸚鵡，節奏陵笙簧。", "援筆不加點，粲然已成章。", "髙才竟爲累，蘭麝空餘香。", "至今鸚鵡洲，葭葦秋蒼蒼。", "醜哉殺士名，千古不可忘。"]'),
('347bd4a4-2496-4908-b6ff-c6fec6b530a3','五哀詩 唐中書令禇遂良','李綱','宋','宋诗','song-poetry','','[]','貞觀萃羣英，實爲太平基。',240,'全唐诗/poet.song.89000.json','["貞觀萃羣英，實爲太平基。", "禇公初侍書，遂以骾亮知。", "諌疏屢獻納，對揚竭論思。", "翩如丹山鳳，來爲簫韶儀。", "飛鳥自依人，此言已堪嗤。", "更云譖劉洎，厥理尤足疑。", "賢者雖已矣，可以此心推。", "薫蕕難共器，梟鸞不同棲。", "故令敬宗輩，汙染成瑕疵。", "我觀永徽間，武氏盗政機。", "禍端始牀第，幾使國祚移。", "當時河南公，力諍伏丹墀。", "頓首願還笏，丐身田里歸。", "義氣動人主，回天初庶幾。", "鄙哉英公勣，一言遂成非。", "坐令牝鷄晨，啄喪靡有遺。", "元勳顧命老，遠竄湘江湄。", "茫然不復召，詎憶抱頸時。", "卑濕所不堪，須髪盡成絲。", "至今潭府帖，志士生長悲。"]'),
('882d7273-6ee5-4f4b-ac0c-2136696a999e','唐工部員外郎杜甫','李綱','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','子美以詩鳴，今古無對手。',288,'全唐诗/poet.song.89000.json','["子美以詩鳴，今古無對手。", "當時謫仙人，長句頗先後。", "精深律切處，故自非其偶。", "而况郊島徒，何敢窺户牖。", "有如登岱宗，衆山皆培塿。", "又如觀武庫，劍戟靡不有。", "髙辭嫓丘墳，古意篆蝌蚪。", "蒼蒼雪中松，濯濯風前柳。", "雲煙紛卷舒，雷電劃奔走。", "澹然衆態俱，沾丐隨所取。", "平生忠義心，多向詩中剖。", "憂國與愛君，誦說不離口。", "饑寒窘衣食，容貌村野叟。", "自以稷契期，此理人勝不。", "中興作諫臣，戎馬方踐蹂。", "上疏救房琯，亦足知素守。", "一跌不復振，造物意豈苟。", "欲使窮吟哦，専志如矇瞍。", "辛苦盗賊中，妻子或顛仆。", "布衾冷似鐵，晨爨乏升斗。", "冒雪斸黄精，呼兒理魚笱。", "蕭條秦隴間，不廢詩千首。", "依嚴遂入蜀，幕府備賓友。", "草堂浣花溪，頗復事南畝。"]'),
('1d0fb096-611e-4c73-ba04-2a4b7b6634e0','黄陵廟','李綱','宋','宋诗','song-poetry','','[]','湘妃廟貌枕江湄，不見當年鼓瑟時。',64,'全唐诗/poet.song.89000.json','["湘妃廟貌枕江湄，不見當年鼓瑟時。", "玉佩風搖雲冉冉，翠帷煙濕草離離。", "淒涼清淚留班竹，寂寞深林叫子規。", "斷簡遺編杳難考，無人爲立退之碑。"]'),
('038bbed4-d4d4-48af-aa65-a51ab04cf687','望九疑','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭渺漭蘆葦秋，九疑聯綿煙靄浮。',64,'全唐诗/poet.song.89000.json','["洞庭渺漭蘆葦秋，九疑聯綿煙靄浮。", "重瞳一去不復返，蒼梧雲物空疑愁。", "兩階干羽久寂寞，千古夷夏相仇讎。", "安得垂衣轉琴軫，薫風爲解吾民憂。"]'),
('fb87b1d6-c571-43c2-bbf2-144a4e5265c5','去歲道巴陵登岳陽樓以望洞庭真天下之壯觀也因誦孟浩然氣蒸雲夢澤波撼岳陽城之句追古今絕唱用以爲韻賦詩十篇  其一','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','登樓窺洞庭，滄波渺無際。',48,'全唐诗/poet.song.89000.json','["登樓窺洞庭，滄波渺無際。", "波間起飛龍，慘澹带雲氣。", "雲雷倐變滅，天水共澄霽。", "矯首望君山，鏡面青螺髻。"]'),
('58ff43e5-08fb-46a9-999c-2bed83cde833','去歲道巴陵登岳陽樓以望洞庭真天下之壯觀也因誦孟浩然氣蒸雲夢澤波撼岳陽城之句追古今絕唱用以爲韻賦詩十篇  其二','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','地枕江湖闊，秋來多鬰蒸。',48,'全唐诗/poet.song.89000.json','["地枕江湖闊，秋來多鬰蒸。", "山城少見日，霧雨長冥冥。", "今夕定何夕，月華風露清。", "於此興不淺，欄干聊復憑。"]'),
('4530bc82-bd12-462a-a67d-e9cd289422c8','去歲道巴陵登岳陽樓以望洞庭真天下之壯觀也因誦孟浩然氣蒸雲夢澤波撼岳陽城之句追古今絕唱用以爲韻賦詩十篇  其三','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','秋色到極浦，層空靄行雲。',48,'全唐诗/poet.song.89000.json','["秋色到極浦，層空靄行雲。", "長劍撫玉珥，欲降雲中君。", "桂旗澹偃蹇，風馭何繽紛。", "淹留豈予願，沐浴空蘭薫。"]'),
('0fe54f22-c2b1-4b1b-a390-3ac01fd59e89','去歲道巴陵登岳陽樓以望洞庭真天下之壯觀也因誦孟浩然氣蒸雲夢澤波撼岳陽城之句追古今絕唱用以爲韻賦詩十篇  其四','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','此身墮江湖，恍若在清夢。',48,'全唐诗/poet.song.89000.json','["此身墮江湖，恍若在清夢。", "夢中亦何爲，思古亦長慟。", "心馳關塞遠，目與飛鴻送。", "賈客不知愁，淒然笛三弄。"]');
